insert into unit_enemy_data values (200100, '擲岩猴', 200100, 0, 0, 270, 800, 1, 3.5, 0, 0, 0, '【物理】遠距離攻擊\\n能夠投擲大石頭，從遠處\\n攻擊的猴子魔物。');
insert into unit_enemy_data values (200200, '氣球鳥', 200200, 0, 0, 270, 800, 1, 3.0, 0, 0, 0, '【恢復】範圍恢復\\n能用膨起的肚子中累積的魔力，\\n來恢復同伴的鳥型魔物。');
insert into unit_enemy_data values (200300, '守門者', 200300, 0, 0, 270, 200, 2, 3.5, 0, 0, 0, '【魔法】範圍攻擊\\n敞開地獄之門，並吐出會使人火傷的熱炎，\\n是魔界的守衛。');
insert into unit_enemy_data values (200301, '守門者', 200300, 0, 0, 270, 350, 2, 3.5, 0, 0, 0, '【魔法】範圍攻擊\\n敞開地獄之門，並吐出會使人火傷的熱炎，\\n是魔界的守衛。');
insert into unit_enemy_data values (200302, '守門者', 200300, 0, 0, 270, 500, 2, 3.5, 0, 0, 0, '【魔法】範圍攻擊\\n敞開地獄之門，並吐出會使人火傷的熱炎，\\n是魔界的守衛。');
insert into unit_enemy_data values (200400, '狼人', 200400, 0, 0, 270, 350, 1, 2.5, 0, 0, 0, '【物理】近距離攻擊\\n以尖銳的利爪敵人撕裂，\\n一種野狼的魔物。');
insert into unit_enemy_data values (200500, '狂野角鹿', 200500, 0, 16, 270, 200, 1, 3.0, 0, 0, 0, '【物理】近距離攻擊\\n巨大的雙角除了攻擊也能防禦，\\n是鹿型的魔物。');
insert into unit_enemy_data values (200501, '冰雪角鹿', 200501, 0, 16, 270, 200, 1, 3.0, 0, 0, 0, '【物理】近距離攻擊\\n住在高山深處，厚實的毛皮下，\\n擁有強壯的身體，是一種馴鹿的魔物。');
insert into unit_enemy_data values (200503, '狂野角鹿', 200503, 0, 16, 750, 580, 1, 3.0, 0, 0, 0, '');
insert into unit_enemy_data values (200504, '狂野角鹿', 200503, 0, 16, 750, 350, 1, 3.0, 0, 0, 0, '');
insert into unit_enemy_data values (200505, '狂野角鹿', 200503, 0, 16, 600, 120, 1, 3.0, 0, 0, 0, '');
insert into unit_enemy_data values (200600, '鼠妖', 200600, 0, 11, 270, 250, 1, 1.5, 0, 0, 0, '【物理】近距離攻擊\\n威力雖然不高，但能迅捷地進行多次\\n攻擊，是鼠型的魔物。');
insert into unit_enemy_data values (200700, '木靈', 200700, 0, 17, 270, 400, 2, 3.0, 0, 0, 0, '【魔法】中距離攻擊\\n扔擲魔力的砲彈，\\n能攻擊到較後方的朽木魔物。');
insert into unit_enemy_data values (200701, '石靈', 200701, 0, 17, 270, 400, 2, 3.0, 0, 0, 0, '【魔法】中距離攻擊\\n能投射出使人燃燒的火焰，\\n使敵人受到火傷，\\n來追加傷害的詛咒石像。');
insert into unit_enemy_data values (200800, '噬岩怪', 200800, 0, 15, 270, 1080, 1, 3.5, 0, 0, 0, '【物理】遠距離攻擊\\n擁有就連岩石都能輕易嚼碎的堅硬牙\\n齒，出沒在山中的精靈。');
insert into unit_enemy_data values (200801, '噬冰怪', 200801, 0, 15, 270, 1080, 1, 3.5, 0, 0, 0, '【物理】遠距離攻擊\\n以冰塊作為武器，甚至食材的\\n雪山的精靈。');
insert into unit_enemy_data values (200900, '樹精', 200900, 0, 15, 270, 200, 1, 2.5, 0, 0, 0, '【物理】前衛，近距離攻擊\\n把柔韌長枝當作鞭子一樣攻擊\\n的樹木魔物。');
insert into unit_enemy_data values (200901, '擰扭相思樹', 200901, 0, 15, 270, 200, 1, 2.5, 0, 0, 0, '【物理】近距離攻擊\\n能用扭捲而成的長枝，將冒險家拖行到森林深處的樹木魔物。');
insert into unit_enemy_data values (200902, '多倫多獸', 200902, 0, 15, 270, 200, 1, 0.5, 0, 0, 0, '【物理】中距離攻擊\\n能自由伸展分枝，以老練的技巧\\n探中痛點的朽木魔物。');
insert into unit_enemy_data values (200903, '多倫多獸', 200902, 0, 15, 270, 3000, 1, 0.5, 0, 0, 0, '【物理】中距離攻擊\\n能自由伸展分枝，以老練的技巧\\n探中痛點的朽木魔物。');
insert into unit_enemy_data values (200904, '多倫多獸', 200904, 0, 15, 270, 3000, 1, 2.0, 0, 0, 0, '【物理】中距離攻擊\\n能自由伸展分枝，以老練的技巧\\n探中痛點的朽木魔物。');
insert into unit_enemy_data values (200905, '多倫多獸', 200905, 0, 15, 270, 3000, 1, 2.0, 0, 0, 0, '【物理】中距離攻擊\\n能自由伸展分枝，以老練的技巧\\n探中痛點的朽木魔物。');
insert into unit_enemy_data values (201000, '怨火之顱', 201000, 0, 17, 270, 1080, 2, 3.0, 0, 0, 0, '【魔法】中距離攻擊\\n身纏著地獄之火，\\n且朝著生者襲擊而來的怨念的集合體。');
insert into unit_enemy_data values (201100, '狗頭人', 201100, 0, 15, 270, 650, 1, 3.5, 0, 0, 0, '【物理】中距離攻擊\\n投擲著用骨頭做成的迴力鏢\\n做為攻擊手段，一種山犬的魔物。');
insert into unit_enemy_data values (201101, '狗頭刺客', 201101, 0, 15, 270, 650, 1, 0.5, 0, 0, 0, '【物理】中距離攻擊\\n以快速步伐耍弄，趁些微的空隙\\n扔出飛刀的山犬魔物。');
insert into unit_enemy_data values (201102, '狗頭刺客', 201102, 0, 15, 350, 370, 1, 0.5, 0, 0, 0, '【物理】中距離攻擊\\n以快速步伐耍弄，趁些微的空隙\\n扔出飛刀的山犬魔物。');
insert into unit_enemy_data values (201200, '魔像', 201200, 0, 16, 270, 150, 1, 5.0, 0, 0, 0, '【物理】近距離攻擊\\n有著堅硬的身軀，\\n是攻守具佳的岩石魔物。');
insert into unit_enemy_data values (201201, '青藍魔像', 201201, 0, 16, 270, 150, 1, 5.0, 0, 0, 0, '【物理】【魔法防禦】近距離攻擊\\n從蘊含著魔力的岩石中誕生而出，\\n擁有魔法耐力的魔像。');
insert into unit_enemy_data values (201202, '青藍魔像', 201202, 0, 16, 270, 150, 1, 5.0, 0, 0, 0, '【物理】【魔法防禦】近距離攻擊\\n從蘊含著魔力的岩石中誕生而出，\\n擁有魔法耐力的魔像。');
insert into unit_enemy_data values (201203, '魔像', 201203, 0, 16, 270, 150, 1, 5.0, 0, 0, 0, '【物理】近距離攻擊\\n有著堅硬的身軀，\\n是攻守具佳的岩石魔物。');
insert into unit_enemy_data values (201204, '青藍魔像', 201204, 0, 16, 270, 150, 1, 5.0, 0, 0, 0, '【物理】【魔法防禦】近距離攻擊\\n從蘊含著魔力的岩石中誕生而出，\\n擁有魔法耐力的魔像。');
insert into unit_enemy_data values (201205, '青藍魔像', 201201, 0, 16, 270, 50, 1, 5.0, 0, 0, 0, '【物理】【魔法防禦】近距離攻擊\\n從蘊含著魔力的岩石中誕生而出，\\n擁有魔法耐力的魔像。');
insert into unit_enemy_data values (201300, '岩花', 201300, 0, 15, 270, 800, 1, 3.5, 0, 0, 0, '【物理】中距離攻擊\\n能將石子像子彈一樣彈射而出來做為\\n攻擊，是以石頭造且能夠移動的花。');
insert into unit_enemy_data values (201301, '癲狂之花', 201301, 0, 15, 270, 800, 1, 3.5, 0, 0, 0, '【物理】中距離攻擊\\n在尾端的花會散發著嚴重的惡臭， \\n也有若習慣那味道後， \\n會使人不禁上癮的說法。');
insert into unit_enemy_data values (201302, '仙人掌花', 201302, 0, 15, 270, 800, 1, 3.5, 0, 0, 0, '【物理】中距離攻擊\\n無限發射會使人麻痺的針，\\n是一株會移動的仙人掌。');
insert into unit_enemy_data values (201400, '雷雲長老', 201400, 0, 0, 270, 1080, 2, 3.0, 0, 0, 0, '【魔法】【輔助】範圍攻擊\\n能夠自在地操縱氣象，\\n能雷擊的雲型魔物。');
insert into unit_enemy_data values (201500, '潛陸水母', 201500, 0, 0, 270, 780, 2, 3.0, 0, 0, 0, '【恢復】範圍恢復\\n將撿來潛水服裡注滿了海水，\\n就算是在陸地上也能戰鬥的水母型魔物。');
insert into unit_enemy_data values (201600, '森之寧芙', 201600, 0, 15, 270, 800, 2, 2.5, 0, 0, 0, '【魔法】【召喚】近距離攻擊\\n能自在利用大地的魔力來生長出\\n魔菇型魔物，分布於森林裡的精靈。');
insert into unit_enemy_data values (201602, '寧芙', 201602, 0, 15, 270, 800, 2, 2.5, 0, 0, 0, '【魔法】中距離攻擊\\n只要找到了可以玩的對象，\\n就會無止盡的捉弄對方，\\n一種森之精靈。');
insert into unit_enemy_data values (201700, '生者戰士像', 201700, 0, 16, 270, 150, 1, 4.0, 0, 0, 0, '【物理】【魔法防禦】近距離攻擊\\n無論是什麼魔法攻擊都能以盾防禦，\\n是座擁有生命的石像。');
insert into unit_enemy_data values (201800, '生者劍士', 201800, 0, 5, 270, 150, 1, 4.0, 0, 0, 0, '【物理】【物理防禦】近距離攻擊\\n無論是什麼物理攻擊都能以劍反射回擊，\\n是座擁有生命的石像。');
insert into unit_enemy_data values (201900, '烏帕魯帕', 201900, 0, 0, 270, 1080, 1, 3.0, 0, 0, 0, '【物理】遠距離攻擊\\n棲息於沉積泥沼地之中，能從口中\\n吐出強力的毒，一種山椒魚型魔物。');
insert into unit_enemy_data values (201901, '岩漿烏帕魯帕', 201901, 0, 0, 270, 1080, 1, 3.0, 0, 0, 0, '【物理】遠距離攻擊\\n潛藏在岩漿之海中，會對接近之物吐\\n出灼熱體液，一種山椒魚魔物。');
insert into unit_enemy_data values (202000, '岩龜暴君', 202000, 0, 16, 270, 150, 1, 5.5, 0, 0, 0, '【物理】【物理防禦】近距離攻擊\\n不管是任何的物理攻擊都能用硬殼\\n給彈開，巨大的龜型魔物。');
insert into unit_enemy_data values (202100, '發光蕈菇', 202100, 0, 14, 270, 200, 1, 2.0, 0, 0, 0, '【物理】近距離攻擊\\n應森精所召喚而出，能夠無限地\\n生長出來的魔菇精靈。');
insert into unit_enemy_data values (202101, '紅蕈菇', 202101, 0, 14, 270, 200, 1, 2.0, 0, 0, 0, '【物理】近距離攻擊\\n傳聞拿來燉煮後意外地好吃，\\n一種會走路的魔菇魔物。');
insert into unit_enemy_data values (202200, '翼耳兔', 202200, 0, 15, 270, 650, 2, 3.5, 0, 0, 0, '【魔法】近距離攻擊\\n能夠煽動巨大的長耳，以著驚人之勢\\n突擊而上，是一種兔子魔物。');
insert into unit_enemy_data values (202300, '火焰咒士', 202300, 0, 17, 270, 1080, 2, 3.5, 0, 0, 0, '【魔法】遠距離攻擊\\n能以地獄喚來火炎，\\n使於魔法上進行攻擊，是一種上級的惡魔。');
insert into unit_enemy_data values (202301, '火焰咒士', 202301, 0, 17, 270, 1080, 2, 3.5, 0, 0, 0, '【魔法】遠距離攻擊\\n能以地獄喚來火炎，\\n使於魔法上進行攻擊，是一種上級的惡魔。');
insert into unit_enemy_data values (202400, '洞窟猿猴', 202400, 0, 12, 270, 750, 1, 3.0, 0, 0, 0, '【物理】近距離攻擊\\n手臂上強韌的肌肉，使牠甚至能夠\\n擺盪鐘乳石間穿梭，是一種大型猴怪魔物。');
insert into unit_enemy_data values (202500, '洞窟蝙蝠', 202500, 0, 15, 270, 550, 2, 3.5, 0, 0, 0, '【魔法】近距離攻擊 \\n棲息於洞窟之中，\\n聽取著獵物的腳步聲 進行襲擊，\\n一種蝙蝠型魔物。');
insert into unit_enemy_data values (202600, '岩窟蝸牛', 202600, 0, 0, 270, 750, 2, 4.0, 0, 0, 0, '【恢復】範圍恢復\\n據說分泌出的黏液，\\n有良好的美容效果，\\n一種蝸牛型魔物。');
insert into unit_enemy_data values (202700, '寄居蟹騎士', 202700, 0, 6, 270, 350, 1, 3.0, 0, 0, 0, '【物理】近距離攻擊\\n將被擊倒的騎士所覆的頭盔，做為\\n自己的貝殼，一種寄居蟹戰士。');
insert into unit_enemy_data values (202800, '流浪之鴉', 202800, 0, 4, 270, 650, 1, 3.0, 0, 0, 0, '【物理】範圍攻擊\\n到處打倒阿斯特朗中強力的魔物\\n的流浪烏鴉。');
insert into unit_enemy_data values (202802, '遷徙之鳶', 202802, 0, 4, 270, 650, 1, 2.6, 0, 0, 0, '【物理】範圍攻擊\\n崇拜著生於荒野，也將死於荒野\\n的生活方式，是一隻孤鳥。');
insert into unit_enemy_data values (202900, '毒牙蜥蜴', 202900, 0, 14, 270, 200, 1, 2.5, 0, 0, 0, '【物理】近距離攻擊\\n被那尖銳之牙給咬上一口，\\n便會留下足以致命的負傷，是一種毒蜥蜴魔物。');
insert into unit_enemy_data values (202901, '岩石蜥蜴', 202901, 0, 14, 270, 200, 1, 3.0, 0, 0, 0, '【物理】近距離攻擊\\n那頭部的外層就如同鎧甲般堅硬，\\n是一種岩石巨蜥魔物。');
insert into unit_enemy_data values (202902, '翠綠蜥蜴', 202902, 0, 14, 270, 200, 1, 3.0, 0, 0, 0, '【物理】近距離攻擊\\n襟領上有著鮮豔的綠葉，\\n是蜥蜴魔物介的時尚大佬。');
insert into unit_enemy_data values (202903, '岩石蜥蜴', 202903, 0, 14, 270, 2050, 1, 3.0, 0, 0, 0, '【物理】近距離攻擊\\n那頭部的外層就如同鎧甲般堅硬，\\n是一種岩石巨蜥魔物。');
insert into unit_enemy_data values (202904, '火蜥蜴', 202904, 0, 14, 270, 200, 1, 0.5, 0, 0, 0, '【物理】近距離攻擊\\n靠著尾巴上永遠燃燒著的火焰\\n能常保身體溫熱，並不停使出二連擊\\n的蜥蜴魔物。');
insert into unit_enemy_data values (202905, '石蜥', 202905, 0, 14, 270, 100, 1, 3.0, 0, 0, 0, '【物理】近距離攻擊\\n沾染上高等・加爾格噴散殘留物的岩石蜥蜴。藉由露娜的魔力，將表皮轉換成了堅固的礦石。');
insert into unit_enemy_data values (203000, '軟泥怪', 203000, 0, 15, 270, 200, 2, 2.0, 0, 0, 0, '【魔法】近距離攻擊\\n用物理攻擊相當難以擊中，\\n非常濕黏的果凍狀魔物。');
insert into unit_enemy_data values (203001, '閃焰軟泥怪', 203001, 0, 15, 270, 200, 2, 2.0, 0, 0, 0, '【魔法】近距離攻擊\\n被森林大火給捲入而著火，\\n因此變得更加凶暴的軟泥怪。');
insert into unit_enemy_data values (203100, '幼年巨蜥', 203100, 0, 17, 270, 800, 2, 3.5, 0, 0, 0, '【魔法】近距離攻擊\\n儘管還年幼仍然會吐著強力\\n的火焰，是巨蜥的幼獸。');
insert into unit_enemy_data values (203200, '搗蛋惡魔', 203200, 0, 12, 270, 650, 2, 3.5, 0, 0, 0, '【魔法】近距離攻擊\\n使用與身長比例不符、異常巨大的爪子\\n做為攻擊，是仍在見習中的惡魔。');
insert into unit_enemy_data values (203300, '哥布林護衛', 203300, 0, 15, 270, 150, 1, 4.0, 0, 0, 0, '【物理】近距離攻擊\\n以逼近身高高度的巨大的盾牌\\n守護著同伴的，見習哥布靈士兵。');
insert into unit_enemy_data values (203301, '叢林護衛', 203301, 0, 15, 270, 150, 1, 4.0, 0, 0, 0, '【物理】近距離攻擊\\n以看似臉譜的大型盾牌嚇阻\\n入侵者，是叢林的守護者。');
insert into unit_enemy_data values (203302, '哥布林護衛', 203300, 0, 15, 270, 50, 1, 4.0, 0, 0, 0, '【物理】近距離攻擊\\n以逼近身高高度的巨大的盾牌\\n守護著同伴的，見習哥布靈士兵。');
insert into unit_enemy_data values (203303, '哥布林護衛', 203303, 0, 15, 350, 170, 1, 4.0, 0, 0, 0, '【物理】近距離攻擊\\n以逼近身高高度的巨大的盾牌\\n守護著同伴的，見習哥布靈士兵。');
insert into unit_enemy_data values (203400, '鬼燈螢', 203400, 0, 0, 270, 800, 2, 4.0, 0, 0, 0, '【恢復】單方恢復\\n儲存於尾部的蜜，能夠成為\\n魔物的營養源，是種不可思議的螢火蟲。');
insert into unit_enemy_data values (203402, '鬼燈螢', 203400, 0, 0, 270, 3000, 2, 4.0, 0, 0, 0, '【恢復】單方恢復\\n儲存於尾部的蜜，能夠成為\\n魔物的營養源，是種不可思議的螢火蟲。');
insert into unit_enemy_data values (203500, '鑽頭鼴鼠', 203500, 0, 16, 270, 750, 1, 3.5, 0, 0, 0, '【物理】中距離攻擊\\n能從地底伸手，從腳下開始\\n攻擊的鼴型魔物。');
insert into unit_enemy_data values (203501, '寒冰鼴鼠', 203501, 0, 16, 270, 750, 1, 3.5, 0, 0, 0, '【物理】中距離攻擊\\n以靈活的利爪刨碎冰塊，\\n並作為攻擊的雪鼴型魔物');
insert into unit_enemy_data values (203700, '堅果射手', 203700, 0, 15, 270, 350, 1, 2.5, 0, 0, 0, '【物理】範圍攻擊\\n將吃完後堅果殼給砸向敵人，\\n一種充滿惡意的松鼠魔物。');
insert into unit_enemy_data values (203702, '臭鼬', 203702, 0, 15, 270, 350, 1, 2.5, 0, 0, 0, '【物理】範圍攻擊\\n能任意使用刺激眼部的\\n惡臭氣體炸彈的臭鼬魔物。');
insert into unit_enemy_data values (203703, '臭鼬', 203702, 0, 15, 270, 100, 1, 2.5, 0, 0, 0, '【物理】範圍攻擊\\n能任意使用刺激眼部的\\n惡臭氣體炸彈的臭鼬魔物。');
insert into unit_enemy_data values (203800, '獸人', 203800, 0, 13, 270, 200, 1, 2.5, 0, 0, 0, '【物理】近距離攻擊\\n身著從被擊倒的冒險家身上\\n搶來的鎧甲，且揮舞著巨斧的一種\\n凶暴的森林獸人。');
insert into unit_enemy_data values (203801, '高等獸人', 203801, 0, 13, 270, 200, 1, 2.5, 0, 0, 0, '【物理】近距離攻擊\\n因反覆且嚴厲的鍛鍊，\\n而獲得強韌肉體，\\n獸人裡頭的上位種。');
insert into unit_enemy_data values (203803, '高等獸人', 203801, 0, 13, 270, 300, 1, 2.5, 0, 0, 0, '【物理】近距離攻擊\\n因反覆且嚴厲的鍛鍊，\\n而獲得強韌肉體，\\n獸人裡頭的上位種。');
insert into unit_enemy_data values (203804, '獸人', 203800, 0, 13, 240, 200, 1, 2.5, 0, 0, 0, '【物理】近距離攻擊\\n身著從被擊倒的冒險家身上\\n搶來的鎧甲，且揮舞著巨斧的一種\\n凶暴的森林獸人。');
insert into unit_enemy_data values (203900, '惡魔加農', 203900, 0, 16, 270, 1080, 1, 4.0, 0, 0, 0, '【物理】近距離攻擊\\n因為長年的使用而寄生著惡魔之魂，\\n擁有生命的砲台。');
insert into unit_enemy_data values (204000, '小小格里芬', 204000, 0, 15, 270, 650, 1, 3.5, 0, 0, 0, '【物理】近距離攻擊\\n羽毛還沒長齊，\\n還飛不起來的雛獅鷲。');
insert into unit_enemy_data values (204200, '女中音之鳥', 204200, 0, 0, 270, 450, 2, 4.0, 0, 0, 0, '【恢復】範圍恢復\\n那治癒人的歌聲甚至能傳送至遠方，\\n在鳥魔物界中是一位知名的歌手');
insert into unit_enemy_data values (204300, '毒莢花', 204300, 0, 15, 270, 750, 1, 2.5, 0, 0, 0, '【物理】近距離攻擊\\n用那血盆大口之中所蘊含的腐蝕液體，\\n將捕獲的獵物吃掉。');
insert into unit_enemy_data values (204301, '毒莢花', 204300, 0, 15, 270, 3000, 1, 2.5, 0, 0, 0, '【物理】近距離攻擊\\n用那血盆大口之中所蘊含的腐蝕液體，\\n將捕獲的獵物吃掉。');
insert into unit_enemy_data values (204400, '惡魔寶寶', 204400, 0, 0, 270, 750, 2, 3.5, 0, 0, 0, '【魔法】中距離攻擊\\n用才剛學會的魔法，不管三七二十一\\n就到處攻擊的幼年惡魔。');
insert into unit_enemy_data values (204500, '重鎚巨蟹', 204500, 0, 0, 270, 200, 1, 2.5, 0, 0, 0, '【物理】近距離攻擊\\n以大型的爪子以及堅硬的殼，\\n面對各種巨大的對手的螃蟹魔物。');
insert into unit_enemy_data values (204501, '重鎚巨蟹', 204501, 0, 0, 270, 50, 1, 2.5, 0, 0, 0, '【物理】近距離攻擊\\n以大型的爪子以及堅硬的殼，\\n面對各種巨大的對手的螃蟹魔物。');
insert into unit_enemy_data values (204502, '棘刺蟹', 204502, 0, 0, 270, 80, 1, 2.0, 0, 0, 0, '【物理】近距離攻擊\\n以巨大的螯鉗與堅硬的殼自豪的\\n螃蟹魔物。潛入沙中悠哉地等待著\\n獵物的模樣，相當討喜。');
insert into unit_enemy_data values (204503, '棘刺蟹', 204502, 0, 0, 270, 20, 1, 2.0, 0, 0, 0, '【物理】近距離攻擊\\n以巨大的螯鉗與堅硬的殼自豪的\\n螃蟹魔物。潛入沙中悠哉地等待著\\n獵物的模樣，相當討喜。');
insert into unit_enemy_data values (204600, '魔法射線', 204600, 0, 0, 270, 1080, 2, 3.5, 0, 0, 0, '【魔法】範圍攻擊\\n以頭部石塊發射超音波，\\n輕鬆狩獵的魟魚魔物。');
insert into unit_enemy_data values (204700, '綠葉野豬', 204700, 0, 0, 270, 200, 1, 4.0, 0, 0, 0, '【物理】近距離攻擊\\n將堅硬的葉子如鎧甲般纏繞身體，\\n碰到即會帶來劇烈疼痛的大型野豬。\\n但終歸只是葉子。無法防禦魔法。');
insert into unit_enemy_data values (204701, '沙塵野豬', 204701, 0, 0, 270, 200, 1, 4.0, 0, 0, 0, '【物理】近距離攻擊\\n將沙子作為鎧甲纏繞於身上，\\n極為身為不畏捨身的戰士的鐵證。\\n但終歸只是沙子。無法防禦魔法。');
insert into unit_enemy_data values (204702, '狂野野豬', 204702, 0, 0, 270, 170, 1, 4.0, 0, 0, 0, '【物理】近距離攻擊\\n生活於熱地，原始的大野豬。\\n在不停衝撞岩漿岩後，\\n習得了連鎧甲都可粉碎的牙之一擊。');
insert into unit_enemy_data values (204800, '廢墟人偶', 204800, 0, 0, 270, 150, 1, 1.8, 0, 0, 0, '【物理】近距離攻擊\\n跟隨並且聽令於逝者‧卡拉迪翁的古代自動人偶。\\n不具意志，在自身瓦解前將會永無止境的進行戰鬥。');
insert into unit_enemy_data values (204900, '小小哥布林', 204900, 0, 0, 270, 100, 1, 0.5, 0, 0, 0, '【物理】近距離攻擊\\n儘管幼小，仍舊勇猛的見習哥布林。\\n以靈巧彌補無力，在前線上活躍。');
insert into unit_enemy_data values (205000, '毒蟾蜍', 205000, 0, 0, 270, 500, 1, 2.5, 0, 0, 0, '【物理】近距離攻擊\\n以擬態的寶石勾引上鉤者並捕食\\n，擁有毒舌的癩蛤蟆魔物。');
insert into unit_enemy_data values (205001, '毒蟾蜍', 205000, 0, 0, 270, 500, 1, 2.5, 0, 0, 0, '【物理】近距離攻擊\\n以擬態的寶石勾引上鉤者並捕食\\n，擁有毒舌的癩蛤蟆魔物。');
insert into unit_enemy_data values (205100, '土蛇', 205100, 0, 13, 270, 550, 1, 2.5, 0, 0, 0, '【物理】中距離攻擊 \\n躲在暗處吸取自\\n各個角落飛來的魔力，\\n以填飽肚子的魔物蛇的變種。\\n魔力越高越容易被它盯上。');
insert into unit_enemy_data values (205200, '海馬騎士', 205200, 0, 0, 270, 650, 1, 2.0, 0, 0, 0, '【物理】中距離攻擊\\n奪取在海中溺水的騎士的茅，\\n劃界警備的海馬戰士');
insert into unit_enemy_data values (205300, '寒冰雛鳥', 205300, 0, 0, 270, 550, 2, 3.0, 0, 0, 0, '【魔法】中距離攻擊\\n以尾部羽毛上發射冰霜攻擊的\\n鳥型魔物。');
insert into unit_enemy_data values (205400, '冰魚', 205400, 0, 12, 270, 550, 1, 2.6, 0, 0, 0, '【物理】近距離攻擊\\n鑿開冰河作為巢穴，對所有接近的人，\\n無差別進行襲擊的魚之魔物。');
insert into unit_enemy_data values (205401, '熔岩魚', 205401, 0, 12, 270, 550, 1, 2.4, 0, 0, 0, '【物理】近距離攻擊\\n以連岩石都能咬碎的強韌下顎，\\n將周遭事物給食之殆盡的魚之魔物。');
insert into unit_enemy_data values (205500, '沙陸毒蛇', 205500, 0, 14, 270, 550, 1, 3.0, 0, 0, 0, '【物理】中距離攻擊\\n挖掘洞穴，靜待獵物掉入洞穴，\\n再以毒牙將其斃命的蛇的魔物。');
insert into unit_enemy_data values (205600, '狂犬', 205600, 0, 0, 270, 100, 1, 2.5, 0, 0, 0, '【物理】近距離攻擊\\n與主人一同被創造出來，一隻兇暴的改造犬。\\n像為得支撐住那大頭所流露的猙獰面容，極為恐怖。');
insert into unit_enemy_data values (205700, '波尼', 205700, 0, 15, 270, 50, 1, 0.4, 0, 0, 0, '召喚地獄獵犬用怪物');
insert into unit_enemy_data values (205701, '波尼', 205701, 0, 15, 270, 50, 1, 0.4, 0, 0, 0, '召喚地獄獵犬用怪物');
insert into unit_enemy_data values (205800, '小霧奇前衛', 205800, 0, 0, 270, 50, 1, 1.8, 0, 0, 0, '霧奇召喚用怪物（弱）');
insert into unit_enemy_data values (205801, '小霧奇中衛', 205801, 0, 0, 270, 200, 1, 1.8, 0, 0, 0, '霧奇召喚用怪物（弱）');
insert into unit_enemy_data values (205802, '小霧奇後衛', 205802, 0, 0, 270, 200, 1, 1.8, 0, 0, 0, '霧奇召喚用怪物（弱）');
insert into unit_enemy_data values (205803, '小霧奇前衛', 205800, 0, 0, 270, 50, 1, 1.8, 0, 0, 0, '霧奇召喚用怪物（強）');
insert into unit_enemy_data values (205804, '小霧奇中衛', 205801, 0, 0, 270, 200, 1, 1.8, 0, 0, 0, '霧奇召喚用怪物（強）');
insert into unit_enemy_data values (205805, '小霧奇後衛', 205802, 0, 0, 270, 200, 1, 1.8, 0, 0, 0, '霧奇召喚用怪物（強）');
insert into unit_enemy_data values (205806, '小霧奇前衛', 205800, 0, 0, 270, 50, 1, 1.8, 0, 0, 0, '霧奇召喚用怪物（弱）');
insert into unit_enemy_data values (205807, '小霧奇中衛', 205801, 0, 0, 270, 200, 1, 1.8, 0, 0, 0, '霧奇召喚用怪物（弱）');
insert into unit_enemy_data values (205808, '小霧奇後衛', 205802, 0, 0, 270, 200, 1, 1.8, 0, 0, 0, '霧奇召喚用怪物（弱）');
insert into unit_enemy_data values (205809, '小霧奇前衛', 205800, 0, 0, 270, 50, 1, 1.8, 0, 0, 0, '霧奇召喚用怪物（強）');
insert into unit_enemy_data values (205810, '小霧奇中衛', 205801, 0, 0, 270, 200, 1, 1.8, 0, 0, 0, '霧奇召喚用怪物（強）');
insert into unit_enemy_data values (205811, '小霧奇後衛', 205802, 0, 0, 270, 200, 1, 1.8, 0, 0, 0, '霧奇召喚用怪物（強）');
insert into unit_enemy_data values (205900, '憤怒烏賊', 205900, 0, 0, 270, 200, 0, 2.5, 0, 0, 0, '【物理】中距離攻擊\\n怒髮衝冠的烏賊魔物。\\n那金屬質的錨，\\n儘管擁有高硬度卻相當沉重，\\n時常導致失衡而摔個十腳朝天。');
insert into unit_enemy_data values (206000, '海獅怪', 206000, 0, 1, 270, 100, 1, 4.0, 0, 0, 0, '【物理】近距離攻擊\\n不論體型還態度，皆為條漢子的北\\n海之怪。以厚重的脂肪層來抵禦且\\n壓制敵人的物理攻擊。');
insert into unit_enemy_data values (206100, '睿智權杖', 206100, 0, 7, 270, 1080, 2, 4.5, 0, 0, 0, '【魔法】遠距離攻擊\\n以被噴到就會凍結的寒氣魔法，\\n剝奪敵人戰意的鸚鵡螺型魔物。');
insert into unit_enemy_data values (206200, '流氓水獺', 206200, 0, 1, 270, 650, 1, 3.5, 0, 0, 0, '【物理】中距離攻擊\\n人一不留意時就拿貝殼亂丟亂砸，\\n一種性格惡劣的北海小混混。');
insert into unit_enemy_data values (206201, '頑皮河狸', 206201, 0, 1, 270, 650, 1, 0.5, 0, 0, 0, '【物理】中距離攻擊\\n會從一端削木並使其倒下的河狸。\\n削下的木片並不是要用來造房子，\\n而是為了保護家園而拿來投擲。');
insert into unit_enemy_data values (206300, '露娜聚光燈', 206300, 0, 0, 270, 1110, 0, 10.0, 0, 0, 0, '【恢復】單體ＴＰ恢復\\n與露娜之塔所建時一同打造出來的一種能量增幅器。\\n將散布各處的魔力濃縮，並做為強化供給於守護者。');
insert into unit_enemy_data values (206400, '小魔眼', 206400, 0, 0, 270, 100, 1, 2.5, 0, 0, 0, '【物理】近距離攻擊\\n侍奉獨眼族之王的小小侍從。\\n對於大王所給予的金光閃閃裝備特別的鍾愛。');
insert into unit_enemy_data values (206500, '擲岩猴老大', 206500, 0, 0, 300, 100, 1, 2.5, 0, 0, 0, '【物理】近距離攻擊\\n擲岩猴更加成長的姿態。從小就持續投擲大岩石\\n的一雙粗臂能持續造成強烈的打擊。');
insert into unit_enemy_data values (206700, '日和的闇影', 206700, 0, 1, 270, 200, 1, 2.295, 0, 0, 0, '有著日和樣貌的特殊魔物\\n\\n‧對面前的 1 名敵人造成大幅度的物理傷害，\\n\u3000並對附近小範圍內所有敵人造成\\n\u3000中幅度的物理傷害。\\n‧對面前的 1 名敵人造成中幅度的物理傷害。\\n‧對面前的 1 名敵人造成小幅度的物理傷害，\\n\u3000並中幅度提升自己的物理攻擊力。');
insert into unit_enemy_data values (206701, '怜（新年）的闇影', 206701, 0, 4, 270, 400, 1, 1.965, 0, 0, 0, '有著怜（新年）樣貌的特殊魔物\\n\\n‧對全體敵人造成中幅度的物理傷害，\\n\u3000並且使其暈眩。\\n‧【挑釁】對全體敵人挑釁。\\n\u3000若在挑釁後的動作中受到攻擊，\\n\u3000則對範圍內的所有敵人造成中幅度的物理傷害，\\n\u3000再小幅度降低其物理防禦力。\\n‧對自己周圍的全體夥伴\\n\u3000展開魔法無效的屏障，\\n\u3000並中幅度提升自己的魔法防禦力。');
insert into unit_enemy_data values (206702, '優衣（新年）的闇影', 206702, 0, 7, 270, 600, 2, 2.27, 0, 0, 0, '有著優衣（新年）樣貌的特殊魔物\\n\\n‧對全體夥伴展開物理/魔法無效的屏障，\\n\u3000並施加持續恢復 HP 的狀態，\\n\u3000但會大幅度降低自己的魔法攻擊力。\\n‧大幅度降低從前方算起第 2 位的 1 名敵人\\n\u3000的物理攻擊力和魔法攻擊力。\\n‧大幅度提升全體夥伴中魔法攻擊角色\\n\u3000的魔法攻擊力。');
insert into unit_enemy_data values (206800, '煩惱力場1', 206800, 0, 0, 20, 0, 0, 999.0, 0, 0, 0, '暫');
insert into unit_enemy_data values (206801, '煩惱力場2', 206801, 0, 0, 20, 0, 0, 999.0, 0, 0, 0, '暫');
insert into unit_enemy_data values (206802, '煩惱力場3', 206802, 0, 0, 20, 0, 0, 999.0, 0, 0, 0, '暫');
insert into unit_enemy_data values (206803, '持有定時炸彈', 206803, 0, 0, 0, 1080, 0, 0.0, 0, 0, 0, '暫');
insert into unit_enemy_data values (206804, '持有定時炸彈', 206803, 0, 0, 0, 1080, 0, 0.0, 0, 0, 0, '暫');
insert into unit_enemy_data values (206900, '沉睡之梟', 206900, 0, 0, 270, 645, 2, 3.5, 0, 0, 0, '【魔法】中距離攻擊\\n因為睡眠不足而倦怠的貓頭鷹魔物。\\n能死盯敵人施放法術來剝奪自由。');
insert into unit_enemy_data values (206901, '沉睡之梟', 206901, 0, 0, 270, 645, 2, 3.5, 0, 0, 0, '【魔法】中距離攻擊\\n因為睡眠不足而倦怠的貓頭鷹魔物。\\n能死盯敵人施放法術來剝奪自由。');
insert into unit_enemy_data values (207000, '小狸貓', 207000, 0, 0, 100, 120, 2, 0.5, 0, 0, 0, '【魔法】一定時間內無敵・\\n中距離攻擊\\n從小就能巧妙的使用變身，\\n拚了命貫徹攻防的豆狸魔物。');
insert into unit_enemy_data values (207001, '小狸貓', 207000, 0, 0, 100, 120, 2, 0.5, 0, 0, 0, '【魔法】一定時間內無敵・\\n中距離攻擊\\n從小就能巧妙的使用變身，\\n拚了命貫徹攻防的豆狸魔物。');
insert into unit_enemy_data values (207100, '殺人蜂', 207100, 0, 0, 270, 550, 1, 0.9, 0, 0, 0, '【物理】遠距離攻擊\\n能夠迅速察覺到擁有威脅的敵人，\\n並確實地鎖定射穿對方的蜂魔物。');
insert into unit_enemy_data values (207101, '殺人蜂', 207100, 0, 0, 270, 650, 1, 1.2, 0, 0, 0, '【物理】遠距離攻擊\\n能夠迅速察覺到擁有威脅的敵人，\\n並確實地鎖定射穿對方的蜂魔物。');
