insert into unit_enemy_data values (209800, '真陽（遊俠）的闇影', 209800, 0, 6, 450, 395, 1, 2.34, 0, 0, 0, '有著真陽（遊俠）樣貌的特殊魔物\\n\\n‧對面前的 1 名敵人造成特大幅度的物理傷害，\\n\u3000同時使其暈眩。\\n‧對面前的 1 名敵人造成小幅度的物理傷害，\\n\u3000並且小幅度擊飛。\\n‧對面前的 1 名敵人造成中幅度的物理傷害，\\n\u3000並且小幅度提升自己的物理攻擊力。');
insert into unit_enemy_data values (209900, '沙蟲', 209900, 0, 11, 270, 100, 1, 1.3, 0, 0, 0, '【物理】中距離攻擊\\n在沙地底下等待獵物，以大顎一口氣\\n將其斃命的蜈蚣魔物');
insert into unit_enemy_data values (210000, '女低音鷹鳥', 210000, 0, 11, 270, 200, 1, 2.0, 0, 0, 0, '【物理】近距離攻擊\\n發出美麗歌聲的妖鳥。\\n牠會在獵物疏於防守時，伸出利爪將其捕獲。');
insert into unit_enemy_data values (210001, '女低音鷹鳥', 210000, 0, 11, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】近距離攻擊\\n發出美麗歌聲的妖鳥。\\n牠會在獵物疏於防守時，伸出利爪將其捕獲。');
