insert into unit_enemy_data values (211001, '惠理子的闇影', 211001, 0, 3, 450, 260, 1, 1.425, 0, 0, 0, '有著惠理子樣貌的特殊魔物\\n\\n‧對面前的1名敵方角色造成特大幅度的物理\\n\u3000傷害，並且使用此技能打倒敵人時，\\n\u3000大幅度提升自身的物理攻擊力。\\n‧小幅度提升自身的物理攻擊力。\\n‧對面前的1名敵方角色造成中幅度的物理\\n\u3000傷害，並且使其陷入中毒狀態。');
insert into unit_enemy_data values (211101, '靜流的闇影', 211101, 0, 5, 450, 150, 1, 2.375, 0, 0, 0, '有著靜流樣貌的特殊魔物\\n\\n‧對面前的1名敵人角色造成大幅度的物理傷害，\\n\u3000並且對自身展開物理吸收的護盾。\\n‧中幅度恢復HP最低的1名我方角色的\\n\u3000HP。\\n‧對自身周圍的我方展開物理無效的\\n\u3000護盾。');
