insert into unit_enemy_data values (300100, '牛頭怪', 300100, 0, 3, 270, 1000, 1, 1.9, 0, 0, 0, '【物理】獲得了更多力量的金牛座之魔星獸。\\n超越了力量極限的戰斧一擊，能破壞所有的一切。\\n\\n‧必殺技會解除敵方全體的護盾，\\n\u3000並依照牛頭怪的物理攻擊力造成物理比例\\n\u3000傷害。\\n\u3000並且施加火傷狀態，中幅度降低TP。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧對魔法攻擊力最高的1名敵方角色造成大幅度的\\n\u3000物理傷害，並且在造成擊退後同時\\n\u3000暈眩。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧對前方的3名角色造成中幅度的魔法傷害，同時\\n\u3000使其麻痺。');
insert into unit_enemy_data values (300101, '牛頭怪', 300101, 0, 3, 270, 1000, 1, 1.9, 0, 0, 0, '【物理】獲得了更多力量的金牛座之魔星獸。\\n超越了力量極限的戰斧一擊，能破壞所有的一切。\\n\\n‧必殺技會解除敵方全體的護盾，\\n\u3000並依照牛頭怪的物理攻擊力造成物理比例\\n\u3000傷害。\\n\u3000並且施加火傷狀態，中幅度降低TP。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧對魔法攻擊力最高的1名敵方角色造成大幅度的\\n\u3000物理傷害，並且在造成擊退後同時\\n\u3000暈眩。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧對前方的3名角色造成中幅度的魔法傷害，同時\\n\u3000使其麻痺。\\n‧中幅度提升自身的物理攻擊力，大幅度提升\\n\u3000魔法攻擊力，同時對前方數來\\n\u3000第1、2名的角色造成大幅度的物理傷害。\\n\u3000在發動技能後，小幅度降低自身的物理防禦力，\\n\u3000中幅度降低魔法防禦力。');
insert into unit_enemy_data values (300102, '牛頭怪', 300102, 0, 3, 270, 1000, 1, 1.9, 0, 0, 0, '【物理】獲得了更多力量的金牛座之魔星獸。\\n超越了力量極限的戰斧一擊，能破壞所有的一切。\\n\\n‧必殺技會解除敵方全體的護盾，\\n\u3000並依照牛頭怪的物理攻擊力造成物理比例\\n\u3000傷害。\\n\u3000並且施加火傷狀態，中幅度降低TP。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧對魔法攻擊力最高的1名敵方角色造成大幅度的\\n\u3000物理傷害，並且在造成擊退後同時\\n\u3000暈眩。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧對前方的3名角色造成中幅度的魔法傷害，同時\\n\u3000使其麻痺。\\n‧中幅度提升自身的物理攻擊力，大幅度提升\\n\u3000魔法攻擊力，同時對前方數來\\n\u3000第1、2名的角色造成大幅度的物理傷害。\\n\u3000在發動技能後，小幅度降低自身的物理防禦力，\\n\u3000中幅度降低魔法防禦力。\\n‧展開戰鬥領域。\\n\\n【戰鬥場地效果】\\n使全領域被火焰籠罩，同時發動以下的\\n效果。\\n‧無視挑釁，將物理攻擊力或魔法攻擊力\\n\u3000其中一者最高的1名我方角色的物理\\n\u3000攻擊力與魔法攻擊力降為0。\\n‧特大幅度降低牛頭怪的物理防禦力與魔法\\n\u3000防禦力。');
insert into unit_enemy_data values (300200, '天蠍毒者', 300200, 0, 6, 270, 1000, 1, 1.5, 0, 0, 0, '揮舞猛毒之尾棘來降下災厄，天蠍座的魔星獸。\\n守護沙漠之蟲神，因信仰的流失而化為了邪神。\\n\\n・對敵方全體造成大量的物理傷害。\\n\u3000每當Boss使用了一次必殺技，\\n\u3000便會提升給予敵人的傷害。\\n\u3000此效果，最多累積上限為3次。\\n・對前方範圍內的敵人給予中量物理傷害，\\n\u3000並使其中毒。\\n・將自身所被施放的降低素質的效果解除，\\n\u3000並且再額外增加自身的物理防禦力。');
insert into unit_enemy_data values (300201, '天蠍毒者', 300201, 0, 6, 270, 1000, 1, 1.5, 0, 0, 0, '【物理】被徒留在失去信仰的神殿，天蠍座魔星獸。\\n過去那些虔誠的崇敬早已被遺忘，如今只剩下毀滅。\\n\\n‧戰鬥開始時，\\n\u3000小幅度提升自身的物理防禦力和魔法防禦力。\\n\u3000以此防禦力提升效果上升的防禦力\\n\u3000不會受到戰鬥中被施加的降低防禦力技能的\\n\u3000影響。\\n‧必殺技能夠對敵方全體造成\\n\u3000中幅度的物理傷害。\\n\u3000在使用過此技能之後，\\n\u3000每當進行了攻擊，天蠍毒者在接下來每次對該敵人所造成的傷害，\\n\u3000都將會有所提升。\\n\u3000此效果最多累積次數為 3 次。\\n\u3000此技能造成的傷害將不會\\n\u3000恢復TP。\\n‧以前方的 1 名角色為中心，造成小範圍的\\n\u3000中幅度物理傷害，並且使其中毒。\\n\u3000此技能施加的中毒狀態所造成的傷害\\n\u3000將不會恢復 TP 。\\n‧中幅度提升\\n\u3000自身的物理攻擊力、物理防禦力、魔法防禦力。');
insert into unit_enemy_data values (300202, '天蠍毒者', 300202, 0, 6, 270, 1000, 1, 1.5, 0, 0, 0, '【物理】被徒留在失去信仰的神殿，天蠍座魔星獸。\\n過去那些虔誠的崇敬早已被遺忘，如今只剩下毀滅。\\n\\n‧戰鬥開始時，\\n\u3000小幅度提升自身的物理防禦力和魔法防禦力。\\n\u3000以此防禦力提升效果上升的防禦力\\n\u3000不會受到戰鬥中被施加的降低防禦力技能的\\n\u3000影響。\\n‧必殺技能夠對敵方全體造成\\n\u3000中幅度的物理傷害。\\n\u3000在使用過此技能之後，\\n\u3000每當進行了攻擊，天蠍毒者在接下來每次對該敵人所造成的傷害，\\n\u3000都將會有所提升。\\n\u3000此效果最多累積次數為 3 次。\\n\u3000此技能造成的傷害將不會\\n\u3000恢復TP。\\n‧以前方的 1 名角色為中心，造成小範圍的\\n\u3000中幅度物理傷害，並且使其中毒。\\n\u3000此技能施加的中毒狀態所造成的傷害\\n\u3000將不會恢復 TP 。\\n‧中幅度提升\\n\u3000自身的物理攻擊力、物理防禦力、魔法防禦力。\\n‧召喚1隻天蠍守衛。\\n\u3000在進行召喚時，將會給予已經被召喚在場上的\\n\u3000天蠍守衛1秒的無敵狀態。\\n‧當第3隻的天蠍守衛被召喚出來時，將對\\n\u3000敵方全體依照其最大HP造成\\n\u3000魔法比例傷害，並使其暈眩。\\n\u3000此技能所造成的狀態異常，\\n\u3000即使傷害無效也會施加。\\n‧當天蠍守衛的HP低於一定數值時，\\n\u3000將會對天蠍毒者造成固定的魔法傷害，並且\\n\u3000中幅度降低祂的物理攻擊力，同時當場消失。');
insert into unit_enemy_data values (300203, '天蠍毒者', 300203, 0, 6, 270, 1000, 1, 1.5, 0, 0, 0, '【物理】被徒留在失去信仰的神殿，天蠍座魔星獸。\\n過去那些虔誠的崇敬早已被遺忘，如今只剩下毀滅。\\n\\n‧戰鬥開始時，\\n\u3000小幅度提升自身的物理防禦力和魔法防禦力。\\n\u3000以此防禦力提升效果上升的防禦力\\n\u3000不會受到戰鬥中被施加的降低防禦力技能的\\n\u3000影響。\\n‧必殺技能夠對敵方全體造成\\n\u3000中幅度的物理傷害。\\n\u3000在使用過此技能之後，\\n\u3000每當進行了攻擊，天蠍毒者在接下來每次對該敵人所造成的傷害，\\n\u3000都將會有所提升。\\n\u3000此效果最多累積次數為 3 次。\\n\u3000此技能造成的傷害將不會\\n\u3000恢復TP。\\n‧以前方的 1 名角色為中心，造成小範圍的\\n\u3000中幅度物理傷害，並且使其中毒。\\n\u3000此技能施加的中毒狀態所造成的傷害\\n\u3000將不會恢復 TP 。\\n‧中幅度提升\\n\u3000自身的物理攻擊力、物理防禦力、魔法防禦力。');
insert into unit_enemy_data values (300204, '天蠍毒者', 300204, 0, 6, 270, 1000, 1, 1.5, 0, 0, 0, '【物理】被徒留在失去信仰的神殿，天蠍座魔星獸。\\n過去那些虔誠的崇敬早已被遺忘，如今只剩下毀滅。\\n\\n‧戰鬥開始時，\\n\u3000小幅度提升自身的物理防禦力和魔法防禦力。\\n\u3000以此防禦力提升效果上升的防禦力\\n\u3000不會受到戰鬥中被施加的降低防禦力技能的\\n\u3000影響。\\n‧必殺技能夠對敵方全體造成\\n\u3000中幅度的物理傷害。\\n\u3000在使用過此技能之後，\\n\u3000每當進行了攻擊，天蠍毒者在接下來每次對該敵人所造成的傷害，\\n\u3000都將會有所提升。\\n\u3000此效果最多累積次數為 3 次。\\n\u3000此技能造成的傷害將不會\\n\u3000恢復TP。\\n‧以前方的 1 名角色為中心，造成小範圍的\\n\u3000中幅度物理傷害，並且使其中毒。\\n\u3000此技能施加的中毒狀態所造成的傷害\\n\u3000將不會恢復 TP 。\\n‧中幅度提升\\n\u3000自身的物理攻擊力、物理防禦力、魔法防禦力。\\n‧召喚1隻天蠍守衛。\\n\u3000在進行召喚時，將會給予已經被召喚在場上的\\n\u3000天蠍守衛1秒的無敵狀態。\\n‧當第3隻的天蠍守衛被召喚出來時，將對\\n\u3000敵方全體依照其最大HP造成\\n\u3000魔法比例傷害，並使其暈眩。\\n\u3000此技能所造成的狀態異常，\\n\u3000即使傷害無效也會施加。\\n‧當天蠍守衛的HP低於一定數值時，\\n\u3000將會對天蠍毒者造成固定的魔法傷害，並且\\n\u3000中幅度降低祂的物理攻擊力，同時當場消失。');
insert into unit_enemy_data values (300205, '天蠍毒者', 300205, 0, 6, 270, 1000, 1, 1.5, 0, 0, 0, '【物理】被徒留在失去信仰的神殿，天蠍座魔星獸。\\n過去那些虔誠的崇敬早已被遺忘，如今只剩下毀滅。\\n\\n‧戰鬥開始時，\\n\u3000小幅度提升自身的物理防禦力和魔法防禦力。\\n\u3000以此防禦力提升效果上升的防禦力\\n\u3000不會受到戰鬥中被施加的降低防禦力技能的\\n\u3000影響。\\n‧必殺技能夠對敵方全體造成\\n\u3000中幅度的物理傷害。\\n\u3000在使用過此技能之後，\\n\u3000每當進行了攻擊，天蠍毒者在接下來每次對該敵人所造成的傷害，\\n\u3000都將會有所提升。\\n\u3000此效果最多累積次數為 3 次。\\n\u3000此技能造成的傷害將不會\\n\u3000恢復TP。\\n‧以前方的 1 名角色為中心，造成小範圍的\\n\u3000中幅度物理傷害，並且使其中毒。\\n\u3000此技能施加的中毒狀態所造成的傷害\\n\u3000將不會恢復 TP 。\\n‧中幅度提升\\n\u3000自身的物理攻擊力、物理防禦力、魔法防禦力。\\n‧召喚1隻天蠍守衛。\\n\u3000在進行召喚時，將會給予已經被召喚在場上的\\n\u3000天蠍守衛1秒的無敵狀態。\\n‧當第3隻的天蠍守衛被召喚出來時，將對\\n\u3000敵方全體依照其最大HP造成\\n\u3000魔法比例傷害，並使其暈眩。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧天蠍守衛會對\\n\u3000敵方全體依照其最大HP造成\\n\u3000魔法比例傷害，並使其暈眩。\\n‧天蠍守衛中幅度提升天蠍毒者的\\n\u3000物理防禦力與魔法防禦力。\\n‧當天蠍守衛的HP低於一定數值時，\\n\u3000將會對天蠍毒者造成固定的魔法傷害，並且\\n\u3000中幅度降低祂的物理攻擊力，同時當場消失。');
insert into unit_enemy_data values (300206, '天蠍毒者', 300206, 0, 6, 270, 1000, 1, 1.5, 0, 0, 0, '【物理】被徒留在失去信仰的神殿，天蠍座魔星獸。\\n過去那些虔誠的崇敬早已被遺忘，如今只剩下毀滅。\\n\\n‧戰鬥開始時，\\n\u3000小幅度提升自身的物理防禦力和魔法防禦力。\\n\u3000以此防禦力提升效果上升的防禦力\\n\u3000不會受到戰鬥中被施加的降低防禦力技能的\\n\u3000影響。\\n‧必殺技能夠對敵方全體造成\\n\u3000中幅度的物理傷害。\\n\u3000在使用過此技能之後，\\n\u3000每當進行了攻擊，天蠍毒者在接下來每次對該敵人所造成的傷害，\\n\u3000都將會有所提升。\\n\u3000此效果最多累積次數為 3 次。\\n\u3000此技能造成的傷害將不會\\n\u3000恢復TP。\\n‧以前方的 1 名角色為中心，造成小範圍的\\n\u3000中幅度物理傷害，並且使其中毒。\\n\u3000此技能施加的中毒狀態所造成的傷害\\n\u3000將不會恢復 TP 。\\n‧中幅度提升\\n\u3000自身的物理攻擊力、物理防禦力、魔法防禦力。\\n‧召喚1隻天蠍守衛。\\n\u3000在進行召喚時，將會給予已經被召喚在場上的\\n\u3000天蠍守衛1秒的無敵狀態。\\n‧當第3隻的天蠍守衛被召喚出來時，將對\\n\u3000敵方全體依照其最大HP造成\\n\u3000魔法比例傷害，並使其暈眩。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧天蠍守衛會對\\n\u3000敵方全體依照其最大HP造成\\n\u3000魔法比例傷害，並使其暈眩。\\n‧天蠍守衛中幅度提升天蠍毒者的\\n\u3000物理防禦力與魔法防禦力。\\n‧當天蠍守衛的HP低於一定數值時，\\n\u3000將會對天蠍毒者造成固定的魔法傷害，並且\\n\u3000中幅度降低祂的物理攻擊力，同時當場消失。');
insert into unit_enemy_data values (300300, '梅莎路提姆', 300300, 0, 7, 270, 1000, 2, 2.5, 0, 0, 0, '【魔法】獲得了更多力量的牡羊座之魔星獸。\\n在鬱悶難耐的睡夢牢獄中，享盡冒險者們的魂魄。\\n\\n‧必殺技會對敵方全體依照其角色最大HP\\n\u3000造成魔法比例傷害。\\n\u3000對無法行動的敵人造成追加的魔法比例\\n\u3000傷害。\\n‧對前方範圍內的敵人造成中幅度的魔法傷害。\\n‧對剩餘HP最低的1名角色造成束縛狀態。');
insert into unit_enemy_data values (300301, '梅莎路提姆', 300301, 0, 7, 270, 1000, 2, 2.5, 0, 0, 0, '【魔法】獲得了更多力量的牡羊座之魔星獸。\\n在鬱悶難耐的睡夢牢獄中，享盡冒險者們的魂魄。\\n\\n‧必殺技會對敵方全體依照其角色最大HP\\n\u3000造成魔法比例傷害。\\n\u3000對無法行動的敵人造成追加的魔法比例\\n\u3000傷害。\\n‧對前方範圍內的敵人造成中幅度的魔法傷害。\\n‧對剩餘HP最低的1名角色造成束縛狀態。\\n‧對敵方全體造成小幅度的魔法傷害。\\n\u3000當角色的HP低於70%時，造成\\n\u3000束縛狀態。');
insert into unit_enemy_data values (300302, '梅莎路提姆', 300302, 0, 7, 270, 1000, 2, 2.5, 0, 0, 0, '【魔法】獲得了更多力量的牡羊座之魔星獸。\\n在鬱悶難耐的睡夢牢獄中，享盡冒險者們的魂魄。\\n\\n‧必殺技會對敵方全體依照其角色最大HP\\n\u3000造成魔法比例傷害。\\n\u3000對無法行動的敵人造成追加的魔法比例\\n\u3000傷害，並且大幅度降低TP。\\n‧對前方範圍內的敵人造成中幅度的魔法傷害。\\n‧對剩餘HP最低的1名角色造成束縛狀態。\\n‧對敵方全體造成小幅度的魔法傷害。\\n\u3000當角色的HP低於70%時，造成\\n\u3000束縛狀態。\\n‧對魔法攻擊力最高的2名角色造成束縛狀態，\\n\u3000小幅度降低自身的物理防禦力與魔法防禦力。');
insert into unit_enemy_data values (300400, '阿爾珈提', 300400, 0, 7, 270, 1000, 2, 1.8, 0, 0, 0, '以妖異的邪教圖謀支配世界，魔羯座的魔星獸。\\n對在沙漠受誘惑而迷途的人，以惡魔的儀式進行俘虜。\\n\\n‧必殺技對可全體敵人造成大幅度的魔法傷害，\\n\u3000並且降低物理攻擊角色的物理攻擊力，\\n\u3000與降低魔法攻擊角色的魔法防禦力。\\n‧對物理攻擊力最高的 1 名角色造成\\n\u3000特大幅度的魔法傷害，並降低其 TP。\\n‧對前方的 2 名角色造成小幅度的魔法傷害，\\n\u3000並且施加沉默狀態。\\n\\n‧再對全體敵人造成中幅度的魔法傷害。');
insert into unit_enemy_data values (300401, '阿爾珈提', 300401, 0, 7, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】窮極了邪教的秘術，摩羯座的魔星獸。\\n能隨心所欲地操弄龐大魔力，進而剝奪萬物的自由。\\n\\n‧必殺技可對敵方全體依照其角色最大HP\\n\u3000造成魔法的比例傷害。\\n\u3000並且大幅度降低物理攻擊角色的物理攻擊力，\\n\u3000同時大幅度降低魔法攻擊角色的魔法攻擊力。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧對前方的 1 名角色造成大幅度的魔法傷害，\\n\u3000並且使其沉默。\\n\u3000同時對敵方全體造成中幅度的魔法傷害。\\n‧對物理攻擊力最高的 1 名角色造成\\n\u3000大幅度的魔法傷害，並中幅度降低其 TP。');
insert into unit_enemy_data values (300402, '阿爾珈提', 300402, 0, 7, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】窮極了邪教的秘術，摩羯座的魔星獸。\\n能隨心所欲地操弄龐大魔力，進而剝奪萬物的自由。\\n\\n‧必殺技可對敵方全體依照其角色最大HP\\n\u3000造成魔法的比例傷害。\\n\u3000並且大幅度降低物理攻擊角色的物理攻擊力，\\n\u3000同時大幅度降低魔法攻擊角色的魔法攻擊力。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧對前方的 1 名角色造成大幅度的魔法傷害，\\n\u3000並且使其沉默。\\n\u3000同時對敵方全體造成中幅度的魔法傷害。\\n‧對物理攻擊力最高的 1 名角色造成\\n\u3000大幅度的魔法傷害，並中幅度降低其 TP。\\n‧對敵方全體造成大幅度的魔法傷害。\\n\u3000當角色的HP低於80％時，\\n\u3000使其沉默。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。');
insert into unit_enemy_data values (300403, '阿爾珈提', 300403, 0, 7, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】窮極了邪教的秘術，摩羯座的魔星獸。\\n能隨心所欲地操弄龐大魔力，進而剝奪萬物的自由。\\n\\n‧必殺技可對全體敵人造成大幅度的魔法傷害，\\n\u3000並且降低物理攻擊角色的物理攻擊力，\\n\u3000同時降低魔法攻擊角色的魔法攻擊力。\\n‧對前方的 1 名角色造成特大幅度的魔法傷害，\\n\u3000並且使其沉默。\\n\u3000同時對全體敵人造成中幅度的魔法傷害。\\n‧對物理攻擊力最高的 1 名角色造成\\n\u3000大幅度的魔法傷害，並降低其 TP。\\n‧當阿爾珈提受到中毒、猛毒、詛咒、火傷\\n\u3000等等效果時，將會對自己施加沉默狀態，\\n\u3000同時造成大幅度的魔法傷害。\\n\u3000當沒有受到以上效果時，將會對\\n\u3000全體敵人造成沉默狀態，\\n\u3000並且同時造成大幅度的魔法傷害。');
insert into unit_enemy_data values (300404, '阿爾珈提', 300404, 0, 7, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】窮極了邪教的秘術，摩羯座的魔星獸。\\n能隨心所欲地操弄龐大魔力，進而剝奪萬物的自由。\\n\\n‧必殺技可對敵方全體依照其角色最大HP\\n\u3000造成魔法的比例傷害。\\n\u3000並且大幅度降低物理攻擊角色的物理攻擊力，\\n\u3000同時大幅度降低魔法攻擊角色的魔法攻擊力。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧對前方的 1 名角色造成大幅度的魔法傷害，\\n\u3000並且使其沉默。\\n\u3000同時對敵方全體造成中幅度的魔法傷害。\\n‧對物理攻擊力最高的 1 名角色造成\\n\u3000大幅度的魔法傷害，並中幅度降低其 TP。\\n‧對敵方全體造成大幅度的魔法傷害。\\n\u3000當角色的HP低於80％時，\\n\u3000使其沉默，並且解除能力提升效果。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。');
insert into unit_enemy_data values (300500, '蜥蜴人', 300500, 0, 4, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】能自在地揮舞\\n手中的兩把劍刃，\\n還可以使用煙霧彈來模糊\\n對手視野的巨蜥戰士。\\n\\n‧對隨機 1 名敵人造成中幅度的物理傷害。\\n\\n‧對以隨機敵人為中心的小範圍內，\\n\u3000造成小幅度的物理傷害，\\n\u3000並且施加黑暗狀態。');
insert into unit_enemy_data values (300600, '爬行者', 300600, 0, 2, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】能從頭部施放劇毒\\n與藤蔓所組成的範圍物理攻擊，\\n能將貿然接近的冒險家的 HP \\n給一口氣奪走的魔性之花。\\n\\n‧對前方的 2 名角色造成中幅度的物理傷害。\\n\\n‧對前方的 3 名角色降低其物理防禦力，\\n\u3000並且施加中毒狀態。');
insert into unit_enemy_data values (300601, '芒刺爬行者', 300601, 0, 2, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】因奇異的力量而變質的爬行者。\\n以帶有許多刺的藤蔓綑綁，限制敵人的行動。\\n\\n・對前方範圍內的敵人造成中幅度的物理傷害，\\n並使其呈現麻痺狀態。\\n・對前方範圍內的敵人造成物理防禦力下降，\\n並使其呈現中毒狀態。');
insert into unit_enemy_data values (300602, '芒刺爬行者', 300602, 0, 2, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】被特異之力影響而產生變質的爬行者。\\n以擁有著無數針刺的藤蔓纏繞敵人，遏止行動。\\n\\n‧必殺技可對前方的2名角色造成\\n\u3000中幅度的物理傷害，並且使其陷入拘束狀態。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧中幅度降低前方3名角色的物理防禦力，\\n\u3000並且使其陷入中毒狀態。\\n\u3000此技能施加的中毒狀態所造成的傷害\\n\u3000將不會恢復TP。');
insert into unit_enemy_data values (300603, '芒刺爬行者', 300603, 0, 2, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】被特異之力影響而產生變質的爬行者。\\n以擁有著無數針刺的藤蔓纏繞敵人，遏止行動。\\n\\n‧必殺技可對前方的2名角色造成\\n\u3000中幅度的物理傷害，並且使其陷入拘束狀態。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧中幅度降低前方3名角色的物理防禦力，\\n\u3000並且使其陷入中毒狀態。\\n\u3000此技能施加的中毒狀態所造成的傷害\\n\u3000將不會恢復TP。');
insert into unit_enemy_data values (300604, '沙之爬行者', 300604, 0, 2, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】棲息於廣闊砂海的\\n巨大食人植物魔物。以帶有凶惡針刺的藤蔓\\n封鎖冒險者的行動並捕食。\\n\\n‧必殺技會對前方的2名角色\\n\u3000造成中幅度的物理傷害，\\n\u3000並且使其陷入拘束狀態。\\n\\n‧降低前方3名角色的物理防禦力，\\n\u3000並且使其陷入中毒狀態。');
insert into unit_enemy_data values (300700, '獸人領導者', 300700, 0, 13, 270, 1000, 1, 1.5, 0, 0, 0, '【物理】以族長的姿態鼓舞著群體，\\n以能震裂大地般的強力連擊\\n造成敵人大幅度的物理傷害，\\n是半獸人中的半獸人。\\n\\n‧對隨機3名敵人造成\\n\u3000中幅度的物理傷害。\\n\\n‧提升全體夥伴的物理攻擊力。');
insert into unit_enemy_data values (300701, '獸人酋長', 300701, 0, 13, 270, 1000, 1, 1.5, 0, 0, 0, '【物理】因奇異的力量而變質的獸人領導者。\\n手持巨大盾牌，能揮出攻防一體的連擊。\\n\\n‧必殺技能夠對前方 3 名角色造成\\n\u3000大幅度的物理傷害，並使其暈眩。\\n‧大幅度降低前方 2 名角色的物理防禦力。');
insert into unit_enemy_data values (300702, '獸人酋長', 300702, 0, 13, 270, 1000, 1, 1.5, 0, 0, 0, '【物理】因奇異的力量而變質的獸人領導者。\\n手持巨大盾牌，能揮出攻防一體的連擊。\\n\\n‧必殺技能夠對前方 3 名角色造成\\n\u3000大幅度的物理傷害，並使其暈眩。\\n‧大幅度降低前方 2 名角色的物理防禦力，\\n\u3000且中幅度降低其 TP 。');
insert into unit_enemy_data values (300800, '角鹿長老', 300800, 0, 1, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】一旦開始狂怒地踐踏震地，\\n便無法控制，聽說那嘶吼\\n甚至能響徹天際，\\n是傳說中的狂野角鹿。\\n\\n‧對全體敵人造成中幅度物理傷害，\\n\u3000同時以小距離拉近。\\n\\n‧對前方的3名角色造成中幅度的\\n\u3000物理傷害，並降低其物理攻擊力\\n\u3000與物理防禦力。');
insert into unit_enemy_data values (300801, '聖靈角鹿', 300801, 0, 1, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】因奇異的力量而變質的角鹿長老。\\n其角富有魔力，\\n可放出大於打擊之力的強力一擊。\\n\\n‧對前方的3名角色造成大幅度的魔法傷害，\\n\u3000並在擊退敵方的同時使其暈眩。\\n‧對前方的3名角色造成小幅度的魔法傷害，\\n\u3000同時大幅度降低魔法防禦力與行動速度。');
insert into unit_enemy_data values (300802, '聖靈角鹿', 300802, 0, 1, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】因奇異的力量而變質的角鹿長老。\\n其角富有魔力，\\n可放出大於打擊之力的強力一擊。\\n\\n‧對前方的3名角色造成大幅度的魔法傷害，\\n\u3000並在擊退敵方的同時使其暈眩。\\n\u3000同時在自己身上展開物理/魔法無效的屏障。\\n‧對前方的3名角色造成小幅度的魔法傷害，\\n\u3000同時大幅度降低魔法防禦力與行動速度。');
insert into unit_enemy_data values (300900, '暴君長老', 300900, 0, 13, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】進化成了如同岩山一般的巨大老龜。\\n那強而有力的頭槌，就連大地都能輕易撕裂。\\n\\n‧必殺技能對前方範圍內造成物理傷害，\\n\u3000同時使目標陷入麻痺狀態。\\n‧降低前方3名角色的物理防禦力。');
insert into unit_enemy_data values (301000, '希德雷克', 301000, 0, 14, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】吐出強力的寒氣\\n將前衛瞬間冰凍，\\n接著將身軀一口咬碎的\\n凶猛深海龍。\\n\\n‧對前方的 3 名角色造成中幅度的物理傷害。\\n\\n‧對前方的 2 名角色造成中幅度的物理傷害，\\n\u3000並且施加凍結狀態。');
insert into unit_enemy_data values (301001, '希德雷克', 301001, 0, 14, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】是能吐出強力的寒氣將前衛瞬間凍結，\\n並且再一口將對方的身軀咬碎的凶猛深海龍。\\n\\n‧對前方3名角色造成中幅度的物理傷害。\\n‧對前方1名角色造成中幅度的物理傷害，\\n\u3000並且使其陷入凍結狀態。');
insert into unit_enemy_data values (301002, '希德雷克', 301002, 0, 14, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】是能吐出強力的寒氣將前衛瞬間凍結，\\n並且再一口將對方的身軀咬碎的凶猛深海龍。\\n\\n‧對前方3名角色造成中幅度的物理傷害。\\n‧對前方2名角色造成中幅度的物理傷害，\\n\u3000並且使其陷入凍結狀態。');
insert into unit_enemy_data values (301100, '殘暴狂熊', 301100, 0, 13, 270, 1000, 1, 1.7, 0, 0, 0, '【物理】以不符合體格的靈敏度\\n以及撕咬攻擊奪取體力，\\n並以巨大的爪子撕裂敵人，\\n是慘無人道的森林支配者。\\n\\n‧對前方的 4 名角色造成大幅度的\\n\u3000物理傷害。\\n\\n‧對前方的 1 名角色造成小幅度的\\n\u3000物理傷害，並降低其物理攻擊力。');
insert into unit_enemy_data values (301101, '狂焰戰熊', 301101, 0, 13, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】因奇異的力量而變質的殘暴狂熊。\\n以嗔怒之巨拳，將敵人連同地面一塊撕裂粉碎。\\n\\n・對前方的3名角色造成大幅度的物理傷害，並且\\n\u3000使其暈眩。\\n‧以前方的第1名敵人為中心，對小範圍內\\n\u3000最多3名角色造成大幅度物理傷害，同時特大幅度\\n\u3000降低物理攻擊力，大幅度降低魔法攻擊力。');
insert into unit_enemy_data values (301102, '狂焰戰熊', 301102, 0, 13, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】因奇異的力量而變質的殘暴狂熊。\\n以嗔怒之巨拳，將敵人連同地面一塊撕裂粉碎。\\n\\n・對前方的3名角色造成大幅度的物理傷害，並且\\n\u3000使其暈眩。\\n‧以前方的第1名敵人為中心，對小範圍內\\n\u3000最多3名角色造成大幅度物理傷害，同時特大幅度\\n\u3000降低物理攻擊力，大幅度降低魔法攻擊力。');
insert into unit_enemy_data values (301200, '碎裂魔像', 301200, 0, 13, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】能無止盡地召喚出魔像，\\n並以尖銳岩石削弱其體力與精神。\\n用魔力將無數的魔像殘骸\\n重塑而成的巨大魔像。\\n\\n‧對前方的4名角色造成中幅度物理傷害，\\n\u3000並減少其 TP。\\n\\n‧召喚魔像。');
insert into unit_enemy_data values (301201, '水晶魔像', 301201, 0, 13, 270, 1000, 1, 1.3, 0, 0, 0, '【物理】被露娜的魔力結晶覆蓋著全身的巨大魔像。\\n纏繞其身的結晶為堅若磐石之盾，亦是無所不穿之矛。\\n・當水晶魔像受到中毒、猛毒、詛咒、火傷等效果時，\\n\u3000行動速度將會大幅度的降低。\\n・將自身的減益效果全部解除，同時能\\n\u3000大幅度提升物理防禦力與魔法防禦力。\\n\u3000並且，還能使自身以外的夥伴們，中幅度\\n\u3000提升物理防禦力與魔法防禦力。\\n・對全體敵人造成中幅度的物理傷害，並且造成暈眩。\\n・對前方範圍內的敵人造成大幅度的物理傷害，\\n\u3000同時小幅度提升全體夥伴的物理攻擊力\\n\u3000與魔法攻擊力。\\n\u3000並且同時中幅度恢復自身的 TP 。');
insert into unit_enemy_data values (301202, '寒冰魔像', 301202, 0, 13, 270, 1000, 1, 1.3, 0, 0, 0, '【物理】潛伏在冰凍大地的洞窟中的\\n巨大魔像。身上圍繞的\\n結晶既是堅固的盾也是矛。\\n\\n‧當寒冰魔像受到中毒、猛毒、詛咒\\n\u3000火傷等效果時，將會\\n\u3000大幅度降低行動速度。\\n\\n‧解除所有自身的減益效果，\\n\u3000中幅度提升物理防禦力與\\n\u3000魔法防禦力。\\n\\n‧對敵方全體造成中幅度的\\n\u3000物理傷害。\\n\\n‧對前方範圍內的敵人造成大幅度的\\n\u3000物理傷害。');
insert into unit_enemy_data values (301203, '寒冰魔像', 301202, 0, 13, 270, 1000, 1, 1.3, 0, 0, 0, '【物理】潛伏在冰凍大地的洞窟中的\\n巨大魔像。身上圍繞的\\n結晶既是堅固的盾也是矛。\\n\\n‧當寒冰魔像受到中毒、猛毒、詛咒\\n\u3000火傷等效果時，將會\\n\u3000大幅度降低行動速度。\\n\\n‧解除所有自身的減益效果，\\n\u3000中幅度提升物理防禦力與\\n\u3000魔法防禦力。\\n\\n‧對敵方全體造成中幅度的\\n\u3000物理傷害。\\n\\n‧對前方範圍內的敵人造成大幅度的\\n\u3000物理傷害。');
insert into unit_enemy_data values (301300, '大胃王', 301300, 0, 4, 270, 1000, 1, 3.0, 0, 0, 0, '惡名昭彰的暴食之兇獸，是為天秤座的魔星獸。\\n秤量被剝奪之魂的善惡，以品嘗之間差異為樂。\\n\\n・不具有對敵人的攻擊所造成的麻痺、暈眩、\\n\u3000束縛，以及行動速度低下的抗性。\\n・對敵方全體造成大量的魔法傷害，並且對自\\n\u3000身的物理與魔法攻擊力給予特大量上升。\\n・對後方範圍內的敵人造成中量的魔法傷害。\\n・對前方範圍內的敵人造成中量的魔法傷害，並\\n\u3000小幅度降低TP。\u3000並且使自身的TP，中幅度\\n\u3000上升。');
insert into unit_enemy_data values (301301, '大胃王', 301301, 0, 4, 270, 1000, 1, 3.0, 0, 0, 0, '【物理】貪圖著萬物的三魂七魄，天秤座的魔星獸。\\n那天秤，與公正背道而馳地傾向了那暴食獸的食慾。\\n\\n‧戰鬥開始時，\\n\u3000小幅度提升自身的物理防禦力和魔法防禦力。\\n\u3000以此防禦力提升效果上升的防禦力\\n\u3000不會受到戰鬥中被施加的降低防禦力技能的\\n\u3000影響。\\n‧必殺技能夠對敵方全體造成大幅度的魔法傷害，\\n\u3000同時大幅度提升自己的物理攻擊力與\\n\u3000魔法攻擊力。\\n\u3000此技能造成的傷害將不會\\n\u3000恢復TP。\\n‧對後方的2名角色造成中幅度的魔法傷害。\\n‧對前方的3名角色造成小幅度的魔法傷害，並且\\n\u3000小幅度降低其TP。\\n\u3000同時中幅度提升自身的TP。\\n‧當左側的目標被破壞時，將會\\n\u3000大幅度降低物理防禦力與魔法防禦力。\\n‧當中央的目標被破壞時，將會\\n\u3000特大幅度降低魔法攻擊力。\\n‧當右側的目標被破壞時，將會\\n\u3000大幅度降低物理防禦力與魔法防禦力。');
insert into unit_enemy_data values (301302, '大胃王', 301302, 0, 4, 270, 1000, 1, 3.0, 0, 0, 0, '【物理】貪圖著萬物的三魂七魄，天秤座的魔星獸。\\n那天秤，與公正背道而馳地傾向了那暴食獸的食慾。\\n\\n‧戰鬥開始時，\\n\u3000小幅度提升自身的物理防禦力和魔法防禦力。\\n\u3000以此防禦力提升效果上升的防禦力\\n\u3000不會受到戰鬥中被施加的降低防禦力技能的\\n\u3000影響。\\n‧必殺技能夠對敵方全體造成大幅度的魔法傷害，\\n\u3000同時大幅度提升自身的物理攻擊力與\\n\u3000魔法攻擊力。\\n\u3000此技能造成的傷害將不會\\n\u3000恢復TP。\\n‧對後方的2名角色造成中幅度的魔法傷害。\\n‧對前方的3名角色造成小幅度的魔法傷害，並且\\n\u3000小幅度降低其TP。\\n\u3000同時中幅度提升自身的TP。\\n‧使前方的3名角色陷入束縛狀態，\\n\u3000並且造成大幅度的魔法傷害。\\n\u3000當自己的目標被破壞時，將會特大幅度提升\\n\u3000自身的魔法攻擊力。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧當左側的目標被破壞時，將會\\n\u3000大幅度降低物理防禦力與魔法防禦力。\\n‧當中央的目標被破壞時，將會\\n\u3000特大幅度降低魔法攻擊力。\\n‧當右側的目標被破壞時，將會\\n\u3000大幅度降低物理防禦力與魔法防禦力。');
insert into unit_enemy_data values (301303, '大胃王', 301303, 0, 4, 270, 1000, 1, 3.0, 0, 0, 0, '【物理】貪圖著萬物的三魂七魄，天秤座的魔星獸。\\n那天秤，與公正背道而馳地傾向了那暴食獸的食慾。\\n\\n‧戰鬥開始時，\\n\u3000小幅度提升自身的物理防禦力和魔法防禦力。\\n\u3000以此防禦力提升效果上升的防禦力\\n\u3000不會受到戰鬥中被施加的降低防禦力技能的\\n\u3000影響。\\n‧必殺技能夠對敵方全體造成大幅度的魔法傷害，\\n\u3000同時大幅度提升自己的物理攻擊力與\\n\u3000魔法攻擊力。\\n\u3000此技能造成的傷害將不會\\n\u3000恢復TP。\\n‧對後方的2名角色造成中幅度的魔法傷害。\\n‧對前方的3名角色造成小幅度的魔法傷害，並且\\n\u3000小幅度降低其TP。\\n\u3000同時中幅度提升自身的TP。\\n‧當左側的目標被破壞時，將會\\n\u3000大幅度降低物理防禦力與魔法防禦力。\\n‧當中央的目標被破壞時，將會\\n\u3000特大幅度降低魔法攻擊力。\\n‧當右側的目標被破壞時，將會\\n\u3000大幅度降低物理防禦力與魔法防禦力。');
insert into unit_enemy_data values (301304, '大胃王', 301304, 0, 4, 270, 1000, 1, 3.0, 0, 0, 0, '【物理】貪圖著萬物的三魂七魄，天秤座的魔星獸。\\n那天秤，與公正背道而馳地傾向了那暴食獸的食慾。\\n\\n‧戰鬥開始時，\\n\u3000小幅度提升自身的物理防禦力和魔法防禦力。\\n\u3000以此防禦力提升效果上升的防禦力\\n\u3000不會受到戰鬥中被施加的降低防禦力技能的\\n\u3000影響。\\n‧必殺技能夠對敵方全體造成大幅度的魔法傷害，\\n\u3000同時大幅度提升自身的物理攻擊力與\\n\u3000魔法攻擊力。\\n\u3000此技能造成的傷害將不會\\n\u3000恢復TP。\\n‧對後方的2名角色造成中幅度的魔法傷害。\\n‧對前方的3名角色造成小幅度的魔法傷害，並且\\n\u3000小幅度降低其TP。\\n\u3000同時中幅度提升自身的TP。\\n‧使前方的3名角色陷入束縛狀態，\\n\u3000並且造成大幅度的魔法傷害。\\n\u3000當自己的目標被破壞時，將會特大幅度提升\\n\u3000自身的魔法攻擊力。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧當左側的目標被破壞時，將會\\n\u3000大幅度降低物理防禦力與魔法防禦力。\\n‧當中央的目標被破壞時，將會\\n\u3000特大幅度降低魔法攻擊力。\\n‧當右側的目標被破壞時，將會\\n\u3000大幅度降低物理防禦力與魔法防禦力。');
insert into unit_enemy_data values (301305, '大胃王', 301305, 0, 4, 270, 1000, 1, 3.0, 0, 0, 0, '【物理】貪圖著萬物的三魂七魄，天秤座的魔星獸。\\n那天秤，與公正背道而馳地傾向了那暴食獸的食慾。\\n\\n‧戰鬥開始時，\\n\u3000小幅度提升自身的物理防禦力和魔法防禦力。\\n\u3000以此防禦力提升效果上升的防禦力\\n\u3000不會受到戰鬥中被施加的降低防禦力技能的\\n\u3000影響。\\n‧必殺技能夠對敵方全體造成大幅度的魔法傷害，\\n\u3000同時大幅度提升自身的物理攻擊力與\\n\u3000魔法攻擊力。\\n\u3000此技能造成的傷害將不會\\n\u3000恢復TP。\\n‧對後方的2名角色造成中幅度的魔法傷害。\\n‧對前方的3名角色造成小幅度的魔法傷害，並且\\n\u3000小幅度降低其TP。\\n\u3000同時中幅度提升自身的TP。\\n‧使前方的3名角色陷入束縛狀態，\\n\u3000並且造成大幅度的魔法傷害。\\n\u3000當自己的目標被破壞時，將會特大幅度提升\\n\u3000自己的魔法攻擊力。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧對敵方全體每秒造成小幅度的魔法傷害。\\n\u3000當自己的目標沒有陷入破壞時，\\n\u3000每秒小幅度降低敵方全體的TP。\\n\u3000此技能造成的傷害將不會\\n\u3000恢復TP。\\n‧當左側的目標被破壞時，將會\\n\u3000大幅度降低物理防禦力與魔法防禦力。\\n‧當中央的目標被破壞時，將會\\n\u3000特大幅度降低魔法攻擊力。\\n‧當右側的目標被破壞時，將會\\n\u3000大幅度降低物理防禦力與魔法防禦力。');
insert into unit_enemy_data values (301400, '美杜莎', 301400, 0, 3, 270, 1000, 1, 2.5, 0, 0, 0, '以無數毒蛇組成的長髮，是為處女座的魔星獸。\\n悲戀之痛，使祂拒萬物於千里且使其幻化成石。\\n\\n・對敵方全體造成大量魔法傷害，並使前方範圍\\n\u3000內的敵人陷入石化狀態。\\n・對前方範圍內的敵人造成物理傷害，\\n\u3000並再對陷入石化狀態的敵人，降低大量的TP。\\n・對物理攻擊力最高的1名敵方角色，造成大量\\n\u3000魔法傷害，使其陷入中毒狀態。');
insert into unit_enemy_data values (301401, '美杜莎', 301401, 0, 3, 270, 1000, 1, 2.5, 0, 0, 0, '【物理】因無盡的愛恨情仇而發狂的處女座魔星獸\\n以不可理喻的妒忌與拒絕，\\n將所見之物全化為石像。\\n\\n‧必殺技能夠對全體敵人依照其最大HP\\n\u3000造成魔法的比例傷害，\\n\u3000再對前方範圍內的全體敵人施加石化狀態。\\n\u3000此技能所造成的狀態異常，\\n\u3000即使傷害無效也會施加。\\n‧對前方範圍內的敵人造成大幅度的物理傷害\\n\u3000且對無法行動的敵人大幅度降低其TP。\\n‧以從後方數來第2名角色為中心，\\n\u3000造成小範圍的小幅度魔法傷害，\\n\u3000並且使其中毒。\\n\u3000此技能施加的中毒狀態所造成的傷害\\n\u3000將不會回復TP。');
insert into unit_enemy_data values (301402, '美杜莎', 301402, 0, 3, 270, 1000, 1, 2.5, 0, 0, 0, '【物理】因無盡的愛恨情仇而發狂的處女座魔星獸\\n以不可理喻的妒忌與拒絕，\\n將所見之物全化為石像。\\n\\n‧必殺技能夠對敵方全體依照其最大HP\\n\u3000造成魔法的比例傷害，\\n\u3000再對前方範圍內的敵方全體施加石化狀態。\\n\u3000此技能所造成的狀態異常，\\n\u3000即使傷害無效也會施加。\\n‧對前方範圍內的敵人造成大幅度的物理傷害，\\n\u3000且對無法行動的敵人大幅度降低其TP。\\n‧以從後方數來第2名角色為中心，\\n\u3000造成小範圍的小幅度的魔法傷害，\\n\u3000並且使其中毒。\\n\u3000此技能施加的中毒狀態所造成的傷害\\n\u3000將不會恢復TP。\\n‧以從後方數來第2名角色為中心，\\n\u3000對小範圍造成小幅度的魔法傷害。\\n\u3000當該角色的HP未滿60%時，\\n\u3000施加石化狀態。');
insert into unit_enemy_data values (301403, '美杜莎', 301403, 0, 3, 270, 1000, 1, 2.5, 0, 0, 0, '【物理】因無盡的愛恨情仇而發狂的處女座魔星獸\\n以不可理喻的妒忌與拒絕，\\n將所見之物全化為石像。\\n\\n‧必殺技能夠對敵方全體依照其最大HP\\n\u3000造成魔法的比例傷害，\\n\u3000再對前方範圍內的敵方全體施加石化狀態。\\n\u3000此技能所造成的狀態異常，\\n\u3000即使傷害無效也會施加。\\n‧對前方範圍內的敵人造成大幅度的物理傷害，\\n\u3000且對無法行動的敵人大幅度降低其TP。\\n‧以從後方數來第2名角色為中心，\\n\u3000造成小範圍的小幅度的魔法傷害，\\n\u3000並且使其中毒。\\n\u3000此技能施加的中毒狀態所造成的傷害\\n\u3000將不會恢復TP。\\n‧以從後方數來第2名角色為中心，\\n\u3000造成小範圍的小幅度魔法傷害。\\n\u3000當該角色的HP未滿60％時，\\n\u3000施加石化狀態。\\n‧召喚1隻僕從，\\n\u3000並中幅度降低自身的物理防禦力，\\n\u3000小幅度降低魔法防禦力。\\n‧僕從會對前方的1名角色造\\n\u3000成中幅度的物理傷害，\\n\u3000並施加石化狀態。\\n‧僕從會小幅度拉近敵方全體。\\n‧當僕從的HP低於一定數值時，\\n\u3000將會對美杜莎造成固定的物理傷害。');
insert into unit_enemy_data values (301404, '美杜莎', 301404, 0, 3, 270, 1000, 1, 2.5, 0, 0, 0, '【物理】因無盡的愛恨情仇而發狂的處女座魔星獸\\n以不可理喻的妒忌與拒絕，\\n將所見之物全化為石像。\\n\\n‧必殺技能夠對敵方全體依照其最大HP\\n\u3000造成魔法的比例傷害，\\n\u3000再對前方範圍內的敵方全體施加石化狀態。\\n\u3000此技能所造成的狀態異常，\\n\u3000即使傷害無效也會施加。\\n‧對前方範圍內的敵人造成大幅度的物理傷害，\\n\u3000且對無法行動的敵人大幅度降低其TP。\\n‧以從後方數來第2名角色為中心，\\n\u3000造成小範圍的小幅度的魔法傷害，\\n\u3000並且使其中毒。\\n\u3000此技能施加的中毒狀態所造成的傷害\\n\u3000將不會恢復TP。\\n‧以從後方數來第2名角色為中心，\\n\u3000造成小範圍的小幅度魔法傷害。\\n\u3000當該角色的HP未滿60％時，\\n\u3000施加石化狀態。\\n‧召喚1隻僕從，\\n\u3000並中幅度降低自身的物理防禦力，\\n\u3000小幅度降低魔法防禦力。\\n‧僕從會對前方的1名角色造\\n\u3000成中幅度的物理傷害，\\n\u3000並施加石化狀態。\\n‧僕從會小幅度拉近敵方全體。\\n‧當僕從的HP低於一定數值時，\\n\u3000將會對美杜莎造成固定的物理傷害。');
insert into unit_enemy_data values (301500, '狂戰之狼', 301500, 0, 12, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】以嚎叫使獵物麻痺，\\n再趁其膽怯時用爪子撕裂。\\n止住無數冒險家的腳步，\\n是極度殘虐的魔界之狼。\\n\\n‧對隨機的 2 名角色造成大幅度的物理傷害。\\n\\n‧對前方的 3 名角色造成小幅度的魔法傷害，\\n\u3000並且施加麻痺狀態。');
insert into unit_enemy_data values (301501, '狂戰之狼', 301501, 0, 12, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】以尖嚎使獵物膽怯，再用那利爪徹底撕裂。\\n順從自身的慾望，貫徹殘虐直至極限的魔狼。\\n\\n‧戰鬥開始時，\\n\u3000小幅度提升自身的物理防禦力和魔法防禦力。\\n\u3000以此防禦力提升效果上升的防禦力\\n\u3000不會受到戰鬥中被施加的降低防禦力技能的\\n\u3000影響。\\n‧必殺技會對前方的2名角色造成大幅度的物理\\n\u3000傷害，並且中幅度降低TP。\\n‧對敵方全體依照其角色最大HP造成魔法比例\\n\u3000傷害，同時使2名物理攻擊力最高的角色\\n\u3000陷入麻痺狀態。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。');
insert into unit_enemy_data values (301600, '席茲', 301600, 0, 3, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】帶來強烈暴風的大怪鳥。\\n逃出魔物圖鑑，做盡破壞之能事。\\n\\n・根據角色的最高 HP，對全體敵人\\n造成大幅度的傷害。\\n・對前方範圍內的敵人造成中幅度的物理傷害，\\n並且使其暈眩。');
insert into unit_enemy_data values (301601, '席茲', 301600, 0, 3, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】帶來強烈暴風的大怪鳥。\\n逃出魔物圖鑑，做盡破壞之能事。\\n\\n・根據角色的最高 HP，對全體敵人\\n造成大幅度的傷害。\\n・對前方範圍內的敵人造成中幅度的物理傷害，\\n並且使其暈眩。\\n・根據角色的最高 HP，對前方範圍內的敵人\\n造成中幅度的傷害，並降低其物理防禦力。\\n・當席茲本身的 HP 降至 50％ 以下，\\n其攻擊力將會越發殘暴。');
insert into unit_enemy_data values (301700, '賈巴沃克', 301700, 0, 3, 270, 1000, 1, 2.6, 0, 0, 0, '【物理】棲息在毒瘴闇稜巔峰的醜惡之狂獸。\\n以猛毒的瘴氣奪走生命，透過食腐做為力量來源。\\n\\n‧必殺技可以對全體敵人造成大幅度的魔法傷害，\\n\u3000並且使其陷入中毒狀態，同時擊退。\\n‧對面前2名角色造成物理傷害，同時降低物理\\n\u3000攻擊力與TP。\\n‧當賈巴沃克自身的血量降至40%以下時，\\n\u3000其攻擊力將會更加殘暴，\\n\u3000同時再召喚出3隻怪物。\\n‧當剩餘時間不到20秒時，將會對全體敵人造成\\n\u3000強力的中毒狀態，同時特大幅度減少自己的TP。');
insert into unit_enemy_data values (301800, '人馬座', 301800, 0, 3, 270, 1000, 1, 2.0, 0, 0, 0, '將衝向天際的許多標的射倒，射手座的魔星獸。\\n令纏繞著電芒的箭，在剎那間貫穿一切的至高絕技。\\n\\n‧必殺技可對所有敵人依最大 HP\\n\u3000造成魔法傷害。\\n\u3000可對黑暗狀態的敵人造成 3 倍傷害。\\n‧對全體敵人造成中幅度的魔法傷害，\\n\u3000並對剩餘 HP 比例最低的 1 名敵人\\n\u3000施加強力黑暗狀態。\\n‧對前方的 3 名敵人造成物理傷害。');
insert into unit_enemy_data values (301801, '人馬座', 301801, 0, 3, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】牠是守護著星穹神殿的射手座之魔星獸。\\n貫穿萬物的一閃，是以紫電輝煌此神域的絕技。\\n\\n‧戰鬥開始時，\\n\u3000小幅度提升自身物理防禦力及魔法防禦力。\\n\u3000因防禦力提升效果而上升的防禦力，\\n\u3000在戰鬥中不會受到防禦力下降技能的影響。\\n‧必殺技能夠對敵方全體依照其最大HP\\n\u3000造成魔法比例傷害，\\n\u3000並且大幅度降低魔法攻擊力。\\n\u3000同時對陷入黑暗狀態的敵人\\n\u3000增加傷害量與魔法攻擊力的降低量。\\n‧對全體敵人造成小幅度的魔法傷害，\\n\u3000並施加強力黑暗狀態。\\n‧對前方的3名敵人造成中幅度物理傷害。');
insert into unit_enemy_data values (301802, '人馬座', 301802, 0, 3, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】牠是守護著星穹神殿的射手座之魔星獸。\\n貫穿萬物的一閃，是以紫電輝煌此神域的絕技。\\n\\n‧戰鬥開始時，\\n\u3000小幅度提升自身物理防禦力及魔法防禦力。\\n\u3000因防禦力提升效果而上升的防禦力，\\n\u3000在戰鬥中不會受到防禦力下降技能的影響。\\n‧必殺技能夠對敵方全體依照其最大HP\\n\u3000造成魔法比例傷害，\\n\u3000並且大幅度降低魔法攻擊力。\\n\u3000同時對陷入黑暗狀態的敵人\\n\u3000增加傷害量與魔法攻擊力的降低量。\\n‧對全體敵人造成小幅度的魔法傷害，\\n\u3000並施加強力黑暗狀態。\\n‧對前方的3名敵人造成中幅度物理傷害。\\n‧對敵方全體造成中幅度的魔法傷害。\\n\u3000當自己的目標沒有被破壞時，\\n\u3000在自身的箭矢上追加1個【黑星】。\\n\u3000當【黑星】的數量為2個時，\\n\u3000將對敵方全體施加強力黑暗狀態。\\n\u3000此技能所造成的狀態異常，\\n\u3000即使傷害無效也會施加。');
insert into unit_enemy_data values (301803, '人馬座', 301803, 0, 3, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】牠是守護著星穹神殿的射手座之魔星獸。\\n貫穿萬物的一閃，是以紫電輝煌此神域的絕技。\\n\\n‧戰鬥開始時，\\n\u3000小幅度提升自身物理防禦力及魔法防禦力。\\n\u3000因防禦力提升效果而上升的防禦力，\\n\u3000在戰鬥中不會受到防禦力下降技能的影響。\\n‧必殺技能夠對敵方全體依照其最大HP\\n\u3000造成魔法比例傷害，\\n\u3000並且大幅度降低魔法攻擊力。\\n\u3000同時對陷入黑暗狀態的敵人\\n\u3000增加傷害量與魔法攻擊力的降低量。\\n\u3000在此技能造成的傷害狀態下，\\n\u3000會減少TP恢復量。\\n‧對敵方全體造成小幅度的魔法傷害，\\n\u3000並施加強力黑暗狀態。\\n‧對前方的3名敵人造成中幅度物理傷害。\\n‧對敵方全體造成中幅度的魔法傷害。\\n\u3000當自己的目標沒有被破壞時，\\n\u3000在自身的箭矢上追加1個【黑星】。\\n\u3000當【黑星】的數量為2個時，\\n\u3000將對敵方全體施加強力黑暗狀態。\\n\u3000此技能所造成的狀態異常，\\n\u3000即使傷害無效也會施加。');
insert into unit_enemy_data values (301900, '嘯浪虎鯨', 301900, 0, 11, 270, 1000, 1, 1.7, 0, 0, 0, '【物理】以銳利的眼神追尋獵物\\n及浪濤的海中獵人。\\n利用魔力讓潮水不斷湧出\\n進而削弱敵方的鋒芒和氣力。\\n\\n‧對前方的 4 名角色造成中幅度的物理傷害，\\n\u3000並降低其物理攻擊力。\\n\\n‧對前方的 2 名角色造成小幅度的魔法傷害，\\n\u3000並降低其 TP。');
insert into unit_enemy_data values (301901, '殺人虎鯨', 301901, 0, 11, 270, 1000, 1, 1.5, 0, 0, 0, '【物理】藉由月之魔力更趨兇暴化的大海之獵人。\\n以經過嚴峻鍛鍊的身驅，施展化為利刃的水流之擊。\\n\\n‧對前方4名角色造成大幅度的物理傷害，\\n\u3000並且中幅度降低物理攻擊力。同時小幅度\\n\u3000提升全體夥伴的TP上升。\\n‧對前方小範圍造成中幅度的魔法傷害，\\n\u3000同時大幅度降低TP。\\n‧以從後方數來第2名的角色為中心，\\n\u3000造成小範圍的中幅度物理傷害，同時\\n\u3000大幅度降低魔法攻擊力。');
insert into unit_enemy_data values (302000, '狂暴格里芬', 302000, 0, 11, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】在嚴酷的環境中進化的小小格里芬。\\n用龍捲風將獵物掃於天際，在空中狩之。\\n\\n‧對前方3名角色造成中幅度的魔法傷害。');
insert into unit_enemy_data values (302001, '狂暴格里芬', 302001, 0, 11, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】在嚴酷的環境中進化的小小格里芬。以龍捲風將獵物捲起，並在空中獵捕。\\n\\n・對前方範圍內的敵人造成中幅度的魔法傷害。');
insert into unit_enemy_data values (302002, '狂暴格里芬', 302002, 0, 11, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】在嚴酷的環境中進化的小小格里芬。\\n用龍捲風將獵物掃於天際，在空中狩之。\\n\\n‧對前方的3名角色造成中幅度的魔法傷害，\\n\u3000同時造成擊退。\\n\u3000當該角色的HP低於70％時，\\n\u3000施加暈眩狀態。\\n\u3000此技能所造成的狀態異常，\\n\u3000即使傷害無效也會施加。\\n‧對前方的3名角色造成中幅度的魔法傷害，\\n\u3000且中幅度降低魔法防禦力。\\n\u3000此技能所造成的狀態異常，\\n\u3000即使傷害無效也會施加。');
insert into unit_enemy_data values (302100, '飛龍', 302100, 0, 11, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】使用寬大的皮翼翱翔於天際的翼龍。\\n能吐出巨大的火球，藉此阻擋入侵者的去向。\\n\\n‧必殺技會以從前方數來第1名的敵人為中心，\\n\u3000對小範圍且最多3名的角色造成中幅度的\\n\u3000物理傷害。');
insert into unit_enemy_data values (302101, '飛龍', 302101, 0, 11, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】使用寬大的皮翼翱翔於天際的翼龍。\\n能吐出巨大的火球，藉此阻擋入侵者的去向。\\n\\n‧必殺技會以從前方數來第1名的敵人為中心，\\n\u3000對小範圍且最多3名的角色\\n\u3000造成中幅度的物理傷害，\\n\u3000並特大幅度降低物理防禦力。\\n\u3000此技能所造成的狀態異常，\\n\u3000即使傷害無效也會施加。\\n‧對前方3名角色造成擊退。');
insert into unit_enemy_data values (302102, '飛龍', 302102, 0, 11, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】使用寬大的皮翼翱翔於天際的翼龍。\\n能吐出巨大的火球，藉此阻擋入侵者的去向。\\n\\n‧以從後方數來第1位角色為中心，對小範圍\\n\u3000且最多3名的角色造成中幅度的物理傷害。');
insert into unit_enemy_data values (302103, '沙塵飛龍', 302103, 0, 11, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】盤踞於沙塵瀰漫的高空的翼龍。\\n牠是荒野上空的支配者，即便身處如此嚴酷的環境，\\n也不會放跑自己的獵物。\\n\\n‧以前方的第 1 名敵人為中心，\\n\u3000對小範圍內最多 3 名角色造成\\n\u3000中幅度的魔法傷害。');
insert into unit_enemy_data values (302104, '沙塵飛龍', 302103, 0, 11, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】盤踞於沙塵瀰漫的高空的翼龍。\\n牠是荒野上空的支配者，即便身處如此嚴酷的環境，\\n也不會放跑自己的獵物。\\n\\n‧以前方的第 1 名敵人為中心，\\n\u3000對小範圍內最多 3 名角色造成\\n\u3000中幅度的魔法傷害。');
insert into unit_enemy_data values (302200, '逝者・卡拉迪翁', 302200, 0, 16, 270, 1000, 2, 1.6, 0, 0, 0, '【魔法】由於露娜的魔力而甦醒，古代的機械兵器。\\n無慈悲地釋放而出的魔力，阻礙著入侵者。\\n\\n・對敵方全體造成特大的魔法傷害，並大幅度地\\n\u3000降低魔法防禦力。\\n・對前方範圍內的敵人造成大量物理傷害。\\n・對前方範圍內的敵人造成大量的魔法傷害，\\n\u3000使其陷入麻痺狀態。');
insert into unit_enemy_data values (302300, '睿智之鴞', 302300, 0, 16, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】棲息於大樹之頂，絕頂聰明的大梟。\\n融會了森林之生者的英智，能巧妙地施展魔術。\\n\\n‧必殺技可以對全體敵人造成魔法傷害。\\n\\n‧隨機對1名角色造成物理傷害，同時使其\\n\u3000陷入麻痺狀態。');
insert into unit_enemy_data values (302400, '電弧守護者', 302400, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】自遠古便守護此遺跡至今的人工生命體。\\n藉由製造者的秘術，獲得了能永遠行動的無限動力。\\n\\n‧必殺技可以對全體敵人造成大幅度的魔法傷害。\\n\\n‧對前方的範圍內造成物理傷害。\\n‧對全體敵人造成魔法傷害，同時使其\\n\u3000陷入沉默狀態。');
insert into unit_enemy_data values (302500, '奇美拉', 302500, 0, 16, 270, 1000, 1, 1.4, 0, 0, 0, '【物理】居於孤塔之頂，一隻暴虐的混合魔物。\\n以那千變萬化的猛攻，屠殺了無數的挑戰者。\\n\\n‧必殺技可以對前方範圍內造成大幅度的\\n\u3000物理傷害，同時造成擊退。\\n‧對前方3名角色造成物理傷害，同時使其\\n\u3000陷入火傷狀態。\\n‧對全體敵人造成魔法傷害，同時降低行動速度、\\n\u3000物理防禦力、魔法防禦力。\\n‧當剩餘時間不到10秒時，將會對全體敵人造成\\n\u3000極大的魔法傷害，再特大幅度減少自己的TP。');
insert into unit_enemy_data values (302600, '野豬雙胞胎', 302600, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】獲得更多力量的雙子座的魔星獸。\\n在前線一邊防禦，一邊用熟練的技能進行攻擊。\\n\\n‧必殺技為對敵方全體依照其最大 HP\\n\u3000造成物理比例傷害。\\n‧對後方的2名角色造成大幅度的物理傷害，\\n\u3000同時大幅度降低其行動速度。\\n‧對敵方全體造成大幅度的物理傷害。');
insert into unit_enemy_data values (302601, '野豬雙胞胎', 302601, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】獲得更多力量的雙子座的魔星獸。\\n在前線一邊防禦，一邊用熟練的技能進行攻擊。\\n\\n‧必殺技為對敵方全體依照其最大 HP\\n\u3000造成物理比例傷害。\\n‧對後方的2名角色造成大幅度的物理傷害，\\n\u3000同時大幅度降低其行動速度。\\n‧對敵方全體造成大幅度的物理傷害。\\n‧大幅度降低自身的物理防禦力與\\n\u3000魔法防禦力。\\n\u3000之後特大幅度提升自身的 TP 上升與\\n\u3000物理暴擊率，\\n\u3000並且對敵方全體造成大幅度的物理傷害。');
insert into unit_enemy_data values (302602, '野豬雙胞胎', 302602, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】獲得更多力量的雙子座的魔星獸。\\n在前線一邊防禦，一邊用熟練的技能進行攻擊。\\n\\n‧必殺技為對敵方全體依照其最大 HP\\n\u3000造成物理比例傷害。\\n‧對後方的2名角色造成大幅度的物理傷害，\\n\u3000同時大幅度降低其行動速度。\\n‧對敵方全體造成大幅度的物理傷害。\\n‧大幅度降低自身的物理防禦力與\\n\u3000魔法防禦力。\\n\u3000之後特大幅度提升自身的 TP 上升與\\n\u3000物理暴擊率，\\n\u3000並且對敵方全體造成大幅度的物理傷害。\\n‧大幅度降低自身的物理防禦力與魔法防禦力，\\n\u3000然後特大幅度降低敵方全體的HP吸收。');
insert into unit_enemy_data values (302700, '加爾基諾司', 302700, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】盤踞在船墳的海灣中，巨蟹座的魔星獸。\\n其巨大剪刀的一擊，可使無數的船隻沉沒。\\n\\n・對敵方全體造成大幅度的魔法傷害，並降低\\n\u3000的物理防禦力。\\n・對前方範圍內的全體敵人造成中幅度的物理傷害\\n\u3000，並使其呈現暈眩狀態。\\n・對敵方全體造成中幅度的物理傷害。');
insert into unit_enemy_data values (302701, '加爾基諾司', 302701, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】使許多的船沉沒的巨蟹座的魔星獸。\\n大海的霸主會裁決、擊碎以及殲滅萬物。\\n\\n‧必殺技會對敵方全體依照其魔法攻擊力\\n\u3000造成魔法比例傷害。\\n\u3000然後，再特大幅度提升自身的魔法攻擊力。\\n‧以前方的第 1 名敵人為中心，對小範圍內的\\n\u3000敵方全體造成中幅度的物理傷害，並使其\\n\u3000暈眩。\\n‧對敵方全體造成小幅度的物理傷害。');
insert into unit_enemy_data values (302702, '加爾基諾司', 302702, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】使許多的船沉沒的巨蟹座的魔星獸。\\n大海的霸主會裁決、擊碎以及殲滅萬物。\\n\\n‧戰鬥開始時，中幅度提升自身的物理防禦力和\\n\u3000魔法防禦力。\\n\u3000以此防禦力提升效果上升的防禦力\\n\u3000不會受到戰鬥中被施加的降低防禦力技能的\\n\u3000影響。\\n‧必殺技會依照自身魔法攻擊力\\n\u3000對敵方全體造成魔法比例傷害。\\n\u3000然後，再特大幅度提升自身的魔法攻擊力。\\n‧以前方的第1名敵人為中心，對小範圍內的\\n\u3000所有敵方造成中幅度的物理傷害，並使其\\n\u3000暈眩。\\n‧對敵方全體造成小幅度的物理傷害。\\n‧在一定時間內變身。\\n\u3000變身時，將敵方全體擊退，並降低\\n\u3000自身的能力提升效果。\\n\u3000同時特大幅度提升自身的魔法攻擊力，\\n\u3000將全部的技能變更為魔法攻擊。\\n‧變身解除時，擊退敵方全體，\\n\u3000並提升自身的能力提升效果。');
insert into unit_enemy_data values (302703, '加爾基諾司', 302703, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】使許多的船沉沒的巨蟹座的魔星獸。\\n大海的霸主會裁決、擊碎以及殲滅萬物。\\n\\n‧戰鬥開始時，中幅度提升自身的物理防禦力和\\n\u3000魔法防禦力。\\n\u3000以此防禦力提升效果上升的防禦力\\n\u3000不會受到戰鬥中被施加的降低防禦力技能的\\n\u3000影響。\\n‧必殺技會依照自身魔法攻擊力\\n\u3000對敵方全體造成魔法比例傷害。\\n\u3000然後，再特大幅度提升自身的魔法攻擊力。\\n‧以前方的第1名敵人為中心，對小範圍內的\\n\u3000所有敵方造成中幅度的物理傷害，並使其\\n\u3000暈眩。\\n‧對敵方全體造成小幅度的物理傷害。\\n‧在一定時間內變身。\\n\u3000變身時，將敵方全體擊退，並降低\\n\u3000自身的能力提升效果。\\n\u3000同時特大幅度提升自身的魔法攻擊力，\\n\u3000將全部的技能變更為魔法攻擊。\\n‧變身解除時，擊退敵方全體，\\n\u3000並提升自身的能力提升效果。');
insert into unit_enemy_data values (302800, '奧爾獅', 302800, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '頗負盛名的熱帶草原霸者，獅子座的魔星獸。\\n對其刀刃相向者，將焚毀於灼熱的咆哮中。\\n\\n・對敵方全體，依照最大HP造成大幅度並無\\n\u3000視防禦力的物理傷害，並對剩餘HP較少的敵人\\n\u3000賦予火傷狀態。\\n・對敵方1名角色造成大幅度物理傷害，\\n\u3000若為火傷狀態時則再追加額外傷害。\\n・對前方範圍內的敵人造成中幅度的物理傷害，\\n\u3000若為火傷狀態時則再追加額外傷害。');
insert into unit_enemy_data values (302801, '奧爾獅', 302801, 0, 16, 270, 1000, 1, 3.0, 0, 0, 0, '【物理】君臨於荒涼原野的獅子座之魔星獸。\\n那銳爪撕裂著大氣，以業火之咆嘯使大地化為焦黑。\\n\\n‧必殺技會對敵方全體依照其最大HP造成\\n\u3000物理比例傷害。\\n\u3000角色的HP未滿80%時，施加\\n\u3000火傷狀態。\\n\u3000此技能施加的火傷狀態所造成的傷害\\n\u3000將不會恢復TP。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧對前方1名角色造成大幅度的物理傷害。\\n\u3000角色陷入火傷狀態時追加傷害。\\n‧對前方範圍內的敵人造成大幅度的物理傷害。\\n\u3000角色陷入火傷狀態時追加傷害。');
insert into unit_enemy_data values (302802, '奧爾獅', 302802, 0, 16, 270, 1000, 1, 3.0, 0, 0, 0, '【物理】君臨於荒涼原野的獅子座之魔星獸。\\n那銳爪撕裂著大氣，以業火之咆嘯使大地化為焦黑。\\n\\n‧必殺技會對敵方全體依照其最大HP造成\\n\u3000物理比例傷害。\\n\u3000角色的HP未滿80%時，施加\\n\u3000火傷狀態。\\n\u3000此技能施加的火傷狀態所造成的傷害\\n\u3000將不會恢復TP。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧對前方1名角色造成大幅度的物理傷害。\\n\u3000角色陷入火傷狀態時追加傷害。\\n‧對前方範圍內的敵人造成大幅度的物理傷害。\\n\u3000角色陷入火傷狀態時追加傷害。\\n‧對敵方全體依照其最大HP造成\\n\u3000魔法比例傷害，並施加暈眩。\\n\u3000角色的HP未滿40%時，施加\\n\u3000長時間暈眩。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。');
insert into unit_enemy_data values (302803, '奧爾獅', 302803, 0, 16, 270, 1000, 1, 3.0, 0, 0, 0, '【物理】君臨於荒涼原野的獅子座之魔星獸。\\n那銳爪撕裂著大氣，以業火之咆嘯使大地化為焦黑。\\n\\n‧小幅度降低奧爾獅造成的\\n\u3000所有傷害產生的隊伍角色\\n\u3000TP恢復量。\\n‧必殺技會對敵方全體依照其最大HP\\n\u3000造成物理比例傷害。\\n\u3000角色的HP未滿80%時，施加\\n\u3000火傷狀態。\\n\u3000此技能施加的火傷狀態所造成的傷害\\n\u3000將不會恢復TP。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧對前方1名角色造成大幅度的物理傷害。\\n\u3000角色陷入火傷狀態時追加傷害。\\n‧對前方範圍內的敵人造成大幅度的物理傷害。\\n\u3000角色陷入火傷狀態時追加傷害。\\n‧對敵方全體依照其最大HP造成\\n\u3000魔法比例傷害，並施加暈眩。\\n\u3000角色的HP未滿40%時，施加\\n\u3000長時間暈眩。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧無視敵方的挑釁，對後方1名角色造成\\n\u3000中幅度的魔法傷害，並且浮空之後拉近自身，\\n\u3000施加暈眩。');
insert into unit_enemy_data values (302900, '水之里歐斯', 302900, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '淪陷於寄宿在神瓶之中那魔力的水瓶座之魔星獸。\\n沉溺於強大的力量中，卻因非得支配大海而暴走。\\n\\n‧必殺技，可對全體敵人造成共計六次的小幅度\\n\u3000魔法傷害。\\n\u3000當角色的 HP 低於 80% 時，能對其造成擊退，\\n\u3000而當低於 40% 時，除了擊退之外還能夠其陷入\\n\u3000暈眩狀態。\\n・對面前的 3 名敵人造成中幅度的物理傷害。\\n・能將自身的素質降低效果，與敵方全體的素質\\n\u3000提升的效果打消解除，並且還能夠增加自己的\\n\u3000TP。');
insert into unit_enemy_data values (302901, '水之里歐斯', 302901, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】操縱寄宿於瓶中之魔力的水瓶座之魔星獸。\\n以激流將萬物吞噬殆盡的蒼海支配者為名而君臨。\\n\\n‧必殺技會對敵方全體依照其角色最大HP\\n\u3000造成魔法比例傷害。\\n\u3000當角色的HP低於80%時，能將其擊退，\\n\u3000而當低於50%時，除了擊退外能再使其\\n\u3000陷入暈眩狀態。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧解除敵方全體的能力提升效果，同時小幅度提升\\n\u3000自身的TP、物理防禦力、魔法防禦力。\\n‧對面前1名敵方角色造成特大幅度的物理傷害，\\n\u3000對前方第2、3名角色造成大幅度的物理傷害。');
insert into unit_enemy_data values (302902, '水之里歐斯', 302902, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】操縱寄宿於瓶中之魔力的水瓶座之魔星獸。\\n以激流將萬物吞噬殆盡的蒼海支配者為名而君臨。\\n\\n‧必殺技會對敵方全體依照其角色最大HP\\n\u3000造成魔法比例傷害。\\n\u3000當角色的HP低於80%時，能將其擊退，\\n\u3000而當低於50%時，除了擊退外能再使其\\n\u3000陷入暈眩狀態。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧解除敵方全體的能力提升效果，同時小幅度提升\\n\u3000自身的TP、物理防禦力、魔法防禦力。\\n‧對面前1名敵方角色造成特大幅度的物理傷害，\\n\u3000對前方第2、3名角色造成大幅度的物理傷害。\\n\\n【戰鬥場地效果】\\n經過了一定的時間後，將會產生激流。\\n‧對隊伍全體角色造成連續的小幅度魔法傷害。\\n\u3000當該角色的HP低於80%時，\\n\u3000能將其擊退。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧當水之里歐斯的目標部位被破壞時，\\n\u3000小幅度減少水之里歐斯的TP。\\n\u3000若水之里歐斯的目標部位尚未被破壞，\\n\u3000將會小幅度提升水之里歐斯的\\n\u3000物理防禦力與魔法防禦力。');
insert into unit_enemy_data values (302903, '水之里歐斯', 302903, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】操縱寄宿於瓶中之魔力的水瓶座之魔星獸。\\n以激流將萬物吞噬殆盡的蒼海支配者為名而君臨。\\n\\n‧必殺技會對敵方全體依照其角色最大HP\\n\u3000造成魔法比例傷害。\\n\u3000當角色的HP低於80%時，能將其擊退，\\n\u3000而當低於50%時，除了擊退外能再使其\\n\u3000陷入暈眩狀態。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧解除敵方全體的能力提升效果，同時小幅度提升\\n\u3000自身的TP、物理防禦力、魔法防禦力。\\n‧對面前1名敵方角色造成特大幅度的物理傷害，\\n\u3000對前方第2、3名角色造成大幅度的物理傷害。\\n\\n【戰鬥場地效果】\\n經過了一定的時間後，將會產生激流。\\n‧對隊伍全體角色造成連續的小幅度魔法傷害。\\n\u3000當該角色的HP低於80%時，\\n\u3000能將其擊退。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧當水之里歐斯的目標部位被破壞時，\\n\u3000小幅度減少水之里歐斯的TP。\\n\u3000若水之里歐斯的目標部位尚未被破壞，\\n\u3000將會小幅度提升水之里歐斯的\\n\u3000物理防禦力與魔法防禦力。');
insert into unit_enemy_data values (302904, '水之里歐斯', 302904, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】操縱寄宿於瓶中之魔力的水瓶座之魔星獸。\\n以激流將萬物吞噬殆盡的蒼海支配者為名而君臨。\\n\\n‧必殺技會對敵方全體依照其角色最大HP\\n\u3000造成魔法比例傷害。\\n\u3000當角色的HP低於80%時，能將其擊退，\\n\u3000而當低於50%時，除了擊退外能再使其\\n\u3000陷入暈眩狀態。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧解除敵方全體的能力提升效果，同時小幅度提升\\n\u3000自身的TP、物理防禦力、魔法防禦力。\\n‧對面前1名敵方角色造成特大幅度的物理傷害，\\n\u3000對前方第2、3名角色造成大幅度的物理傷害。\\n\\n【戰鬥場地效果】\\n經過了一定的時間後，將會產生激流。\\n‧對隊伍全體角色造成連續的小幅度魔法傷害。\\n\u3000當該角色的HP低於80%時，\\n\u3000能將其擊退。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧當水之里歐斯的目標部位被破壞時，\\n\u3000小幅度減少水之里歐斯的TP。\\n\u3000若水之里歐斯的目標部位尚未被破壞，\\n\u3000將會小幅度提升水之里歐斯的\\n\u3000物理防禦力與魔法防禦力。');
insert into unit_enemy_data values (303000, '托爾披頓', 303000, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '使大海原暴走，並喚起狂風暴雨的雙魚座之魔星獸。\\n周邊小弟身上的紅魚鰭，是扁人剛好啦！的證明。\\n\\n・更加地容易受到物理攻擊力提升、降低的效果\\n\u3000影響。\\n‧必殺技，能夠對全體敵人造成大幅度的物理傷害，\\n\u3000並且能夠再使自己的行動速度與物理攻擊力\\n\u3000提升。\\n・對敵方全體造成小幅度的物理傷害。\\n・對前方的 2 名敵人造成中幅度的物理傷害，\\n\u3000並小幅度降低其物理防禦力。');
insert into unit_enemy_data values (303001, '托爾披頓', 303001, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】背負著大海而聳立，爆走的雙魚座魔星獸。\\n被他吸引的小弟居於背上。與牠一同邁向霸道之極。\\n\\n‧較為容易受到物理攻擊力提升、降低的效果\\n\u3000影響。\\n‧必殺技會解除敵方全體的護盾，\\n\u3000並對敵方全體依照托爾披頓的物理攻擊力造成\\n\u3000物理比例傷害。\\n\u3000同時提升中幅度自身的行動速度與物理\\n\u3000攻擊力。\\n‧對敵方全體造成小幅度的物理傷害。\\n‧對前方2名角色造成中幅度的物理傷害，\\n\u3000同時小幅度降低物理防禦力。');
insert into unit_enemy_data values (303002, '托爾披頓', 303002, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】背負著大海而聳立，爆走的雙魚座魔星獸。\\n被他吸引的小弟居於背上。與牠一同邁向霸道之極。\\n\\n‧較為容易受到物理攻擊力提升、降低的效果\\n\u3000影響。\\n‧必殺技會解除敵方全體的護盾，\\n\u3000並對敵方全體依照托爾披頓的物理攻擊力造成\\n\u3000物理比例傷害。\\n\u3000同時提升中幅度自身的行動速度與物理\\n\u3000攻擊力。\\n‧對敵方全體造成小幅度的物理傷害。\\n‧對前方2名角色造成中幅度的物理傷害，\\n\u3000同時小幅度降低物理防禦力。\\n‧召喚1隻拿著旗子的小弟。\\n\u3000拿著旗子的小弟將會恢復托爾披頓的TP。\\n\u3000當拿著旗子的小弟的HP低於一定數值時，\\n\u3000隊伍角色全體的物理攻擊力與魔法攻擊力將會\\n\u3000中幅度提升。');
insert into unit_enemy_data values (303003, '托爾披頓', 303003, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】背負著大海而聳立，爆走的雙魚座魔星獸。\\n被他吸引的小弟居於背上。與牠一同邁向霸道之極。\\n\\n‧較為容易受到物理攻擊力提升、降低的效果\\n\u3000影響。\\n‧必殺技會解除敵方全體的護盾，\\n\u3000並對敵方全體依照托爾披頓的物理攻擊力造成\\n\u3000物理比例傷害。\\n\u3000同時提升中幅度自身的行動速度與物理\\n\u3000攻擊力。\\n‧對敵方全體造成小幅度的物理傷害。\\n‧對前方2名角色造成中幅度的物理傷害，\\n\u3000同時小幅度降低物理防禦力。\\n‧召喚1隻拿著旗子的小弟。\\n\u3000拿著旗子的小弟將會恢復托爾披頓的TP。\\n\u3000當拿著旗子的小弟的HP低於一定數值時，\\n\u3000隊伍角色全體的物理攻擊力與魔法攻擊力將會\\n\u3000中幅度提升。');
insert into unit_enemy_data values (303004, '托爾披頓', 303002, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】背負著大海而聳立，爆走的雙魚座魔星獸。\\n被他吸引的小弟居於背上。與牠一同邁向霸道之極。\\n\\n‧較為容易受到物理攻擊力提升、降低的效果\\n\u3000影響。\\n‧必殺技會解除敵方全體的護盾，\\n\u3000並對敵方全體依照托爾披頓的物理攻擊力造成\\n\u3000物理比例傷害。\\n\u3000同時提升中幅度自身的行動速度與物理\\n\u3000攻擊力。\\n‧對敵方全體造成小幅度的物理傷害。\\n‧對前方2名角色造成中幅度的物理傷害，\\n\u3000同時小幅度降低物理防禦力。\\n‧召喚1隻拿著旗子的小弟。\\n\u3000拿著旗子的小弟將會恢復托爾披頓的TP。\\n\u3000當拿著旗子的小弟的HP低於一定數值時，\\n\u3000隊伍角色全體的物理攻擊力與魔法攻擊力將會\\n\u3000中幅度提升。');
insert into unit_enemy_data values (303100, '冬眠之熊', 303100, 0, 13, 270, 1000, 1, 3.5, 0, 0, 0, '【物理】躲藏於冰穴最深處，\\n決意要終身冬眠的巨大野熊。\\n長年累月在睡夢中度過，\\n僅於狩獵的一瞬間甦醒過來。\\n\\n‧對全體敵人造成大幅度的魔法傷害，\\n\u3000並降低其物理攻擊力。\\n\\n‧對前方的 3 名角色造成小幅度的\\n\u3000物理傷害。並且將前方的 1 名角色\\n\u3000大幅度擊飛，再施加凍結狀態\\n\u3000降低其移動速度。');
insert into unit_enemy_data values (303200, '寒冰孔雀夫人', 303200, 0, 6, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】伴隨著暴風雪現身，\\n會呼朋引伴的襲擊\\n侵犯地盤的人，\\n是雪國之中最華麗的女士。\\n\\n‧對前方的 4 名角色造成中幅度的\\n\u3000魔法傷害。\\n\\n‧對隨機的 2 名角色造成\\n\u3000小幅度的魔法傷害，\\n\u3000並且施加凍結狀態。');
insert into unit_enemy_data values (303300, '石像鬼', 303300, 0, 13, 270, 1000, 1, 2.1, 0, 0, 0, '【物理】遺留在腐朽的遺跡裡，守護著\\n主人死去的地方，謎樣的鳥型雕像。\\n隨著城鎮、命令的逝去，現在的他們\\n無論來者是誰，全部予以火焰攻擊。\\n\\n‧對前方5名角色造成中幅度魔法\\n\u3000傷害，並且施加火傷狀態。同時\\n\u3000降低魔法防禦力。\\n\\n‧隨機對3名角色造成\\n\u3000小幅度的魔法傷害，\\n\u3000同時使其陷入黑暗狀態。');
insert into unit_enemy_data values (303301, '闇黑石像鬼', 303301, 0, 13, 270, 1000, 1, 2.1, 0, 0, 0, '【物理】侍奉於暴食的君主，近衛軍的黑鐵像。\\n以巧妙伎倆拐騙於冥府徬徨之魂，再獻之於主。\\n\\n‧戰鬥開始時，\\n\u3000小幅度提升自身的物理防禦力和魔法防禦力。\\n\u3000以此防禦力提升效果上升的防禦力\\n\u3000不會受到戰鬥中被施加的\\n\u3000降低防禦力技能的影響。\\n‧必殺技能夠對敵方全體\\n\u3000造成中幅度的魔法傷害，施加火傷狀態，\\n\u3000同時中幅度降低魔法防禦力。\\n\u3000此技能造成的傷害將不會恢復TP。\\n‧對前方的1名角色\\n\u3000造成特大幅度的魔法傷害。\\n\u3000同時對敵方全體造成中幅度的魔法傷害，\\n\u3000中幅度降低物理攻擊力和魔法攻擊力。\\n\u3000此技能所造成的狀態異常，\\n\u3000即使傷害無效也會施加。');
insert into unit_enemy_data values (303302, '闇黑石像鬼', 303302, 0, 13, 270, 1000, 1, 2.1, 0, 0, 0, '【物理】侍奉於暴食的君主，近衛軍的黑鐵像。\\n以巧妙伎倆拐騙於冥府徬徨之魂，再獻之於主。\\n\\n‧戰鬥開始時，\\n\u3000小幅度提升自身的物理防禦力和魔法防禦力。\\n\u3000以此防禦力提升效果上升的防禦力\\n\u3000不會受到戰鬥中被施加的\\n\u3000降低防禦力技能的影響。\\n‧必殺技能夠對敵方全體\\n\u3000造成中幅度的魔法傷害，施加火傷狀態，\\n\u3000同時中幅度降低魔法防禦力。\\n\u3000此技能造成的傷害將不會恢復TP。\\n‧對前方的1名角色造成特大幅度的魔法傷害。\\n\u3000同時對敵方全體造成中幅度的魔法傷害，\\n\u3000同時中幅度降低物理攻擊力與魔法攻擊力。\\n\u3000當該角色的HP未滿80％時，\\n\u3000同時造成擊退。\\n\u3000此技能所造成的狀態異常，\\n\u3000即使傷害無效也會施加。');
insert into unit_enemy_data values (303303, '沙塵石像鬼', 303303, 0, 13, 270, 1000, 1, 2.1, 0, 0, 0, '【物理】蘊含塔之魔力而寄宿著生命的\\n砂岩雕像魔物。在沙塵飛揚之地等待敵人，\\n再吐出灼熱火焰襲擊。\\n\\n‧對前方的範圍內造成大幅度的魔法傷害，\\n\u3000使其陷入火傷狀態。\\n\u3000並且中幅度降低魔法防禦力。\\n‧對前方的3名角色造成中幅度的魔法傷害，\\n\u3000並使敵方全體陷入黑暗狀態。\\n‧對面前的1名敵方角色造成大幅度的物理傷害。\\n\u3000對敵方全體中火傷狀態的敵人造成\\n\u3000大幅度的魔法傷害。');
insert into unit_enemy_data values (303304, '滴水嘴獸', 303304, 0, 13, 270, 1000, 1, 2.1, 0, 0, 0, '【物理】守護黃沙大地的漆黑惡魔像\\n對著遼闊的沙漠一端，\\n噴吐焚盡一切氣息，\\n阻擋冒險者在灼熱大地前進。\\n\\n‧必殺技能夠對敵方全體\\n\u3000造成中幅度的魔法傷害，\\n\u3000施加火傷狀態，\\n\u3000同時小幅度降低魔法防禦力。\\n\u3000在此技能造成的傷害狀態下，\\n\u3000敵人不會恢復TP。\\n\\n‧對前方1名敵人造成\\n\u3000中幅度的魔法傷害，\\n\u3000再對敵方全體\\n\u3000造成中幅度的魔法傷害，\\n\u3000並中幅度降低物理攻擊力\\n\u3000與魔法攻擊力。');
insert into unit_enemy_data values (303400, '沙蜥蜴', 303400, 0, 13, 270, 1000, 1, 1.9, 0, 0, 0, '【物理】在生存競爭激烈的\\n沙漠中的王者，是隻巨大蜥蜴。\\n使用劇毒，活用沙子的戰略，\\n就是嚴酷環境中習得的生存之道。\\n\\n‧對全體敵人造成中幅度的物理傷害\\n，並降低其行動速度。\\n\u3000再提升全體夥伴的物理攻擊力。\\n‧對以前方 1 名角色為中心的\\n\u3000小範圍內造成小幅度的物理傷害，\\n\u3000並施加中毒狀態。再降低其物理\\n\u3000防禦力。');
insert into unit_enemy_data values (303401, '岩之錘', 303401, 0, 13, 270, 1000, 1, 1.9, 0, 0, 0, '【物理】身負月之魔力而產生變異的巨大蜥蜴。\\n棘狀且堅硬的鱗片，能輕易削去敵人的體力與鎧甲。\\n\\n‧對全體敵人造成大幅度的物理傷害，並且減少其\\n\u3000TP。\\n‧對前方的 2 名角色造成中幅度的物理傷害，\\n\u3000並且使其中毒。\\n‧對前方的 3 名角色造成物理傷害。\\n\u3000並對前方的 1 名敵人造成大幅度的物理傷害，\\n\u3000並中幅度降低其物理防禦力和魔法防禦力。');
insert into unit_enemy_data values (303402, '岩之錘', 303402, 0, 13, 270, 1000, 1, 1.9, 0, 0, 0, '【物理】身負月之魔力而產生變異的巨大蜥蜴。\\n棘狀且堅硬的鱗片，能輕易削去敵人的體力與鎧甲。\\n\\n‧對全體敵人造成大幅度的物理傷害，並且減少其\\n\u3000TP。\\n‧對前方的 2 名角色造成中幅度的物理傷害，\\n\u3000並且使其中毒。\\n‧對前方的 3 名角色造成物理傷害。\\n\u3000並對前方的 1 名敵人造成大幅度的物理傷害，\\n\u3000並中幅度降低其物理防禦力和魔法防禦力。');
insert into unit_enemy_data values (303500, '怒蛇', 303500, 0, 13, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】從吸取他人的魔力之中，\\n體悟出了妖術的魔物。\\n能從敵人的傷口上奪取魔力，\\n進而獲得更大的力量。\\n\\n‧對全體敵人造成中幅度的魔法傷害，\\n\u3000並降低全體敵人中\\n\u3000魔法攻擊角色的 TP。\\n\\n‧對以前方 1 名角色為中心的\\n\u3000小範圍內造成小幅度的魔法傷害，\\n\u3000並降低其魔法防禦力。');
insert into unit_enemy_data values (303501, '怒蛇', 303501, 0, 13, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】藉由持續吸取他人魔力獲得妖術的魔物。\\n從敵人的傷口中奪取魔力，追求更強大的力量。\\n\\n‧對全體敵人造成中幅度的魔法傷害。\\n\u3000並且大幅度降低使用魔法攻擊的敵人\\n\u3000的TP。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧對前方2名角色造成中幅度的魔法傷害，\\n\u3000大幅度降低物理攻擊力。');
insert into unit_enemy_data values (303502, '怒蛇', 303502, 0, 13, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】藉由持續吸取他人魔力獲得妖術的魔物。\\n從敵人的傷口中奪取魔力，追求更強大的力量。\\n\\n‧對全體敵人造成中幅度的魔法傷害，\\n\u3000並同時擊退。\\n\u3000並且大幅度降低使用魔法攻擊的敵人\\n\u3000的TP。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧對前方2名角色造成中幅度的魔法傷害，\\n\u3000大幅度降低物理攻擊力。');
insert into unit_enemy_data values (303600, '熾焰巨獸龍', 303600, 0, 13, 270, 1000, 1, 1.7, 0, 0, 0, '【物理】靠著強韌的雙腳與銳利的爪子，\\n可在一瞬間捕獲獵物的兇猛恐龍。\\n在滅亡的大地上吞食熔岩，\\n找出生存之道的孤高存在。\\n\\n‧對全體敵人造成中幅度的物理傷害，\\n\u3000並提升自己的行動速度。\\n\\n‧對前方的 3 名敵人造成中幅度的物理傷害，\\n\u3000並降低其行動速度。');
insert into unit_enemy_data values (303700, '地獄獵犬', 303700, 0, 14, 270, 1000, 1, 0.7, 0, 0, 0, '【物理】儘管墜入了那火山之中，\\n依舊身負地獄之炎復甦的雙頭魔犬。\\n與愛犬波尼一同在地盤上奔馳著，\\n並讓入侵者親身體驗那灼熱的洗禮。\\n\\n‧對全體敵人造成中幅度的物理傷害，\\n\u3000並施加火傷狀態。\\n\u3000再恢復召喚怪物的 HP。\\n\\n‧召喚波尼。');
insert into unit_enemy_data values (303701, '熾焰狼', 303701, 0, 14, 270, 1000, 1, 0.7, 0, 0, 0, '【物理】藉由塔之魔力使魔界火焰現形的魔狼。\\n和搭檔波尼一同在灼熱的大地等候著。\\n\\n‧對敵方全體造成大幅度的物理傷害，\\n\u3000並使其陷入火傷狀態，\\n\u3000並且恢復波尼的HP。\\n‧召喚波尼。\\n‧對敵方全體造成中幅度的物理傷害，\\n\u3000並降低行動速度，\\n\u3000並且大幅度提升我方全體的\\n\u3000物理攻擊力。');
insert into unit_enemy_data values (303800, '阿爾瑪', 303800, 0, 16, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】遠古時用來守護迷宮的防衛兵器。作為最後的陷阱，靜待入侵者。\\n・根據角色的最高 HP，對全體敵人\\n造成中幅度的魔法傷害。\\n・對前方範圍內的敵人造成中幅度的物理傷害。');
insert into unit_enemy_data values (303801, '阿爾瑪', 303800, 0, 16, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】遠古時用來守護迷宮的防衛兵器。作為最後的陷阱，靜待入侵者。\\n・根據角色的最高 HP，對全體敵人\\n造成特大幅度的魔法傷害。\\n・對前方範圍內的敵人造成中幅度的物理傷害。\\n・根據角色的最高 HP，對剩餘 HP 最高的敵人\\n造成中幅度的魔法傷害，並使其暈眩。\\n・當古老惡靈衛兵本身的 HP 降至 50％ 以下，\\n其攻擊力將會越發殘暴。');
insert into unit_enemy_data values (303900, '獨眼巨人', 303900, 0, 13, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】以怪力引以為傲，兇暴的獨眼巨人。\\n將魔力凝聚於瞳中，進而釋放強力的怪異光線。\\n\\n‧對全體敵人造成大幅度的魔法傷害。\\n\u3000對剩餘 HP 為 100% 的角色提升造成的傷害，\\n\u3000同時降低行動速度。\\n‧對物理攻擊力最高的 1 名角色，依照其最大 HP\\n\u3000造成中幅度的物理傷害，並且減少其 TP。');
insert into unit_enemy_data values (303901, '獨眼巨人', 303901, 0, 13, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】以怪力引以為傲，兇暴的獨眼巨人。\\n將魔力凝聚於瞳中，進而釋放強力的怪異光線。\\n\\n‧對敵方全體造成大幅度魔法傷害。\\n\u3000對剩餘HP為100%的角色提升傷害，\\n\u3000並且降低其行動速度。\\n‧對物理攻擊力最高的1名角色，依照其最大HP\\n\u3000造成中幅度的物理傷害，並且減少其TP。');
insert into unit_enemy_data values (303902, '獨眼巨人', 303902, 0, 13, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】以怪力引以為傲，兇暴的獨眼巨人。\\n將魔力凝聚於瞳中，進而釋放強力的怪異光線。\\n\\n‧對全體敵人造成大幅度的魔法傷害，同時解除\\n\u3000素質提升的效果。\\n\u3000並且降低行動速度。\\n\u3000對剩餘 HP 為 100% 的角色提升造成的傷害。\\n‧對物理攻擊力最高的 1 名角色，依照其最大 HP\\n\u3000造成中幅度的物理傷害，並且減少其 TP。\\n‧每當進行普通攻擊時，小幅度增加自己的 TP。');
insert into unit_enemy_data values (304000, '夢魘', 304000, 0, 13, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】誕生於幻想，徬徨於黑暗中的魔獸。\\n將獵物囚於惡夢之牢中，並大快朵頤那些精氣。\\n\\n‧對物理攻擊力最高的1名敵方角色造成特大幅度\\n\u3000的魔法傷害，同時特大幅度減少其TP。\\n‧無視敵方的挑釁，以距離最遠的1名敵方角色\\n\u3000為中心，對範圍內所有的敵人\\n\u3000施加詛咒狀態。\\n\u3000此技能施加的詛咒所造成的傷害\\n\u3000不會恢復TP。');
insert into unit_enemy_data values (304001, '夢魘', 304001, 0, 13, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】誕生於幻想，徬徨於黑暗中的魔獸。\\n將獵物囚於惡夢之牢中，並大快朵頤那些精氣。\\n\\n‧對物理攻擊力最高的1名敵方角色造成特大幅度\\n\u3000的魔法傷害，同時特大幅度減少其TP。\\n‧無視敵方的挑釁，以距離最遠的1名敵方角色\\n\u3000為中心，降低範圍內所有的敵人的TP，\\n\u3000並施加詛咒狀態。\\n\u3000此技能施加的詛咒所造成的傷害\\n\u3000不會恢復TP。');
insert into unit_enemy_data values (304100, '泰坦龍龜', 304100, 0, 13, 270, 1000, 1, 2.5, 0, 0, 0, '就連甲殼上都能扎起大樹之根的遠古陸龜。\\n持續忍受著攻擊，伺機用憤怒之擊還以顏色。\\n\\n・對敵方全體造成大量的物理傷害。\\n・將躲在甲殼裡時所受到的傷害量，給予敵人相\\n\u3000應的物理傷害。');
insert into unit_enemy_data values (304101, '泰坦龍龜', 304101, 0, 13, 270, 1000, 1, 0.1, 0, 0, 0, '【物理】甲殼甚至能讓大樹生根的巨型老陸龜。\\n持續忍受著攻擊，伺機用憤怒之擊還以顏色。\\n\\n‧對全體敵人造成中幅度的物理傷害。\\n‧依照縮進甲殼內時所受的傷害量，\\n\u3000對全體敵人造成物理傷害。\\n‧當全部的目標部位都被破壞時，\\n\u3000一定時間內將無法行動。\\n\u3000無法行動的期間，\\n\u3000降低自己100%的物理防禦力\\n\u3000與魔法防禦力。');
insert into unit_enemy_data values (304102, '泰坦龍龜', 304102, 0, 13, 270, 1000, 1, 0.1, 0, 0, 0, '【物理】甲殼甚至能讓大樹生根的巨型老陸龜。\\n持續忍受著攻擊，伺機用憤怒之擊還以顏色。\\n\\n‧對全體敵人造成中幅度的物理傷害。\\n‧依照縮進甲殼內時所受的傷害量，\\n\u3000對全體敵人造成物理傷害。\\n‧當全部的目標部位都被破壞時，\\n\u3000一定時間內將無法行動。\\n\u3000無法行動的期間，\\n\u3000降低自己100%的物理防禦力\\n\u3000與魔法防禦力。');
insert into unit_enemy_data values (304200, '加爾格', 304200, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】啃食屍體的殘暴的大型魔獸。\\n強韌的刺佈滿全身，追捕獵物的執念甚深。\\n・根據角色的最高 HP，對全體敵人\\n造成中幅度的物理傷害。\\n・對後方範圍的敵人造成中幅度的物理傷害，\\n並使其暈眩。');
insert into unit_enemy_data values (304201, '加爾格', 304200, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】啃食屍體的殘暴的大型魔獸。\\n強韌的刺佈滿全身，追捕獵物的執念甚深。\\n・根據角色的最高 HP，對全體敵人\\n造成中幅度的物理傷害。\\n・對後方範圍的敵人造成中幅度的物理傷害，\\n並使其暈眩。\\n・對前方數來第 2 名的敵人造成大幅度的物理傷害。\\n・當加爾格本身的 HP 降至 50％ 以下，\\n其攻擊力將會越發殘暴。');
insert into unit_enemy_data values (304300, '天塔帕斯', 304300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】君臨於海邊的巨大軟體魔獸。\\n強韌的觸手與鋼鐵的大矛將把一切破壞殆盡。\\n・對敵方全體角色依照最大HP造成\\n\u3000大幅度的物理傷害。\\n・對後方範圍內造成中幅度的魔法傷害、\\n\u3000賦予麻痺狀態，並特大幅度降低物理攻\\n\u3000力及魔法攻擊力。\\n・經過一定時間後對敵方單體\\n\u3000造成超特大幅度的物理傷害。\\n・當天塔帕斯自身的HP低於40％後，\\n\u3000其攻擊將會變得越發殘暴。');
insert into unit_enemy_data values (304301, '天塔帕斯', 304300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】君臨於海邊的巨大軟體魔獸。\\n強韌的觸手與鋼鐵的大矛將把一切破壞殆盡。\\n・對敵方全體角色依照最大HP造成\\n\u3000大幅度的物理傷害。\\n・對後方範圍內造成中幅度的魔法傷害、\\n\u3000賦予麻痺狀態，並特大幅度降低物理攻\\n\u3000力及魔法攻擊力。');
insert into unit_enemy_data values (304302, '天塔帕斯', 304300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】君臨於海邊的巨大軟體魔獸。\\n強韌的觸手與鋼鐵的大矛將把一切破壞殆盡。\\n・對敵方全體角色依照最大HP造成\\n\u3000大幅度的物理傷害。\\n・對後方範圍內造成中幅度的魔法傷害、\\n\u3000賦予麻痺狀態，並特大幅度降低物理攻\\n\u3000力及魔法攻擊力。\\n・當天塔帕斯自身的HP低於40％後，\\n\u3000其攻擊將會變得越發殘暴。');
insert into unit_enemy_data values (304303, '天塔帕斯', 304300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】君臨於海邊的巨大軟體魔獸。\\n強韌的觸手與鋼鐵的大矛將把一切破壞殆盡。\\n・對敵方全體角色依照最大HP造成\\n\u3000大幅度的物理傷害。\\n・對後方範圍內造成中幅度的魔法傷害、\\n\u3000賦予麻痺狀態，並特大幅度降低物理攻\\n\u3000力及魔法攻擊力。\\n・經過一定時間後對敵方單體\\n\u3000造成超特大幅度的物理傷害。\\n・當天塔帕斯自身的HP低於40％後，\\n\u3000其攻擊將會變得越發殘暴。');
insert into unit_enemy_data values (304304, '奧克塔斯基德', 304304, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】計畫利用塔的力量向人類復仇的軟體魔獸。\\n年輕時被魚叉刺中的仇恨，比大海還要深。\\n\\n‧對全體敵人造成大幅度的物理傷害。\\n‧對前方數來第3名之後的敵人造成中幅度的\\n\u3000魔法傷害，中幅度降低物理防禦力與行動速度。\\n\u3000並且解除素質提升效果。\\n‧對剩餘HP最多的敵人依照其剩餘HP\\n\u3000造成大幅度的物理傷害，中幅度降低TP。');
insert into unit_enemy_data values (304400, '島鯨', 304400, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】將為數眾多的探險家給吞噬的幻島之巨鯨。無慈悲地葬送了那些被慾望、幻想給憑依的愚者。\\n\\n‧對全體敵人依照其最大HP造成大幅度的\\n\u3000物理傷害。\\n‧對全體敵人造成中幅度的魔法傷害，\\n\u3000並且對島鯨自身的物理防禦力、\\n\u3000魔法防禦力給予極大幅度的上升。\\n‧對前方數來第3名角色造成大幅度的魔法傷害，\\n\u3000並且大幅度將其擊飛。\\n‧當島鯨自身的HP低於40%時，\\n\u3000牠的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (304401, '島鯨', 304400, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】將為數眾多的探險家給吞噬的幻島之巨鯨。無慈悲地葬送了那些被慾望、幻想給憑依的愚者。\\n\\n‧對全體敵人依照其最大HP造成大幅度的\\n\u3000物理傷害。\\n‧對全體敵人造成中幅度的魔法傷害，\\n\u3000並且對島鯨自身的物理防禦力、\\n\u3000魔法防禦力給予極大幅度的上升。');
insert into unit_enemy_data values (304402, '島鯨', 304400, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】將為數眾多的探險家給吞噬的幻島之巨鯨。無慈悲地葬送了那些被慾望、幻想給憑依的愚者。\\n\\n‧對全體敵人依照其最大HP造成大幅度的\\n\u3000物理傷害。\\n‧對全體敵人造成中幅度的魔法傷害，\\n\u3000並且對島鯨自身的物理防禦力、\\n\u3000魔法防禦力給予極大幅度的上升。\\n‧對前方數來第3名角色造成大幅度的魔法傷害，\\n\u3000並且大幅度將其擊飛。\\n‧當島鯨自身的HP低於40%時，\\n\u3000牠的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (304403, '島鯨', 304400, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】將為數眾多的探險家給吞噬的幻島之巨鯨。無慈悲地葬送了那些被慾望、幻想給憑依的愚者。\\n\\n‧對全體敵人依照其最大HP造成大幅度的\\n\u3000物理傷害。\\n‧對全體敵人造成中幅度的魔法傷害，\\n\u3000並且對島鯨自身的物理防禦力、\\n\u3000魔法防禦力給予極大幅度的上升。\\n‧對前方數來第3名角色造成大幅度的魔法傷害，\\n\u3000並且大幅度將其擊飛。\\n‧當島鯨自身的HP低於40%時，\\n\u3000牠的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (304500, '雷電', 304500, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】以熟練的戰鬥術來玩弄敵人的鍬形蟲魔物。\\n面對纏繞著豪雷的招式，被麻痺者接踵而出。\\n\\n‧必殺技會對前方2名角色造成中幅度的\\n\u3000物理傷害，並造成麻痺。\\n\u3000並且大幅度降低敵方全體的行動速度後，\\n\u3000中幅度降低自身的物理防禦力和魔法防禦力。\\n‧一定時間內，特大幅度提升自身的物理防禦力與\\n\u3000魔法防禦力。');
insert into unit_enemy_data values (304600, '雷雷', 304600, 0, 16, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】使喚著雷雲，天真無邪地四處大鬧的雷少女。\\n若大意了，可會被賞上好幾發毫不留情的雷擊。\\n\\n‧必殺技會對敵方全體造成中幅度的魔法傷害。\\n‧對後方2名角色造成小幅度的魔法傷害。');
insert into unit_enemy_data values (304601, '雷雷', 304601, 0, 16, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】使喚著雷雲，天真無邪地四處大鬧的雷少女。\\n若大意了，可會被賞上好幾發毫不留情的雷擊。\\n\\n‧必殺技會對敵方全體造成中幅度的\\n\u3000魔法傷害，並且使其陷入暈眩。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧對後方2名角色造成小幅度的魔法傷害，\\n\u3000並且小幅度降低TP。');
insert into unit_enemy_data values (304602, '雷雷', 304602, 0, 16, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】使喚著雷雲，天真無邪地四處大鬧的雷娘。\\n若大意了，可會被賞上好幾發毫不留情的雷擊。\\n\\n‧對全體敵人造成中幅度的魔法傷害。\\n‧對後方2名角色造成小幅度的魔法傷害。');
insert into unit_enemy_data values (304700, '亡靈鎧甲', 304700, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】吞噬金屬，並操縱武器的謎樣魔物。\\n透過增生融合成為超大的怪物，並威脅著和平。\\n・對敵方全體角色依照最大HP造成\\n\u3000大幅度的物理傷害，並大幅度的降低物理攻\\n\u3000擊力及物理防禦力。\\n・對前方範圍內造成大幅度的物理傷害。\\n・減少TP最高的敵方3名角色的TP，\\n\u3000並大幅提升自身的物理攻擊力。\\n・當亡靈鎧甲自身的HP低於40％後，\\n\u3000其攻擊將會變得越發殘暴。');
insert into unit_enemy_data values (304701, '亡靈鎧甲', 304700, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】吞噬金屬，並操縱武器的謎樣魔物。\\n透過增生融合成為超大的怪物，並威脅著和平。\\n・對敵方全體角色依照最大HP造成\\n\u3000大幅度的物理傷害，並大幅度的降低物理攻\\n\u3000擊力及物理防禦力。\\n・對前方範圍內造成大幅度的物理傷害。');
insert into unit_enemy_data values (304702, '亡靈鎧甲', 304700, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】吞噬金屬，並操縱武器的謎樣魔物。\\n透過增生融合成為超大的怪物，並威脅著和平。\\n・對敵方全體角色依照最大HP造成\\n\u3000大幅度的物理傷害，並大幅度的降低物理攻\\n\u3000擊力及物理防禦力。\\n・對前方範圍內造成大幅度的物理傷害。\\n・減少TP最高的敵方3名角色的TP，\\n\u3000並大幅提升自身的物理攻擊力。\\n・當亡靈鎧甲自身的HP低於40％後，\\n\u3000其攻擊將會變得越發殘暴。');
insert into unit_enemy_data values (304703, '亡靈鎧甲', 304700, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】吞噬金屬，並操縱武器的謎樣魔物。\\n透過增生融合成為超大的怪物，並威脅著和平。\\n・對敵方全體角色依照最大HP造成\\n\u3000大幅度的物理傷害，並大幅度的降低物理攻\\n\u3000擊力及物理防禦力。\\n・對前方範圍內造成大幅度的物理傷害。\\n・減少TP最高的敵方3名角色的TP，\\n\u3000並大幅提升自身的物理攻擊力。\\n・當亡靈鎧甲自身的HP低於40％後，\\n\u3000其攻擊將會變得越發殘暴。');
insert into unit_enemy_data values (304704, '壞亂黑鎧騎士', 304704, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】貪食著露娜之塔的魔力，不斷增生融合\\n的謎之魔物。對所有的事物進行無差別的碾碎。\\n\\n‧對全體敵人造成大幅度物理傷害，\\n\u3000並且中幅度降低其物理防禦力。\\n・對前方範圍內的敵人造成物理傷害，\\n\u3000並同時對其中 2 名物理攻擊力較為高的角色，\\n\u3000使其物理攻擊力大幅度降低，且同時特\\n\u3000大幅度減少其TP。\\n\u3000使自己物理防禦力大幅度減少。\\n‧對前方 3 名敵人造成中幅度的物理傷害，\\n\u3000並中幅度提升自己的物理攻擊力。');
insert into unit_enemy_data values (304705, '亡靈鎧甲', 304705, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】吞噬著金屬，且操使武具的謎之魔物。\\n因增殖融合而成為了巨大的怪物，威脅著和平。\\n\\n‧必殺技能夠對全體敵人\\n\u3000依照其最大HP造成大幅度的物理傷害，\\n\u3000同時大幅度降低物理攻擊力與物理防禦力。\\n‧對前方的3名角色造成大幅度的物理傷害。\\n‧使敵方TP最高的3名角色的TP減少，\\n\u3000並使自身的物理攻擊力大幅度上升。\\n‧當亡靈鎧甲自身的HP低於40%時，\\n\u3000它的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (304706, '亡靈鎧甲', 304705, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】吞噬著金屬，且操使武具的謎之魔物。\\n因增殖融合而成為了巨大的怪物，威脅著和平。\\n\\n‧必殺技能夠對全體敵人\\n\u3000依照其最大HP造成大幅度的物理傷害，\\n\u3000同時大幅度降低物理攻擊力與物理防禦力。\\n‧對前方的3名角色造成大幅度的物理傷害。');
insert into unit_enemy_data values (304707, '亡靈鎧甲', 304705, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】吞噬著金屬，且操使武具的謎之魔物。\\n因增殖融合而成為了巨大的怪物，威脅著和平。\\n\\n‧必殺技能夠對全體敵人\\n\u3000依照其最大HP造成大幅度的物理傷害，\\n\u3000同時大幅度降低物理攻擊力與物理防禦力。\\n‧使敵方HP比例最高的3名角色的TP減少，\\n\u3000並將其擊退。\\n\u3000同時再大幅度提升自己的物理攻擊力。\\n‧對前方的3名角色造成大幅度的物理傷害。\\n‧當亡靈鎧甲自身的HP低於40%時，\\n\u3000它的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (304708, '亡靈鎧甲', 304705, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】吞噬著金屬，且操使武具的謎之魔物。\\n因增殖融合而成為了巨大的怪物，威脅著和平。\\n\\n‧必殺技能夠對全體敵人\\n\u3000依照其最大HP造成大幅度的物理傷害，\\n\u3000同時大幅度降低物理攻擊力與物理防禦力。\\n‧使敵方HP比例最高的3名角色的TP減少，\\n\u3000並將其擊退。\\n\u3000同時再大幅度提升自己的物理攻擊力。\\n‧對前方的3名角色造成大幅度的物理傷害。\\n‧當亡靈鎧甲自身的HP低於40%時，\\n\u3000它的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (304800, '亡魂支配者', 304800, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】將強者之魂作為幽鬼使喚的冥府高官。\\n以亡者意念糾纏刀刃，使敵方行動更為遲鈍。\\n\\n‧戰鬥開始時，小幅度提升自身的\\n\u3000物理防禦力和魔法防禦力。\\n\u3000以此防禦力提升效果上升的防禦力\\n\u3000不會受到戰鬥中被施加的\\n\u3000降低防禦力技能的影響。\\n‧必殺技無視挑釁，對物理攻擊力最高的1名角色\\n\u3000及魔法攻擊力最高的1名角色\\n\u3000造成大幅度的魔法傷害。\\n\u3000此技能造成的傷害不會恢復TP。\\n‧對前方範圍內的全體敵人\\n\u3000造成中幅度的魔法傷害，\\n\u3000並且大幅度降低物理攻擊力與行動速度。');
insert into unit_enemy_data values (304801, '亡魂支配者', 304801, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】將強者之魂作為幽鬼使喚的冥府高官。\\n以亡者意念糾纏刀刃，使敵方行動更為遲鈍。\\n\\n‧戰鬥開始時，中幅度提升自身的\\n\u3000物理防禦力和魔法防禦力。\\n\u3000以此防禦力提升效果上升的防禦力\\n\u3000不會受到戰鬥中被施加的\\n\u3000降低防禦力技能的影響。\\n‧必殺技無視挑釁，對物理攻擊力最高的1名角色\\n\u3000及魔法攻擊力最高的1名角色\\n\u3000造成大幅度的魔法傷害。\\n\u3000此技能造成的傷害不會恢復TP。\\n‧對前方範圍內的全體敵人\\n\u3000造成中幅度的魔法傷害，\\n\u3000並且大幅度降低物理攻擊力與行動速度。');
insert into unit_enemy_data values (304802, '噬魂者', 304802, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】藉由塔之魔力甦醒，貪戀生者魔力，\\n四處徘徊的惡靈。會揮舞纏繞著幽鬼怨念\\n的大鐮刀，無差別地收割生者的靈魂。\\n\\n‧對前方的範圍內造成大幅度的魔法傷害，\\n\u3000特大幅度降低其物理攻擊力。\\n‧對前方的範圍內造成中幅度的魔法傷害。\\n\u3000對進行物理攻擊的敵人造成追加的魔法傷害，\\n\u3000並且降低其行動速度。\\n‧對前方的範圍內造成中幅度的物理傷害，\\n\u3000解除其能力提升效果。');
insert into unit_enemy_data values (304900, '電光・怪人', 304900, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】由於露娜的魔力而甦醒，巨腕的改造人類。\\n小型反應爐於最大能量輸出時，甚至能使自身感電。\\n\\n・對前方範圍內的敵人造成大量物理傷害＆麻痺。\\n\u3000將自己身上的素質降低效果給解除，並使\\n\u3000其物理、魔法防禦力中量的下降。\\n・對敵方全體造成大量的魔法傷害，\\n\u3000並對自身物理攻擊力長時間大幅上升。\\n・使己方全體行動速度大幅度上升。');
insert into unit_enemy_data values (305000, '傑克南瓜布丁', 305000, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】企圖對人類進行復仇，靈界的住民。\\n「我乃傑克！傑克南瓜布丁！\\n\u3000若不和我玩的話，我可就要搗蛋囉～」\\n\\n・對敵方全體造成大量的物理傷害，\\n\u3000且當該角色的HP低於40%之時，使其陷入\\n\u3000誘惑狀態。\\n・對敵方全體造成小量的魔法傷害，\\n\u3000並使該角色的素質提升效果解除。\\n・對最接近的敵人造成中量的物理傷害，\\n\u3000並對最前方的3名角色，造成中量的\\n\u3000物理傷害＆暈眩。\\n・當傑克南瓜布丁自身的HP低於40%之\\n\u3000時，他的攻擊將會變得更加兇暴。\\n');
insert into unit_enemy_data values (305001, '傑克南瓜布丁', 305000, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】企圖對人類進行復仇，靈界的住民。\\n「我乃傑克！傑克南瓜布丁！\\n\u3000若不和我玩的話，我可就要搗蛋囉～」\\n\\n・對敵方全體造成大量的物理傷害，\\n\u3000且當該角色的HP低於40%之時，使其陷入\\n\u3000誘惑狀態。\\n・對最接近的敵人造成中量的物理傷害，\\n\u3000並對最前方的3名角色，造成中量的\\n\u3000物理傷害＆暈眩。\\n');
insert into unit_enemy_data values (305002, '傑克南瓜布丁', 305000, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】企圖對人類進行復仇，靈界的住民。\\n「我乃傑克！傑克南瓜布丁！\\n\u3000若不和我玩的話，我可就要搗蛋囉～」\\n\\n・對敵方全體造成大量的物理傷害，\\n\u3000且當該角色的HP低於40%之時，使其陷入\\n\u3000誘惑狀態。\\n・對敵方全體造成小量的魔法傷害，\\n\u3000並使該角色的素質提升效果解除。\\n・對最接近的敵人造成中量的物理傷害，\\n\u3000並對最前方的3名角色，造成中量的\\n\u3000物理傷害＆暈眩。\\n・當傑克南瓜布丁自身的HP低於40%之\\n\u3000時，他的攻擊將會變得更加兇暴。\\n');
insert into unit_enemy_data values (305003, '傑克南瓜布丁', 305000, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】企圖對人類進行復仇，靈界的住民。\\n「我乃傑克！傑克南瓜布丁！\\n\u3000若不和我玩的話，我可就要搗蛋囉～」\\n\\n・對敵方全體造成大量的物理傷害，\\n\u3000且當該角色的HP低於40%之時，使其陷入\\n\u3000誘惑狀態。\\n・對敵方全體造成小量的魔法傷害，\\n\u3000並使該角色的素質提升效果解除。\\n・對最接近的敵人造成中量的物理傷害，\\n\u3000並對最前方的3名角色，造成中量的\\n\u3000物理傷害＆暈眩。\\n・當傑克南瓜布丁自身的HP低於40%之\\n\u3000時，他的攻擊將會變得更加兇暴。\\n');
insert into unit_enemy_data values (305004, '傑克南瓜布丁', 305004, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】企圖對人類進行復仇，靈界的住民。\\n「我乃傑克！傑克南瓜布丁！\\n\u3000若不和我玩的話，我可就要搗蛋囉～」\\n\\n‧對全體敵人依照其最大HP\\n\u3000造成大幅度的物理傷害，\\n\u3000同時若角色的HP低於40%之時，\\n\u3000使其陷入誘惑狀態。\\n‧對敵方全體造成小幅度的魔法傷害，\\n\u3000並使該角色的素質提升效果解除。\\n‧對最接近的敵人造成中幅度的物理傷害，\\n\u3000並對最前方的3名角色，造成中幅度的\\n\u3000物理傷害&暈眩。\\n‧當傑克南瓜布丁自身的HP\\n\u3000低於40%之時，他的攻擊\\n\u3000將會變得更加兇暴。\\n');
insert into unit_enemy_data values (305005, '傑克南瓜布丁', 305004, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】企圖對人類進行復仇，靈界的住民。\\n「我乃傑克！傑克南瓜布丁！\\n\u3000若不和我玩的話，我可就要搗蛋囉～」\\n\\n‧必殺技能夠對全體敵人依照其最大HP\\n\u3000造成中幅度的物理傷害，\\n\u3000同時若角色的HP低於40%時，\\n\u3000使其陷入誘惑狀態。\\n‧對距離最近的敵人造成大幅度的\\n\u3000物理傷害，同時對前方3名角色，\\n\u3000造成中幅度的物理傷害&暈眩。\\n');
insert into unit_enemy_data values (305006, '傑克南瓜布丁', 305004, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】企圖對人類進行復仇，靈界的住民。\\n「我乃傑克！傑克南瓜布丁！\\n\u3000若不和我玩的話，我可就要搗蛋囉～」\\n\\n‧必殺技能夠對全體敵人依照其最大HP\\n\u3000造成中幅度的物理傷害，\\n\u3000同時若角色的HP低於40%時，\\n\u3000使其陷入誘惑狀態。\\n‧對全體敵人造成小幅度的魔法傷害，\\n\u3000並使該角色的素質提升效果解除。\\n‧對距離最近的敵人造成大幅度的\\n\u3000物理傷害，同時對前方3名角色，\\n\u3000造成中幅度的物理傷害&暈眩。\\n‧當傑克南瓜布丁自身的HP\\n\u3000低於40%時，他的攻擊\\n\u3000將會變得更加兇暴。\\n');
insert into unit_enemy_data values (305007, '傑克南瓜布丁', 305004, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】企圖對人類進行復仇，靈界的住民。\\n「我乃傑克！傑克南瓜布丁！\\n\u3000若不和我玩的話，我可就要搗蛋囉～」\\n\\n‧必殺技能夠對全體敵人依照其最大HP\\n\u3000造成中幅度的物理傷害，\\n\u3000同時若角色的HP低於40%時，\\n\u3000使其陷入誘惑狀態。\\n‧對全體敵人造成小幅度的魔法傷害，\\n\u3000並使該角色的素質提升效果解除。\\n‧對距離最近的敵人造成大幅度的\\n\u3000物理傷害，同時對前方3名角色，\\n\u3000造成中幅度的物理傷害&暈眩。\\n‧當傑克南瓜布丁自身的HP\\n\u3000低於40%時，他的攻擊\\n\u3000將會變得更加兇暴。\\n');
insert into unit_enemy_data values (305100, '獨角兔', 305100, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】利用那巨大身體為非作歹的巨兔魔物。\\n重複打出的一擊消耗劇烈，似乎是精力過剩。\\n\\n‧必殺技能夠對全體敵人造成大幅度的\\n\u3000物理傷害，並且造成擊退。\\n\u3000之後，在頭暈目眩期間，將大幅度降低\\n\u3000自己的物理防禦力與魔法防禦力。\\n‧對全體敵人造成中幅度的物理傷害，同時\\n\u3000對前方範圍內的敵人造成暈眩。\\n\u3000此技能所造成的狀態異常，同時也會使傷害\\n\u3000無效化。');
insert into unit_enemy_data values (305101, '獨角兔', 305100, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】驅使巨大的身體為非作歹，\\n一種巨兔魔物。接二連三的每一擊\\n消耗甚大，使人難以招架。\\n\\n‧對全體敵人造成大幅度的\\n\u3000物理傷害，同時擊退。\\n\u3000發動技能後，在頭暈目眩期間內，\\n\u3000大幅度降低自身的物理防禦力\\n\u3000與魔法防禦力。\\n\\n‧對全體敵人造成中幅度的物理傷害，\\n\u3000同時對前方範圍內的敵人造成\\n\u3000暈眩。');
insert into unit_enemy_data values (305102, '獨角兔', 305102, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】利用那巨大身體為非作歹的巨兔魔物。\\n重複打出的一擊消耗劇烈，似乎是精力過剩。\\n\\n‧戰鬥開始時，小幅度提升自身的物理防禦力和\\n\u3000魔法防禦力。\\n\u3000以此防禦力提升效果上升的防禦力\\n\u3000不會受到戰鬥中被施加的降低防禦力技能的\\n\u3000影響。\\n‧必殺技能夠對敵方全體造成大幅度的\\n\u3000物理傷害，並且造成擊退。\\n\u3000之後，在頭暈目眩期間，將特大幅度降低\\n\u3000自己的物理防禦力與魔法防禦力。\\n\u3000然後，小幅度降低自己的\\n\u3000物理防禦力與魔法防禦力。\\n\u3000自己的物理防禦力與魔法防禦力。\\n\u3000此技能所造成的狀態異常，同時也會使傷害\\n\u3000無效化。\\n\u3000此技能造成的傷害不會\\n\u3000恢復TP。\\n‧對敵方全體造成中幅度的物理傷害，同時\\n\u3000對前方範圍內的敵人造成暈眩。\\n\u3000並且在那之後，中幅度恢復自身的 TP。\\n\u3000此技能所造成的狀態異常，同時也會使傷害\\n\u3000無效化。\\n‧普通攻擊將會對站在前方的角色造成大幅度的\\n\u3000物理傷害，同時造成擊退。\\n\u3000此技能所造成的狀態異常，同時也會使傷害\\n\u3000無效化。');
insert into unit_enemy_data values (305200, '奧拉姆', 305200, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】在遠古之前便被生產出的防衛兵器。\\n因惡黨的陰謀，迎來了那悠久之沉睡的終焉。\\n\\n‧對全體敵人造成對應最大 HP 的\\n\u3000大幅度物理傷害，\\n\u3000同時大幅度降低自己的物理攻擊力。\\n‧對前方中範圍內的敵人造成中幅度的物理傷害，\\n\u3000並大幅度降低其物理攻擊力。\\n‧對前方廣範圍內的敵人造成中幅度的物理傷害，\\n\u3000並施加麻痺狀態。\\n\u3000當該角色的 HP 低於 70% 以下時，\\n\u3000麻痺的效果時間將會延長。\\n‧當奧拉姆自身的 HP 低於 40% 之時，\\n\u3000它的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (305201, '奧拉姆', 305200, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】在遠古之前便被鍛造而出的防衛兵器。\\n因惡黨的陰謀，迎來了那悠久之沉睡的終焉。\\n\\n・對敵方全體角色造成相應於最大HP的\\n\u3000大量物理傷害之際，使得自身\u3000\\n的物理攻擊力也受到大幅度下降。\\n・對前方中範圍內的敵人造成中量物理傷害，\\n\u3000使其物理攻擊力大幅下降。');
insert into unit_enemy_data values (305202, '奧拉姆', 305200, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】在遠古之前便被生產出的防衛兵器。\\n因惡黨的陰謀，迎來了那悠久之沉睡的終焉。\\n\\n‧對全體敵人造成對應最大 HP 的\\n\u3000大幅度物理傷害，\\n\u3000同時大幅度降低自己的物理攻擊力。\\n‧對前方中範圍內的敵人造成中幅度的物理傷害，\\n\u3000並大幅度降低其物理攻擊力。\\n‧對前方廣範圍內的敵人造成中幅度的物理傷害，\\n\u3000並施加麻痺狀態。\\n\u3000當該角色的 HP 低於 70% 以下時，\\n\u3000麻痺的效果時間將會延長。\\n‧當奧拉姆自身的 HP 低於 40% 之時，\\n\u3000它的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (305203, '奧拉姆', 305200, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】在遠古之前便被生產出的防衛兵器。\\n因惡黨的陰謀，迎來了那悠久之沉睡的終焉。\\n\\n‧對全體敵人造成對應最大 HP 的\\n\u3000大幅度物理傷害，\\n\u3000同時大幅度降低自己的物理攻擊力。\\n‧對前方中範圍內的敵人造成中幅度的物理傷害，\\n\u3000並大幅度降低其物理攻擊力。\\n‧對前方廣範圍內的敵人造成中幅度的物理傷害，\\n\u3000並施加麻痺狀態。\\n\u3000當該角色的 HP 低於 70% 以下時，\\n\u3000麻痺的效果時間將會延長。\\n‧當奧拉姆自身的 HP 低於 40% 之時，\\n\u3000它的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (305204, '詛咒・奧拉姆', 305204, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】因為露娜之塔的魔力暴走的，古代兵器。\\n古老的守護之力，散布詛咒變成了災難。\\n\\n‧對全體敵人造成大幅度的魔法傷害，並大幅度降\u3000低自己的物理防禦力與魔法防禦力。\\n・對前方１名角色為中心的範圍內全體敵人，\\n\u3000造成中幅度的物理傷害，\\n\u3000中幅度的物理防禦力下降，並使其暈眩。\\n‧對全體敵人造成中幅度的物理傷害，\\n\u3000並施加詛咒狀態。角色的ＨＰ低於40％\\n\u3000的狀況下，詛咒的傷害會變成２倍。');
insert into unit_enemy_data values (305205, '奧拉姆', 305205, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】在遠古之前便被生產出的防衛兵器。\\n因惡黨的陰謀，迎來了那悠久之沉睡的終焉。\\n\\n‧必殺技能夠對全體敵人造成\\n對應該角色最大 HP 的大幅度物理傷害，\\n同時大幅度降低自己的物理攻擊力。\\n‧對前方中範圍內的敵人造成中幅度的物理傷害，\\n\u3000並大幅度降低其物理攻擊力。\\n‧對前方大範圍內的敵人造成中幅度的物理傷害，\\n\u3000並施加麻痺狀態。\\n\u3000當該角色的 HP 低於 70% 以下時，\\n\u3000麻痺效果的時間將會延長。\u3000\\n\u3000當奧拉姆自身的 HP 低於 40% 之時，\\n\u3000它的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (305206, '奧拉姆', 305205, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】在遠古之前就被生產出來的防衛兵器。\\n因惡黨的陰謀，迎來了那悠久之沉睡的終焉。\\n\\n‧必殺技能夠對全體敵人造成\\n\u3000對應該角色最大 HP 的大幅度物理傷害，\\n\u3000同時大幅度降低自己的物理攻擊力。\\n‧對前方中範圍內的敵人造成大幅度的物理傷害，\\n\u3000並且大幅度降低其物理攻擊力。');
insert into unit_enemy_data values (305207, '奧拉姆', 305205, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】在遠古之前便被生產出的防衛兵器。\\n因惡黨的陰謀，迎來了那悠久之沉睡的終焉。\\n\\n‧必殺技能夠對全體敵人造成\\n\u3000對應該角色最大 HP 的大幅度物理傷害，\\n\u3000同時大幅度降低自己的物理攻擊力。\\n‧對前方中範圍內的敵人造成大幅度的物理傷害，\\n\u3000並大幅度降低其物理攻擊力。\\n‧對前方大範圍內的敵人造成大幅度的物理傷害，\\n\u3000並施加麻痺狀態。\\n\u3000當該角色的 HP 低於 70% 以下時，\\n\u3000麻痺效果的時間將會延長。\\n‧當奧拉姆自身的 HP 低於 40% 之時，\\n\u3000它的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (305208, '奧拉姆', 305205, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】在遠古之前便被生產出的防衛兵器。\\n因惡黨的陰謀，迎來了那悠久之沉睡的終焉。\\n\\n‧必殺技能夠對全體敵人造成\\n\u3000對應該角色最大 HP 的大幅度物理傷害，\\n\u3000同時大幅度降低自己的物理攻擊力。\\n‧對前方中範圍內的敵人造成大幅度的物理傷害，\\n\u3000並大幅度降低其物理攻擊力。\\n‧對前方大範圍內的敵人造成大幅度的物理傷害，\\n\u3000並施加麻痺狀態。\\n\u3000當該角色的 HP 低於 70% 以下時，\\n\u3000麻痺效果的時間將會延長。\\n‧當奧拉姆自身的 HP 低於 40% 之時，\\n\u3000它的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (305300, '高等加爾格', 305300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】身負露娜之魔力而產生變異的猙獰魔獸。\\n那尖銳的利牙，就連歷練的冒險家都能輕易撕裂。\\n\\n・必殺技能對敵方全體造成大量的物理傷害，並且\\n\u3000使自身的HP恢復。\\n・對後方範圍內的敵人造成物理傷害，使其暈眩。\\n\u3000\u3000並且使敵方全體的物理防禦力中幅度下降。\\n・對前方範圍內的敵人造成物理傷害，使其中毒。');
insert into unit_enemy_data values (305301, '寒冰加爾格', 305301, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】棲息於雪山中的凶猛魔狼。\\n堅韌的利牙甚至能輕易將\\n身經百戰的冒險者變成冰塊的墓碑。\\n\\n‧必殺技會對敵方全體造成\\n\u3000大幅度的物理傷害\\n\\n‧以最後方的敵方角色為中心，\\n\u3000對範圍內的所有敵人造成小幅度的\\n\u3000物理傷害，並使其暈眩。\\n\u3000同時中幅度降低敵方全體的\\n\u3000物理防禦力。\\n\\n‧對前方範圍內的所有敵人\\n\u3000造成小幅度的物理傷害，\\n\u3000並使其陷入中毒狀態。');
insert into unit_enemy_data values (305302, '寒冰加爾格', 305301, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】棲息於雪山中的凶猛魔狼。\\n堅韌的利牙甚至能輕易將\\n身經百戰的冒險者變成冰塊的墓碑。\\n\\n‧必殺技會對敵方全體造成\\n\u3000大幅度的物理傷害\\n\\n‧以最後方的敵方角色為中心，\\n\u3000對範圍內的所有敵人造成小幅度的\\n\u3000物理傷害，並使其暈眩。\\n\u3000同時中幅度降低敵方全體的\\n\u3000物理防禦力。\\n\\n‧對前方範圍內的所有敵人\\n\u3000造成小幅度的物理傷害，\\n\u3000並使其陷入中毒狀態。');
insert into unit_enemy_data values (305400, '冰角', 305400, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】此獨角獸那強力的尖刺，\\n就算再牢固的盾也能貫穿。\\n牠會將冒險者逼到北方的冰丘上，\\n再一舉推下至那冰獄。\\n\\n‧對全體敵人造成大幅度的魔法傷害，\\n\u3000並降低其魔法防禦力。\\n\u3000同時提升所有夥伴的\\n\u3000TP 上升率。\\n\\n‧對前方小範圍內造成小幅度魔法傷害，\\n\u3000並且使其陷入凍結狀態。\\n\u3000同時對全體造成小幅度的魔法傷害，\\n\u3000再將前方 3 名角色\\n\u3000稍微擊飛。');
insert into unit_enemy_data values (305500, '霧奇', 305500, 0, 16, 270, 2160, 2, 3.0, 0, 0, 0, '【魔法】在許多的傳說之中留下名號，記憶的大精靈。\\n如霧狀般的不具實體，可將一切覆蓋隱藏。\\n\\n‧必殺技可對所有敵人\\n\u3000造成大幅度的魔法傷害，\\n\u3000當敵人處於詛咒狀態時，\\n\u3000傷害會上升。\\n‧對全體敵人造成中幅度的魔法傷害。\\n\u3000並且施加詛咒狀態。\\n‧從分身體（紫）（紅）（藍）之中\\n\u3000任意召喚 1 匹。\\n\u3000召喚時將全體敵人擊退。\\n‧【物理】分身體（紫）可對自己展開\\n\u3000吸收物理/魔法的屏障。\\n‧【物理】分身體（紅）可對全體敵人\\n\u3000造成中幅度的魔法傷害。\\n‧【物理】分身體（藍）可對全體敵人\\n\u3000造成中幅度的魔法傷害。\\n\u3000再施加詛咒狀態。\\n\u3000分身體（藍） 的 HP 在 30% 以下時，\\n\u3000恢復霧奇的 300 TP。\\n‧當霧奇自身的 HP 低於 \\n\u300050% 時，牠的攻擊將會\\n\u3000變得更加兇暴。');
insert into unit_enemy_data values (305501, '霧奇', 305500, 0, 16, 270, 2160, 2, 3.0, 0, 0, 0, '【魔法】在許多的傳說之中留下名號，記憶的大精靈。\\n如霧狀般的不具實體，可將一切覆蓋隱藏。\\n\\n‧必殺技可對所有敵人\\n\u3000造成大幅度的魔法傷害，\\n\u3000當敵人處於詛咒狀態時，\\n\u3000傷害會上升。\\n‧對全體敵人造成中幅度的魔法傷害，\\n\u3000並且施加詛咒狀態。\\n‧從分身體（紫）（紅）之中\\n\u3000任意召喚 1 匹。\\n\u3000召喚時將全體敵人擊退。\\n‧【物理】分身體（紫）可對自己展開\\n\u3000吸收物理/魔法的屏障。\\n‧【物理】分身體（紅）可對全體敵人\\n\u3000造成中幅度的魔法傷害。');
insert into unit_enemy_data values (305502, '霧奇', 305500, 0, 16, 270, 2160, 2, 3.0, 0, 0, 0, '【魔法】在許多的傳說之中留下名號，記憶的大精靈。\\n如霧狀般的不具實體，可將一切覆蓋隱藏。\\n\\n‧必殺技可對所有敵人\\n\u3000造成大幅度的魔法傷害，\\n\u3000當敵人處於詛咒狀態時，\\n\u3000傷害會上升。\\n‧對全體敵人造成中幅度的魔法傷害，\\n\u3000並且施加詛咒狀態。\\n‧從分身體（紫）（紅）之中\\n\u3000任意召喚 1 匹。\\n\u3000召喚時將全體敵人擊退。\\n‧【物理】分身體（紫）可對自己展開\\n\u3000吸收物理/魔法的屏障。\\n‧【物理】分身體（紅）可對全體敵人\\n\u3000造成中幅度的魔法傷害。\\n‧當霧奇自身的 HP 低於 \\n\u300050% 時，牠的攻擊將會\\n\u3000變得更加兇暴。');
insert into unit_enemy_data values (305503, '霧奇', 305500, 0, 16, 270, 2160, 2, 3.0, 0, 0, 0, '【魔法】在許多的傳說之中留下名號，記憶的大精靈。\\n如霧狀般的不具實體，可將一切覆蓋隱藏。\\n\\n‧必殺技可對所有敵人\\n\u3000造成大幅度的魔法傷害，\\n\u3000當敵人處於詛咒狀態時，\\n\u3000傷害會上升。\\n‧對全體敵人造成中幅度的魔法傷害。\\n\u3000並且施加詛咒狀態。\\n‧從分身體（紫）（紅）（藍）之中\\n\u3000任意召喚 1 匹。\\n\u3000召喚時將全體敵人擊退。\\n‧【物理】分身體（紫）可對自己展開\\n\u3000吸收物理/魔法的屏障。\\n‧【物理】分身體（紅）可對全體敵人\\n\u3000造成中幅度的魔法傷害。\\n‧【物理】分身體（藍）可對全體敵人\\n\u3000造成中幅度的魔法傷害。\\n\u3000再施加詛咒狀態。\\n\u3000分身體（藍） 的 HP 在 30% 以下時，\\n\u3000恢復霧奇的 300 TP。\\n‧當霧奇自身的 HP 低於 \\n\u300050% 時，牠的攻擊將會\\n\u3000變得更加兇暴。');
insert into unit_enemy_data values (305504, '霧奇', 305500, 0, 16, 270, 2160, 2, 3.0, 0, 0, 0, '【魔法】在許多的傳說之中留下名號，記憶的大精靈。\\n如霧狀般的不具實體，可將一切覆蓋隱藏。\\n\\n‧必殺技能夠對全體敵人造成\\n\u3000大幅度的魔法傷害，同時當敵人\\n\u3000處於詛咒狀態時，傷害將會\\n\u3000有所提升。\\n‧對全體敵人造成大幅度的魔法傷害。\\n\u3000並且使其陷入詛咒狀態。\\n‧從分身體（紫）（紅）（藍）之中\\n\u3000任意召喚 1 匹。\\n\u3000召喚時將全體敵人擊退。\\n‧【物理】分身體（紫）可對自己展開\\n\u3000吸收物理/魔法的屏障。\\n‧【物理】分身體（紅）可對全體敵人\\n\u3000造成中幅度的魔法傷害。\\n‧【物理】分身體（藍）可對全體敵人\\n\u3000造成中幅度的魔法傷害。\\n\u3000同時使其陷入詛咒狀態。\\n\u3000分身體（藍） 的 HP 在 30% 以下時，\\n\u3000恢復霧奇的 300 TP。\\n‧當霧奇自身的 HP 低於 \\n\u300050% 時，牠的攻擊將會\\n\u3000變得更加兇暴。');
insert into unit_enemy_data values (305505, '霧奇', 305500, 0, 16, 270, 2160, 2, 3.0, 0, 0, 0, '【魔法】在許多的傳說之中留下名號，記憶的大精靈。\\n如霧狀般的不具實體，可將一切覆蓋隱藏。\\n\\n‧必殺技能夠對全體敵人造成\\n\u3000中幅度的魔法傷害，同時當敵人\\n\u3000處於詛咒狀態時，傷害將會\\n\u3000有所提升。\\n‧對全體敵人造成小幅度的魔法傷害，\\n\u3000並且使其陷入詛咒狀態。\\n‧從分身體（紫）（紅）之中\\n\u3000任意召喚 1 匹。\\n\u3000召喚時將全體敵人擊退。\\n‧【物理】分身體（紫）可對自己展開\\n\u3000吸收物理/魔法的屏障。\\n‧【物理】分身體（紅）可對全體敵人\\n\u3000造成大幅度的魔法傷害。');
insert into unit_enemy_data values (305506, '霧奇', 305500, 0, 16, 270, 2160, 2, 3.0, 0, 0, 0, '【魔法】在許多的傳說之中留下名號，記憶的大精靈。\\n如霧狀般的不具實體，可將一切覆蓋隱藏。\\n\\n‧必殺技能夠對全體敵人造成\\n\u3000中幅度的魔法傷害，同時當敵人\\n\u3000處於詛咒狀態時，傷害將會\\n\u3000有所提升。\\n‧對全體敵人造成小幅度的魔法傷害，\\n\u3000並且使其陷入詛咒狀態。\\n‧從分身體（紫）（紅）之中\\n\u3000任意召喚 1 匹。\\n\u3000召喚時將全體敵人擊退。\\n‧【物理】分身體（紫）可對自己展開\\n\u3000吸收物理/魔法的屏障。\\n‧【物理】分身體（紅）可對全體敵人\\n\u3000造成大幅度的魔法傷害。\\n‧當霧奇自身的 HP 低於 \\n\u300050% 時，牠的攻擊將會\\n\u3000變得更加兇暴。');
insert into unit_enemy_data values (305507, '霧奇', 305500, 0, 16, 270, 2160, 2, 3.0, 0, 0, 0, '【魔法】在許多的傳說之中留下名號，記憶的大精靈。\\n如霧狀般的不具實體，可將一切覆蓋隱藏。\\n\\n‧必殺技能夠對全體敵人造成\\n\u3000大幅度的魔法傷害，同時當敵人\\n\u3000處於詛咒狀態時，傷害將會\\n\u3000有所提升。\\n‧對全體敵人造成大幅度的魔法傷害。\\n\u3000並且使其陷入詛咒狀態。\\n‧從分身體（紫）（紅）（藍）之中\\n\u3000任意召喚 1 匹。\\n\u3000召喚時將全體敵人擊退。\\n‧【物理】分身體（紫）可對自己展開\\n\u3000吸收物理/魔法的屏障。\\n‧【物理】分身體（紅）可對全體敵人\\n\u3000造成大幅度的魔法傷害。\\n‧【物理】分身體（藍）可對全體敵人\\n\u3000造成小幅度的物理傷害。\\n\u3000同時使其陷入詛咒狀態。\\n\u3000分身體（藍） 的 HP 在 30% 以下時，\\n\u3000恢復霧奇的 300 TP。\\n‧當霧奇自身的 HP 低於 \\n\u300050% 時，牠的攻擊將會\\n\u3000變得更加兇暴。');
insert into unit_enemy_data values (305600, '邪惡領主', 305600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】覬覦月之魔力而現身的異界魔物。\\n以魔眼與率領的兵力，放眼於征服露娜之塔。\\n\\n‧對全體敵人造成大幅度的魔法傷害，\\n\u3000並中幅度降低全體敵人的魔法防禦力。\\n‧隨機分 6 次對 1 名角色造成小幅度的\\n\u3000魔法傷害。\\n‧對從後方算起第 3 名角色造成中幅度的\\n\u3000魔法傷害，並施加長時間的拘束狀態。\\n\u3000再對全體造成小幅度的的魔法傷害。');
insert into unit_enemy_data values (305700, '哥布林王者', 305700, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】豪邁地揮舞著戰斧，是老練的哥布林戰士\\n單手抱著年幼的戰士，展現畢生的絕技。\\n\\n‧必殺技可中幅度提升自己的物理攻擊力\\n\u3000與小幅度提升物理防禦力，\\n\u3000並對面前的 1 名角色\\n\u3000造成特大幅度的物理傷害。');
insert into unit_enemy_data values (305701, '哥布林王者', 305701, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '豪邁地揮舞著戰斧，是老練的哥布林戰士。\\n單手抱著年幼的戰士，展現畢生的絕技。\\n\\n‧必殺技可中幅度提升自己的物理攻擊力\\n\u3000與小幅度提升物理防禦力，並對面前的\\n\u30001 名角色造成特大幅度的物理傷害。');
insert into unit_enemy_data values (305702, '哥布林王者', 305702, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】豪邁地揮舞著戰斧，是老練的哥布林戰士\\n單手抱著年幼的戰士，展現畢生的絕技。\\n\\n‧必殺技可中幅度提升自己的物理攻擊力，同時\\n\u3000小幅度提升物理防禦力。\\n\u3000並且對面前的 1 名敵人\\n\u3000造成特大幅度的物理傷害，\\n\u3000同時造成暈眩。');
insert into unit_enemy_data values (305703, '蠻族的隊長', 305703, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】靠著頑強的身心在沙漠\\n生存的蠻族戰士。為了守護年幼的\\n親生孩子，不斷揮舞著戰斧。\\n\\n‧必殺技會中幅度提升自身的\\n\u3000物理攻擊力，小幅度提升\\n\u3000物理防禦力。\\n\u3000並且對面前的1名角色造成\\n\u3000特大幅度物理傷害。');
insert into unit_enemy_data values (305800, '涅普堤利昂', 305800, 0, 16, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】海神的使者，不可思議的軟體魔物。\\n據說身體組成幾乎都是蘊含魔力的海水。\\n\\n‧必殺技會對敵方全體依照其角色最大HP造成\\n\u3000魔法比例傷害，並且大幅度降低\\n\u3000物理攻擊力，中幅度降低魔法攻擊力。\\n‧對前方的第2名角色造成特大幅度的魔法傷害，\\n\u3000對前方的第3名角色造成中幅度的魔法傷害。\\n‧在一定範圍內，展開大幅降低行動速度，\\n\u3000並持續造成魔法傷害的領域。');
insert into unit_enemy_data values (305801, '海神使徒', 305801, 0, 16, 270, 1000, 2, 2.6, 0, 0, 0, '【魔法】大鬧於露娜之塔的海獸。曾仕於太古之\\n海神，然而失去大義的如今已成了一介破壞者。\\n\\n・對全體敵人造成魔法傷害。\\n・在一定的範圍內，展開降低物理攻擊力與\\n\u3000魔法防禦力，同時造成持續魔法傷害的領域。\\n\u3000\\n・對從前方數來第 2 與 3 名的角色，\\n\u3000造成大幅度的魔法傷害。');
insert into unit_enemy_data values (305802, '涅普堤利昂', 305802, 0, 16, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】侍奉海神的奇妙魔物。\\n\u3000看見威脅水域平靜的侵入者時，\\n便會使用神使的力量，將其清理乾淨。\\n\\n‧對全體敵人造成大幅度的魔法傷害。\\n\\n‧對前方的第2名角色造成特大幅度的\\n\u3000魔法傷害，對前方的第3名角色造成\\n\u3000中幅度的魔法傷害。\\n\\n‧在一定範圍內，展開降低魔法防禦力\\n\u3000並持續給予魔法傷害的\\n\u3000領域。');
insert into unit_enemy_data values (305900, '稜鏡夫人', 305900, 0, 16, 270, 1000, 1, 2.2, 0, 0, 0, '【物理】散發壓倒性的魅力，絢麗的極彩色之豔鳥。\\n若臣服於那美貌成為階下囚，將會開始襲擊伙伴。\\n\\n‧必殺技將會對誘惑狀態以外的敵人角色，\\n\u3000造成大幅度的物理傷害。\\n‧對前方2名角色造成小幅度的魔法傷害和誘惑\\n\u3000狀態，之後還能大幅度提升自己物理攻擊力\\n\u3000與魔法攻擊力。');
insert into unit_enemy_data values (305901, '稜鏡夫人', 305901, 0, 16, 270, 1000, 1, 2.2, 0, 0, 0, '【物理】散發壓倒性的魅力，絢麗的極彩色之豔鳥。\\n若臣服於那美貌成為階下囚，將會開始襲擊伙伴。\\n\\n‧必殺技將對誘惑狀態以外的全體敵人\\n\u3000造成大幅度物理傷害。\\n\u3000同時使全體敵人陷入誘惑狀態。\\n\u3000此技能所造成的狀態異常，同時也會使傷害\\n\u3000無效化。\\n‧對前方的 2 名角色造成小幅度的魔法傷害與\\n\u3000誘惑狀態，同時在這之後大幅度提升物理攻擊力\\n\u3000與魔法攻擊力。');
insert into unit_enemy_data values (306000, '邪餅神鏡餅', 306000, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【物理】由邪念的殘餘物聚集所化成的邪神。\\n將其具現的煩惱給全數淨化，以迎接新年吧！\\n\\n‧必殺技可對全體敵人造成大幅度的\\n\u3000物理傷害。\\n‧對前方的 3 名角色造成中幅度的\\n\u3000魔法傷害，並降低其物理攻擊力。\\n‧在前方中距離召喚定時炸彈年糕。\\n‧當炸彈年糕被召喚出來，\\n\u30008 秒後造成大爆炸，對範圍內的全體敵人\\n\u3000造成中幅度的物理傷害。\\n\u3000但是若炸彈年糕在爆炸前的 HP 低於 50% 時，\\n\u3000將小幅度恢復全體敵人的 HP，\\n\u3000並當場消失。\\n‧當邪餅神鏡餅自身的 HP 低於 \\n\u300050% 時，祂的攻擊將會\\n\u3000變得更加兇暴。');
insert into unit_enemy_data values (306001, '邪餅神鏡餅', 306000, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【物理】由邪念的殘餘物聚集所化成的邪神。\\n將其具現的煩惱給全數淨化，以迎接新年吧！\\n\\n‧必殺技可對全體敵人造成大幅度的\\n\u3000物理傷害。\\n‧對面前的 3 名角色造成中幅度的魔法傷害，\\n\u3000並降低其物理攻擊力。');
insert into unit_enemy_data values (306002, '邪餅神鏡餅', 306000, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【物理】由邪念的殘餘物聚集所化成的邪神。\\n將其具現的煩惱給全數淨化，以迎接新年吧！\\n\\n‧必殺技可對全體敵人造成大幅度的\\n\u3000物理傷害。\\n‧對前方的 3 名角色造成中幅度的\\n\u3000魔法傷害，並降低其物理攻擊力。\\n‧在前方中距離召喚定時炸彈年糕。\\n‧當炸彈年糕被召喚出來，\\n\u30008 秒後造成大爆炸，對範圍內的全體敵人\\n\u3000造成中幅度的物理傷害。\\n\u3000但是若炸彈年糕在爆炸前的 HP 低於 50% 時，\\n\u3000將小幅度恢復全體敵人的 HP，\\n\u3000並當場消失。\\n‧當邪餅神鏡餅自身的 HP 低於 \\n\u300050% 時，祂的攻擊將會\\n\u3000變得更加兇暴。');
insert into unit_enemy_data values (306003, '邪餅神鏡餅', 306000, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【物理】由邪念的殘餘物聚集所化成的邪神。\\n將其具現的煩惱給全數淨化，以迎接新年吧！\\n\\n‧必殺技可對全體敵人造成大幅度的\\n\u3000物理傷害。\\n‧對前方的 3 名角色造成中幅度的\\n\u3000魔法傷害，並降低其物理攻擊力。\\n‧在前方中距離召喚定時炸彈年糕。\\n‧當炸彈年糕被召喚出來，\\n\u30008 秒後造成大爆炸，對範圍內的全體敵人\\n\u3000造成中幅度的物理傷害。\\n\u3000但是若炸彈年糕在爆炸前的 HP 低於 50% 時，\\n\u3000將小幅度恢復全體敵人的 HP，\\n\u3000並當場消失。\\n‧當邪餅神鏡餅自身的 HP 低於 \\n\u300050% 時，祂的攻擊將會\\n\u3000變得更加兇暴。');
insert into unit_enemy_data values (306004, '邪餅神鏡餅', 306004, 0, 16, 270, 3000, 1, 0.0, 0, 0, 0, '【MODE1】由邪念的殘餘物聚集所化成的邪神。\\n將其具現的煩惱給全數淨化，以迎接新年吧！\\n\\n‧當邪餅神鏡餅受到攻擊時，\\n\u3000將小幅度恢復所有夥伴的 HP，\\n\u3000而邪餅神鏡餅將恢復自己的全部 HP。');
insert into unit_enemy_data values (306005, '邪餅神鏡餅', 306005, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE2】由邪念的殘餘物聚集所化成的邪神。\\n將其具現的煩惱給全數淨化，以迎接新年吧！\\n\\n‧對前方的 1 名角色造成物理傷害。\\n‧對前方的範圍內造成中幅度的魔法傷害，\\n\u3000並且大幅度將其擊飛。\\n‧混入 6 個邪念所召喚的煩惱（紅）。\\n‧混入 3 個邪念所召喚的煩惱（紫）。\\n‧混入 1 個邪念所召喚的煩惱（藍）。');
insert into unit_enemy_data values (306006, '邪餅神鏡餅', 306006, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【MODE3】由邪念的殘餘物聚集所化成的邪神。\\n將其具現的煩惱給全數淨化，以迎接新年吧！\\n\\n‧對前方的 1 名角色造成物理傷害。\\n‧必殺技可對全體敵人造成大幅度的\\n\u3000物理傷害。\\n‧對前方的 3 名角色造成中幅度的\\n\u3000魔法傷害，並降低其物理攻擊力。\\n‧在前方中距離召喚定時炸彈年糕。\\n‧當炸彈年糕被召喚出來，\\n\u30008 秒後造成大爆炸，對範圍內的全體敵人\\n\u3000造成中幅度的物理傷害。\\n\u3000但是若炸彈年糕在爆炸前的 HP \\n\u3000低於 50% 時，將小幅度恢復\\n\u3000全體敵人的 HP，並當場消失。');
insert into unit_enemy_data values (306007, '邪餅神鏡餅', 306000, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【物理】由邪念的殘餘物聚集所化成的邪神。\\n將其具現的煩惱給全數淨化，以迎接新年吧！\\n\\n‧必殺技可對敵方全體依照其角色最大HP\\n\u3000造成大幅度的物理傷害。\\n‧對前方的3名角色造成中幅度的魔法傷害，\\n\u3000並小幅度降低其物理攻擊力。\\n‧在前方中距離召喚定時炸彈年糕。\\n‧當炸彈年糕被召喚出來，\\n\u30008秒後造成大爆炸，對範圍內的敵方全體\\n\u3000造成中幅度的物理傷害。\\n\u3000但是若炸彈年糕在爆炸前的HP低於50％時，\\n\u3000將小幅度恢復敵方全體的HP，\\n\u3000並當場消失。');
insert into unit_enemy_data values (306008, '邪餅神鏡餅', 306000, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【物理】由邪念的殘餘物聚集所化成的邪神。\\n將其具現的煩惱給全數淨化，以迎接新年吧！\\n\\n‧必殺技可對敵方全體依照其角色最大HP\\n\u3000造成大幅度的物理傷害。\\n‧對前方的3名角色造成中幅度的魔法傷害，\\n\u3000並小幅度降低其物理攻擊力。\\n‧在前方中距離召喚定時炸彈年糕。\\n‧當炸彈年糕被召喚出來，\\n\u30008秒後造成大爆炸，對範圍內的敵方全體\\n\u3000造成中幅度的物理傷害。\\n\u3000但是若炸彈年糕在爆炸前的HP低於50％時，\\n\u3000將小幅度恢復敵方全體的HP，\\n\u3000並當場消失。\\n‧當邪餅神鏡餅自身的HP低於\\n\u300050％時，祂的攻擊將會\\n\u3000變得更加兇暴。');
insert into unit_enemy_data values (306009, '邪餅神鏡餅', 306000, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【物理】由邪念的殘餘物聚集所化成的邪神。\\n將其具現的煩惱給全數淨化，以迎接新年吧！\\n\\n‧必殺技可對敵方全體依照其角色最大HP\\n\u3000造成大幅度的物理傷害。\\n‧對前方的3名角色造成中幅度的魔法傷害，\\n\u3000並小幅度降低其物理攻擊力。\\n‧在前方中距離召喚定時炸彈年糕。\\n‧當炸彈年糕被召喚出來，\\n\u30008秒後造成大爆炸，對範圍內的敵方全體\\n\u3000造成大幅度的物理傷害。\\n\u3000但是若炸彈年糕在爆炸前的HP低於50％時，\\n\u3000將小幅度恢復敵方全體的HP，\\n\u3000並當場消失。\\n‧當邪餅神鏡餅自身的HP低於\\n\u300050％時，祂的攻擊將會\\n\u3000變得更加兇暴。');
insert into unit_enemy_data values (306010, '邪餅神鏡餅', 306000, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【物理】由邪念的殘餘物聚集所化成的邪神。\\n將其具現的煩惱給全數淨化，以迎接新年吧！\\n\\n‧必殺技可以夠對全體敵人依照\\n\u3000其最大HP造成大幅度物理的\\n\u3000比例傷害。\\n‧對前方3名角色造成中幅度的魔法傷害，\\n\u3000同時降低物理攻擊力。\\n‧在前方中距離召喚定時炸彈年糕。\\n‧當炸彈年糕被召喚出來的8秒後\\n\u3000造成大爆炸，對範圍內的全體敵人\\n\u3000造成中幅度的物理傷害。\\n\u3000但是若炸彈年糕在爆炸前的HP低於\\n\u300050%時，將小幅度恢復全體敵人的HP，\\n\u3000同時當場消失。\\n‧當邪餅神鏡餅自身的HP低於\\n\u300060% 時，祂的攻擊將會變得\\n\u3000更加兇暴。');
insert into unit_enemy_data values (306100, '貪婪豺狼', 306100, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】藏匿於黑暗，以竊盜村落維生的\\n魔物頭目\\n會將偷來的武器毫不留情的丟出，\\n是開拓的過程中必須除掉的麻煩。\\n\\n‧對前方的3名角色造成中幅度的物理傷害，\\n\u3000並且使其麻痺。\\n\\n‧對全體敵人造成小幅度的物理傷害，\\n\u3000降低行動速度。\\n\u3000並且使前方小範圍內造成中毒狀態。\\n');
insert into unit_enemy_data values (306101, '貪婪豺狼', 306101, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】藏匿於黑暗，以竊盜村落維生的魔物頭目。\\n會使用偷來的武器戰鬥的無賴。\\n\\n‧對前方的3名角色造成中幅度的物理傷害，\\n\u3000並且使其麻痺。\\n‧對全體敵人造成小幅度的物理傷害，\\n\u3000降低行動速度。\\n\u3000並且使前方小範圍內造成中毒狀態。\\n\u3000此技能的毒即使傷害無效也會\\n\u3000施加。');
insert into unit_enemy_data values (306102, '貪婪豺狼', 306102, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】藏匿於黑暗，以竊盜村落維生的魔物頭目。\\n會使用偷來的武器戰鬥的無賴。\\n\\n‧對前方的3名角色造成中幅度的物理傷害，\\n\u3000並且使其麻痺。\\n‧對全體敵人造成小幅度的物理傷害，\\n\u3000降低行動速度。\\n\u3000並且使前方小範圍內造成中毒狀態。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n\u3000此技能造成的傷害不會\\n\u3000回復TP。');
insert into unit_enemy_data values (306200, '大王‧山狸', 306200, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】盤踞森林深處，\\n與手下支配著周遭一帶，老奸巨猾的大狸。\\n使人陷入不存在的虛幻，巧妙地操縱\\n侵蝕精神的幻影攻擊。\\n\\n‧對全體敵人造成中幅度魔法傷害，\\n\u3000且召喚出 2 隻小狸貓。\\n\\n・對全體敵人造成小幅度魔法傷害，\\n\u3000一併消滅不處於無敵狀態之中的召\\n\u3000喚魔物。\\n\u3000且當敵人 HP 在 40% 以下時，\\n\u3000使其陷入麻痺狀態。');
insert into unit_enemy_data values (306201, '大王‧山狸', 306201, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】盤踞森林深處，與手下支配著周遭一帶，老奸巨猾的大狸。\\n牠可以召喚小狸貓，與其相互配合以擾亂對手。\\n\\n‧戰鬥開始時，\\n\u3000小幅度提升自身物理防禦力及魔法防禦力。\\n\u3000因防禦力提升效果而上升的防禦力，\\n\u3000在戰鬥中不會受到防禦力下降技能的影響。\\n‧必殺技能對敵方全體造成中幅度的魔法傷害，\\n\u3000且召喚出2隻小狸貓。\\n\u3000在此技能造成的傷害狀態下，\\n\u3000敵人不會恢復TP。\\n‧對敵方全體造成小幅度的魔法傷害並擊退，\\n\u3000且一併消滅不處於無敵狀態的小狸貓。\\n\u3000當敵人HP低於50％時，\\n\u3000使其陷入麻痺狀態。');
insert into unit_enemy_data values (306202, '大王‧山狸', 306201, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】盤踞森林深處，與手下支配著周遭一帶，老奸巨猾的大狸。\\n牠可以召喚小狸貓，與其相互配合以擾亂對手。\\n\\n‧戰鬥開始時，\\n\u3000小幅度提升自身物理防禦力及魔法防禦力。\\n\u3000因防禦力提升效果而上升的防禦力，\\n\u3000在戰鬥中不會受到防禦力下降技能的影響。\\n‧必殺技能對敵方全體造成中幅度的魔法傷害，\\n\u3000且召喚出2隻小狸貓。\\n\u3000在此技能造成的傷害狀態下，\\n\u3000敵人不會恢復TP。\\n‧對敵方全體造成小幅度的魔法傷害並擊退，\\n\u3000且一併消滅不處於無敵狀態的小狸貓。\\n\u3000當敵人HP低於50％時，\\n\u3000使其陷入麻痺狀態。');
insert into unit_enemy_data values (306203, '大王‧山狸', 306201, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】盤踞森林深處，與手下支配著周遭一帶，老奸巨猾的大狸。\\n牠可以召喚小狸貓，與其相互配合以擾亂對手。\\n\\n‧戰鬥開始時，\\n\u3000小幅度提升自身物理防禦力及魔法防禦力。\\n\u3000因防禦力提升效果而上升的防禦力，\\n\u3000在戰鬥中不會受到防禦力下降技能的影響。\\n‧必殺技能對敵方全體造成中幅度的魔法傷害，\\n\u3000且召喚出2隻小狸貓。\\n\u3000在此技能造成的傷害狀態下，\\n\u3000敵人不會恢復TP。\\n‧對敵方全體造成小幅度的魔法傷害並擊退，\\n\u3000且一併消滅不處於無敵狀態的小狸貓。\\n\u3000當敵人HP低於50％時，\\n\u3000使其陷入麻痺狀態。');
insert into unit_enemy_data values (306204, '大王‧山狸', 306201, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】盤踞森林深處，與手下支配著周遭一帶，老奸巨猾的大狸。\\n牠可以召喚小狸貓，與其相互配合以擾亂對手。\\n\\n‧戰鬥開始時，\\n\u3000小幅度提升自身物理防禦力及魔法防禦力。\\n\u3000因防禦力提升效果而上升的防禦力，\\n\u3000在戰鬥中不會受到防禦力下降技能的影響。\\n‧必殺技能對敵方全體造成中幅度的魔法傷害，\\n\u3000且召喚出2隻小狸貓。\\n\u3000在此技能造成的傷害狀態下，\\n\u3000敵人不會恢復TP。\\n‧對敵方全體造成小幅度的魔法傷害並擊退，\\n\u3000且一併消滅不處於無敵狀態的小狸貓。\\n\u3000當敵人HP低於50％時，\\n\u3000使其陷入麻痺狀態。');
insert into unit_enemy_data values (306300, '擲岩猴仙', 306300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】統領著使用月之魔力的擲岩猴們的仙猴。\\n能自由使用寶武具之棍，將敵人一掃而空。\\n\\n‧對全體敵人造成大幅度的物理傷害。\\n\u3000此攻擊對於對火傷狀態的敵人\\n\u3000傷害為 1.8 倍。\\n‧對前方中範圍內的敵人造成中幅度的物理傷害。\\n‧對前方小範圍內的敵人造成中幅度的魔法傷害，\\n\u3000並施加火傷狀態。');
insert into unit_enemy_data values (306301, '擲岩猴仙', 306301, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】統領著使用月之魔力的擲岩猴們的仙猴。\\n能自由使用寶武具之棍，將敵人一掃而空。\\n\\n‧對全體敵人造成大幅度的物理傷害，\\n\u3000並降低物理攻擊角色的物理攻擊力。\\n\u3000此攻擊對於對火傷狀態的敵人\\n\u3000傷害為 1.8 倍。\\n‧對前方中範圍內的敵人造成中幅度的物理傷害。\\n‧對前方小範圍內的敵人造成中幅度的魔法傷害，\\n\u3000並施加火傷狀態。');
insert into unit_enemy_data values (306400, '野蠻之爪', 306400, 0, 16, 270, 1000, 1, 3.5, 0, 0, 0, '【物理】以捕食者之姿君臨於荒山中\\n，一隻兇惡的怪鳥獸。\\n用著那日以繼夜的狩獵鍛鍊而出的\\n臂力與利爪，將入侵者擒獲。\\n\\n‧對全體敵人造成大幅度物理傷害\\n，並且降低其 TP 上升。\u3000\\n每次發動技能的同時，還能夠\\n提升傷害。這個效果最多累積次\\n數為 3 次。\\n\\n‧對從後方算起第 2 名角色為中心\\n的小範圍，造成小幅度的物理傷害\\n，並且使其麻痺。');
insert into unit_enemy_data values (306500, '部落半獸人', 306500, 0, 16, 270, 1000, 1, 0.9, 0, 0, 0, '【物理】邊境之森半獸人們的首領。\\n傳播著自己獨有的民族性奇異旋律。\\n那個奇怪的聲音，\\n會使敵人掉入混亂的漩渦。\\n\\n‧對全體敵人\\n造成大幅度的魔法傷害\\n降低物理防禦力與魔法防禦力\\n並且提高自己的物理攻擊力\\n與魔法攻擊力。\\n\\n‧對前方的 4 名角色\\n造成小幅度的魔法傷害\\n敵人的ＨＰ低於70％的狀況\\n會使對方陷入混亂狀態。');
insert into unit_enemy_data values (306501, '噪音半獸人', 306501, 0, 16, 270, 1000, 1, 0.9, 0, 0, 0, '【物理】被露娜之塔的力量吸引的獸人首領。\\n用太鼓敲打著怪異的旋律，在戰場中引發騷亂。\\n\\n‧對全體敵人造成大幅度的物理傷害，並降低其\\n\u3000物理防禦力與魔法防禦力，\\n\u3000並提升自身的物理攻擊力與魔法攻擊力。\\n‧對前方的 3 名角色造成小幅度的魔法傷害，\\n\u3000並小幅度的擊飛。當敵人的 HP 低於\\n\u300070% 以下時，使其陷入混亂狀態。\\n‧對全體敵人造成對應該角色剩餘 HP 的\\n\u3000大幅度魔法傷害，同時降低其行動速度。\\n\u3000最後，解除全體敵人身上的\\n\u3000狀態提升效果。');
insert into unit_enemy_data values (306600, '猛毒火蠑螈', 306600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】為尋求獵物而使水邊滿溢著\\n猛毒，是一種山椒魚的魔物。\\n那囤積至幾乎快要滿出來的猛毒，\\n危險到光是接近意識就會被奪去。\\n\\n・對全體敵人造成中幅度魔法傷害\\n\u3000同時使其中毒，\\n\u3000並且再造成猛毒狀態。\\n・對前方範圍內的敵人\\n，造成小幅度的魔法傷害\\n，並且使其陷入猛毒狀態。');
insert into unit_enemy_data values (306700, '醜陋可愛', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【物理】因辱罵而暴走，一隻巨大的巧克力魔物。\\n傾訴的愛意若有所誤，便將會幻化為傷人之刃。\\n\\n‧必殺技，能夠對全體敵人依照其最大 HP\\n\u3000造成大幅度的物理傷害，並且若對方為\\n\u3000火傷的狀態時，將有更多的追加傷害。\\n‧對前方的 3 名角色造成中幅度的物理傷害，\\n\u3000並且使其暈眩。\\n\u3000而當其角色的 HP 在 50% 以下時，\\n\u3000使其陷入火傷狀態。\\n・當醜陋可愛自身的 HP 低於 50%之時，\\n\u3000他的攻擊將變得更加的兇暴。');
insert into unit_enemy_data values (306701, '醜陋可愛', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【物理】因辱罵而暴走，一隻巨大的巧克力魔物。\\n傾訴的愛意若有所誤，便將會幻化為傷人之刃。\\n\\n‧必殺技，能夠對全體敵人依照其最大 HP\\n\u3000造成大幅度的物理傷害，並且若對方為\\n\u3000火傷的狀態時，將有更多的追加傷害。\\n‧對前方的 3 名角色造成中幅度的物理傷害，\\n\u3000並且使其暈眩。\\n\u3000而當其角色的 HP 在 50% 以下時，\\n\u3000使其陷入火傷狀態。');
insert into unit_enemy_data values (306702, '醜陋可愛', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【物理】因辱罵而暴走，一隻巨大的巧克力魔物。\\n傾訴的愛意若有所誤，便將會幻化為傷人之刃。\\n\\n‧必殺技，能夠對全體敵人依照其最大 HP\\n\u3000造成大幅度的物理傷害，並且若對方為\\n\u3000火傷的狀態時，將有更多的追加傷害。\\n‧對前方的 3 名角色造成中幅度的物理傷害，\\n\u3000並且使其暈眩。\\n\u3000而當其角色的 HP 在 50% 以下時，\\n\u3000使其陷入火傷狀態。\\n・當醜陋可愛自身的 HP 低於 50%之時，\\n\u3000他的攻擊將變得更加的兇暴。');
insert into unit_enemy_data values (306703, '醜陋可愛', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【物理】因辱罵而暴走，一隻巨大的巧克力魔物。\\n傾訴的愛意若有所誤，便將會幻化為傷人之刃。\\n\\n‧必殺技，能夠對全體敵人依照其最大 HP\\n\u3000造成大幅度的物理傷害，並且若對方為\\n\u3000火傷的狀態時，將有更多的追加傷害。\\n‧對前方的 3 名角色造成中幅度的物理傷害，\\n\u3000並且使其暈眩。\\n\u3000而當其角色的 HP 在 50% 以下時，\\n\u3000使其陷入火傷狀態。\\n・當醜陋可愛自身的 HP 低於 50%之時，\\n\u3000他的攻擊將變得更加的兇暴。');
insert into unit_enemy_data values (306704, '醜陋可愛', 306700, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【MODE1】將巧克力大噴射，並且隱藏身軀。\\n若持續受到敵人的攻擊，將會炸裂憤怒的一擊。\\n\\n‧對全體敵人造成小幅度的物理傷害，並且在戰鬥\\n\u3000期間造成火傷狀態。\\n・在躲於巧克力保壘之中的期間，醜陋可愛將會\\n\u3000中幅度提升自身的物理防禦力。\\n\u3000在巧克力保壘的狀態解除之際，\\n\u3000將會依照在狀態中所受到傷害量，\\n\u3000對敵人來造成物理傷害。\\n\u3000並且醜陋可愛自身的物理防禦力，將會大幅度\\n\u3000的降低。');
insert into unit_enemy_data values (306705, '醜陋可愛', 306700, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【MODE2】可可亞烏拉挺身而出，\\n 一頭栽進了死地。\\n 皆是為了從被激化的魔物手\\n 中，保護最珍惜的人們。\\n\\n‧必殺技，能夠對全體敵人依照其最大 HP\\n\u3000造成大幅度的物理傷害。\\n・可可亞烏拉將會以夥伴的身份出現。\\n\u3000當可可亞烏拉出現時，將會中幅度提升\\n\u3000全體角色的物理攻擊力、\\n\u3000魔法攻擊力和行動速度。\\n・對全體敵人造成小幅度魔法傷害，\\n\u3000並且大幅度的降低行動速度。\\n');
insert into unit_enemy_data values (306706, '醜陋可愛', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【MODE3】震耳欲聾的咆哮，壟罩著整個會場\\n交織愛恨情仇的情人節事變終究迎向了大結局。\\n\\n‧必殺技，能夠對全體敵人依照其最大 HP\\n\u3000造成大幅度的物理傷害，並且若對方為\\n\u3000火傷的狀態時，將有更多的追加傷害。\\n‧對前方的 3 名角色造成中幅度的物理傷害，\\n\u3000並且使其暈眩。\\n\u3000且當其角色的 HP 在 50%以下時，\\n\u3000使其陷入火傷狀態。');
insert into unit_enemy_data values (306708, '醜陋可愛', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【物理】因辱罵而暴走，一隻巨大的巧克力魔物。\\n傾訴的愛意若有所誤，便將會幻化為傷人之刃。\\n\\n‧必殺技可以對敵方全體依照其角色最大HP\\n\u3000造成大幅度的物理傷害，並且若對方為\\n\u3000火傷的狀態時，將有更多的追加傷害。\\n‧對前方3名角色依照其角色最大HP造成\\n\u3000中幅度的物理傷害，\\n\u3000並使其陷入火傷狀態。');
insert into unit_enemy_data values (306709, '醜陋可愛', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【物理】因辱罵而暴走，一隻巨大的巧克力魔物。\\n傾訴的愛意若有所誤，便將會幻化為傷人之刃。\\n\\n‧必殺技可以對敵方全體依照其角色最大HP\\n\u3000造成大幅度的物理傷害，並且若對方為\\n\u3000火傷的狀態時，將有更多的追加傷害。\\n‧對前方3名角色依照其角色最大HP造成\\n\u3000中幅度的物理傷害，\\n\u3000並使其陷入火傷狀態。\\n‧當醜陋可愛自身的HP低於45%時，\\n\u3000牠的攻擊將變得更加兇暴。');
insert into unit_enemy_data values (306710, '醜陋可愛', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【物理】因辱罵而暴走，一隻巨大的巧克力魔物。\\n傾訴的愛意若有所誤，便將會幻化為傷人之刃。\\n\\n‧必殺技可以對敵方全體依照其角色最大HP\\n\u3000造成大幅度的物理傷害，並且若對方為\\n\u3000火傷的狀態時，將有更多的追加傷害。\\n‧對前方3名角色依照其角色最大HP造成\\n\u3000中幅度的物理傷害，\\n\u3000並使其陷入火傷狀態。\\n‧當醜陋可愛自身的HP低於45%時，\\n\u3000牠的攻擊將變得更加兇暴。');
insert into unit_enemy_data values (306711, '醜陋可愛', 306700, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【MODE1】將巧克力大噴射，並且隱藏身軀。\\n若持續受到敵人的攻擊，將會炸裂憤怒的一擊。\\n\\n‧對全體敵人造成小幅度的物理傷害，並且在戰鬥\\n\u3000期間造成火傷狀態。\\n・在躲於巧克力保壘之中的期間，醜陋可愛將會\\n\u3000中幅度提升自身的物理防禦力。\\n\u3000在巧克力保壘的狀態解除之際，\\n\u3000將會依照在狀態中所受到傷害量，\\n\u3000對敵人來造成物理傷害。\\n\u3000並且醜陋可愛自身的物理防禦力，將會大幅度\\n\u3000的降低。');
insert into unit_enemy_data values (306712, '醜陋可愛', 306700, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【MODE2】可可亞烏拉挺身而出，\\n 一頭栽進了死地。\\n 牠是為了從被激怒的魔物手中，\\n保護最珍惜的人們。\\n\\n‧必殺技可以夠對全體敵人依照其最大HP\\n\u3000造成大幅度的物理傷害。\\n‧可可亞烏拉將會以夥伴的身分出現。\\n\u3000當可可亞烏拉出現時，\\n\u3000將會中幅度提升全體角色的\\n\u3000物理攻擊力、魔法攻擊力和行動速度。\\n‧對全體敵人造成小幅度魔法傷害，\\n\u3000並且大幅度的降低行動速度。');
insert into unit_enemy_data values (306713, '醜陋可愛', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【MODE3】震耳欲聾的咆哮，壟罩著整個會場\\n交織愛恨情仇的情人節事變終究迎向了大結局。\\n\\n‧必殺技可以對全體敵人依照其最大HP\\n\u3000造成大幅度的物理傷害，並且若對方為\\n\u3000火傷的狀態時，將有更多的追加傷害。\\n‧對前方3名角色依照其最大HP造成中幅度的\\n\u3000物理傷害，同時使其暈眩，\\n\u3000而當其角色的HP在50%以下時，使其陷入\\n\u3000火傷狀態。\\n‧在戰鬥開始之後，提升自己的物理攻擊力\\n\u3000和行動速度。');
insert into unit_enemy_data values (306800, '哀嘆之女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】因失意與絕望，而墮落於魔的悲哀王女。\\n冀求著慟哭之聲，將恐懼與詛咒滿溢至一切。\\n\\n‧必殺技，能夠對全體敵人依照其最大 HP\\n\u3000造成大幅度的魔法傷害，並且降低其\\n\u3000魔法防禦力。\\n‧對前方第 2 名、第 3 名的角色，造成\\n\u3000中幅度的魔法傷害，並且使其暈眩。\\n‧對前方的 2 名角色造成小幅度的魔法傷害，\\n\u3000降低其物理攻擊力，且減少其ＴＰ。\\n\u3000並且施加詛咒狀態。\\n‧當哀嘆之女神自身的 HP\\n\u3000低於 40% 時，她的攻擊將會變得更加\\n\u3000兇暴。');
insert into unit_enemy_data values (306801, '哀嘆之女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】因失意與絕望，而墮落於魔的悲哀王女。\\n冀求著慟哭之聲，將恐懼與詛咒滿溢至一切。\\n\\n‧必殺技，能夠對全體敵人依照其最大 HP\\n\u3000造成大幅度的魔法傷害，並且降低其\\n\u3000魔法防禦力。\\n‧對前方第 2 名、第 3 名的角色造成中幅度的\\n\u3000魔法傷害，並且使其暈眩。');
insert into unit_enemy_data values (306802, '哀嘆之女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】因失意與絕望，而墮落於魔的悲哀王女。\\n冀求著慟哭之聲，將恐懼與詛咒滿溢至一切。\\n\\n‧必殺技，能夠對全體敵人依照其最大 HP\\n\u3000造成大幅度的魔法傷害，並且降低其\\n\u3000魔法防禦力。\\n‧對前方第 2 名、第 3 名的角色，造成\\n\u3000中幅度的魔法傷害，並且使其暈眩。\\n‧對前方的 2 名角色造成小幅度的魔法傷害，\\n\u3000降低其物理攻擊力，且減少其ＴＰ。\\n\u3000並且施加詛咒狀態。\\n\u3000此技能所造成的狀態異常，還能夠額外\\n\u3000造成其傷害無效化。\\n‧當哀嘆之女神自身的 HP\\n\u3000低於 40% 時，她的攻擊將會變得更加\\n\u3000兇暴。');
insert into unit_enemy_data values (306803, '哀嘆之女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】因失意與絕望，而墮落於魔的悲哀王女。\\n冀求著慟哭之聲，將恐懼與詛咒滿溢至一切。\\n\\n‧必殺技，能夠對全體敵人依照其最大 HP\\n\u3000造成大幅度的魔法傷害，並且降低其\\n\u3000魔法防禦力。\\n‧對前方第 2 名、第 3 名的角色，造成\\n\u3000中幅度的魔法傷害，並且使其暈眩。\\n‧對前方的 2 名角色造成小幅度的魔法傷害，\\n\u3000降低其物理攻擊力，且減少其ＴＰ。\\n\u3000並且施加詛咒狀態。\\n\u3000此技能所造成的狀態異常，還能夠額外\\n\u3000造成其傷害無效化。\\n‧當哀嘆之女神自身的 HP\\n\u3000低於 40% 時，她的攻擊將會變得更加\\n\u3000兇暴。');
insert into unit_enemy_data values (306804, '哀嘆之女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE1】將【哞哞自衛隊】的成員做為闇影召喚。\\n以斷絕羈絆為企圖，撥弄挑戰者內心深處的弱點。\\n\\n・使闇影現身。\\n・哀嘆之女神自身將不會進行攻擊。');
insert into unit_enemy_data values (306805, '哀嘆之女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE2】將周圍完全壟罩起永久的黑暗，\\n\u3000以那所擁有的咒言詛咒，無止盡地阻擋著\\n\u3000冒險者的一切。\\n\\n‧必殺技，能夠對全體敵人依照其最大 HP\\n\u3000造成大幅度的魔法傷害，並且降低其\\n\u3000魔法防禦力。\\n‧對前方的 3 名角色造成小幅度的魔法傷害，\\n\u3000降低其物理防禦力，降低ＴＰ\\n\u3000取得率也下降。\\n\u3000並使其陷入詛咒、混亂狀態，且降低行動速度。\\n\u3000此技能所造成的狀態異常，還能夠額外\\n\u3000造成其傷害無效化。\\n・哀嘆之女神自身的物理防禦力將會降低。\\n\u3000並且會變成詛咒狀態，減少ＴＰ。');
insert into unit_enemy_data values (306806, '哀嘆之女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE3】滿溢著那狂氣的悲哀，解放了女王真正的姿態。充斥著災厄之願，連一縷希望也無法原諒。\\n\\n‧必殺技，能夠對全體敵人依照其最大 HP\\n\u3000造成大幅度的魔法傷害，並且降低其\\n\u3000魔法防禦力。\\n‧對前方第 2 名、第 3 名的角色，造成\\n\u3000中幅度的魔法傷害，並且使其暈眩。\\n‧對前方的 2 名角色造成小幅度的魔法傷害，\\n\u3000降低其物理攻擊力，且減少其ＴＰ。\\n\u3000並且施加詛咒狀態。\\n\u3000此技能所造成的狀態異常，還能夠額外\\n\u3000造成其傷害無效化。');
insert into unit_enemy_data values (306807, '哀嘆之女神', 306807, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】因失意與絕望，而墮落於魔的悲哀王女。\\n冀求著慟哭之聲，將恐懼與詛咒滿溢至一切。\\n\\n‧必殺技，能夠對全體敵人依照其最大 HP\\n\u3000造成大幅度的魔法傷害，並且降低其\\n\u3000魔法防禦力。\\n‧對前方第 2 名、第 3 名的角色，造成\\n\u3000中幅度的魔法傷害，並且使其暈眩。\\n‧對前方的 2 名角色造成小幅度的魔法傷害，\\n\u3000降低其物理攻擊力，且減少其ＴＰ。\\n\u3000並且施加詛咒狀態。\\n‧當哀嘆之女神自身的 HP\\n\u3000低於 40% 時，她的攻擊將會變得更加\\n\u3000兇暴。');
insert into unit_enemy_data values (306808, '哀嘆之女神', 306807, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】因失意與絕望，而墮落於魔的悲哀王女。\\n冀求著慟哭之聲，將恐懼與詛咒滿溢至一切。\\n\\n‧必殺技能夠對全體敵人依照其最大 HP\\n\u3000造成大幅度的魔法傷害，並且降低其\\n\u3000魔法防禦力。\\n‧對前方第 2、3 名的角色，依照其角色的\\n\u3000最大 HP 造成中幅度的魔法傷害，\\n\u3000同時使其暈眩。');
insert into unit_enemy_data values (306809, '哀嘆之女神', 306807, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】因失意與絕望，而墮落於魔的悲哀王女。\\n冀求著慟哭之聲，將恐懼與詛咒滿溢至一切。\\n\\n‧必殺技能夠對全體敵人依照其最大 HP\\n\u3000造成大幅度的魔法傷害，並且降低其\\n\u3000魔法防禦力。\\n‧對前方第 2、3 名的角色，依照其角色的\\n\u3000最大 HP 造成中幅度的魔法傷害，\\n\u3000同時使其暈眩。\\n‧對前方的 2 名角色造成小幅度的魔法傷害，\\n\u3000降低其物理攻擊力，且減少其 TP。\\n\u3000並且施加詛咒狀態。\\n\u3000此技能所造成的狀態異常，同時也會使傷害\\n\u3000無效化。\\n‧當哀嘆之女神自身的 HP\\n\u3000低於 40% 時，她的攻擊將會變得更加\\n\u3000兇暴。');
insert into unit_enemy_data values (306810, '哀嘆之女神', 306807, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】因失意與絕望，而墮落於魔的悲哀王女。\\n冀求著慟哭之聲，將恐懼與詛咒滿溢至一切。\\n\\n‧必殺技能夠對全體敵人依照其最大 HP\\n\u3000造成大幅度的魔法傷害，並且降低其\\n\u3000魔法防禦力。\\n‧對前方第 2、3 名的角色，依照其角色的\\n\u3000最大 HP 造成中幅度的魔法傷害，\\n\u3000同時使其暈眩。\\n‧對前方的 2 名角色造成小幅度的魔法傷害，\\n\u3000降低其物理攻擊力，且減少其 TP。\\n\u3000並且施加詛咒狀態。\\n\u3000此技能所造成的狀態異常，同時也會使傷害\\n\u3000無效化。\\n‧當哀嘆之女神自身的 HP\\n\u3000低於 40% 時，她的攻擊將會變得更加\\n\u3000兇暴。');
insert into unit_enemy_data values (306811, '哀嘆之女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE1】將【哞哞自衛隊】的成員做為闇影召喚。\\n以斷絕羈絆為企圖，撥弄挑戰者內心深處的弱點。\\n\\n・使闇影現身。\\n・哀嘆之女神自身將不會進行攻擊。');
insert into unit_enemy_data values (306812, '哀嘆之女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE2】將周圍完全壟罩起永久的黑暗，\\n\u3000以那所擁有的咒言詛咒，無止盡地阻擋著\\n\u3000冒險者的一切。\\n\\n‧必殺技能夠對全體敵人依照其最大 HP\\n\u3000造成大幅度的魔法傷害，並且降低其\\n\u3000魔法防禦力。\\n‧對前方的 3 名角色造成小幅度的魔法傷害，\\n\u3000同時降低物理防禦力，並且減少 TP ，\\n\u3000再降低 TP 上升。\\n\u3000同時再造成詛咒、混亂狀態，並且提升行動速度。\\n\u3000此技能所造成的狀態異常，同時也會使傷害\\n\u3000無效化。\\n‧哀嘆之女神自身的物理防禦力將會降低。\\n\u3000並且會變成詛咒狀態，減少 TP。');
insert into unit_enemy_data values (306813, '哀嘆之女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE3】滿溢著那狂氣的悲哀，解放了女王真正的姿態。充斥著災厄之願，連一縷希望也無法原諒。\\n\\n‧必殺技能夠對全體敵人依照其最大 HP\\n\u3000造成大幅度的魔法傷害，並且降低其\\n\u3000魔法防禦力。\\n‧對前方第 2 名、第 3 名的角色造成\\n\u3000中幅度的魔法傷害，並且使其暈眩。\\n‧對前方的 2 名角色造成小幅度的魔法傷害，\\n\u3000降低其物理攻擊力，且減少其 TP。\\n\u3000並且施加詛咒狀態。\\n\u3000此技能所造成的狀態異常，同時也會使傷害\\n\u3000無效化。\\n‧在戰鬥剛開始時，提升自己的魔法攻擊力\\n\u3000與行動速度。');
insert into unit_enemy_data values (306900, '三重搖滾', 306900, 0, 16, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】被過去的人們祭祀著的三戰士的石像。\\n互相增強各自的能力，發出必殺的一擊。\\n\\n・容易被物理攻擊力下降與魔法攻擊力下降的效果\\n所影響。\\n・極大幅度提高自己的物理攻擊力與魔法攻擊力\\n\u3000對全體敵人造成中幅度的物理傷害與\\n\u3000中幅度的魔法傷害。\\n・對前方範圍內的敵人造成小幅度的魔法傷害。\\n・對全體敵人造成中幅度的物理傷害。');
insert into unit_enemy_data values (306901, '三重搖滾', 306901, 0, 16, 270, 3000, 2, 1.8, 0, 0, 0, '【魔法】被過去的人們祭祀著的三戰士的石像。\\n互相增強各自的能力，發出必殺的一擊。\\n\\n‧容易受到物理攻擊力降低與魔法攻擊力\\n\u3000降低的效果影響。\\n‧必殺技可特大幅度提升自身的物理攻擊力與\\n\u3000魔法攻擊力，對敵方全體造成\\n\u3000中幅度的物理傷害與中幅度的魔法傷害。\\n‧以最前方數來第 1 名敵人為中心，\\n\u3000造成小範圍的中幅度魔法傷害。\\n‧對敵方全體造成中幅度的物理傷害。');
insert into unit_enemy_data values (307000, '元核‧巨靈', 307000, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '');
insert into unit_enemy_data values (307001, '元核‧巨靈', 307000, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】從異界之魔石中所誕生的，弩級之巨人。\\n以強韌的肉體做為武器，嚴苛的猛攻從不止息。\\n\\n・更加地容易受到物理攻擊力提升、降低的效果\\n\u3000影響。\\n‧必殺技，能夠對全體敵人造成大幅度的物理傷害。\\n‧對前方 3 名角色造成中幅度的物理傷害。\\n・對全體敵人造成物理傷害，並大距離向後擊飛\\n\u3000且使其暈眩。');
insert into unit_enemy_data values (307002, '元核‧巨靈', 307002, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '');
insert into unit_enemy_data values (307003, '元核‧巨靈', 307002, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】從異界之魔石中所誕生的，弩級之巨人。\\n以強韌的肉體做為武器，嚴苛的猛攻從不止息。\\n\\n・更加地容易受到物理攻擊力提升、降低的效果\\n\u3000影響。\\n‧必殺技，能夠對全體敵人造成大幅度的物理傷害。\\n‧對前方 3 名角色造成中幅度的物理傷害。\\n・於一定時間內保持著防禦的架式，而在之後將會\\n\u3000依照這段間內所受到的傷害量，對全體敵人造成\\n\u3000物理傷害，使前方 2 名角色麻痺。\\n\u3000並且再提高自己的物理攻擊力。\\n・對全體敵人造成物理傷害，並大距離向後擊飛\\n\u3000且使其暈眩。\\n・當元核‧巨靈自身的ＨＰ低於40％的時候，\\n\u3000他的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (307004, '元核‧巨靈', 307002, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】從異界之魔石中所誕生的，弩級之巨人。\\n以強韌的肉體做為武器，嚴苛的猛攻從不止息。\\n\\n・更加地容易受到物理攻擊力提升、降低的效果\\n\u3000影響。\\n‧必殺技，能夠對全體敵人造成大幅度的物理傷害。\\n‧對前方 3 名角色造成中幅度的物理傷害。\\n・於一定時間內保持著防禦的架式，而在之後將會\\n\u3000依照這段間內所受到的傷害量，對全體敵人造成\\n\u3000物理傷害，使前方 2 名角色麻痺。\\n\u3000並且再提高自己的物理攻擊力。\\n・對全體敵人造成物理傷害，並大距離向後擊飛\\n\u3000且使其暈眩。\\n・當元核‧巨靈自身的ＨＰ低於40％的時候，\\n\u3000他的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (307005, '元核‧巨靈', 307002, 0, 16, 270, 3000, 1, 5.0, 0, 0, 0, '【MODE1】將【美食殿堂】的成員做為闇影\\n召喚。以旅途的回憶做為擋箭牌，試圖\\n煽動 3 人心中的弱點。\\n\\n・使闇影現身。\\n‧對前方的 3 名角色造成中幅度的物理傷害。\\n・對全體敵人造成物理傷害，並大距離向後擊飛\\n\u3000且使其暈眩。');
insert into unit_enemy_data values (307006, '元核‧巨靈', 307002, 0, 16, 270, 3000, 1, 5.0, 0, 0, 0, '【MODE2】那強韌的肉體，不論是何等\\n攻擊皆能凌駕於上。以憤怒為糧，巨人會讓人\\n見識排山倒海般的大反擊。\\n\\n・更加地容易受到物理攻擊力提升、降低的效果\\n\u3000影響。\\n‧必殺技，能夠對全體敵人造成大幅度的物理傷害。\\n‧對前方 3 名角色造成中幅度的物理傷害。\\n・於一定時間內保持著防禦的架式，而在之後將會\\n\u3000依照這段間內所受到的傷害量，對全體敵人造成\\n\u3000物理傷害，使前方 2 名角色麻痺。\\n\u3000並且再提高自己的物理攻擊力。');
insert into unit_enemy_data values (307007, '元核‧巨靈', 307002, 0, 16, 270, 3000, 1, 3.0, 0, 0, 0, '【MODE3】弩級的巨人，將全身所有的力量\\n完全解放。在無與倫比的破壞力面前\\n，任何的小技倆皆無用。\\n\\n・更加地容易受到物理攻擊力提升、降低的效果\\n\u3000影響。\\n‧必殺技，能夠對全體敵人造成大幅度的物理傷害。\\n‧對前方 3 名角色造成中幅度的物理傷害。\\n・於一定時間內保持著防禦的架式，而在之後將會\\n\u3000依照這段間內所受到的傷害量，對全體敵人造成\\n\u3000物理傷害，使前方 2 名角色麻痺。\\n\u3000並且再提高自己的物理攻擊力。\\n・對全體敵人造成物理傷害，並大距離向後擊飛\\n\u3000且使其暈眩。');
insert into unit_enemy_data values (307008, '元核‧巨靈', 307000, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '');
insert into unit_enemy_data values (307009, '元核‧巨靈', 307000, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】從異界之魔石中所誕生的，弩級之巨人。\\n以強韌的肉體做為武器，嚴苛的猛攻從不止息。\\n\\n‧更加地容易受到物理攻擊力提升、降低的效果\\n\u3000影響。\\n‧必殺技能夠對全體敵人依照其最大 HP\\n\u3000造成大幅度的物理傷害。\\n‧對前方的 3 名角色造成中幅度的物理傷害。\\n‧對全體敵人造成中幅度的物理傷害，同時\\n\u3000大幅度擊退。');
insert into unit_enemy_data values (307010, '元核‧巨靈', 307008, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】從異界之魔石中所誕生的，弩級之巨人。\\n以強韌的肉體做為武器，嚴苛的猛攻從不止息。\\n\\n‧更加地容易受到物理攻擊力提升、降低的效果\\n\u3000影響。\\n‧必殺技能夠對敵方全體依照其角色最大HP\\n\u3000造成大幅度的物理傷害。\\n‧對前方的3名角色造成中幅度的物理傷害。\\n‧對敵方全體造成中幅度的物理傷害，同時\\n\u3000大幅度擊退。\\n‧於一定時間內保持著防禦的架式，而在之後將會\\n\u3000依照這段間內所受到的傷害量，對敵方全體造成\\n\u3000物理傷害，同時降低行動速度。\\n\u3000並且麻痺前方2名角色，同時提升自己的\\n\u3000物理攻擊力。\\n‧當元核‧巨靈自身的HP不到35%時，\\n\u3000他的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (307011, '元核‧巨靈', 307008, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】從異界之魔石中所誕生的，弩級之巨人。\\n以強韌的肉體做為武器，嚴苛的猛攻從不止息。\\n\\n‧更加地容易受到物理攻擊力提升、降低的效果\\n\u3000影響。\\n‧必殺技能夠對敵方全體依照其角色最大HP\\n\u3000造成大幅度的物理傷害。\\n‧對前方的3名角色造成中幅度的物理傷害。\\n‧對敵方全體造成中幅度的物理傷害，同時\\n\u3000大幅度擊退。\\n‧於一定時間內保持著防禦的架式，而在之後將會\\n\u3000依照這段間內所受到的傷害量，對敵方全體造成\\n\u3000物理傷害，同時降低行動速度。\\n\u3000並且麻痺前方2名角色，同時提升自己的\\n\u3000物理攻擊力。\\n‧當元核‧巨靈自身的HP不到35%時，\\n\u3000他的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (307012, '元核‧巨靈', 307008, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】從異界之魔石中所誕生的，弩級之巨人。\\n以強韌的肉體做為武器，嚴苛的猛攻從不止息。\\n\\n‧更加地容易受到物理攻擊力提升、降低的效果\\n\u3000影響。\\n‧必殺技能夠對全體敵人依照其最大 HP\\n\u3000造成大幅度的物理傷害。\\n‧對前方的 3 名角色造成中幅度的物理傷害。\\n‧於一定時間內保持著防禦的架式，而在之後將會\\n\u3000依照這段間內所受到的傷害量，對全體敵人造成\\n\u3000物理傷害，同時降低行動速度。\\n\u3000並且麻痺前方 2 名角色，同時提升自己的\\n\u3000物理攻擊力。\\n‧對全體敵人造成中幅度的物理傷害，同時\\n\u3000大幅度擊退。\\n‧當元核‧巨靈自身的 HP 低於 35% 時，\\n\u3000他的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (307013, '元核‧巨靈', 307002, 0, 16, 270, 3000, 1, 5.0, 0, 0, 0, '【MODE1】召喚出【美食殿堂】成員們的\\n闇影。以旅途的回憶做為擋箭牌，試圖\\n煽動 3 人心中的弱點。\\n\\n‧對前方的 3 名角色造成中幅度的物理傷害。\\n‧對全體敵人造成中幅度的物理傷害，同時\\n\u3000大幅度擊退。');
insert into unit_enemy_data values (307014, '元核‧巨靈', 307002, 0, 16, 270, 3000, 1, 5.0, 0, 0, 0, '【MODE2】那強韌的肉體，不論是何等\\n攻擊皆能抵抗忍受。以憤怒為糧，巨人會讓人\\n見識排山倒海般的大反擊。\\n\\n‧更加地容易受到物理攻擊力提升、降低的效果\\n\u3000影響。\\n‧必殺技能夠對全體敵人造成中幅度的物理傷害。\\n‧對前方的 3 名角色造成大幅度的物理傷害。\\n‧於一定時間內保持著防禦的架式，而在之後將會\\n\u3000依照這段間內所受到的傷害量，對全體敵人造成\\n\u3000物理傷害，使前方 2 名角色麻痺。\\n\u3000並且再提高自己的物理攻擊力。');
insert into unit_enemy_data values (307015, '元核‧巨靈', 307002, 0, 16, 270, 3000, 1, 3.0, 0, 0, 0, '【MODE3】弩級的巨人，將全身所有的力量\\n完全解放。在無與倫比的破壞力面前，\\n任何的小技倆皆無用。\\n\\n‧更加地容易受到物理攻擊力提升、降低的效果\\n\u3000影響。\\n‧必殺技能夠對全體敵人造成中幅度的物理傷害。\\n‧對前方的 3 名角色造成大幅度的物理傷害。\\n‧於一定時間內保持著防禦的架式，而在之後將會\\n\u3000依照這段間內所受到的傷害量，對全體敵人造成\\n\u3000物理傷害，使前方 2 名角色麻痺。\\n\u3000並且再提高自己的物理攻擊力。\\n‧對全體敵人造成大幅度的物理傷害，同時\\n\u3000大幅度擊退。\\n‧在戰鬥剛開始時，提升自己的物理攻擊力\\n\u3000和行動速度。');
insert into unit_enemy_data values (307100, '機械莉瑪（模式1）', 307100, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '堅固且擁有多樣招式的謎之巨大兵器的第一型態。\\n以蘋果型補給機能夠充填未知的能量，並且還能\\n使出將廣範圍焦土化的連續攻擊，請小心！\\n\\n‧必殺技能夠對全體敵人造成大幅度的物理傷害。\\n‧對前方的 1 名角色造成小幅度的物理傷害。\\n‧於一定範圍內，展開降低物理攻擊力與迴避，\\n\u3000同時造成物理傷害的領域。\\n\u3000並且解除前方範圍內角色的\\n\u3000素質提升效果。\\n‧對前方範圍內造成中幅度的物理傷害，\\n\u3000且提升自己的 TP 上升。');
insert into unit_enemy_data values (307101, '機械莉瑪（模式2）', 307101, 0, 16, 270, 3000, 1, 1.2, 0, 0, 0, '完全地切換到進攻模式的謎之巨大兵器的第二型態。\\n核心莉瑪反應爐所釋放的光線，能將大地燃燒殆盡。\\n趁機用大量傷害將無防備的巨大兵器狠狠揍一頓吧！\\n\\n‧必殺技能夠對前方小範圍內造成特大幅度的\\n\u3000物理傷害，中範圍處造成大幅度的物理傷害，\\n\u3000廣範圍處則是造成中幅度的物理傷害，\\n\u3000並且大幅度向後擊飛。\\n‧對前方的 1 名角色造成小幅度的物理傷害。\\n‧對隨機的 1 名角色造成小幅度的物理傷害。\\n‧於一定範圍內，展開大幅度降低物理攻擊力\\n\u3000與魔法攻擊力，同時造成魔法傷害的領域。\\n\u3000同時使魔法攻擊力最高的 2 名角色沉默。');
insert into unit_enemy_data values (307102, '機械莉瑪（模式3）', 307102, 0, 16, 270, 3000, 1, 5.5, 0, 0, 0, '能夠自我修復耗損的謎之巨大兵器的第三型態。\\n對破綻百出的本體攻擊時，將會有防衛機器人阻撓。\\n用範圍攻擊滅掉那些機器人，並且把握這個好機會！\\n\\n‧將全體敵人大幅度向後擊飛，\\n\u3000並且召喚 3 隻迷你機械莉瑪。\\n‧迷你機械莉瑪能夠對前方的 1 名\\n\u3000角色造成小幅度的物理傷害。\\n‧迷你機械莉瑪能夠對隨機的 1 名\\n\u3000角色造成中幅度的魔法傷害。\\n‧對全體敵人依照其剩餘 HP 造成\\n\u3000特大幅度的物理比例傷害。');
insert into unit_enemy_data values (307200, '巴西利斯克', 307200, 0, 16, 270, 3000, 2, 1.8, 0, 0, 0, '【魔法】追求月之魔力因而飛來的大怪鳥。\\n統馭著雛鳥，且揮舞著石化的詛咒之劍。\\n\\n・對未處於石化狀態的全體角色，造成大幅度的\\n\u3000魔法傷害，且短時間內石化。\\n\u3000對石化狀態的全體角色，\\n\u3000造成最大HP80%的傷害。\\n‧對前方 3 名角色造成小幅度的魔法傷害。\\n\u3000並且此技能傷害所影響造成的中毒狀態，\\n\u3000將會使角色陷入長時間的石化。\\n・對前方範圍內的敵人給予中幅度的物魔法傷害，\\n\u3000並且使其中毒。\\n\u3000當自身的HP在50%以下時，額外將全體敵人\\n\u3000向後擊飛，並且召喚咯咯。\\n・咯咯能夠對前方範圍內物理攻擊力最高的\\n\u30001 名角色，造成小幅度的物理傷害，並且使其\\n\u3000陷入中毒狀態。\\n\u3000另外當自己的HP低於最大HP35%時，\\n\u3000將會對物理攻擊力最高的同伴\\n\u3000中幅度的提高TP，\\n\u3000而自己將會無法繼續戰鬥。');
insert into unit_enemy_data values (307201, '巴西利斯克', 307201, 0, 16, 270, 3000, 2, 1.8, 0, 0, 0, '【魔法】帶著石化詛咒之劍的怪鳥。\\n用尾部毒蛇的毒牙侵蝕獵物，\\n並用詛咒之劍的石化阻止冒險者的腳步。\\n\\n‧必殺技能夠對沒有陷入無法行動狀態的所有角色\\n\u3000造成大幅度的魔法傷害，\\n\u3000並使其陷入石化狀態。\\n\u3000對陷入無法行動狀態的所有角色\\n\u3000造成最大HP的80%的傷害。\\n\u3000並且解除敵方全體的能力提升效果。\\n\u3000此技能所造成的狀態異常，\\n\u3000即使傷害無效也會施加。\\n‧對前方3名角色造成小幅度的魔法傷害。\\n\u3000並且使被此技能造成傷害的\\n\u3000中毒狀態的角色陷入石化狀態。\\n‧對前方範圍內的角色造成中幅度的魔法傷害，\\n\u3000並使其陷入中毒狀態。');
insert into unit_enemy_data values (307300, '惡代官', 307300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】渾身都是貪婪的機關人偶。\\n以大江戶町的專制政治者的身分在位，\\n做極盡蠻橫之事\\n\\n・對全體敵人角色造成對應最大HP的\\n\u3000大幅度的物理傷害，中幅度的提高\\n\u3000自己的物理攻擊力。');
insert into unit_enemy_data values (307301, '惡代官', 307300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】渾身都是貪婪的機關人偶。\\n以大江戶町的專制政治者的身分在位，\\n做極盡蠻橫之事\\n\\n・對全體敵人角色造成對應最大HP的\\n\u3000大幅度的物理傷害，中幅度的提高\\n\u3000自己的物理攻擊力。');
insert into unit_enemy_data values (307302, '惡代官', 307300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】渾身都是貪婪的機關人偶。\\n以大江戶町的專制政治者的身分在位，\\n做極盡蠻橫之事\\n\\n・對全體敵人角色造成對應最大HP的\\n\u3000大幅度的物理傷害，中幅度的提高\\n\u3000自己的物理攻擊力。');
insert into unit_enemy_data values (307303, '惡代官', 307300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】渾身都是貪婪的機關人偶。\\n以大江戶町的專制政治者的身分在位，\\n做極盡蠻橫之事\\n\\n・對全體敵人角色造成對應最大HP的\\n\u3000大幅度的物理傷害，中幅度的提高\\n\u3000自己的物理攻擊力。並且，\\n\u3000被召喚的所有家臣的ＨＰ\\n\u3000會歸零。\\n\\n・召喚會對面前的 1 名敵人\\n\u3000進行物理攻擊的家臣。\\n\u3000當自己的ＨＰ歸零後家臣會，\\n\u3000大爆炸，會造成範圍內的全體敵人\\n\u3000中幅度的物理傷害。\\n‧當惡代官自身的 HP 低於40% 時， \\n\u3000他的攻擊將會\\n\u3000變得更加兇暴。');
insert into unit_enemy_data values (307304, '惡代官', 307300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE1】把【純白之翼\\n蘭德索爾分部】成員作為闇影\\n召喚出來。嘲笑３個人的堅強羈絆\\n慾望的影子強烈襲擊。\\n\\n・使闇影出現\\n・對面前的 1 名敵人造成物理攻擊。\\n');
insert into unit_enemy_data values (307305, '惡代官', 307300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE2】為了用物慾使喚周遭，\\n用各種虛構將人拖引進慾望的漩渦。\\n\\n・對面前的 1 名敵人造成物理傷害\\n・造成所有敵人小幅度的物理傷害，\\n\u3000再使其陷入誘惑狀態。\\n');
insert into unit_enemy_data values (307306, '惡代官', 307300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE3】被虛榮心填滿的貪念，\\n打算支配一切解放真實的力量。\\n\\n・對全體敵人角色造成對應最大HP的\\n\u3000大幅度的物理傷害，中幅度的提高\\n\u3000自己的物理攻擊力。並且，\\n\u3000被召喚的所有家臣的ＨＰ\\n\u3000會歸零。\\n\\n・召喚會對面前的 1 名敵人\\n\u3000進行物理攻擊的家臣。\\n\u3000當自己的ＨＰ歸零後家臣會，\\n\u3000大爆炸，會造成範圍內的全體敵人\\n\u3000中幅度的物理傷害。\\n');
insert into unit_enemy_data values (307307, '惡代官', 307307, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】渾身都是貪婪的機關人偶。\\n以大江戶町的專制政治者的身分在位，\\n做極盡蠻橫之事\\n\\n‧對全體敵人依照其最大HP造成\\n\u3000物理比例傷害，中幅度提升\\n\u3000自己的物理攻擊力。');
insert into unit_enemy_data values (307308, '惡代官', 307307, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】渾身都是貪婪的機關人偶。\\n以大江戶町的專制政治者的身分在位，\\n做極盡蠻橫之事\\n\\n‧對全體敵人依照其最大HP造成\\n\u3000物理比例傷害，中幅度提升\\n\u3000自己的物理攻擊力。');
insert into unit_enemy_data values (307309, '惡代官', 307307, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】渾身都是貪婪的機關人偶。\\n以大江戶町的專制政治者的身分在位，\\n做極盡蠻橫之事\\n\\n‧對全體敵人依照其最大HP造成\\n\u3000物理比例傷害，中幅度提升\\n\u3000自己的物理攻擊力。並且，\\n\u3000被召喚的所有家臣的HP\\n\u3000會歸零。\\n‧召喚會對面前的1名敵人\\n\u3000進行物理攻擊的家臣。\\n\u3000家臣在自己的血量變為0時會大爆炸，\\n\u3000對全體敵人依照其最大HP造成\\n\u3000物理比例傷害。\\n‧當惡代官自身的HP低於40%時，\\n\u3000他的攻擊將會\\n\u3000變得更加兇暴。');
insert into unit_enemy_data values (307310, '惡代官', 307307, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】渾身都是貪婪的機關人偶。\\n以大江戶町的專制政治者的身分在位，\\n做極盡蠻橫之事\\n\\n‧對全體敵人依照其最大HP造成\\n\u3000物理比例傷害，中幅度提升\\n\u3000自己的物理攻擊力。並且，\\n\u3000被召喚的所有家臣的HP\\n\u3000會歸零。\\n‧召喚會對面前的1名敵人\\n\u3000進行物理攻擊的家臣。\\n\u3000家臣在自己的血量變為0時會大爆炸，\\n\u3000對全體敵人依照其最大HP造成\\n\u3000物理比例傷害。\\n‧當惡代官自身的HP低於40%時，\\n\u3000他的攻擊將會\\n\u3000變得更加兇暴。');
insert into unit_enemy_data values (307311, '惡代官', 307307, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE1】召喚【純白之翼\\n蘭德索爾分部】成員\\n的闇影。嘲笑3個人的堅強羈絆\\n慾望的影子強烈襲擊。\\n\\n‧對前方的1名角色造成物理傷害。');
insert into unit_enemy_data values (307312, '惡代官', 307307, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE2】用物慾令周圍臣服，\\n用各種虛構將事物捲進慾望的漩渦之中。\\n\\n‧對前方的1名角色造成物理傷害。\\n‧對全體敵人造成小幅度的物理傷害，\\n\u3000並且使其陷入誘惑狀態。');
insert into unit_enemy_data values (307313, '惡代官', 307307, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE3】滿足了虛榮的慾望之心，為了\\n支配一切解放了真正的力量。\\n\\n‧對全體敵人依照其最大HP造成\\n\u3000物理比例傷害，中幅度提升\\n\u3000自己的物理攻擊力。並且，\\n\u3000被召喚的所有家臣的HP\\n\u3000會歸零。\\n‧召喚會對面前的1名敵人\\n\u3000進行物理攻擊的家臣。\\n\u3000家臣在自己的血量變為0時會大爆炸，\\n\u3000對全體敵人依照其最大HP造成\\n\u3000物理比例傷害。\\n‧在戰鬥開始之後，提升自己的物理攻擊力\\n\u3000與行動速度。');
insert into unit_enemy_data values (307400, '貝特魯吉烏斯', 307400, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '');
insert into unit_enemy_data values (307401, '貝特魯吉烏斯', 307400, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】在露格尼卡臭名昭彰的魔女教幹部。\\n即使來到了異世界仍貫徹著自己的信念，\\n以強大權能「不可視之手」的力量在暗中活動著。\\n\\n‧必殺技能對全體敵人依照其最大HP造成\\n\u3000魔法比例傷害。\\n‧對前方範圍內的所有角色造成中幅度的魔法傷害\\n\u3000並降低其 TP 。\\n\u3000且對全體敵人造成中幅度的魔法傷害。\\n‧對後方 2 名角色依照其最大HP造成\\n\u3000物理比例傷害。\\n‧當左側的目標被破壞時，將會\\n\u3000小幅度降低物理防禦力與魔法防禦力，\\n\u3000且小幅度降低物理攻擊力、\\n\u3000中幅度降低魔法攻擊力。\\n‧當中央的目標被破壞時，將會\\n\u3000大幅度降低物理防禦力與魔法防禦力，\\n\u3000且小幅度降低物理攻擊力、\\n\u3000特大幅度降低魔法攻擊力。\\n‧當右側的目標被破壞時，將會\\n\u3000大幅度降低物理防禦力與魔法防禦力，\\n\u3000且小幅度降低物理攻擊力、\\n\u3000大幅度降低魔法攻擊力。');
insert into unit_enemy_data values (307402, '貝特魯吉烏斯', 307400, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】在露格尼卡臭名昭彰的魔女教幹部。\\n即使來到了異世界仍貫徹著自己的信念，\\n以強大權能「不可視之手」的力量在暗中活動著。\\n\\n‧必殺技能對全體敵人依照其最大HP造成\\n\u3000魔法比例傷害。\\n‧對前方範圍內的所有角色造成中幅度的魔法傷害\\n\u3000並降低其 TP 。\\n\u3000且對全體敵人造成中幅度的魔法傷害。\\n‧對後方 2 名角色依照其最大HP造成\\n\u3000物理比例傷害。\\n‧當左側的目標被破壞時，將會\\n\u3000小幅度降低物理防禦力與魔法防禦力，\\n\u3000且小幅度降低物理攻擊力、\\n\u3000中幅度降低魔法攻擊力。\\n‧當中央的目標被破壞時，將會\\n\u3000大幅度降低物理防禦力與魔法防禦力，\\n\u3000且小幅度降低物理攻擊力、\\n\u3000特大幅度降低魔法攻擊力。\\n‧當右側的目標被破壞時，將會\\n\u3000大幅度降低物理防禦力與魔法防禦力，\\n\u3000且小幅度降低物理攻擊力、\\n\u3000大幅度降低魔法攻擊力。\\n‧當剩餘時間低於40秒時，\\n\u3000其攻擊將會變得更加狂暴。');
insert into unit_enemy_data values (307403, '貝特魯吉烏斯', 307400, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】在露格尼卡臭名昭彰的魔女教幹部。\\n即使來到了異世界仍貫徹著自己的信念，\\n以強大權能「不可視之手」的力量在暗中活動著。\\n\\n‧必殺技能對全體敵人依照其最大HP造成\\n\u3000魔法比例傷害。\\n‧對前方範圍內的所有角色造成中幅度的魔法傷害\\n\u3000並降低其 TP 。\\n\u3000且對全體敵人造成中幅度的魔法傷害。\\n‧對後方 2 名角色依照其最大HP造成\\n\u3000物理比例傷害。\\n‧當左側的目標被破壞時，將會\\n\u3000小幅度降低物理防禦力與魔法防禦力，\\n\u3000且小幅度降低物理攻擊力、\\n\u3000中幅度降低魔法攻擊力。\\n‧當中央的目標被破壞時，將會\\n\u3000大幅度降低物理防禦力與魔法防禦力，\\n\u3000且小幅度降低物理攻擊力、\\n\u3000特大幅度降低魔法攻擊力。\\n‧當右側的目標被破壞時，將會\\n\u3000大幅度降低物理防禦力與魔法防禦力，\\n\u3000且小幅度降低物理攻擊力、\\n\u3000大幅度降低魔法攻擊力。\\n‧當剩餘時間低於40秒時，\\n\u3000其攻擊將會變得更加狂暴。');
insert into unit_enemy_data values (307404, '貝特魯吉烏斯', 307400, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE1】召喚出雷姆和拉姆的闇影。\\n被大罪司教的狂氣所吞噬的雙子之影，\\n成了魔女教的爪牙，擋住夥伴們的去路。\\n\\n‧對前方的 1 名敵人造成物理傷害。');
insert into unit_enemy_data values (307405, '貝特魯吉烏斯', 307400, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE2】威力增幅的強大權能\\n毫無慈悲的為怠惰的怨敵帶來終焉。\\n\\n‧必殺技能對全體敵人依照其最大HP造成\\n\u3000魔法比例傷害。\\n‧對後方 2 名角色依照其最大HP造成\\n\u3000物理比例傷害。\\n‧對剩餘 HP 比例最少的 1 名敵人\\n\u3000造成大幅度的魔法傷害，並\\n\u3000賦予倒計時效果。\\n\u3000當倒數到 0 時，\\n\u3000會對該角色依照其最大HP造成\\n\u3000魔法比例傷害。\\n‧當左側的目標被破壞時，將會\\n\u3000小幅度降低物理防禦力與魔法防禦力，\\n\u3000且小幅度降低物理攻擊力、\\n\u3000中幅度降低魔法攻擊力。\\n‧當中央的目標被破壞時，將會\\n\u3000中幅度降低物理防禦力、\\n\u3000大幅度降低魔法防禦力，\\n\u3000且小幅度降低物理攻擊力、\\n\u3000特大幅度降低魔法攻擊力。\\n‧當右側的目標被破壞時，將會\\n\u3000中幅度降低物理防禦力、\\n\u3000大幅度降低魔法防禦力，\\n\u3000且小幅度降低物理攻擊力、\\n\u3000大幅度降低魔法攻擊力。');
insert into unit_enemy_data values (307406, '貝特魯吉烏斯', 307400, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE3】理性和人類樣貌盡失的狂熱信徒，\\n只依靠執念而行動，為忠愛奮戰致死。\\n\\n‧必殺技能對全體敵人依照其最大HP造成\\n\u3000魔法比例傷害。\\n‧對前方範圍內的所有角色造成中幅度的魔法傷害\\n\u3000並降低其 TP 。\\n\u3000且對全體敵人造成中幅度的魔法傷害。\\n‧對後方 2 名角色依照其最大HP造成\\n\u3000物理比例傷害。\\n‧當左側的目標被破壞時，將會\\n\u3000小幅度降低物理防禦力與魔法防禦力，\\n\u3000且小幅度降低物理攻擊力、\\n\u3000中幅度降低魔法攻擊力。\\n‧當中央的目標被破壞時，將會\\n\u3000中幅度降低物理防禦力、\\n\u3000大幅度降低魔法防禦力，\\n\u3000且小幅度降低物理攻擊力、\\n\u3000特大幅度降低魔法攻擊力。\\n‧當右側的目標被破壞時，將會\\n\u3000中幅度降低物理防禦力、\\n\u3000大幅度降低魔法防禦力，\\n\u3000且小幅度降低物理攻擊力、\\n\u3000大幅度降低魔法攻擊力。\\n‧當剩餘時間低於40秒時，\\n\u3000其攻擊將會變得更加狂暴。');
insert into unit_enemy_data values (307500, '席茲', 307500, 0, 3, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】纏繞著猛然兇狂暴風的大怪鳥。\\n從魔物圖鑑中脫逃，並將所見之物破壞殆盡。\\n\\n・對全體敵人依照其最大 HP 造成大幅度的\\n\u3000物理傷害。\\n・對前方範圍內的敵人造成中幅度物理傷害，\\n\u3000並使其暈眩。');
insert into unit_enemy_data values (307501, '席茲', 307500, 0, 3, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】纏繞著猛然兇狂暴風的大怪鳥。\\n從魔物圖鑑中脫逃，並將所見之物破壞殆盡。\\n\\n・對全體敵人依照其最大 HP 造成大幅度的\\n\u3000物理傷害。\\n・對前方範圍內的敵人造成中幅度物理傷害，\\n\u3000並使其暈眩。');
insert into unit_enemy_data values (307502, '席茲', 307500, 0, 3, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】纏繞著猛然兇狂暴風的大怪鳥。\\n從魔物圖鑑中脫逃，並將所見之物破壞殆盡。\\n\\n・對全體敵人依照其最大 HP 造成大幅度的\\n\u3000物理傷害。\\n・對前方範圍內的敵人造成中幅度物理傷害，\\n\u3000並使其暈眩。\\n・對前方範圍內的敵人依照其最大 HP 造成中幅度\\n\u3000的物理傷害。\\n・當席茲自身的 HP 低於 50% 之時，牠的攻擊\\n\u3000將會變得更加兇暴。');
insert into unit_enemy_data values (307503, '席茲', 307500, 0, 3, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】纏繞著猛然兇狂暴風的大怪鳥。\\n從魔物圖鑑中脫逃，並將所見之物破壞殆盡。\\n\\n・對全體敵人依照其最大 HP 造成大幅度的\\n\u3000物理傷害。\\n・對前方範圍內的敵人造成中幅度物理傷害，\\n\u3000並使其暈眩。\\n・對前方範圍內的敵人依照其最大 HP 造成中幅度\\n\u3000的物理傷害。\\n・當席茲自身的 HP 低於 50% 之時，牠的攻擊\\n\u3000將會變得更加兇暴。');
insert into unit_enemy_data values (307504, '紅極鳥', 307504, 0, 3, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】貪食塔之魔力，到處為非作歹的巨大魔鳥。\\n若因大意過於接近，將會被那暴風與豪雷撕成兩半。\\n\\n‧對全體敵人造成大幅度的物理傷害，同時對進行\\n\u3000魔法攻擊的所有敵人造成中幅度的追加物理傷害。\\n‧以從前方數來第2名的角色為中心，造成\\n\u3000小範圍的小幅度的物理傷害，並且暈眩。\\n‧對前方範圍內的敵人造成中幅度的物理傷害，\\n\u3000同時小幅度擊飛。');
insert into unit_enemy_data values (307505, '席茲', 307505, 0, 3, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】纏繞著猛然兇狂暴風的大怪鳥。\\n從魔物圖鑑中脫逃，並將所見之物破壞殆盡。\\n\\n‧對全體敵人依照其最大 HP 造成大幅度的\\n\u3000物理傷害。\\n‧對前方範圍內的敵人造成中幅度的物理傷害，\\n\u3000並使其暈眩。\\n‧對前方範圍內的敵人依照其最大 HP 造成\\n\u3000中幅度的物理傷害。\\n‧當席茲自身的 HP 低於 50% 時，牠的攻擊\\n\u3000將會變得更加兇暴。');
insert into unit_enemy_data values (307600, '狂暴王冠', 307600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】謀劃把露娜之塔當作自己的舞台，\\n魔界的小丑。以開朗的笑容和瘋狂，玩弄觀眾的命。\\n\\n・對全體敵人造成大幅度的魔法傷害，\\n\u3000並使其陷入黑暗狀態。\\n‧隨機分 6 次對 1 名角色造成小幅度的物理傷害\\n\u3000對全體敵人造成大的物理傷害。\\n\u3000愈是在前排的角色\\n\u3000會變得愈容易被這個攻擊擊中。\\n‧在前方中距離召喚定時炸彈。\\n\u3000炸彈被召喚出來後不僅會在8 秒後大爆炸，\\n\u3000也會對範圍內的全體敵人造成中幅度的物理傷害。\\n\u3000但是，到爆炸為止前炸彈的ＨＰ\\n\u3000低於1％後，會造成狂暴王冠\\n\u3000最大ＨＰ15％的物理傷害。');
insert into unit_enemy_data values (307700, '阿爾瑪', 307700, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】遠古時用來守護迷宮的防衛兵器。在最深處，靜待著跨越了所有困難的入侵者。\\n\\n・對全體敵人角色造成對應最大HP的\\n\u3000特大幅度的魔法傷害。\\n・對前方範圍內的敵人造成中幅度的物理傷害。');
insert into unit_enemy_data values (307701, '阿爾瑪', 307700, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】遠古時用來守護迷宮的防衛兵器。在最深處，靜待著跨越了所有困難的入侵者。\\n\\n・對全體敵人角色造成對應最大HP的\\n\u3000特大幅度的魔法傷害。\\n・對前方範圍內的敵人造成中幅度的物理傷害。');
insert into unit_enemy_data values (307702, '阿爾瑪', 307700, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】遠古時用來守護迷宮的防衛兵器。在最深處，靜待著跨越了所有困難的入侵者。\\n\\n・對全體敵人角色造成對應最大HP的\\n\u3000特大幅度的魔法傷害。\\n・對前方範圍內的敵人造成中幅度的物理傷害。\\n・對剩餘的HP較高的敵人，造成對應最大HP的\\n\u3000中幅度的魔法傷害，並且使其陷入麻痺。\\n・當阿爾瑪自身的HP低於50%之時，\\n\u3000它的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (307703, '阿爾瑪', 307700, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】遠古時用來守護迷宮的防衛兵器。在最深處，靜待著跨越了所有困難的入侵者。\\n\\n・對全體敵人角色造成對應最大HP的\\n\u3000特大幅度的魔法傷害。\\n・對前方範圍內的敵人造成中幅度的物理傷害。\\n・對剩餘的HP較高的敵人，造成對應最大HP的\\n\u3000中幅度的魔法傷害，並且使其陷入麻痺。\\n・當阿爾瑪自身的HP低於50%之時，\\n\u3000它的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (307704, '詛咒‧阿爾瑪', 307704, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】因為露娜之塔的魔力暴走的，古代兵器。\\n因魔力而凶暴化的守護之力，成了粉碎一切的災厄。\\n\\n‧對全體敵人造成特大幅度的物理傷害。\\n‧對前方小範圍內的隨機敵人角色，造成\\n\u3000共計3次的大幅度物理傷害。\\n‧對魔法攻擊力最高的1名角色，\\n\u3000造成中幅度的物理傷害，同時使其麻痺。\\n\u3000並且對該角色周圍小範圍的敵人角色，\\n\u3000造成中幅度的物理傷害。');
insert into unit_enemy_data values (307800, '雨神大人', 307800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】自古以來便司掌島嶼天候至今的守護神。\\n因苦求友人之心而鬱，導致演變成如此不祥的樣貌。\\n大地萬物皆將被那哀哭之雨淹沒殆盡。\\n\\n・必殺技可對全體敵人造成大幅度\\n\u3000的魔法傷害，同時擊飛。\\n\u3000並且，對前方範圍內全體敵人造成\\n\u3000中幅度的魔法追加傷害。\\n・對離最遠的 1 名敵人造成中幅度的魔法傷害，\\n\u3000並且小幅度的將其拉近。');
insert into unit_enemy_data values (307801, '雨神大人', 307800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】自古以來便司掌島嶼天候至今的守護神。\\n因苦求友人之心而鬱，導致演變成如此不祥的樣貌。\\n大地萬物皆將被那哀哭之雨淹沒殆盡。\\n\\n‧必殺技為對全體敵人依照其最大HP\\n\u3000造成魔法比例傷害，並將其向後擊飛。\\n\u3000同時對前方範圍內的全體敵人\\n\u3000依照其最大HP造成魔法比例\\n\u3000傷害。\\n‧對離最遠的1名敵人造成中幅度的魔法傷害，\\n\u3000並且小幅度的將其拉近。');
insert into unit_enemy_data values (307802, '雨神大人', 307800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】自古以來便司掌島嶼天候至今的守護神。\\n因苦求友人之心而鬱，導致演變成如此不祥的樣貌。\\n大地萬物皆將被那哀哭之雨淹沒殆盡。\\n\\n‧必殺技為對全體敵人依照其最大HP\\n\u3000造成魔法比例傷害，並將其向後擊飛。\\n\u3000同時對前方範圍內的全體敵人\\n\u3000依照其最大HP造成魔法比例\\n\u3000傷害。\\n‧對前方範圍內的全體敵人造成中幅度的魔法傷害，\\n\u3000同時小幅度擊飛。並且對離最近的1名敵人，\\n\u3000造成中幅度的魔法追加傷害。\\n‧對離最遠的1名敵人造成中幅度的魔法傷害，\\n\u3000並且小幅度的將其拉近。\\n‧當雨神大人自身HP低於40%時，\\n\u3000其攻擊將會便得更加狂暴。');
insert into unit_enemy_data values (307803, '雨神大人', 307800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】自古以來便司掌島嶼天候至今的守護神。\\n因苦求友人之心而鬱，導致演變成如此不祥的樣貌。\\n大地萬物皆將被那哀哭之雨淹沒殆盡。\\n\\n‧必殺技為對全體敵人依照其最大HP\\n\u3000造成魔法比例傷害，並將其向後擊飛。\\n\u3000同時對前方範圍內的全體敵人\\n\u3000依照其最大HP造成魔法比例\\n\u3000傷害。\\n‧對前方範圍內的全體敵人造成中幅度的魔法傷害，\\n\u3000同時小幅度擊飛。並且對離最近的1名敵人，\\n\u3000造成中幅度的魔法追加傷害。\\n‧對離最遠的1名敵人造成中幅度的魔法傷害，\\n\u3000並且小幅度的將其拉近。\\n‧當雨神大人自身HP低於40%時，\\n\u3000其攻擊將會便得更加狂暴。');
insert into unit_enemy_data values (307804, '雨神大人', 307801, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE1】因悲嘆而失去理智的雨吉，\\n將眾人的思念拒之千里，而那焦慮的內心，\\n甚至就連晴吉那所苦求殷盼許久的聲音，\\n也觸及不了。\\n\\n・展開護盾，使其不會受到敵人造成的任何攻擊。\\n\u3000此護盾與傷害量無關，而是每當受到攻擊時，\\n\u3000便會漸漸的降低其耐久度。\\n\u3000當受到 200 次的攻擊後，護盾將會被破壞。\\n\u3000\\n・必殺技能夠對全體敵人造成大幅度的魔法傷害，\\n\u3000同時造成擊飛。並且對前方範圍內全體敵人造成\\n\u3000中幅度的追加魔法傷害。\\n・對前方範圍內的全體敵人造成中幅度的魔法傷害，\\n\u3000同時小幅度擊飛。並且對離最近的 1 名敵人，\\n\u3000造成中幅度的魔法追加傷害。');
insert into unit_enemy_data values (307805, '雨神大人', 307800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE2】哀哭之雨，伴隨著哀戚一同降下。\\n那漆黑的雨滴，夾帶對悲哀的渴望，\\n將人們的身心俱蝕。\\n\\n・在戰鬥開始時，祂將召喚出帶來詛咒的水晶。\\n\u3000而當詛咒的水晶仍然存在於在戰鬥場上的時候，\\n\u3000將會對全體敵人持續造成傷害。同時，\\n\u3000不論是打算以任何效果進行 HP 的恢復，\\n\u3000該恢復都將會無效，並將原本恢復量的 10%\\n\u3000轉變為傷害。\\n・必殺技能夠對全體敵人造成大幅度的魔法傷害，\\n\u3000同時造成擊飛。並且對前方範圍內全體敵人造成\\n\u3000中幅度的追加魔法傷害。\\n・對前方範圍內的全體敵人造成中幅度的魔法傷害，\\n\u3000同時小幅度擊飛。並且對離最近的一名敵人，\\n\u3000造成中幅度的魔法追加傷害。\\n・對離最遠的 1 名敵人造成中幅度的魔法傷害，\\n\u3000並且小幅度的將其拉近。');
insert into unit_enemy_data values (307806, '雨神大人', 307800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE3】為得贖罪於晴吉而乞懇慟哭\\n所造成的洪流，同時撕裂著對峙者的心靈。\\n愛、友情，一切的情感也都將化為烏有。\\n\\n・必殺技能夠對全體敵人造成大幅度的魔法傷害，\\n\u3000同時造成擊飛。並且對前方範圍內全體敵人造成\\n\u3000中幅度的追加魔法傷害。\\n・對前方範圍內的全體敵人造成中幅度的魔法傷害，\\n\u3000同時小幅度擊飛。並且對離最近的一名敵人，\\n\u3000造成中幅度的魔法追加傷害。\\n・對離最遠的 1 名敵人造成中幅度的魔法傷害，\\n\u3000並且小幅度的將其拉近。\\n・當雨神大人自身 HP 低於 40% 時，\\n\u3000其攻擊將會便得更加狂暴。');
insert into unit_enemy_data values (307807, '雨神大人', 307800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】自古以來便司掌島嶼天候至今的守護神。\\n因苦求友人之心而鬱，導致演變成如此不祥的樣貌。\\n大地萬物皆將被那哀哭之雨淹沒殆盡。\\n\\n‧必殺技為對全體敵人依照其最大HP\\n\u3000造成魔法比例傷害，並將其向後擊飛。\\n\u3000同時對前方範圍內的全體敵人\\n\u3000依照其最大HP造成魔法比例\\n\u3000傷害。\\n‧對離最遠的1名敵人造成中幅度的魔法傷害，\\n\u3000並且小幅度的將其拉近。');
