insert into unit_enemy_data values (307811, '雨神大人', 307801, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE1】因悲嘆而失去理智的雨吉，\\n將眾人的思念拒之千里，而那焦慮的內心，\\n甚至就連晴吉那所苦求殷盼許久的聲音，\\n也觸及不了。\\n\\n‧展開護盾，使其不會受到敵人造成的任何攻擊。\\n\u3000此護盾與傷害量無關，而是每當受到攻擊時，\\n\u3000便會漸漸的降低其耐久度。\\n\u3000當受到200次的攻擊後，護盾將會被破壞。\\n\u3000\\n‧必殺技為對全體敵人依照其最大HP\\n\u3000造成魔法比例傷害，並將其向後擊飛。\\n\u3000同時對前方範圍內的全體敵人\\n\u3000依照其最大HP造成魔法比例\\n\u3000傷害。\\n‧對前方範圍內的全體敵人\\n\u3000造成中幅度的魔法傷害。\\n');
insert into unit_enemy_data values (307812, '雨神大人', 307800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE2】哀哭之雨，伴隨著哀戚一同降下。\\n那漆黑的雨滴，夾帶對悲哀的渴望，\\n將人們的身心俱蝕。\\n\\n‧在戰鬥開始時，祂將召喚出帶來詛咒的水晶。\\n\u3000詛咒的水晶存在於場上的時候，\\n\u3000會持續對全體敵人造成魔法傷害。同時，\\n\u3000不論是打算以任何效果進行HP的恢復，\\n\u3000該恢復都將會無效，並將原本恢復量的10%\\n\u3000轉變為傷害。\\n‧必殺技為對全體敵人依照其最大HP\\n\u3000造成魔法比例傷害，並將其向後擊飛。\\n\u3000同時對前方範圍內的全體敵人\\n\u3000依照其最大HP造成魔法比例\\n\u3000傷害。\\n‧對前方範圍內的全體敵人造成中幅度的魔法傷害，\\n\u3000同時小幅度擊飛。並且對離最近的1名敵人，\\n\u3000造成中幅度的魔法追加傷害。\\n‧對離最遠的1名敵人造成中幅度的魔法傷害，\\n\u3000並且小幅度的將其拉近。');
insert into unit_enemy_data values (307813, '雨神大人', 307800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE3】為得贖罪於晴吉而乞懇慟哭\\n所造成的洪流，同時撕裂著對峙者的心靈。\\n愛、友情，一切的情感也都將化為烏有。\\n\\n‧必殺技為對全體敵人依照其最大HP\\n\u3000造成魔法比例傷害，並將其向後擊飛。\\n\u3000同時對前方範圍內的全體敵人\\n\u3000依照其最大HP造成魔法比例\\n\u3000傷害。\\n‧對前方範圍內的全體敵人造成中幅度的魔法傷害，\\n\u3000同時小幅度擊飛。並且對離最近的1名敵人，\\n\u3000造成中幅度的魔法追加傷害。\\n‧對離最遠的1名敵人造成中幅度的魔法傷害，\\n\u3000並且小幅度的將其拉近。\\n‧當雨神大人自身HP低於40%時，\\n\u3000其攻擊將會便得更加狂暴。');
insert into unit_enemy_data values (307900, '加爾格', 307900, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】以屍肉為食的大型兇暴魔獸。\\n將強韌的荊棘纏於身，並異常執著於追捕獵物。\\n\\n‧對全體敵人依照其最大HP造成\\n\u3000物理比例傷害。\\n‧對前方的第3、4、5名角色造成\\n\u3000中幅度的物理傷害，同時使其暈眩。');
insert into unit_enemy_data values (307901, '加爾格', 307900, 0, 16, 270, 1000, 1, 1.9, 0, 0, 0, '【物理】以屍肉為食的大型兇暴魔獸。\\n將強韌的荊棘纏於身，並異常執著於追捕獵物。\\n\\n‧對全體敵人依照其最大HP造成\\n\u3000物理比例傷害。\\n‧對前方的第3、4、5名角色造成\\n\u3000中幅度的物理傷害，同時使其暈眩。');
insert into unit_enemy_data values (307902, '加爾格', 307900, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】以屍肉為食的大型兇暴魔獸。\\n將強韌的荊棘纏於身，並異常執著於追捕獵物。\\n\\n‧對全體敵人依照其最大HP造成\\n\u3000物理比例傷害。\\n‧對前方的第3、4、5名角色造成\\n\u3000中幅度的物理傷害，同時使其暈眩。\\n‧對前方的2名角色造成中幅度的物理傷害。\\n‧當加爾格自身的HP低於50%時，\\n\u3000牠的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (307903, '加爾格', 307900, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】以屍肉為食的大型兇暴魔獸。\\n將強韌的荊棘纏於身，並異常執著於追捕獵物。\\n\\n‧對全體敵人依照其最大HP造成\\n\u3000物理比例傷害。\\n‧對前方的第3、4、5名角色造成\\n\u3000中幅度的物理傷害，同時使其暈眩。\\n‧對前方的2名角色造成中幅度的物理傷害。\\n‧當加爾格自身的HP低於50%時，\\n\u3000牠的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (308000, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】以善良之魂為食，是兇殘至極的惡靈。\\n為貪求更好的祭品，那眾多的分身體正蠢蠢欲動。\\n\\n・奄美魔物將會依照所保持著的【吸魂】素質數量，\\n\u3000進而使普通攻擊和各種技能等等的效果受到強化。\\n\u3000\\n・每次的普通攻擊，都會追加 6 個【吸魂】。\\n・必殺技可對全體敵人造成特大幅度的\\n\u3000魔法傷害。並且追加 5 個【吸魂】。\\n・對全體造成小幅度的魔法傷害，同時減少其 TP，\\n\u3000並且展開小幅度降低 TP 上升的領域。\\n\u3000此領域的 TP 減少量效果值，\\n\u3000將會依照奄美魔物所保持著的【吸魂】\\n\u3000數量多寡而有所強化。\\n・每當攻擊時奄美魔物都會追加 1 個【吸魂】，\\n\u3000同時召喚 3 隻分身體，並且對全體敵人\\n\u3000造成小幅度的擊飛。\\n・每當奄美魔物受到暴擊傷害時，\\n\u3000將會減少奄美魔物的 2 個【吸魂】。\\n・每當分身體受到暴擊傷害時，\\n\u3000則會減少奄美魔物的 1 個【吸魂】。\\n・當奄美魔物的 HP 低於 40% 時，\\n\u3000其攻擊將會變得更加狂暴。\\n\u3000並且追加 20 個【吸魂】。');
insert into unit_enemy_data values (308001, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】以善良之魂為食，是兇殘至極的惡靈。\\n為貪求更好的祭品，那眾多的分身體正蠢蠢欲動。\\n\\n・奄美魔物將會依照所保持著的【吸魂】素質數量，\\n\u3000進而使普通攻擊和各種技能等等的效果受到強化。\\n\u3000\\n・每次的普通攻擊，都會追加 6 個【吸魂】。\\n・必殺技可對全體敵人造成特大幅度的\\n\u3000魔法傷害。並且追加 5 個【吸魂】。\\n・對全體造成小幅度的魔法傷害，同時減少其 TP，\\n\u3000並且展開小幅度降低 TP 上升的領域。\\n\u3000此領域的 TP 減少量效果值，\\n\u3000將會依照奄美魔物所保持著的【吸魂】\\n\u3000數量多寡而有所強化。\\n・每當攻擊時奄美魔物都會追加 1 個【吸魂】，\\n\u3000同時召喚 3 隻分身體，並且對全體敵人\\n\u3000造成小幅度的擊飛。\\n・每當奄美魔物受到暴擊傷害時，\\n\u3000將會減少奄美魔物的 2 個【吸魂】。\\n・每當分身體受到暴擊傷害時，\\n\u3000則會減少奄美魔物的 1 個【吸魂】。');
insert into unit_enemy_data values (308002, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】以善良之魂為食，是兇殘至極的惡靈。\\n為貪求更好的祭品，那眾多的分身體正蠢蠢欲動。\\n\\n・奄美魔物將會依照所保持著的【吸魂】素質數量，\\n\u3000進而使普通攻擊和各種技能等等的效果受到強化。\\n\u3000\\n・每次的普通攻擊，都會追加 6 個【吸魂】。\\n・必殺技可對全體敵人造成特大幅度的\\n\u3000魔法傷害。並且追加 5 個【吸魂】。\\n・對全體造成小幅度的魔法傷害，同時減少其 TP，\\n\u3000並且展開小幅度降低 TP 上升的領域。\\n\u3000此領域的 TP 減少量效果值，\\n\u3000將會依照奄美魔物所保持著的【吸魂】\\n\u3000數量多寡而有所強化。\\n・每當攻擊時奄美魔物都會追加 1 個【吸魂】，\\n\u3000同時召喚 3 隻分身體，並且對全體敵人\\n\u3000造成小幅度的擊飛。\\n・每當奄美魔物受到暴擊傷害時，\\n\u3000將會減少奄美魔物的 2 個【吸魂】。\\n・每當分身體受到暴擊傷害時，\\n\u3000則會減少奄美魔物的 1 個【吸魂】。\\n・當奄美魔物的 HP 低於 40% 時，\\n\u3000其攻擊將會變得更加狂暴。\\n\u3000並且追加 20 個【吸魂】。');
insert into unit_enemy_data values (308003, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE1】那黃昏時分出沒的巨惡之化身，\\n遵循著本能大快朵頤著千百魂魄。\\n\\n・在戰鬥開始的同時，將會特大幅度提升自身\\n\u3000的魔法攻擊力，並且向敵方的隊伍展開\\n\u3000特大幅度降低物理暴擊與魔法暴擊\\n\u3000的領域。\\n・奄美魔物將會依照所保持著的【吸魂】素質數量，\\n\u3000進而使普通攻擊和各種技能等等的效果受到強化。\\n\u3000\\n・每次的普通攻擊，都會追加 6 個【吸魂】。\\n・必殺技可對全體敵人造成特大幅度的魔法傷害。\\n\u3000並且追加 5 個【吸魂】。\\n・對全體造成小幅度的魔法傷害，同時減少其 TP，\\n\u3000並且展開小幅度降低 TP 上升的領域。\\n\u3000此領域的 TP減少量效果值，\\n\u3000將會依照奄美魔物所保持著的【吸魂】\\n\u3000數量多寡而有所強化。\\n・每當奄美魔物受到暴擊傷害時，\\n\u3000將會減少奄美魔物的 5 個【吸魂】。');
insert into unit_enemy_data values (308004, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE2】於那晦夜時分出沒的鬱鬱怨靈，\\n欲將萬物生靈之魂撕裂粉碎。\\n\\n・每當打倒了 1 隻的分身體，所剩的奄美魔物數量\\n\u3000將會減少 1 個。然而此後，分身體將會再次被召喚。\\n・奄美魔物將會依照所保持著的【吸魂】素質數量，\\n\u3000進而使普通攻擊和各種技能等等的效果受到強化。\\n\u3000\\n・每次的普通攻擊，都會追加 6 個【吸魂】。\\n・每當攻擊時奄美魔物都會追加 1 個【吸魂】，\\n\u3000同時召喚 3 隻分身體，並且對全體敵人\\n\u3000造成小幅度的擊飛。\\n・每當奄美魔物受到暴擊傷害時，\\n\u3000將會減少奄美魔物的 2 個【吸魂】。\\n・每當分身體受到暴擊傷害時，\\n\u3000則會減少奄美魔物的 1 個【吸魂】。');
insert into unit_enemy_data values (308005, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE3】跋扈於無日之曉的魑魅魍魎，\\n因三千世界之魂無以果腹而伸出了魔爪。\\n\\n・奄美魔物將會依照所保持著的【吸魂】素質數量，\\n\u3000進而使普通攻擊和各種技能等等的效果受到強化。\\n\u3000\\n・每次的普通攻擊，都會追加 6 個【吸魂】。\\n・必殺技可對全體敵人造成特大幅度的\\n\u3000魔法傷害。並且追加 5 個【吸魂】。\\n・對全體造成小幅度的魔法傷害，同時減少其 TP，\\n\u3000並且展開小幅度降低 TP 上升的領域。\\n\u3000此領域的 TP 減少量效果值，\\n\u3000將會依照奄美魔物所保持著的【吸魂】\\n\u3000數量多寡而有所強化。\\n・每當攻擊時奄美魔物都會追加 1 個【吸魂】，\\n\u3000同時召喚 3 隻分身體，並且對全體敵人\\n\u3000造成小幅度的擊飛。\\n・每當奄美魔物受到暴擊傷害時，\\n\u3000將會減少奄美魔物的 2 個【吸魂】。\\n・每當分身體受到暴擊傷害時，\\n\u3000則會減少奄美魔物的 1 個【吸魂】。\\n・當剩餘時間不到 40 秒時，其攻擊將會\\n\u3000變得更加狂暴。\\n\u3000並且追加 20 個【吸魂】。');
insert into unit_enemy_data values (308006, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】以善良之魂為食，是兇殘至極的惡靈。\\n為貪求更好的祭品，那眾多的分身體正蠢蠢欲動。\\n\\n‧奄美魔物將會依照所保持著的【吸魂】素質數量，\\n\u3000進而使普通攻擊和各種技能等等的效果受到強化。\\n\u3000\\n‧每次的普通攻擊，都會追加6個【吸魂】。\\n‧必殺技能夠對全體敵人依照其最大HP\\n\u3000造成魔法比例傷害，\\n\u3000並且追加5個【吸魂】。\\n‧對全體敵人造成小幅度的魔法傷害再減少TP，\\n\u3000並且展開降低TP上升的\\n\u3000領域。此領域的TP減少量效果值，\\n\u3000將會依照奄美魔物所保持著的【吸魂】\\n\u3000數量多寡而有所強化。\\n‧攻擊時奄美魔物會追加1個【吸魂】，\\n\u3000召喚3隻分身，並且將全體敵人\\n\u3000小幅度擊飛。\\n‧每當奄美魔物受到暴擊傷害時，\\n\u3000將會減少奄美魔物的2個【吸魂】。\\n‧每當分身體受到暴擊傷害時，\\n\u3000則會減少奄美魔物的1個【吸魂】。\\n‧當奄美魔物的HP低於30%時，\\n\u3000其攻擊將會變得更加狂暴。\\n\u3000並且追加20個【吸魂】。');
insert into unit_enemy_data values (308007, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】以善良之魂為食，是兇殘至極的惡靈。\\n為貪求更好的祭品，那眾多的分身體正蠢蠢欲動。\\n\\n‧奄美魔物將會依照所保持著的【吸魂】素質數量，\\n\u3000進而使普通攻擊和各種技能等等的效果受到強化。\\n\u3000\\n‧每次的普通攻擊，都會追加6個【吸魂】。\\n‧必殺技會對全體敵人依照\\n\u3000所保持著的【吸魂】數量\\n\u3000造成魔法比例傷害，\\n\u3000並且追加5個【吸魂】。\\n‧對全體敵人造成小幅度的魔法傷害再減少TP，\\n\u3000並且展開降低TP上升的\\n\u3000領域。此領域的TP減少量效果值，\\n\u3000將會依照奄美魔物所保持著的【吸魂】\\n\u3000數量多寡而有所強化。\\n‧攻擊時奄美魔物會追加1個【吸魂】，\\n\u3000召喚3隻分身，並且將全體敵人\\n\u3000小幅度擊飛。\\n‧每當奄美魔物受到暴擊傷害時，\\n\u3000將會減少奄美魔物的2個【吸魂】。\\n‧每當分身體受到暴擊傷害時，\\n\u3000則會減少奄美魔物的1個【吸魂】。');
insert into unit_enemy_data values (308008, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】以善良之魂為食，是兇殘至極的惡靈。\\n為貪求更好的祭品，那眾多的分身體正蠢蠢欲動。\\n\\n‧奄美魔物將會依照所保持著的【吸魂】素質數量，\\n\u3000進而使普通攻擊和各種技能等等的效果受到強化。\\n\u3000\\n‧每次的普通攻擊，都會追加6個【吸魂】。\\n‧必殺技會對全體敵人依照\\n\u3000所保持著的【吸魂】數量\\n\u3000造成魔法比例傷害，\\n\u3000並且追加5個【吸魂】。\\n‧對全體敵人造成小幅度的魔法傷害再減少TP，\\n\u3000並且展開降低TP上升的\\n\u3000領域。此領域的TP減少量效果值，\\n\u3000將會依照奄美魔物所保持著的【吸魂】\\n\u3000數量多寡而有所強化。\\n‧攻擊時奄美魔物會追加1個【吸魂】，\\n\u3000召喚3隻分身，並且將全體敵人\\n\u3000小幅度擊飛。\\n‧每當奄美魔物受到暴擊傷害時，\\n\u3000將會減少奄美魔物的2個【吸魂】。\\n‧每當分身體受到暴擊傷害時，\\n\u3000則會減少奄美魔物的1個【吸魂】。\\n‧當奄美魔物的HP低於30%時，\\n\u3000其攻擊將會變得更加狂暴。\\n\u3000並且追加20個【吸魂】。');
insert into unit_enemy_data values (308009, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE1】從黃昏中誕生的巨惡化身，\\n遵循本能吞噬了數百靈魂。\\n\\n‧戰鬥開始後，特大幅度提升自己的\\n\u3000魔法攻擊力，並且展開特大幅降低\\n\u3000全體敵人物理暴擊率與魔法暴擊率\\n\u3000的領域。\\n‧奄美魔物將會依照所保持著的【吸魂】素質數量，\\n\u3000進而使普通攻擊和各種技能等等的效果受到強化。\\n\u3000\\n‧每次的普通攻擊，都會追加6個【吸魂】。\\n‧必殺技會對全體敵人依照\\n\u3000所保持著的【吸魂】數量\\n\u3000造成魔法比例傷害，\\n\u3000並且追加5個【吸魂】。\\n‧對全體敵人造成小幅度的魔法傷害再減少TP，\\n\u3000並且展開降低TP上升的\\n\u3000領域。此領域的TP減少量效果值，\\n\u3000將會依照奄美魔物所保持著的【吸魂】\\n\u3000數量多寡而有所強化。\\n‧每當奄美魔物受到暴擊傷害時，\\n\u3000將會減少奄美魔物的5個【吸魂】。');
insert into unit_enemy_data values (308010, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE2】從薄暮中現形的怨靈集合體，\\n將數千人魂撕成碎片。\\n\\n‧每當打倒了1隻的分身體，所剩的奄美魔物數量\\n\u3000將會減少1個。而之後，分身體將會再次被召喚。\\n‧奄美魔物將會依照所保持著的【吸魂】素質數量，\\n\u3000進而使普通攻擊和各種技能等等的效果受到強化。\\n\u3000\\n‧每次的普通攻擊，都會追加6個【吸魂】。\\n‧攻擊時奄美魔物會追加1個【吸魂】，\\n\u3000召喚3隻分身，並且將全體敵人\\n\u3000小幅度擊飛。\\n‧每當奄美魔物受到暴擊傷害時，\\n\u3000將會減少奄美魔物的2個【吸魂】。\\n‧每當分身體受到暴擊傷害時，\\n\u3000則會減少奄美魔物的1個【吸魂】。');
insert into unit_enemy_data values (308011, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE3】在黎明前黑暗中肆虐的魑魅，\\n終於為了吞噬三千世界靈魂而露出獠牙。\\n\\n‧奄美魔物將會依照所保持著的【吸魂】素質數量，\\n\u3000進而使普通攻擊和各種技能等等的效果受到強化。\\n\u3000\\n‧每次的普通攻擊，都會追加6個【吸魂】。\\n‧必殺技會對全體敵人依照\\n\u3000所保持著的【吸魂】數量\\n\u3000造成魔法比例傷害，\\n\u3000並且追加5個【吸魂】。\\n‧對全體敵人造成小幅度的魔法傷害再減少TP，\\n\u3000並且展開降低TP上升的\\n\u3000領域。此領域的TP減少量效果值，\\n\u3000將會依照奄美魔物所保持著的【吸魂】\\n\u3000數量多寡而有所強化。\\n‧攻擊時奄美魔物會追加1個【吸魂】，\\n\u3000召喚3隻分身，並且將全體敵人\\n\u3000小幅度擊飛。\\n‧每當奄美魔物受到暴擊傷害時，\\n\u3000將會減少奄美魔物的2個【吸魂】。\\n‧每當分身體受到暴擊傷害時，\\n\u3000則會減少奄美魔物的1個【吸魂】。\\n‧當剩餘時間不到30秒時，其攻擊將會\\n\u3000變得更加狂暴。\\n\u3000並且追加20個【吸魂】。');
insert into unit_enemy_data values (308012, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】以善良之魂為食，是兇殘至極的惡靈。\\n為貪求更好的祭品，那眾多的分身體正蠢蠢欲動。\\n\\n‧奄美魔物將會依照所保持著的【吸魂】素質數量，\\n\u3000進而使普通攻擊和各種技能等等的效果受到強化。\\n\u3000\\n‧每次的普通攻擊，都會追加6個【吸魂】。\\n‧必殺技會對全體敵人依照\\n\u3000所保持著的【吸魂】數量\\n\u3000造成魔法比例傷害，\\n\u3000並且追加5個【吸魂】。\\n‧對全體敵人造成小幅度的魔法傷害再減少TP，\\n\u3000並且展開降低TP上升的\\n\u3000領域。此領域的TP減少量效果值，\\n\u3000將會依照奄美魔物所保持著的【吸魂】\\n\u3000數量多寡而有所強化。\\n‧攻擊時奄美魔物會追加1個【吸魂】，\\n\u3000召喚3隻分身，並且將全體敵人\\n\u3000小幅度擊飛。\\n‧每當奄美魔物受到暴擊傷害時，\\n\u3000將會減少奄美魔物的2個【吸魂】。\\n‧每當分身體受到暴擊傷害時，\\n\u3000則會減少奄美魔物的1個【吸魂】。');
insert into unit_enemy_data values (308100, '天塔帕斯', 308100, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】君臨於海邊的巨大軟體魔物。\\n以強韌的觸手與鋼鐵的大鉗，將一切都摧之殆盡。\\n\\n‧對全體敵人依照其最大HP造成大幅度的\\n\u3000物理傷害。\\n‧對後方範圍內的敵人造成中幅度的魔法傷害，\\n\u3000使其陷入麻痺狀態，並且使其物理攻擊力、\\n\u3000魔法攻擊力特大幅度下降。\\n‧每當經過一定的時間，將會造成\\n\u3000敵方單體超特大幅度的物理傷害。\\n‧當天塔帕斯自身的HP低於40%時，\\n\u3000牠的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (308101, '天塔帕斯', 308100, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】君臨於海邊的巨大軟體魔物。\\n以強韌的觸手與鋼鐵的大鉗，將一切都摧之殆盡。\\n\\n‧對全體敵人依照其最大HP造成大幅度的\\n\u3000物理傷害。\\n‧對後方範圍內的敵人造成中幅度的魔法傷害，\\n\u3000使其陷入麻痺狀態，並且使其物理攻擊力、\\n\u3000魔法攻擊力特大幅度下降。');
insert into unit_enemy_data values (308102, '天塔帕斯', 308100, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】君臨於海邊的巨大軟體魔物。\\n以強韌的觸手與鋼鐵的大鉗，將一切都摧之殆盡。\\n\\n‧對全體敵人依照其最大HP造成大幅度的\\n\u3000物理傷害。\\n‧對後方範圍內的敵人造成中幅度的魔法傷害，\\n\u3000使其陷入麻痺狀態，並且使其物理攻擊力、\\n\u3000魔法攻擊力特大幅度下降。\\n‧當天塔帕斯自身的HP低於40%時，\\n\u3000牠的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (308103, '天塔帕斯', 308100, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】君臨於海邊的巨大軟體魔物。\\n以強韌的觸手與鋼鐵的大鉗，將一切都摧之殆盡。\\n\\n‧對全體敵人依照其最大HP造成大幅度的\\n\u3000物理傷害。\\n‧對後方範圍內的敵人造成中幅度的魔法傷害，\\n\u3000使其陷入麻痺狀態，並且使其物理攻擊力、\\n\u3000魔法攻擊力特大幅度下降。\\n‧每當經過一定的時間，將會造成\\n\u3000敵方單體超特大幅度的物理傷害。\\n‧當天塔帕斯自身的HP低於40%時，\\n\u3000牠的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (308200, '劇毒曼德拉草', 308200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '');
insert into unit_enemy_data values (308201, '劇毒曼德拉草', 308200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】碧栽培地異常良好的曼德拉草。\\n以堅韌的根和種子的子彈，壓制眼前的敵人。\\n\\n‧對前方2名角色依照其最大HP造成物理的\\n\u3000比例傷害。\\n‧必殺技能夠對全體敵人造成大幅度的\\n\u3000物理傷害，並且依據總計所造成的傷害，\\n\u3000來恢復自己的HP。\\n‧對全體敵人連續造成小幅度的物理傷害，\\n\u3000同時降低3次的物理防禦力。\\n‧在增加自己的物理攻擊力的同時，\\n\u3000也提升自己的TP。');
insert into unit_enemy_data values (308202, '劇毒曼德拉草', 308200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】碧栽培地異常良好的曼德拉草。\\n以堅韌的根和種子的子彈，壓制眼前的敵人。\\n\\n‧對前方2名角色依照其最大HP造成物理的\\n\u3000比例傷害。\\n‧必殺技能夠對全體敵人造成大幅度的\\n\u3000物理傷害，並且依據總計所造成的傷害，\\n\u3000來恢復自己的HP。\\n‧對全體敵人連續造成小幅度的物理傷害，\\n\u3000同時降低3次的物理防禦力。\\n‧在增加自己的物理攻擊力的同時，\\n\u3000也提升自己的TP。');
insert into unit_enemy_data values (308203, '劇毒曼德拉草', 308200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】碧栽培地異常良好的曼德拉草。\\n以堅韌的根和種子的子彈，壓制眼前的敵人。\\n\\n‧對前方2名角色依照其最大HP造成物理的\\n\u3000比例傷害。\\n‧必殺技能夠對全體敵人造成大幅度的\\n\u3000物理傷害，並且依據總計所造成的傷害，\\n\u3000來恢復自己的HP。\\n‧對全體敵人連續造成小幅度的物理傷害，\\n\u3000同時降低3次的物理防禦力。\\n‧在增加自己的物理攻擊力的同時，\\n\u3000也提升自己的TP。\\n‧當曼德拉草自身的HP低於40%時，\\n\u3000其攻擊將會變得更加狂暴。');
insert into unit_enemy_data values (308204, '劇毒曼德拉草', 308204, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE2】降下猛毒的胞子，使大地萬物\\n陷入一片荒蕪。\\n以無數的殘骸做為苗床，使那猛毒的一輪，\\n華麗綻放。\\n\\n按照以下的順序重複進行行動。\\n‧當曼德拉草把自己埋進地面下時，將會變成\\n\u3000無法受到傷害的狀態。\\n‧使全體敵人陷入強力的中毒狀態。\\n‧在解除自己身上被施放的所有降低素質的狀態\\n\u3000與效果後，極大幅度降低自己的物理防禦力與\\n\u3000魔法防禦力。');
insert into unit_enemy_data values (308205, '劇毒曼德拉草', 308200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE1】從觸手上滴落的水珠含有猛毒。\\n僅需一滴便能使泉水枯竭、森林腐敗，生命殞滅。\\n\\n‧對前方2名角色造成物理傷害，並且使其\\n\u3000陷入中毒狀態。\\n‧必殺技能夠對全體敵人造成大幅度的\\n\u3000物理傷害，並且依據總計所造成的傷害，\\n\u3000來恢復自己的HP。\\n\u3000對陷入中毒狀態的角色，大幅度提高傷害。\\n‧對全體敵人連續造成小幅度的物理傷害，\\n\u3000同時降低3次的物理防禦力。\\n‧在增加自己的物理攻擊力的同時，\\n\u3000也提升自己的TP。');
insert into unit_enemy_data values (308206, '劇毒曼德拉草', 308200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE3】絕命的咆哮，巨腕的蹂躪。\\n如同花朵般凋零的生命。以自身臨死的一聲\\n做為搖籃曲，使亡骸陷入永眠。\\n\\n‧對前方2名角色依照其最大HP造成物理的\\n\u3000比例傷害。\\n‧必殺技能夠對全體敵人造成大幅度的\\n\u3000物理傷害，並且依據總計所造成的傷害，\\n\u3000來恢復自己的HP。\\n‧對全體敵人連續造成小幅度的物理傷害，\\n\u3000同時降低3次的物理防禦力。\\n‧在增加自己的物理攻擊力的同時，\\n\u3000也提升自己的TP。\\n‧當剩餘時間低於40秒時，其攻擊將會變得\\n\u3000更加狂暴。');
insert into unit_enemy_data values (308207, '大王花曼德拉草', 308207, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】藉由塔之魔力開花並釋放劇毒的死亡大花\\n其毒會擾亂所有的知覺，腐蝕所有生物。\\n\\n‧對前方的2名角色造成物理傷害。\\n\u3000自身的HP低於80％之時，\\n\u3000同時使其陷入中毒狀態。\\n‧必殺技會對敵方全體造成大幅度的物理傷害，\\n\u3000對陷入中毒狀態的角色造成比例傷害。\\n\u3000之後大幅度降低敵方全體的物理攻擊力，\\n\u3000並大幅度提升自己的物理攻擊力。\\n‧對敵方全體造成小幅度的物理傷害，\\n\u3000降低物理防禦力。\\n‧提升自身的物理攻擊力與TP。\\n‧當剩餘HP低於80％時，\\n\u3000攻擊將會變得更加激烈且凶暴。\\n‧當它把自己埋進地面下時，將會變成\\n\u3000無法受到傷害的狀態，\\n\u3000使敵方全體長時間陷入中毒狀態。\\n\u3000同時使中毒狀態的角色陷入猛毒狀態。\\n\u3000之後，當它鑽出地面上時，\\n\u3000將解除自己身上被施放的\\n\u3000所有降低素質的狀態與效果，\\n\u3000極大幅度降低物理防禦力與魔法防禦力。');
insert into unit_enemy_data values (308300, '島鯨', 308300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】將為數眾多的探險家給吞噬的幻島之巨鯨。無慈悲地葬送了那些被慾望、幻想給憑依的愚者。\\n\\n‧對全體敵人依照其最大HP造成大幅度的\\n\u3000物理傷害。\\n‧對全體敵人造成中幅度的魔法傷害，\\n\u3000並且對島鯨自身的物理防禦力、\\n\u3000魔法防禦力給予極大幅度的上升。\\n‧對前方數來第3名角色造成大幅度的魔法傷害，\\n\u3000並且大幅度將其擊飛。\\n‧當島鯨自身的HP低於40%時，\\n\u3000牠的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (308301, '島鯨', 308300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】將為數眾多的探險家給吞噬的幻島之巨鯨。無慈悲地葬送了那些被慾望、幻想給憑依的愚者。\\n\\n‧對全體敵人依照其最大HP造成大幅度的\\n\u3000物理傷害。\\n‧對全體敵人造成中幅度的魔法傷害，\\n\u3000並且對島鯨自身的物理防禦力、\\n\u3000魔法防禦力給予極大幅度的上升。');
insert into unit_enemy_data values (308302, '島鯨', 308300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】將為數眾多的探險家給吞噬的幻島之巨鯨。無慈悲地葬送了那些被慾望、幻想給憑依的愚者。\\n\\n‧對全體敵人依照其最大HP造成大幅度的\\n\u3000物理傷害。\\n‧對全體敵人造成中幅度的魔法傷害，\\n\u3000並且對島鯨自身的物理防禦力、\\n\u3000魔法防禦力給予極大幅度的上升。\\n‧對前方數來第3名角色造成大幅度的魔法傷害，\\n\u3000並且大幅度將其擊飛。\\n‧當島鯨自身的HP低於40%時，\\n\u3000牠的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (308303, '島鯨', 308300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】將為數眾多的探險家給吞噬的幻島之巨鯨。無慈悲地葬送了那些被慾望、幻想給憑依的愚者。\\n\\n‧對全體敵人依照其最大HP造成大幅度的\\n\u3000物理傷害。\\n‧對全體敵人造成中幅度的魔法傷害，\\n\u3000並且對島鯨自身的物理防禦力、\\n\u3000魔法防禦力給予極大幅度的上升。\\n‧對前方數來第3名角色造成大幅度的魔法傷害，\\n\u3000並且大幅度將其擊飛。\\n‧當島鯨自身的HP低於40%時，\\n\u3000牠的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (308400, '幻影男爵', 308400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】走不出對孩子的執念，一名亡親之靈。\\n為了和女兒享受虛偽的天倫之樂，\\n對礙事者將毫不留情痛下毒手。\\n\\n‧必殺技能夠對全體敵人依照其最大HP\\n\u3000造成魔法的比例傷害，\\n\u3000同時降低魔法防禦力。\\n‧對距離最近的1名敵人造成大幅度的魔法傷害。\\n\u3000同時對前方3名角色依照其最大HP\\n\u3000造成魔法的比例傷害，\\n\u3000並且大距離向後擊飛。');
insert into unit_enemy_data values (308401, '幻影男爵', 308400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】走不出對孩子的執念，一名亡親之靈。\\n為了和女兒享受虛偽的天倫之樂，\\n對礙事者將毫不留情痛下毒手。\\n\\n‧必殺技能夠對全體敵人依照其最大HP\\n\u3000造成魔法的比例傷害，\\n\u3000同時降低魔法防禦力。\\n‧對距離最近的1名敵人造成大幅度的魔法傷害。\\n\u3000同時對前方3名角色依照其最大HP\\n\u3000造成魔法的比例傷害，\\n\u3000並且大距離向後擊飛。');
insert into unit_enemy_data values (308402, '幻影男爵', 308400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】走不出對孩子的執念，一名亡親之靈。\\n為了和女兒享受虛偽的天倫之樂，\\n對礙事者將毫不留情痛下毒手。\\n\\n‧必殺技能夠對全體敵人依照其最大HP\\n\u3000造成魔法的比例傷害，\\n\u3000同時降低魔法防禦力。\\n‧對距離最近的1名敵人造成大幅度的魔法傷害。\\n\u3000同時對前方3名角色依照其最大HP\\n\u3000造成魔法的比例傷害，\\n\u3000並且大距離向後擊飛。\\n‧對距離最遠的1名敵人造成中幅度的\\n\u3000物理傷害，並且將其拉至最前面一名角色\\n\u3000的位置，同時造成暈眩。\\n‧當幻影男爵自身的HP低於40%時，其攻擊\\n\u3000將會變得更加狂暴。');
insert into unit_enemy_data values (308403, '幻影男爵', 308400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】走不出對孩子的執念，一名亡親之靈。\\n為了和女兒享受虛偽的天倫之樂，\\n對礙事者將毫不留情痛下毒手。\\n\\n‧必殺技能夠對全體敵人依照其最大HP\\n\u3000造成魔法的比例傷害，\\n\u3000同時降低魔法防禦力。\\n‧對距離最近的1名敵人造成大幅度的魔法傷害。\\n\u3000同時對前方3名角色依照其最大HP\\n\u3000造成魔法的比例傷害，\\n\u3000並且大距離向後擊飛。\\n‧對距離最遠的1名敵人造成中幅度的\\n\u3000物理傷害，並且將其拉至最前面一名角色\\n\u3000的位置，同時造成暈眩。\\n‧當幻影男爵自身的HP低於40%時，其攻擊\\n\u3000將會變得更加狂暴。');
insert into unit_enemy_data values (308404, '幻影男爵', 308400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE1】召喚【小小甜心】\\n一行人的闇影。\\n向天真的少女們招手之處，是亡者蠢動的永夜之國。\\n\\n‧對前方1名角色造成魔法傷害。');
insert into unit_enemy_data values (308405, '幻影男爵', 308400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE2】當冥府之門敞開之際，\\n生者之魂將殞落於深淵。早就已經回天也乏術，\\n便以寄情之物為標的散播黑暗。\\n\\n‧必殺技能夠對全體敵人依照其最大HP\\n\u3000造成魔法的比例傷害，\\n\u3000同時降低魔法防禦力。\\n‧對距離最遠的1名敵人造成中幅度的\\n\u3000物理傷害，並且將其拉至最前面一名角色\\n\u3000的位置，同時造成暈眩。\\n‧對前方3名角色造成中幅度的魔法傷害，\\n\u3000中幅度降低其TP，並且中幅度恢復\\n\u3000幻影男爵的TP。\\n\u3000同時解除前方3名進行物理攻擊\\n\u3000的角色身上的增益效果，\\n\u3000對前方3名進行魔法攻擊\\n\u3000的角色追加造成大幅度的\\n\u3000魔法傷害。');
insert into unit_enemy_data values (308406, '幻影男爵', 308400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE3】與深愛之人別離正逐刻逼近。\\n為了反抗這悲傷的宿命，\\n怨靈尖聲發出了陣陣寂滅的慟哭。\\n\\n‧必殺技能夠對全體敵人依照其最大HP\\n\u3000造成魔法的比例傷害，\\n\u3000同時降低魔法防禦力。\\n‧對距離最近的1名敵人造成大幅度的魔法傷害。\\n\u3000同時對前方3名角色依照其最大HP\\n\u3000造成魔法的比例傷害，\\n\u3000並且大距離向後擊飛。\\n‧對距離最遠的1名敵人造成中幅度的\\n\u3000物理傷害，並且將其拉至最前面一名角色\\n\u3000的位置，同時造成暈眩。\\n‧在戰鬥剛開始時，提升自己的魔法攻擊力\\n\u3000與行動速度。');
insert into unit_enemy_data values (308500, '水瑚麟', 308500, 0, 16, 270, 1000, 1, 2.8, 0, 0, 0, '【物理】沉溺於月之魔力，大鬧四方的水之神獸。\\n忘卻了職責，成為了試圖將萬物徹底淹滅的狂獸。\\n\\n‧對全體敵人造成大幅度的魔法傷害，且使其畏懼。\\n\u3000陷入畏懼狀態的角色，在一定的時間之內進行\\n\u3000攻擊與HP恢復的必殺技，其效果都將減半。\\n‧對前方範圍內造成中幅度的魔法傷害，並且\\n\u3000依照命中次數的多寡，小幅度提升自身的\\n\u3000物理防禦力。同時展開能構造成\\n\u3000魔法傷害的領域。\\n‧對前方1名角色造成大幅度的魔法傷害，\\n\u3000並且消費自身的HP，對全體敵人造成\\n\u3000中幅度的魔法追加傷害。\\n\u3000同時，小幅度提升自己的物理攻擊力與\\n\u3000魔法攻擊力。');
insert into unit_enemy_data values (308600, '似龍生物', 308600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '');
insert into unit_enemy_data values (308601, '似龍生物', 308600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】以龍？一般的大翼翱翔於天際，\\n並以龍？一般的灼熱吐息將敵人燒得一片焦黑。\\n\\n‧在戰鬥開始時，\\n\u3000向自己追加70個【火焰果實】。\\n‧必殺技將會依據似龍生物所持有的\\n\u3000【火焰果實】數量多寡，\\n\u3000對敵方全體造成物理比例傷害。\\n\u3000使用後，【火焰果實】將減少60個。\\n‧對前方 3 名角色依照其最大HP造成\\n\u3000物理比例傷害，並使其暈眩。\\n‧發動時，在短時間內\\n\u3000大幅度降低自己的物理防禦力\\n\u3000與魔法防禦力，並且在進食的行動中，\\n\u3000將會持續增加【火焰果實】\\n\u3000直到最大60個為止。\\n\u3000在進食的行動中，當似龍生物受到了\\n\u30005000以上的傷害時，\\n\u3000此技能將會被迫中斷，\\n\u3000同時減少牠持有30個【火焰果實】。');
insert into unit_enemy_data values (308602, '似龍生物', 308600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】以龍？一般的大翼翱翔於天際，\\n並以龍？一般的灼熱吐息將敵人燒得一片焦黑。\\n\\n‧在戰鬥開始時，向自己追加70個【火焰果實】\\n‧必殺技將會依據似龍生物所持有的\\n\u3000【火焰果實】數量多寡，\\n\u3000對全體敵人造成物理比例傷害。\\n\u3000使用後，【火焰果實】將減少60個。\\n‧對前方 3 名角色依照其最大HP造成\\n\u3000物理比例傷害，並使其暈眩。\\n‧發動時，在短時間內\\n\u3000大幅度降低自己的物理防禦力\\n\u3000與魔法防禦力，並且在進食的行動中，\\n\u3000將會持續增加【火焰果實】\\n\u3000直到最大60個為止。\\n\u3000在進食的行動中，當似龍生物受到了\\n\u300020000以上的傷害時，\\n\u3000此技能將會被迫中斷\\n\u3000同時減少牠持有30個【火焰果實】。');
insert into unit_enemy_data values (308603, '似龍生物', 308600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】以龍？一般的大翼翱翔於天際，\\n並以龍？一般的灼熱吐息將敵人燒得一片焦黑。\\n\\n‧在戰鬥開始時，向自己追加70個【火焰果實】\\n‧必殺技將會依據似龍生物所持有的\\n\u3000【火焰果實】數量多寡，\\n\u3000對全體敵人造成物理比例傷害。\\n\u3000使用後，【火焰果實】將減少60個。\\n‧對前方 3 名角色依照其最大HP造成\\n\u3000物理比例傷害，並使其暈眩。\\n‧發動時，在短時間內\\n\u3000大幅度降低自己的物理防禦力\\n\u3000與魔法防禦力，並且在進食的行動中，\\n\u3000將會持續增加【火焰果實】\\n\u3000直到最大60個為止。\\n\u3000在進食的行動中，當似龍生物受到了\\n\u3000160000以上的傷害時，\\n\u3000此技能將會被迫中斷，\\n\u3000同時減少牠持有30個【火焰果實】。\\n‧當似龍生物的 HP 在 40% 以下時，\\n\u3000牠的攻擊將會變得更加狂暴。');
insert into unit_enemy_data values (308604, '似龍生物', 308600, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【MODE1】從蒼天傳來的咆哮撕裂了天際，\\n以璀璨烈陽般的自豪雙翼，巨大偽龍應聲降臨。\\n\\n‧當似龍生物所剩的HP低於80％時，\\n\u3000將會進到下一個MODE。\\n\\n‧在戰鬥開始時，向自己追加70個【火焰果實】\\n‧必殺技將會依據似龍生物所持有的\\n\u3000【火焰果實】數量多寡，\\n\u3000對全體敵人造成物理比例傷害。\\n\u3000使用後，【火焰果實】將減少60個。\\n‧對前方 3 名角色依照其最大HP造成\\n\u3000物理比例傷害，並使其暈眩。\\n‧發動時，在短時間內\\n\u3000大幅度降低自己的物理防禦力與\\n\u3000魔法防禦力，並且在進食的行動中，\\n\u3000將會持續增加【火焰果實】\\n\u3000直到最大60個為止。\\n\u3000在進食的行動中，當似龍生物受到了\\n\u3000150000以上的傷害時，\\n\u3000此技能將會被迫中斷，同時減少\\n\u3000牠持有的30個【火焰果實】。\\n‧叫出4隻魔物，\\n\u3000同時對全體敵人造成小幅度的擊退。');
insert into unit_enemy_data values (308605, '似龍生物', 308600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【MODE2】偽龍的一聲令下，森林內的魔物們\\n便集結而至。且為了守護牠拼上了小命。\\n\\n‧當魔像、多倫多獸\\n\u3000和毒莢花都被打倒時，\\n\u3000將會進到下一個MODE。\\n‧似龍生物將會對在牠面前的 1 名角色\\n\u3000造成物理攻擊。');
insert into unit_enemy_data values (308606, '似龍生物', 308606, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【MODE3】只因對龍的憧憬，使那蜥蜴覺醒了\\n統治天際之霸者的吹息，可使座島陷入無盡劫火。\\n\\n‧在戰鬥開始時，向自己追加70個【火焰果實】\\n‧必殺技將會依據似龍生物所持有的\\n\u3000【火焰果實】數量多寡，對全體敵人\\n\u3000造成物理比例傷害。\\n\u3000使用後，【火焰果實】將減少60個。\\n‧對前方3名角色依照其最大HP造成\\n\u3000物理比例傷害，並使其暈眩。\\n‧發動時，在短時間內\\n\u3000大幅度降低自己的物理防禦力\\n\u3000與魔法防禦力，並且在進食的行動中，\\n\u3000將會持續增加【火焰果實】\\n\u3000直到最大60個為止。\\n\u3000在進食的行動中，當似龍生物受到了\\n\u3000250000以上的傷害時，\\n\u3000此技能將會被迫中斷，\\n\u3000同時減少牠持有的30個【火焰果實】。\\n‧在戰鬥剛開始時，\\n\u3000牠的攻擊將會變得更加狂暴。');
insert into unit_enemy_data values (309000, '沙陸樹懶', 309000, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】於夢與實的狹縫間怠惰貪睡的一種樹獺。\\n若睡眠被妨礙將會很生氣，而以超能力大鬧一番。\\n\\n‧對全體敵人依照其最大HP造成\\n\u3000魔法比例傷害，並且大幅度降低物理攻擊力\\n\u3000與魔法攻擊力。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧對全體敵人造成小幅度的魔法傷害。');
insert into unit_enemy_data values (309001, '沙陸樹懶', 309001, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】於夢與實的狹縫間怠惰貪睡的一種樹獺。\\n若睡眠被妨礙將會很生氣，而以超能力大鬧一番。\\n\\n‧對全體敵人依照其最大HP造成\\n\u3000魔法比例傷害，並且大幅度降低物理攻擊力\\n\u3000與魔法攻擊力。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧對全體敵人造成小幅度的魔法傷害，並施加暈眩。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。');
insert into unit_enemy_data values (309100, '泥巴鱷', 309100, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】棲息於大河中的大鱷魚怪。\\n雖有著一臉蠢樣，卻以不可思議的\\n長槍將大地融解，封鎖冒險者的行\\n動。\\n\\n‧對全體敵人造成大幅度物理傷害\\n，並且同時降低物理防禦力與\\n\u3000行動速度。\\n\\n‧以從後方數來第3位角色為中心\\n，造成小範圍的小幅度物理傷害\\n，並且使其陷入束縛狀態。');
insert into unit_enemy_data values (309200, '蒼天女武神', 309200, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】於戰空中翩翩起舞，天上之女武神。\\n以目不暇給的連續射擊，完全封鎖敵人的退路。\\n\\n‧戰鬥開始時，\\n\u3000小幅度提升自身物理防禦力及魔法防禦力。\\n\u3000因防禦力提升效果而上升的防禦力，\\n\u3000在戰鬥中不會受到防禦力下降技能的影響。\\n‧必殺技能對前方範圍內最多4名角色\\n\u3000造成大幅度的物理傷害，並且特大幅度降低其TP，\\n\u3000同時大幅度降低其行動速度。\\n‧對前方3名敵人造成中幅度的物理傷害，\\n\u3000同時大幅度提升自身的行動速度。');
insert into unit_enemy_data values (309201, '蒼天女武神', 309201, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】於戰空中翩翩起舞，天上之女武神。\\n以目不暇給的連續射擊，完全封鎖敵人的退路。\\n\\n‧戰鬥開始時，\\n\u3000小幅度提升自身物理防禦力及魔法防禦力。\\n\u3000因防禦力提升效果而上升的防禦力，\\n\u3000在戰鬥中不會受到防禦力下降技能的影響。\\n‧必殺技能對前方範圍內最多4名角色\\n\u3000造成大幅度的物理傷害，並且特大幅度降低其TP，\\n\u3000同時大幅度降低其行動速度。\\n‧對前方4名敵人造成中幅度的物理傷害，\\n\u3000並大幅度降低其物理攻擊力與魔法攻擊力，\\n\u3000同時大幅度提升自身的行動速度。');
insert into unit_enemy_data values (309300, '復仇者馴鹿', 309300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '');
insert into unit_enemy_data values (309301, '復仇者馴鹿', 309300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】下定決心要高舉反叛旗幟的精英馴鹿。\\n向無盡慾望的聖誕老人，以從者之心揮下鐵槌。\\n\\n‧必殺技將會在消滅了召喚物後，\\n\u3000對敵方全體依照其角色最大HP\\n\u3000造成物理的比例傷害。\\n\u3000當受到此技能的傷害後，若角色的HP\\n\u3000低於40%，該名角色將會在一定時間內\\n\u3000變成馴鹿，同時降低其物理暴擊率\\n\u3000和魔法暴擊率。而變成了馴鹿的角色，\\n\u3000將只能夠使用普通攻擊。\\n\u3000在一定時間內，大幅度降低自身的物理防禦力。\\n‧以最前方的角色為中心，在一定範圍內\\n\u3000依照其角色最大HP造成物理的比例傷害。\\n\u3000同時提升自身的物理攻擊力。\\n‧對最前方的角色造成物理傷害與擊退，\\n\u3000並且同時使其陷入暈眩狀態。');
insert into unit_enemy_data values (309302, '復仇者馴鹿', 309300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】下定決心要高舉反叛旗幟的精英馴鹿。\\n向無盡慾望的聖誕老人，以從者之心揮下鐵槌。\\n\\n‧必殺技將會在消滅了召喚物後，\\n\u3000對敵方全體依照其角色最大HP\\n\u3000造成物理的比例傷害。\\n\u3000當受到此技能的傷害後，若角色的HP\\n\u3000低於40%，該名角色將會在一定時間內\\n\u3000變成馴鹿，同時降低其物理暴擊率\\n\u3000和魔法暴擊率。而變成了馴鹿的角色，\\n\u3000將只能夠使用普通攻擊。\\n\u3000在一定時間內，大幅度降低自身的物理防禦力。\\n‧以最前方的角色為中心，在一定範圍內\\n\u3000依照其角色最大HP造成物理的比例傷害。\\n\u3000同時提升自身的物理攻擊力。\\n‧對最前方的角色造成物理傷害與擊退，\\n\u3000並且同時使其陷入暈眩狀態。');
insert into unit_enemy_data values (309303, '復仇者馴鹿', 309300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】下定決心要高舉反叛旗幟的精英馴鹿。\\n向無盡慾望的聖誕老人，以從者之心揮下鐵槌。\\n\\n‧必殺技將會在消滅了召喚物後，\\n\u3000對敵方全體依照其角色最大HP\\n\u3000造成物理的比例傷害。\\n\u3000當受到此技能的傷害後，若角色的HP\\n\u3000低於40%，該名角色將會在一定時間內\\n\u3000變成馴鹿，同時降低其物理暴擊率\\n\u3000和魔法暴擊率。而變成了馴鹿的角色，\\n\u3000將只能夠使用普通攻擊。\\n\u3000在一定時間內，大幅度降低自身的物理防禦力。\\n‧以最前方的角色為中心，在一定範圍內\\n\u3000依照其角色最大HP造成物理的比例傷害。\\n\u3000同時提升自己的物理攻擊力。\\n‧對最前方的角色造成物理傷害與擊退，\\n\u3000並且同時使其陷入暈眩狀態。\\n‧當復仇者馴鹿自身的HP低於50％之時，\\n\u3000牠的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (309304, '復仇者馴鹿', 309300, 0, 16, 270, 3000, 1, 4.2, 0, 0, 0, '【MODE1】召喚出克莉絲提娜、望、伊莉亞的\\n闇影。三人那扭曲的慾望與好管閒事，\\n形成了具體之物並且將聖夜帶向了渾沌。\\n\\n‧對最前方的角色造成物理傷害。');
insert into unit_enemy_data values (309305, '復仇者馴鹿', 309300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【MODE2】絕望如同白雪一般在聖夜的街道上\\n沉積。從那被慾望染指的大袋之中滿溢而出的，\\n是累積已久的憎惡。\\n\\n‧必殺技將會在消滅了召喚物後，\\n\u3000對敵方全體依照其角色最大HP\\n\u3000造成物理的比例傷害。\\n\u3000當受到此技能的傷害後，若角色的HP\\n\u3000低於40%，該名角色將會在一定時間內\\n\u3000變成馴鹿，同時降低其物理暴擊率\\n\u3000和魔法暴擊率。而變成了馴鹿的角色，\\n\u3000將只能夠使用普通攻擊。\\n\u3000在一定時間內，大幅度降低自身的物理防禦力。\\n‧以最前方的角色為中心，在一定範圍內\\n\u3000依照其角色最大HP造成物理的比例傷害。\\n\u3000同時提升自身的物理攻擊力。\\n‧在一定時間內，於前方生成一個領域。\\n\u3000對處於此領域內的角色，\\n\u3000大幅度降低其物理攻擊力與物理暴擊率\\n\u3000和TP上升。\\n‧對最前方的角色造成物理傷害與擊退，\\n\u3000並且同時使其陷入暈眩狀態。');
insert into unit_enemy_data values (309306, '復仇者馴鹿', 309300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【MODE3】身負重傷的巨獸，燃起了反擊的狼煙。\\n將自身墮落於於憎惡與憤怒之終，\\n極盡殘虐之性情至最後一刻。\\n\\n‧必殺技將會在消滅了召喚物後，\\n\u3000對敵方全體依照其角色最大HP\\n\u3000造成物理的比例傷害。\\n\u3000當受到此技能的傷害後，若角色的HP\\n\u3000低於35%，該名角色將會在一定時間內\\n\u3000變成馴鹿，同時降低其物理暴擊率\\n\u3000和魔法暴擊率。而變成了馴鹿的角色，\\n\u3000將只能夠使用普通攻擊。\\n\u3000在一定時間內，大幅度降低自身的物理防禦力。\\n‧以最前方的角色為中心，在一定範圍內\\n\u3000依照其角色最大HP造成物理的比例傷害。\\n\u3000同時提升自身的物理攻擊力。\\n‧對最前方的角色造成物理傷害與擊退，\\n\u3000並且同時使其陷入暈眩狀態。\\n‧在戰鬥剛開始時，\\n\u3000牠的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (309400, '僕役‧刀刃（物理）', 309400, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】由霸瞳皇帝創造而出的自立能量儲藏庫。\\n擁有司掌著體力的權能，以那極大的劍戟斬斷一切。\\n\\n‧暈眩與擊飛能發揮效果。\\n\\n‧必殺技能夠對全體敵人依照其最大 HP\\n\u3000造成大幅度物理的比例傷害。\\n\\n‧以面前的敵人為中心，對範圍內所有的敵人\\n\u3000依照其角色最大 HP\\n\u3000造成物理的比例傷害。\\n\\n‧當僕役‧刀刃（物理）自身的 HP\\n\u3000低於 40% 之時，它的攻擊\\n\u3000將會變得更加的兇暴。');
insert into unit_enemy_data values (309500, '僕役‧魔能（魔法）', 309500, 0, 16, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】由霸瞳皇帝創造而出的自立能量儲藏庫。\\n擁有司掌著魔道的權能，能以無盡魔力將萬物消滅。\\n\\n‧必殺技能夠對全體敵人依照其最大 HP\\n\u3000造成大幅度的魔法比例傷害。\\n\u3000同時小幅度降低其物理攻擊力與魔法攻擊力。\\n\\n‧對隨機的 1 名角色造成魔法傷害，並且使其\\n\u3000陷入詛咒、麻痺狀態，同時大幅度降低 TP。\\n\\n‧僕役‧魔能（魔法）自身的 HP\\n\u3000低於 40% 之時，它的攻擊\\n\u3000將會變得更加的兇暴。');
insert into unit_enemy_data values (309600, '僕役‧洛克斯（複部位）', 309600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】由霸瞳皇帝創造而出的自立能量儲藏庫。\\n司掌著雙肩的權能，對廣泛領域的一切進行屠殺。\\n\\n‧必殺技將以面前的敵人為中心，對範圍內\\n\u3000所有的敵人依照其角色最大HP，造成物理\\n\u3000的比例傷害，同時再對面前的敵人造成\\n\u3000小幅度的物理傷害。\\n\\n‧以面前的敵人為中心，依照其\\n\u3000角色最大HP，造成物理的\\n\u3000比例傷害。\\n\\n‧當僕役‧洛克斯（複部位）自身的 HP\\n\u3000低於 40% 之時，它的防禦力\\n\u3000將會有所提升，而變得更加頑強。');
insert into unit_enemy_data values (309700, '僕役‧城牆（防衛）', 309700, 0, 16, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】由霸瞳皇帝創造而出的自立能量儲藏庫。\\n司掌著守護的權能，以毫不動搖的高牆拒絕一切。\\n\\n‧必殺技能夠大幅度提升自身的物理防禦力、\\n\u3000魔法防禦力。\\n\\n‧以面前的敵人為中心，對範圍內所有的敵人\\n\u3000造成魔法傷害。並且小幅度提升自身的\\n\u3000物理防禦力與魔法防禦力。\\n\\n‧當僕役‧城牆（防衛）自身的 HP\\n\u3000低於 40% 之時，它的防禦力\\n\u3000將會有所提升，而變得更加頑強。');
insert into unit_enemy_data values (309800, '霸瞳皇帝', 309800, 0, 16, 270, 1000, 1, 3.6, 309800, 309800, 0, '王都終末決戰_基本隊伍');
insert into unit_enemy_data values (309801, '霸瞳皇帝', 309801, 0, 16, 270, 1000, 1, 2.4, 309800, 309800, 0, '【MODE1】將一切拒絕在外的悲戚王女。\\n以神自居，將自身沉浸在禍殃之力之中。\\n並且對整個阿斯特朗揮舞起了那狂亂之刃。\\n守護那欺瞞之王女的牆壁，就用無數之刃來打破吧。\\n\\n‧展開護盾，使其不會受到敵人造成的任何攻擊。\\n\u3000此護盾與傷害量無關，而是每當受到攻擊時，\\n\u3000便會漸漸的降低其耐久度。\\n\u3000當受到280次的攻擊後，護盾將會被破壞。\\n\\n\\n‧必殺技將會依照敵方全體所剩的HP\\n\u3000造成特大幅度的比例傷害。\\n\\n‧對全體敵人造成小幅度的\\n\u3000魔法傷害。');
insert into unit_enemy_data values (309802, '霸瞳皇帝', 309800, 0, 16, 270, 1000, 1, 1.8, 309800, 309800, 0, '【MODE2】對渺小之徒的反抗露出了些許的煩躁。\\n對懷抱希望，起身反抗祂的所有人以我理裁之。\\n以悲憤之劍將其刺穿，使魂魄挫敗於塵芥之下。\\n暫居神位之人所放出的黑刃，就以正義的\\n魔法與之抗衡吧。\\n\\n‧必殺技將會依照敵方全體所剩的HP\\n\u3000造成特大幅度的比例傷害。\\n\\n‧對面前的1名敵人造成特大幅度的物理傷害，\\n\u3000並對其周圍的所有敵人造成中幅度的魔法傷害，\\n\u3000並且使其昏迷。而同時已經昏迷的角色，\\n\u3000再受到下一次攻擊前將無法行動。\\n\\n‧對全體敵人造成小幅度的\\n\u3000魔法傷害。');
insert into unit_enemy_data values (309803, '霸瞳皇帝', 309800, 0, 16, 270, 1000, 1, 1.6, 309800, 309800, 0, '【MODE3】創世之神，迎向了那終末的咆哮。\\n因怨嗟而出口的拒絕之言辭幻化為詛咒，\\n削減著身體、精神與魂魄，將一切葬送闇中。\\n一決生死之際終究到來了。各位，高舉手中的\\n劍開拓嶄新的明日吧。\\n\\n‧必殺技將會依照敵方全體所剩的HP\\n\u3000造成特大幅度的比例傷害。\\n\\n‧對面前的1名敵人造成特大幅度的物理傷害，\\n\u3000並對其周圍的所有敵人造成中幅度的魔法傷害，\\n\u3000並且使其昏迷。而同時已經昏迷的角色，\\n\u3000再受到下一次攻擊前將無法行動。\\n\\n‧對全體敵人造成小幅度的\\n\u3000魔法傷害。\\n\\n‧以最後面的1名敵人為中心，展開能夠中幅度\\n\u3000降低其物理防禦力與魔法防禦力的領域，\\n\u3000並且造成小幅度的魔法傷害，\\n\u3000同時使其被詛咒。而由詛咒所產生的持續傷害，\\n\u3000將會隨著每秒進而增加。\\n\\n‧在戰鬥開始之後，立刻大幅度增加自己的\\n\u3000行動速度，同時小幅度增加自己的\\n\u3000魔法防禦力。');
insert into unit_enemy_data values (309804, '霸瞳皇帝', 309804, 0, 16, 270, 1000, 1, 1.8, 309800, 309800, 0, '表示地圖用');
insert into unit_enemy_data values (309900, '哥布林大師', 309900, 0, 17, 270, 1100, 2, 1.8, 0, 0, 0, '【魔法】企圖將塔之魔力收刮囊中的小鬼學者。\\n以禁術操弄著土塊之人偶，強奪著一切的自由。\\n\\n‧對全體敵人造成大幅度魔法傷害，\\n\u3000同時使所有的召喚物、分身立即死亡。\\n‧對前方廣範圍內依照其剩餘HP造成中幅度\\n\u3000的物理比例傷害，同時大幅度擊飛，\\n\u3000同時召喚1隻泥巴人偶。\\n\u3000泥巴人偶對最前衛與從前方數來第2名的角色\\n\u3000造成物理傷害，同時降低行動速度。\\n‧以從前方數來第2名的角色為中心，造成小範圍\\n\u3000的中幅度物理傷害，同時造成猛毒和暈眩。');
insert into unit_enemy_data values (310000, '山神大人', 310000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】狂奔之神與傳說中的山之土地神。\\n自遠古便尋覓著好對手而趾高氣昂的在大地競走著。\\n\\n‧必殺技會對敵方全體依照其角色最大\\n\u3000HP造成物理比例傷害，\\n\u3000並將其擊退。\\n\u3000同時對最前方的角色造成特大幅度的\\n\u3000追加物理傷害，並且大幅度擊飛\\n\u3000和使其暈眩。\\n\u3000而每當山神大人發動必殺技時，\\n\u3000降低自身的物理防禦力。\\n\u3000此效果將會累積。\\n‧對魔法攻擊力最高的1名角色\\n\u3000依照其角色最大HP造成魔法比例傷害，\\n\u3000同時大幅度降低TP。\\n‧提升自身的TP與行動速度。\\n‧當山神大人自身的HP低於55%時，祂的攻擊\\n\u3000將會變得更加兇暴，但相對也會\\n\u3000降低自身的物理防禦力。');
insert into unit_enemy_data values (310001, '山神大人', 310000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】狂奔之神與傳說中的山之土地神。\\n自遠古便尋覓著好對手而趾高氣昂的在大地競走著。\\n\\n‧必殺技會對敵方全體依照其角色最大HP\\n\u3000造成物理比例傷害且將其擊退，\\n\u3000同時對最前方的角色造成特大幅度的\\n\u3000追加物理傷害，並且擊退和使其暈眩。\\n\u3000每當山神大人發動必殺技時，\\n\u3000降低自身的物理防禦力。\\n\u3000此效果將會累積。\\n‧提升自身的TP與行動速度。');
insert into unit_enemy_data values (310002, '山神大人', 310000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】狂奔之神與傳說中的山之土地神。\\n自遠古便尋覓著好對手而趾高氣昂的在大地競走著。\\n\\n‧必殺技會對敵方全體依照其角色最大HP\\n\u3000造成物理比例傷害，並將其擊退。\\n\u3000同時對最前方的角色造成特大幅度的\\n\u3000追加物理傷害，並且擊退和使其暈眩。\\n\u3000每當山神大人發動必殺技時，\\n\u3000降低自身的物理防禦力。\\n\u3000此效果將會累積。\\n‧對魔法攻擊力最高的1名角色\\n\u3000依照其角色最大HP造成魔法比例傷害，\\n\u3000同時降低TP。\\n‧提升自身的TP與行動速度。\\n‧當山神大人自身的HP低於55％時，\\n\u3000攻擊將會變得更加兇暴，\\n\u3000同時降低自身的物理防禦力。');
insert into unit_enemy_data values (310003, '山神大人', 310000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】狂奔之神與傳說中的山之土地神。\\n自遠古便尋覓著好對手而趾高氣昂的在大地競走著。\\n\\n‧必殺技會對敵方全體依照其角色最大HP\\n\u3000造成物理比例傷害，並將其擊退。\\n\u3000同時對最前方的角色造成特大幅度的\\n\u3000追加物理傷害，並且擊退和使其暈眩。\\n\u3000每當山神大人發動必殺技時，\\n\u3000降低自身的物理防禦力。\\n\u3000此效果將會累積。\\n‧對魔法攻擊力最高的1名角色\\n\u3000依照其角色最大HP造成魔法比例傷害，\\n\u3000同時降低TP。\\n‧提升自身的TP與行動速度。\\n‧當山神大人自身的HP低於55％時，\\n\u3000攻擊將會變得更加兇暴，\\n\u3000同時降低自身的物理防禦力。');
insert into unit_enemy_data values (310004, '山神大人', 310000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE1】做為冒險者之力的測試，召喚出\\n了親近之人的影子。在大肆吹拂著寒風的\\n天下之險，自身脆弱的一面將會被受考驗。\\n\\n‧對最前方的角色造成物理傷害。');
insert into unit_enemy_data values (310005, '山神大人', 310000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE2】勇夫豪傑的奔馳連大地都為之震撼。\\n那英姿宛如祝賀之勢，好兆頭連山峻也為之起舞。\\n\\n‧必殺技會對敵方全體依照其角色最大\\n\u3000HP造成物理比例傷害，\\n\u3000並將其擊退。\\n\u3000同時對最前方的角色造成特大幅度的\\n\u3000追加物理傷害，並且大幅度擊飛\\n\u3000和使其暈眩。\\n\u3000而每當山神大人發動必殺技時，\\n\u3000降低自身的物理防禦力。\\n\u3000此效果將會累積。\\n‧對魔法攻擊力最高的2名角色\\n\u3000依照其角色最大HP造成魔法比例傷害，\\n\u3000同時大幅度降低TP。\\n‧在後方展開降低物理防禦力的領域，\\n\u3000同時對敵方全體造成中幅度的傷害。\\n\u3000在大眼鯛離開背後的期間，山神大人的\\n\u3000魔法防禦力將會特大幅度地降低。');
insert into unit_enemy_data values (310006, '山神大人', 310000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE3】給和神一較高下之強者的最終試煉。\\n各自託付了一切，朝著思慕之人身邊奔去。\\n\\n‧必殺技會對敵方全體依照其角色最大\\n\u3000HP造成物理比例傷害，\\n\u3000並將其擊退。\\n\u3000同時對最前方的角色造成特大幅度的\\n\u3000追加物理傷害，並且大幅度擊飛\\n\u3000和使其暈眩。\\n\u3000而每當山神大人發動必殺技時，\\n\u3000降低自身的物理防禦力。\\n\u3000此效果將會累積。\\n‧對魔法攻擊力最高的1名角色\\n\u3000依照其角色最大HP造成魔法比例傷害，\\n\u3000同時大幅度降低TP。\\n‧提升自身的TP與行動速度。\\n‧在戰鬥開始之後，攻擊將會變得\\n\u3000更加兇暴，但相對也會降低自身的\\n\u3000物理防禦力。');
insert into unit_enemy_data values (310100, '狂怒綠龍', 310100, 0, 14, 270, 1000, 1, 2.6, 0, 0, 0, '【物理】居住在忘卻之密境中的年輕巨龍。\\n踏進禁忌之地的冒險者將被灼熱之業火燒成灰燼。\\n\\n‧必殺技可以對全體敵人造成物理比例傷害，\\n\u3000同時降低TP。\\n‧戰鬥開始時，將會特大幅度降低自身的TP。\\n‧以前方的1名角色為中心，對一定範圍內的\\n\u3000角色造成魔法傷害，同時降低物理防禦力。\\n\\n‧對全體敵人造成物理傷害，同時使其\\n\u3000陷入火傷狀態。\\n‧對全體敵人造成物理傷害並且擊退，\\n\u3000同時消除素質提升的效果。\\n\\n\\n‧當全部的目標部位都被破壞時，\\n\u3000牠的TP將會被特大幅度減少。\\n‧當狂怒綠龍自身的血量降至10%以下時，\\n\u3000其攻擊力將會更加殘暴，同時部位將會\\n\u3000無法被破壞。\\n‧當戰鬥的時間結束時，使全體敵人無法再\\n\u3000繼續戰鬥。\\n');
insert into unit_enemy_data values (310200, '鯊頭魟', 310200, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】做為統治者君臨於海蝕洞，\\n一種魟鯊類的魔物。將那兇猛的\\n慾望全數投注在捕食上的大惡黨。\\n\\n‧對全體敵人造成特大幅度物理傷害\\n，同時降低物理防禦力\\n\u3000和魔法攻擊力。\\n\\n‧對前方範圍內所有敵人造成\\n\u3000小幅度的魔法傷害，同時\\n\u3000降低其TP與TP上升率。');
insert into unit_enemy_data values (310201, '貪婪鬼鯊', 310201, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】吸收了塔的魔力，暴食的巨大鮫鯊。\\n能用音波干擾五感，吞食變得遲鈍的獵物。\\n\\n‧對全體敵人造成特大幅度的物理傷害，\\n\u3000同時降低物理防禦力和魔法攻擊力。\\n‧對TP最高的1名敵人造成中幅度的魔法傷害，\\n\u3000同時使其麻痺。\\n\u3000並且施加挑釁狀態。\\n‧無視挑釁，對HP最高的1名敵人\\n\u3000造成每秒增加的持續傷害。');
insert into unit_enemy_data values (310300, '反逆獸', 310300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '');
insert into unit_enemy_data values (310301, '反逆獸', 310300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】追求愛之力而現身的一種負面魔法生物。\\n以人們心中的愛之力來扭曲世界並且帶來災厄。\\n\\n‧必殺技可以從異次元取出道具\\n\u3000來進行攻擊。隨著道具的不同，\\n\u3000效果也會有所變化。\\n\u3000當道具是槌子時，對敵方全體依照其角色\\n\u3000最大HP造成物理比例傷害，同時\\n\u3000大幅度降低物理攻擊力。\\n\u3000當道具是銅鈸時，對敵方全體依照其角色\\n\u3000最大HP造成物理比例傷害，同時\\n\u3000大幅度降低魔法攻擊力。\\n\u3000當道具是炸彈時，對敵方全體依照其角色\\n\u3000最大HP造成物理比例傷害，\\n\u3000並使其陷入詛咒狀態。\\n‧以最前方的敵人為中心，對範圍內所有敵人\\n\u3000造成中幅度的物理傷害，\\n\u3000並將其擊退。\\n‧對固定範圍內的所有敵人造成大幅度的\\n\u3000物理傷害。');
insert into unit_enemy_data values (310302, '反逆獸', 310300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】追求愛之力而現身的一種負面魔法生物。\\n以人們心中的愛之力來扭曲世界並且帶來災厄。\\n\\n‧必殺技可以從異次元取出道具\\n\u3000來進行攻擊。隨著道具的不同，\\n\u3000效果也會有所變化。\\n\u3000當道具是槌子時，對敵方全體依照其角色\\n\u3000最大HP造成物理比例傷害，同時\\n\u3000大幅度降低物理攻擊力。\\n\u3000當道具是銅鈸時，對敵方全體依照其角色\\n\u3000最大HP造成物理比例傷害，同時\\n\u3000大幅度降低魔法攻擊力。\\n\u3000當道具是炸彈時，對敵方全體依照其角色\\n\u3000最大HP造成物理比例傷害，\\n\u3000並使其陷入詛咒狀態。\\n‧以最前方的敵人為中心，對範圍內所有敵人\\n\u3000造成中幅度的物理傷害，\\n\u3000並將其擊退。\\n‧對固定範圍內的所有敵人造成大幅度的\\n\u3000物理傷害。');
insert into unit_enemy_data values (310303, '反逆獸', 310300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】追求愛之力而現身的一種負面魔法生物。\\n以人們心中的愛之力來扭曲世界並且帶來災厄。\\n\\n‧必殺技可以從異次元取出道具\\n\u3000來進行攻擊。隨著道具的不同，\\n\u3000效果也會有所變化。\\n\u3000當道具是槌子時，對敵方全體依照其角色\\n\u3000最大HP造成物理比例傷害，同時大幅度降低\\n\u3000物理攻擊力。\\n\u3000當道具是銅鈸時，對敵方全體依照其角色\\n\u3000最大HP造成物理比例傷害，同時大幅度降低\\n\u3000魔法攻擊力。\\n\u3000當道具是炸彈時，對敵方全體依照其角色\\n\u3000最大HP造成物理比例傷害，\\n\u3000並使其陷入詛咒狀態。\\n‧以最前方的敵人為中心，對範圍內所有敵人\\n\u3000造成中幅度的物理傷害，\\n\u3000並將其擊退。\\n‧對固定範圍內的所有敵人造成大幅度的\\n\u3000物理傷害。\\n‧當反逆獸自身的HP低於50%時，\\n\u3000牠的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (310304, '反逆獸', 310304, 0, 16, 270, 3000, 1, 4.2, 0, 0, 0, '【MODE1】藉由被闇之力所滲透的愛與慾望，\\n所幻化成實體的負面之魔法生物。毫無慈悲地\\n開始扭曲起了這個世界。\\n\\n‧必殺技可以從異次元取出道具\\n\u3000來進行攻擊。隨著道具的不同，\\n\u3000效果也會有所變化。\\n\u3000當道具是槌子時，對敵方全體依照其角色\\n\u3000最大HP造成物理比例傷害，同時大幅度降低\\n\u3000物理攻擊力。\\n\u3000當道具是銅鈸時，對敵方全體依照其角色\\n\u3000最大HP造成物理比例傷害，同時大幅度降低\\n\u3000魔法攻擊力。\\n\u3000當道具是炸彈時，對敵方全體依照其角色\\n\u3000最大HP造成物理比例傷害，\\n\u3000並使其陷入詛咒狀態。\\n‧以最前方的敵人為中心，對範圍內所有敵人\\n\u3000造成中幅度的物理傷害，\\n\u3000並將其擊退。\\n‧對固定範圍內的所有敵人造成大幅度的\\n\u3000物理傷害。');
insert into unit_enemy_data values (310305, '反逆獸', 310300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【MODE2】召喚出魔法少女的闇影。\\n以扭曲的負面與絕望之影，對魔法少女們的\\n愛與希望之力提出了考驗。\\n\\n‧它將靜靜地觀望闇影的戰鬥。');
insert into unit_enemy_data values (310306, '反逆獸', 310300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【MODE3】負面之魔法生物因為憤怒終究解放了\\n真正的力量。只為了將魔法少女的心靈徹底粉碎，\\n並且用扭曲的愛之力將萬物踐踏於地。\\n\\n‧必殺技可以從異次元取出道具\\n\u3000來進行攻擊。隨著道具的不同，\\n\u3000效果也會有所變化。\\n\u3000當道具是槌子時，對敵方全體依照其角色\\n\u3000最大HP造成物理比例傷害，同時大幅度降低\\n\u3000物理攻擊力。\\n\u3000當道具是銅鈸時，對敵方全體依照其角色\\n\u3000最大HP造成物理比例傷害，同時大幅度降低\\n\u3000魔法攻擊力。\\n\u3000當道具是炸彈時，對敵方全體依照其角色\\n\u3000最大HP造成物理比例傷害，\\n\u3000並使其陷入詛咒狀態。\\n‧以最前方的敵人為中心，對範圍內所有敵人\\n\u3000造成中幅度的物理傷害，\\n\u3000並將其擊退。\\n‧對固定範圍內的所有敵人造成大幅度的\\n\u3000物理傷害。\\n‧在戰鬥剛開始時，牠的攻擊\\n\u3000將會變得更加兇暴。');
insert into unit_enemy_data values (310400, '真假變色龍', 310400, 0, 11, 270, 1000, 1, 2.4, 0, 0, 0, '【物理】潛伏於雨林中靜候獵物上門\\n的變色龍魔物。儘管個性膽小狡猾，\\n但若生氣了將會以角進行突擊。\\n\\n‧必殺技能夠對全體敵人造成大幅度\\n\u3000的物理傷害，並且大幅度降低\\n\u3000物理防禦力。\\n\\n‧對隨機1名敵人造成\\n\u3000中幅度的物理傷害。\\n\\n‧當真假變色龍暫時擬態於背景時，\\n\u3000將會極大幅度提升迴避，特大幅度\\n\u3000提升行動速度，大幅度降低\\n\u3000物理防禦力。\\n\\n‧對前方的3名角色造成中幅度的物理\\n\u3000傷害。');
insert into unit_enemy_data values (310401, '真假變色龍', 310401, 0, 11, 270, 1000, 1, 2.4, 0, 0, 0, '【物理】潛伏於雨林中靜候獵物上門\\n的變色龍魔物。儘管個性膽小狡猾，\\n但若生氣了將會以角進行突擊。\\n\\n‧必殺技能夠對全體敵人造成大幅度\\n\u3000的物理傷害，並且大幅度降低\\n\u3000物理防禦力。\\n\\n‧對隨機1名敵人造成\\n\u3000中幅度的物理傷害。\\n\\n‧當真假變色龍暫時擬態於背景時，\\n\u3000將會極大幅度提升迴避，特大幅度\\n\u3000提升行動速度，大幅度降低\\n\u3000物理防禦力。\\n\\n‧對前方的3名角色造成中幅度的物理\\n\u3000傷害。');
insert into unit_enemy_data values (310500, '喧囂獨角兔', 310500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '');
insert into unit_enemy_data values (310501, '喧囂獨角兔', 310500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】將體色換成了亮麗顏色的大兔子魔物。\\n與乍看之下的外表大相逕庭的那歌聲，能夠震撼\\n大地並且動搖冒險者的心靈。\\n\\n‧必殺技能夠對敵方全體依照其角色最大\\n\u3000HP造成物理比例傷害，\\n\u3000並造成擊退。發動技能後，在頭暈目眩\\n\u3000期間內，大幅度降低自身的物理與\\n\u3000魔法防禦力。\\n‧以最前方的角色為中心，在一定範圍內\\n\u3000造成中幅度的物理傷害，同時降低\\n\u3000行動速度。');
insert into unit_enemy_data values (310502, '喧囂獨角兔', 310500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】將體色換成了亮麗顏色的大兔子魔物。\\n與乍看之下的外表大相逕庭的那歌聲，能夠震撼\\n大地並且動搖冒險者的心靈。\\n\\n‧必殺技能夠對敵方全體依照其角色最大\\n\u3000HP造成物理比例傷害，\\n\u3000並造成擊退。發動技能後，在頭暈目眩\\n\u3000期間內，大幅度降低自身的物理與\\n\u3000魔法防禦力。\\n‧以最前方的角色為中心，在一定範圍內\\n\u3000造成中幅度的物理傷害，同時降低\\n\u3000行動速度。\\n‧對前方的3名角色造成小幅度的物理傷害，\\n\u3000同時大幅度降低物理防禦力。');
insert into unit_enemy_data values (310503, '喧囂獨角兔', 310500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】將體色換成了亮麗顏色的大兔子魔物。\\n與乍看之下的外表大相逕庭的那歌聲，能夠震撼\\n大地並且動搖冒險者的心靈。\\n\\n‧必殺技能夠對敵方全體依照其角色最大\\n\u3000HP造成物理比例傷害，\\n\u3000並造成擊退。發動技能後，在頭暈目眩\\n\u3000期間內，大幅度降低自身的物理與\\n\u3000魔法防禦力。\\n‧以最前方的角色為中心，在一定範圍內\\n\u3000造成中幅度的物理傷害，同時降低\\n\u3000行動速度。\\n‧對前方的3名角色造成小幅度的物理傷害，\\n\u3000同時大幅度降低物理防禦力。\\n‧當喧囂獨角兔自身的HP不到40%時，\\n\u3000牠的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (310504, '喧囂獨角兔', 310500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE1】召喚出new generations\\n的闇影。在森林中遇見的大兔子。\\n為了考驗三人那永不放棄的心是否能夠貫徹，\\n大兔子找出了她們每個人的軟弱。\\n\\n‧對最前方的角色造成物理傷害。');
insert into unit_enemy_data values (310505, '喧囂獨角兔', 310500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE2】由於森林人氣王的歌聲，魔物們開始\\n大肆喧鬧。使人血脈賁張的野生宴會，\\n現正開幕。\\n\\n‧在打倒了青藍魔像、沉睡之梟、\\n\u3000戳戳鳥後，將能進到下一個MODE。\\n\\n‧喧囂獨角兔將會對最前方的角色造成\\n\u3000物理傷害。');
insert into unit_enemy_data values (310506, '喧囂獨角兔', 310500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE3】宴會的終場，大兔竭盡了最後\\n之力。近乎為咆哮般震耳欲聾的歌聲，阻撓著三人邁向夢想\\n的道路。\\n\\n‧必殺技能夠對敵方全體依照其角色最大\\n\u3000HP造成物理比例傷害，\\n\u3000同時造成擊退。發動技能後，在頭暈目眩\\n\u3000期間內，大幅度降低自身的物理與\\n\u3000魔法防禦力。\\n‧以最前方的角色為中心，在一定範圍內\\n\u3000造成中幅度物理傷害，同時降低\\n\u3000行動速度。\\n‧對前方的3名敵人造成小幅度的物理傷害，\\n\u3000同時大幅度降低物理防禦力。\\n‧在戰鬥剛開始時，牠的攻擊將會變得\\n\u3000更加兇暴。');
insert into unit_enemy_data values (310600, '糾結的盆栽小花', 310600, 0, 16, 270, 3000, 1, 1.6, 310600, 310600, 0, '');
insert into unit_enemy_data values (310601, '糾結的盆栽小花', 310600, 0, 16, 270, 3000, 1, 1.6, 310600, 310600, 0, '【魔法】不知是魔物還究竟是精靈，是有諸多謎團\\n的巨大生物。保持著那著難以言喻的表情一面散發\\n著謎之花粉，使著市中陷入了混亂。\\n\\n‧必殺技能夠對全體敵人造成大幅度的魔法傷害，\\n\u3000同時降低物理防禦力與魔法防禦力。\\n‧對前方範圍內的敵人造成物理傷害，同時造成\\n\u3000擊退。\\n‧當左右的葉子被破壞後，短時間內會被消滅。\\n‧當左側的葉子被破壞時，將會小幅度降低物理\\n\u3000防禦力與魔法防禦力。\\n‧當本體被破壞時，將會大幅度降低物理防禦力\\n\u3000與魔法防禦力。\\n‧當右側的葉子被破壞時，將會小幅度降低物理\\n\u3000防禦力與魔法防禦力。');
insert into unit_enemy_data values (310602, '糾結的盆栽小花', 310600, 0, 16, 270, 3000, 1, 1.6, 310600, 310600, 0, '【魔法】不知是魔物還究竟是精靈，是有諸多謎團\\n的巨大生物。保持著那著難以言喻的表情一面散發\\n著謎之花粉，使著市中陷入了混亂。\\n\\n‧必殺技能夠對全體敵人造成大幅度的魔法傷害，\\n\u3000同時降低物理防禦力與魔法防禦力。\\n‧對前方範圍內的敵人造成物理傷害，同時造成\\n\u3000擊退。\\n‧召喚小球根。\\n\u3000當小球根將無法被當成攻擊的對象，同時在經過\\n\u3000一段時間後將會自爆，並且對前方範圍內的角色\\n\u3000造成魔法傷害。\\n‧當左右的葉子被破壞後，短時間內會被消滅。\\n‧當左側的葉子被破壞時，將會小幅度降低物理\\n\u3000防禦力與魔法防禦力。\\n‧當本體被破壞時，將會大幅度降低物理防禦力\\n\u3000與魔法防禦力。\\n‧當右側的葉子被破壞時，將會小幅度降低物理\\n\u3000防禦力與魔法防禦力。');
insert into unit_enemy_data values (310603, '糾結的盆栽小花', 310603, 0, 16, 270, 3000, 1, 1.6, 310600, 310600, 0, '【魔法】不知是魔物還究竟是精靈，是有諸多謎團\\n的巨大生物。保持著那著難以言喻的表情一面散發\\n著謎之花粉，使著市中陷入了混亂。\\n\\n‧必殺技能夠對全體敵人造成大幅度的魔法傷害，\\n\u3000同時降低物理防禦力與魔法防禦力。\\n‧對前方範圍內的敵人造成物理傷害，同時造成\\n\u3000擊退。\\n‧召喚小球根。\\n\u3000當小球根將無法被當成攻擊的對象，同時在經過\\n\u3000一段時間後將會自爆，並且對前方範圍內的角色\\n\u3000造成魔法傷害。\\n‧當左右的葉子被破壞後，短時間內會被消滅。\\n‧當左側的葉子被破壞時，將會小幅度降低物理\\n\u3000防禦力與魔法防禦力。\\n‧當本體被破壞時，將會大幅度降低物理防禦力\\n\u3000與魔法防禦力。\\n‧當右側的葉子被破壞時，將會小幅度降低物理\\n\u3000防禦力與魔法防禦力。\\n‧當盆栽小花自身的 HP 低於 40% 時，\\n\u3000牠的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (310604, '糾結的盆栽小花', 310604, 0, 16, 270, 3000, 1, 1.6, 310600, 310600, 0, '');
insert into unit_enemy_data values (310605, '糾結的盆栽小花', 310604, 0, 16, 270, 3000, 1, 1.6, 310600, 310600, 0, '【MODE1】最終極大化了的謎之生物。\\n依舊是保持那難以言喻的表情，並將大瀑布般的\\n淚水灑向於大地，那淚水則妄為地侵蝕著所有人。\\n\\n‧必殺技能夠對全體敵人造成大幅度的魔法傷害，\\n\u3000同時降低物理防禦力與魔法防禦力。\\n‧提升全體敵人的 TP，但同時展開造成\\n\u3000持續魔法傷害的領域。\\n‧當左右的葉子被破壞後，短時間內會被消滅。\\n‧當左側的葉子被破壞時，將會小幅度降低物理\\n\u3000防禦力與魔法防禦力。\\n‧當本體被破壞時，將會大幅度降低物理防禦力\\n\u3000與魔法防禦力。\\n‧當右側的葉子被破壞時，將會小幅度降低物理\\n\u3000防禦力與魔法防禦力。');
insert into unit_enemy_data values (310606, '糾結的盆栽小花', 310604, 0, 16, 270, 3000, 1, 1.6, 310600, 310600, 0, '【MODE2】不知是否是畏懼了冒險者們的抵抗，\\n那兩片大葉與巨大體軀露出了破綻並佇立著。\\n然而，卻還是依舊保持著那難以言喻的表情。\\n\\n‧使全部目標的破壞無效。\\n‧必殺技能夠對敵方全體造成大幅度的\\n\u3000魔法傷害，降低物理防禦力與\\n\u3000魔法防禦力。\\n‧對前方範圍內的敵人造成物理傷害，\\n\u3000同時造成擊退。\\n‧召喚小球根。\\n\u3000小球根無法被當成攻擊的對象，在經過\\n\u3000一段時間後將會自爆，並且對前方範圍內的角色\\n\u3000造成魔法傷害。\\n');
insert into unit_enemy_data values (310607, '糾結的盆栽小花', 310604, 0, 16, 270, 3000, 1, 1.6, 310600, 310600, 0, '【MODE3】那一成不變的表情，直到最後依舊\\n毫無變色，而冒險者對那生物的狂氣感到了\\n不寒而慄。究竟她們最後\\n能否解開這個生物之謎呢……？\\n\\n‧必殺技能夠對全體敵人造成大幅度的魔法傷害，\\n\u3000同時降低物理防禦力與魔法防禦力。\\n‧對前方範圍內的敵人造成物理傷害，同時造成\\n\u3000擊退。\\n‧召喚小球根。\\n\u3000當小球根將無法被當成攻擊的對象，同時在經過\\n\u3000一段時間後將會自爆，並且對前方範圍內的角色\\n\u3000造成魔法傷害。\\n‧當左右的葉子被破壞後，短時間內會被消滅。\\n‧當左側的葉子被破壞時，將會小幅度降低物理\\n\u3000防禦力與魔法防禦力。\\n‧當本體被破壞時，將會大幅度降低物理防禦力\\n\u3000與魔法防禦力。\\n‧當右側的葉子被破壞時，將會小幅度降低物理\\n\u3000防禦力與魔法防禦力。');
insert into unit_enemy_data values (310700, '好朋友X', 310700, 0, 16, 270, 3000, 1, 1.4, 0, 0, 0, '');
insert into unit_enemy_data values (310701, '好朋友X', 310700, 0, 16, 270, 3000, 1, 1.4, 0, 0, 0, '【物理】從異想天開的點子與扭曲的熱情中誕生的\\n鋼鐵巨人。以參照基準之人的特性再以異常的解釋\\n重新詮釋，對敵人的言語中樞與精神進行破壞。\\n\\n‧當自身受到中毒、猛毒、詛咒、火傷等效果時，\\n\u3000將會大幅度降低自身的物理防禦力與魔法\\n\u3000防禦力和行動速度。\\n‧必殺技能夠對敵方全體依照其角色最大HP\\n\u3000造成魔法比例傷害。\\n‧在提升自己的物理攻擊力之後，對全體\\n\u3000敵人造成物理傷害。\\n‧對前方的3名角色依照其最大HP造成魔法比例\\n\u3000傷害，同時降低行動速度。');
insert into unit_enemy_data values (310702, '好朋友X', 310700, 0, 16, 270, 3000, 1, 1.4, 0, 0, 0, '【物理】從異想天開的點子與扭曲的熱情中誕生的\\n鋼鐵巨人。以參照基準之人的特性再以異常的解釋\\n重新詮釋，對敵人的言語中樞與精神進行破壞。\\n\\n‧當自身受到中毒、猛毒、詛咒、火傷等效果時，\\n\u3000將會大幅度降低自身的物理防禦力與魔法\\n\u3000防禦力和行動速度。\\n‧必殺技能夠對敵方全體依照其角色最大HP\\n\u3000造成魔法比例傷害。\\n‧在提升自己的物理攻擊力之後，對全體\\n\u3000敵人造成物理傷害。\\n‧對前方的3名角色依照其最大HP造成魔法比例\\n\u3000傷害，同時降低行動速度。');
insert into unit_enemy_data values (310703, '好朋友X', 310700, 0, 16, 270, 3000, 1, 1.4, 0, 0, 0, '【物理】從異想天開的點子與扭曲的熱情中誕生的\\n鋼鐵巨人。以參照基準之人的特性再以異常的解釋\\n重新詮釋，對敵人的言語中樞與精神進行破壞。\\n\\n‧當自身受到中毒、猛毒、詛咒、火傷等效果時，\\n\u3000將會大幅度降低自身的物理防禦力與魔法\\n\u3000防禦力和行動速度。\\n‧必殺技能夠對敵方全體依照其角色最大HP\\n\u3000造成魔法比例傷害。\\n‧在提升自己的物理攻擊力之後，對全體\\n\u3000敵人造成物理傷害。\\n‧對前方的3名角色依照其最大HP造成魔法比例\\n\u3000傷害，同時降低行動速度。\\n‧當好朋友X自身的HP不到40%時，\\n\u3000牠的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (310704, '好朋友X', 310700, 0, 16, 270, 3000, 1, 4.2, 0, 0, 0, '【MODE1】召喚出【墨丘利財團】\\n成員們的闇影。如同就像是在嘲笑著自身\\n犯的錯一般，它們以影子的姿態愚弄著所有人。\\n\\n‧當自身受到中毒、猛毒、詛咒、火傷等效果時，\\n\u3000將會大幅度降低自身的物理防禦力與魔法\\n\u3000防禦力和行動速度。\\n‧對面前的1名敵方角色造成物理傷害。');
insert into unit_enemy_data values (310705, '好朋友X', 310700, 0, 16, 270, 3000, 1, 1.4, 0, 0, 0, '【MODE2】鋼鐵的球體，以完美的切嚕與傾訴\\n著。「切～嚕～」。那緊緊攫起心靈不輕易鬆手的\\n洗腦話語，確確實實地將世界帶往了切嚕的未來。\\n\\n‧對隨機的 1 名角色造成中幅度的魔法傷害，\\n\u3000同時使其陷入沉默與誘惑狀態。');
insert into unit_enemy_data values (310706, '好朋友X', 310700, 0, 16, 270, 3000, 1, 1.4, 0, 0, 0, '【MODE3】鋼鐵的機關人偶再次聳立於大地。\\n解放了「雙刃之劍‧最終模式」的它，\\n將好朋友社的三人逼向了絕境。\\n\\n‧當自身受到中毒、猛毒、詛咒、火傷等效果時，\\n\u3000將會大幅度降低自身的物理防禦力與魔法\\n\u3000防禦力和行動速度。\\n‧必殺技能夠對敵方全體依照其角色最大HP\\n\u3000造成魔法比例傷害。\\n‧在提升自己的物理攻擊力之後，對全體\\n\u3000敵人造成物理傷害。\\n‧對前方的3名角色依照其最大HP造成魔法比例\\n\u3000傷害，同時降低行動速度。\\n‧在戰鬥剛開始時，牠的攻擊將會變得\\n\u3000更加兇暴。');
insert into unit_enemy_data values (310800, '忍者首領半藏', 310800, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】被惡質監察官所雇用的忍者首領。\\n失去了義的忍者，任憑身心墮落於金與利。然而\\n那依然健在的高超武技，阻擋了眾人的去路。\\n\\n‧在戰鬥開始後，監察官將會登場。而當\\n\u3000監察官受到傷害時，\\n\u3000將馬上特大幅度降低忍者首領半藏的\\n\u3000物理防禦力與魔法防禦力。\\n‧必殺技能夠對敵方全體依照其最大 HP\\n\u3000造成物理的比例傷害。\\n‧變化成大蟾蜍並且吐出毒，\\n\u3000使敵方全體陷入中毒狀態。\\n\u3000此攻擊必定會命中。\\n‧對敵方全體造成中幅度的物理傷害。');
insert into unit_enemy_data values (310801, '忍者首領半藏', 310800, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】被惡質監察官所雇用的忍者首領。\\n失去了義的忍者，任憑身心墮落於金與利。然而\\n那依然健在的高超武技，阻擋了眾人的去路。\\n\\n‧在戰鬥開始後，監察官將會登場。而當\\n\u3000監察官受到傷害時，\\n\u3000將馬上特大幅度降低忍者首領半藏的\\n\u3000物理防禦力與魔法防禦力。\\n‧必殺技能夠對敵方全體依照其最大 HP\\n\u3000造成物理的比例傷害。\\n‧變化成大蟾蜍並且吐出毒，\\n\u3000使敵方全體陷入中毒狀態。\\n\u3000此攻擊必定會命中。\\n‧對敵方全體造成中幅度的物理傷害。');
insert into unit_enemy_data values (310802, '忍者首領半藏', 310800, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】被惡質監察官所雇用的忍者首領。\\n失去了義的忍者，任憑身心墮落於金與利。然而\\n那依然健在的高超武技，阻擋了眾人的去路。\\n\\n‧在戰鬥開始後，監察官將會登場。而當\\n\u3000監察官受到傷害時，\\n\u3000將馬上特大幅度降低忍者首領半藏的\\n\u3000物理防禦力與魔法防禦力。\\n‧必殺技能夠對敵方全體依照其最大 HP\\n\u3000造成物理的比例傷害。\\n‧變化成大蟾蜍並且吐出毒，\\n\u3000使敵方全體陷入中毒狀態。\\n\u3000當自身的 HP 在 30% 以下時，\\n\u3000使全體敵人陷入猛毒的狀態。\\n\u3000此攻擊必定會命中。\\n‧對敵方全體造成中幅度的物理傷害。\\n\u3000當自身的 HP 在 30% 以下時，\\n\u3000同時再對敵方全體造成暈眩。\\n‧當忍者首領半藏自身的 HP 低於30%時，\\n\u3000他的技能效果將會有所變化。');
insert into unit_enemy_data values (310803, '忍者首領半藏', 310800, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】被惡質監察官所雇用的忍者首領。\\n失去了義的忍者，任憑身心墮落於金與利。然而\\n那依然健在的高超武技，阻擋了眾人的去路。\\n\\n‧在戰鬥開始後，監察官將會登場。而當\\n\u3000監察官受到傷害時，\\n\u3000將馬上特大幅度降低忍者首領半藏的\\n\u3000物理防禦力與魔法防禦力。\\n‧必殺技能夠對敵方全體依照其最大 HP\\n\u3000造成物理的比例傷害。\\n‧變化成大蟾蜍並且吐出毒，\\n\u3000使敵方全體陷入中毒狀態。\\n\u3000當自身的 HP 在 30% 以下時，\\n\u3000使全體敵人陷入猛毒的狀態。\\n\u3000此攻擊必定會命中。\\n‧對敵方全體造成中幅度的物理傷害。\\n\u3000當自身的 HP 在 30% 以下時，\\n\u3000同時再對敵方全體造成暈眩。\\n‧當忍者首領半藏自身的 HP 低於30%時，\\n\u3000他的技能效果將會有所變化。');
insert into unit_enemy_data values (310804, '忍者首領半藏', 310801, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【MODE1】召喚出【伊麗莎白牧場】成員們的\\n闇影。利用幻術所製造出來的四農士之幻影，\\n又再次使眾人們的歸所陷入了絕境。\\n\\n‧對面前的 1 名敵人造成物理傷害。');
insert into unit_enemy_data values (310805, '忍者首領半藏', 310800, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【MODE2】以秘傳的通靈之術幻化成了忍蛙，\\n並且將蟾蜍的猛毒噴灑至週遭。人們只要吸入了\\n該猛毒，便將侵蝕全身，最後身體將徐徐地潰爛。\\n\\n‧在戰鬥開始後，監察官將會登場。而當\\n\u3000監察官受到傷害時，將馬上特大幅度降低\\n\u3000忍者首領半藏的物理防禦力與魔法防禦力。\\n‧必殺技能夠對全體敵人依照其最大 HP\\n\u3000造成物理的比例傷害。\\n‧變化成大蟾蜍並且吐出劇毒，使全體敵人陷入\\n\u3000猛毒狀態。此攻擊必定會命中。\\n‧對全體敵人造成中幅度的物理傷害，同時對全體\\n\u3000敵人造成暈眩。');
insert into unit_enemy_data values (310806, '忍者首領半藏', 310800, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【MODE3】他最終取回了身為忍者的尊嚴，\\n並且發揮出了自身真正的力量。\\n那電光一閃的神技，使人在慘叫都喊不了聲\\n就化為了屍骸。\\n\\n‧在戰鬥剛開始時，提升自己的技能威力。\\n‧必殺技能夠對全體敵人依照其最大 HP\\n\u3000造成物理的比例傷害。\\n‧變化成大蟾蜍並且吐出劇毒，使全體敵人陷入\\n\u3000猛毒狀態。此攻擊必定會命中。\\n‧對全體敵人造成中幅度的物理傷害，同時對全體\\n\u3000敵人造成暈眩。');
insert into unit_enemy_data values (310900, '襲擊了蘭德索爾各地的神秘圓盤', 310900, 0, 16, 270, 3000, 1, 0.1, 0, 0, 0, '【物理】突然襲擊了和平的豐年祭的謎之飛行物體。\\n突如其來在蘭德索爾各地現身，進行著破壞與掠奪。\\n\\n‧必殺技能夠對全體敵人造成大幅度的物理傷害。\\n‧對前方的 1 名角色造成小幅度的物理傷害。\\n‧對剩餘 HP 較高的 1 名角色造成小幅度物理傷害。\\n‧對隨機的 1 名角色造成小幅度的物理傷害。');
insert into unit_enemy_data values (311000, '城堡多倫多獸', 311000, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】以塔之魔力產生變異而要塞化的巨大魔樹。\\n將大地之力幻化成砲彈，以那堅固的身軀為根基，\\n進行著永無止境的破壞。\\n\\n‧對全體敵人造成大幅度的物理傷害。\\n‧對範圍內的全體敵人造成持續的魔法傷害，\\n\u3000同時展開降低物理防禦力的領域。\\n‧以從後方數來第 2 名的角色為中心，造成\\n\u3000小範圍內中幅度的物理傷害，並且減少其 TP。\\n\u3000並且在那之後，恢復全體夥伴的 TP。');
insert into unit_enemy_data values (311100, '黑之王賈巴沃克', 311100, 0, 16, 270, 1000, 1, 2.1, 0, 0, 0, '【物理】為了扭曲世界而從狹界中顯現的黑之王。\\n打算用身上纏繞的暗黑瘴氣蹂躪不可思議之國。\\n\\n‧必殺技為對全體敵人依照其最大HP\\n\u3000造成魔法比例傷害，施加毒狀態，\\n\u3000並將其擊退。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧對前方的2名角色造成中幅度的物理傷害，\\n\u3000同時降低物理防禦力與TP。');
insert into unit_enemy_data values (311101, '黑之王賈巴沃克', 311100, 0, 16, 270, 1000, 1, 2.1, 0, 0, 0, '【物理】為了扭曲世界而從狹界中顯現的黑之王。\\n打算用身上纏繞的暗黑瘴氣蹂躪不可思議之國。\\n\\n‧必殺技為對全體敵人依照其最大HP\\n\u3000造成魔法比例傷害，施加毒狀態，\\n\u3000並將其擊退。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧對前方的2名角色造成中幅度的物理傷害，\\n\u3000同時降低物理防禦力與TP。');
insert into unit_enemy_data values (311102, '黑之王賈巴沃克', 311100, 0, 16, 270, 1000, 1, 2.1, 0, 0, 0, '【物理】為了扭曲世界而從狹界中顯現的黑之王。\\n打算用身上纏繞的暗黑瘴氣蹂躪不可思議之國。\\n\\n‧必殺技為對敵方全體依照其最大HP\\n\u3000造成魔法比例傷害，施加中毒狀態，\\n\u3000並將其擊退。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧對前方的2名角色造成中幅度的物理傷害，\\n\u3000同時降低物理防禦力與TP。\\n‧對前方範圍內的角色造成中幅度的魔法傷害，\\n\u3000同時大幅降低魔法防禦力。\\n\u3000角色HP低於50%的時候，還會降低\\n\u3000行動速度。');
insert into unit_enemy_data values (311103, '黑之王賈巴沃克', 311100, 0, 16, 270, 1000, 1, 2.1, 0, 0, 0, '【物理】為了扭曲世界而從狹界中顯現的黑之王。\\n打算用身上纏繞的暗黑瘴氣蹂躪不可思議之國。\\n\\n‧必殺技為對敵方全體依照其最大HP\\n\u3000造成魔法比例傷害，施加中毒狀態，\\n\u3000並將其擊退。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧對前方的2名角色造成中幅度的物理傷害，\\n\u3000同時降低物理防禦力與TP。\\n‧對前方範圍內的角色造成中幅度的魔法傷害，\\n\u3000同時大幅降低魔法防禦力。\\n\u3000角色HP低於50%的時候，還會降低\\n\u3000行動速度。\\n‧當黑之王賈巴沃克自身的HP低於35%時，\\n\u3000牠的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (311104, '黑之王賈巴沃克', 311101, 0, 16, 270, 1000, 1, 2.1, 0, 0, 0, '【MODE1】瘴黑之幕纏繞於身，黑之王再次\\n降臨。黑暗與混沌混合的障壁，據說就連\\n救世主的光之一射也能承受。\\n\\n‧展開護盾，使其不會受到敵人造成的任何攻擊。\\n\u3000護盾受到攻擊時會漸漸降低耐久，\\n\u3000受到2400000傷害時護盾\\n\u3000就會被破壞。\\n‧必殺技為對敵方全體依照其最大HP\\n\u3000造成魔法比例傷害，施加中毒狀態，\\n\u3000並將其擊退。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧對前方範圍內的角色造成中幅度的魔法傷害，\\n\u3000同時大幅降低魔法防禦力。');
insert into unit_enemy_data values (311105, '黑之王賈巴沃克', 311100, 0, 16, 270, 1000, 1, 2.1, 0, 0, 0, '【MODE2】召喚璃乃、步未、日和的闇影。\\n將心靈的黑暗實體化，揭露自己的弱點。\\n她們能夠取回希望之心嗎？如今正被如此詢問。\\n\\n‧對前方的1名敵人造成物理傷害。');
insert into unit_enemy_data values (311106, '黑之王賈巴沃克', 311100, 0, 16, 270, 1000, 1, 2.1, 0, 0, 0, '【MODE3】黑之王解放終結的力量，要讓世界\\n墮入永恆的黑暗。將書本的頁面盡數染黑，\\n救世主的故事也將迎來終結。\\n\\n‧必殺技為對敵方全體依照其最大HP\\n\u3000造成魔法比例傷害，施加中毒狀態，\\n\u3000並將其擊退。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧對前方的2名角色造成中幅度的物理傷害，\\n\u3000同時降低物理防禦力與TP。\\n‧對前方範圍內的角色造成中幅度的魔法傷害，\\n\u3000同時大幅降低魔法防禦力。\\n\u3000角色HP低於50%的時候，還會大幅降低\\n\u3000行動速度。\\n‧在戰鬥剛開始時，牠的攻擊將會變得\\n\u3000更加兇暴。');
insert into unit_enemy_data values (311200, '花朵騎士', 311200, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】擬態成巨大花朵的魔物。\\n不小心被牠的美麗所吸引的獵物，\\n將會面臨盛開的絕望之光。\\n\\n‧對前方的3名角色造成大幅度的\\n\u3000物理傷害，再對全體敵人\\n\u3000造成大幅度物理傷害。\\n\\n‧對前方的2名角色造成小幅度的\\n\u3000物理傷害，並且中幅度提升自己的\\n\u3000物理攻擊力。\\n\\n‧對前方的第1名角色造成中幅度的\\n\u3000物理傷害，同時中幅度降低\\n\u3000物理防禦力。\\n\\n‧對前方的第2名角色造成中幅度的\\n\u3000物理傷害，同時中幅度降低物\\n\u3000理防禦力。');
insert into unit_enemy_data values (311201, '花朵騎士', 311200, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】擬態成巨大花朵的魔物。\\n不小心被牠的美麗所吸引的獵物，\\n將會面臨盛開的絕望之光。\\n\\n‧對前方的3名角色造成大幅度的\\n\u3000物理傷害，再對全體敵人\\n\u3000造成大幅度物理傷害。\\n\\n‧對前方的2名角色造成小幅度的\\n\u3000物理傷害，並且中幅度提升自己的\\n\u3000物理攻擊力。\\n\\n‧對前方的第1名角色造成中幅度的\\n\u3000物理傷害，同時中幅度降低\\n\u3000物理防禦力。\\n\\n‧對前方的第2名角色造成中幅度的\\n\u3000物理傷害，同時中幅度降低物\\n\u3000理防禦力。');
insert into unit_enemy_data values (311300, '覺醒‧花心星', 311300, 0, 16, 270, 3000, 2, 2.8, 0, 0, 0, '');
insert into unit_enemy_data values (311301, '覺醒‧花心星', 311300, 0, 16, 270, 3000, 2, 2.8, 0, 0, 0, '【魔法】利用心靈空虛的間隙侵入依附的\\n星之精靈。以過剩的自我意識跟純潔的真心\\n迷惑對手。\\n\\n‧必殺技對敵方全體造成依照花心星保有的\\n\u3000【二心】數量的魔法比例\\n\u3000傷害。\\n\u3000另外花心星剩餘HP未滿50%的時候，\\n\u3000更進一步提升造成的傷害。\\n\u3000造成傷害後，花心星保有的\\n\u3000【二心】數量將會歸零。\\n‧以最後方的敵方為中心，對一定範圍內\\n\u3000造成魔法傷害，再施加誘惑狀態\\n\u3000並提升物理攻擊力與魔法攻擊力。\\n\u3000此技能造成傷害的敵方數量\\n\u3000會在一定時間內為花心星增加【二心】。\\n‧擊退前方範圍內的敵方，\\n\u3000並造成魔法傷害。\\n\u3000並且使其陷入誘惑狀態並提升物理攻擊力與\\n\u3000魔法攻擊力。\\n\u3000此技能造成傷害的敵人數量\\n\u3000會在一定時間內為花心星增加【二心】。');
insert into unit_enemy_data values (311302, '覺醒‧花心星', 311300, 0, 16, 270, 3000, 2, 3.0, 0, 0, 0, '【魔法】利用心靈空虛的間隙侵入依附的\\n星之精靈。以過剩的自我意識跟純潔的真心\\n迷惑對手。\\n\\n‧必殺技對敵方全體造成依照花心星保有的\\n\u3000【二心】數量的魔法比例\\n\u3000傷害。\\n\u3000另外花心星剩餘HP未滿50%的時候，\\n\u3000更進一步提升造成的傷害。\\n\u3000造成傷害後，花心星保有的\\n\u3000【二心】數量將會歸零。\\n‧以最後方的敵方為中心，對一定範圍內\\n\u3000造成魔法傷害，再施加誘惑狀態\\n\u3000並提升物理攻擊力與魔法攻擊力。\\n\u3000此技能造成傷害的敵方數量\\n\u3000會在一定時間內為花心星增加【二心】。\\n‧擊退前方範圍內的敵方，\\n\u3000並造成魔法傷害。\\n\u3000並且使其陷入誘惑狀態並提升物理攻擊力與\\n\u3000魔法攻擊力。\\n\u3000此技能造成傷害的敵人數量\\n\u3000會在一定時間內為花心星增加【二心】。');
insert into unit_enemy_data values (311303, '覺醒‧花心星', 311300, 0, 16, 270, 3000, 2, 3.0, 0, 0, 0, '【魔法】利用心靈空虛的間隙侵入依附的\\n星之精靈。以過剩的自我意識跟純潔的真心\\n迷惑對手。\\n\\n‧必殺技對敵方全體造成依照花心星保有的\\n\u3000【二心】數量的魔法比例\\n\u3000傷害。\\n\u3000另外花心星剩餘HP未滿50%的時候，\\n\u3000更進一步提升造成的傷害。\\n\u3000造成傷害後，花心星保有的\\n\u3000【二心】數量將會歸零。\\n‧對敵方全體依照角色的最大HP造成\\n\u3000魔法比例傷害。\\n‧以最後方的敵方為中心，對一定範圍內\\n\u3000造成魔法傷害，再施加誘惑狀態\\n\u3000並提升物理攻擊力與魔法攻擊力。\\n\u3000此技能造成傷害的敵方數量\\n\u3000會在一定時間內為花心星增加【二心】。\\n‧擊退前方範圍內的敵方，\\n\u3000並造成魔法傷害。\\n\u3000再使其陷入誘惑狀態並提升物理攻擊力與\\n\u3000魔法攻擊力。\\n\u3000此技能造成傷害的敵人數量\\n\u3000會在一定時間內為花心星增加【二心】。');
insert into unit_enemy_data values (311304, '覺醒‧花心星', 311300, 0, 16, 270, 3000, 2, 3.0, 0, 0, 0, '【MODE1】為了自己建立後宮的夢想，\\n恣意地強制魅惑著少女們。\\n\\n‧必殺技對敵方全體造成依照花心星保有的\\n\u3000【二心】數量的魔法比例傷害。\\n\u3000造成傷害後，花心星保有的\\n\u3000【二心】數量將會歸零。\\n‧對敵方全體依照其最大HP造成\\n\u3000魔法比例傷害。\\n‧無視挑釁，對最後方的1名敵方角色造成\\n\u3000魔法傷害，並將其拉近。\\n‧以最前方的敵方為中心，對一定範圍內\\n\u3000造成魔法傷害，\\n\u3000並且使其陷入誘惑狀態\\n\u3000並提升物理攻擊力與魔法攻擊力。\\n\u3000此技能所造成的狀態異常，\\n\u3000即使傷害無效也會施加。\\n\u3000此技能造成傷害的敵人數量\\n\u3000會在一定時間內為花心星增加【二心】。');
insert into unit_enemy_data values (311305, '覺醒‧花心星', 311300, 0, 16, 270, 3000, 2, 3.0, 0, 0, 0, '【MODE2】連耀眼明星都會眼花，對自己\\n光芒的完全自信，這份盲信和少女的思念\\n將整個銀河捲入，並且迷惑一切。\\n\\n‧必殺技對敵方全體造成依照花心星保有的\\n\u3000【二心】數量的魔法比例傷害。\\n\u3000另外花心星剩餘HP未滿60%的時候，\\n\u3000更進一步提升造成的傷害。\\n\u3000造成傷害後，花心星保有的\\n\u3000【二心】數量將會歸零。\\n‧以最前方的敵方為中心，\\n\u3000對一定範圍內造成魔法傷害，\\n\u3000並且使其陷入誘惑狀態\\n\u3000並提升物理攻擊力與魔法攻擊力。\\n\u3000此技能所造成的狀態異常，\\n\u3000即使傷害無效也會施加。\\n\u3000此技能造成傷害的敵人數量\\n\u3000會在一定時間內為花心星增加【二心】。');
insert into unit_enemy_data values (311306, '覺醒‧花心星', 311300, 0, 16, 270, 3000, 2, 3.0, 0, 0, 0, '【MODE3】在夢想中的後宮夢碎之後，想讓一切\\n歸於虛無而解放了真正的力量。為了讓銀河的\\n星星們全數沉沒，散布著全部的真心。\\n\\n‧必殺技為對敵方全體造成依照花心星保有的\\n\u3000【二心】數量的魔法比例傷害。\\n\u3000另外在戰鬥剛開始之後，\\n\u3000更進一步提升造成的傷害。\\n\u3000造成傷害後，花心星保有的\\n\u3000【二心】數量將會歸零。\\n‧對敵方全體依照角色的最大HP造成\\n\u3000魔法比例傷害。\\n‧以最後方的敵方為中心，\\n\u3000對一定範圍內造成魔法傷害，\\n\u3000並且使其陷入誘惑狀態\\n\u3000並提升物理攻擊力與魔法攻擊力。\\n\u3000此技能造成傷害的敵人數量\\n\u3000會在一定時間內為花心星增加【二心】。\\n‧擊退前方範圍內的敵方，\\n\u3000造成魔法傷害。\\n\u3000並且使其陷入誘惑狀態並提升物理攻擊力與\\n\u3000魔法攻擊力。\\n\u3000此技能造成傷害的敵方數量\\n\u3000會在一定時間內為花心星增加【二心】。');
insert into unit_enemy_data values (311400, '海岸暴君‧鮫吉', 311400, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '');
insert into unit_enemy_data values (311401, '海岸暴君‧鮫吉', 311400, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】佔領海灘一帶的近海區域的海洋族暴君。\\n對找上門的架從來不曾轉身逃避，\\n絕對不會原諒破壞島嶼的傢伙。\\n\\n‧必殺技能夠對全體敵人依照其最大HP\\n\u3000造成物理比例傷害，降低其物理防禦力，\\n\u3000與提升物理攻擊力。\\n‧對前方範圍內的全體敵人\\n\u3000造成大幅度的物理傷害，\\n\u3000並且小幅度降低其物理防禦力。\\n‧擊退全體敵人。之後的一定時間內，\\n\u3000在自己身上纏繞雷電，極大幅度提升自己的\\n\u3000物理防禦力與魔法防禦力。\\n\u3000鮫吉受到中毒、猛毒、詛咒、火傷等效果時，\\n\u3000物理防禦力與魔法防禦力提升的時間\\n\u3000將會縮短。');
insert into unit_enemy_data values (311402, '海岸暴君‧鮫吉', 311400, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】佔領海灘一帶的近海區域的海洋族暴君。\\n對找上門的架從來不曾轉身逃避，\\n絕對不會原諒來地盤搗亂的傢伙。\\n\\n‧必殺技能夠對敵方全體依照其最大HP\\n\u3000造成物理比例傷害，\\n\u3000降低其物理防禦力，\\n\u3000與提升物理攻擊力。\\n‧對前方範圍內的敵方全體\\n\u3000造成大幅度的物理傷害，\\n\u3000降低物理防禦力。\\n‧擊退敵方全體。之後的一定時間內，\\n\u3000在自己身上纏繞雷電，極大幅度提升自身的\\n\u3000物理防禦力與魔法防禦力。\\n\u3000鮫吉受到中毒、猛毒、詛咒、火傷等效果時，\\n\u3000自身的物理防禦力與魔法防禦力提升的時間\\n\u3000將會縮短。\\n‧當鮫吉自身的HP低於20%時，對敵方全體\\n\u3000依照角色的最大HP造成物理比例傷害，\\n\u3000施加一定時間內無法使用必殺技\\n\u3000的狀態，並降低其魔法攻擊力。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n\u3000並且攻擊將會變得更加激烈且凶暴。');
insert into unit_enemy_data values (311403, '海岸暴君‧鮫吉', 311400, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】佔領海灘一帶的近海區域的海洋族暴君。\\n對找上門的架從來不曾轉身逃避，\\n絕對不會原諒來地盤搗亂的傢伙。\\n\\n‧必殺技能夠對敵方全體依照其最大HP\\n\u3000造成物理比例傷害，\\n\u3000大幅度降低其物理防禦力，\\n\u3000與提升物理攻擊力。\\n‧對前方範圍內的敵方全體\\n\u3000造成大幅度的物理傷害，\\n\u3000降低物理防禦力。\\n‧擊退敵方全體。之後的一定時間內，\\n\u3000在自己身上纏繞雷電，極大幅度提升自身的\\n\u3000物理防禦力與魔法防禦力。\\n\u3000鮫吉受到中毒、猛毒、詛咒、火傷等效果時，\\n\u3000自身的物理防禦力與魔法防禦力提升的時間\\n\u3000將會縮短。\\n‧當鮫吉自身的HP低於20%時，對敵方全體\\n\u3000依照角色的最大HP造成物理比例傷害，\\n\u3000施加一定時間內無法使用必殺技\\n\u3000的狀態，並降低其魔法攻擊力。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n\u3000並且攻擊將會變得更加激烈且凶暴。');
insert into unit_enemy_data values (311404, '海岸暴君‧鮫吉', 311404, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【MODE1】對於搗亂地盤的無禮之徒，解放從\\n數千抗爭中鍛鍊出的鋼鐵肉體內暗藏的力量，\\n以全身全靈的認真對決將其轟飛。\\n\\n‧必殺技能夠對敵方全體依照角色的最大HP\\n\u3000造成物理比例傷害，\\n\u3000降低其物理防禦力，\\n\u3000與提升物理攻擊力。\\n‧對前方範圍內的敵方全體\\n\u3000造成大幅度的物理傷害，\\n\u3000並且大幅度降低其物理防禦力。\\n‧對前方3名角色造成大幅度的物理傷害。並且\\n\u3000也對自身造成物理傷害，一定時間內\\n\u3000極大幅度降低物理防禦力與魔法防禦力。');
insert into unit_enemy_data values (311405, '海岸暴君‧鮫吉', 311405, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【MODE2】集結因為牠壓倒性的毅力和\\n絕望性的暴力而跟隨在牠身後的小弟們。\\n集結海洋族精銳的鬥毆，現在正要開幕。\\n\\n‧鮫吉會對面前的1名敵人進行物理攻擊。\\n‧對前方3名角色造成大幅度的物理傷害。並且\\n\u3000也對自身造成物理傷害，一定時間內\\n\u3000極大幅度降低物理防禦力與魔法防禦力。');
insert into unit_enemy_data values (311406, '海岸暴君‧鮫吉', 311404, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【MODE3】隨著兇猛的吼叫聲，暴君開始了\\n不斷的追擊。直到將敵對自己的人徹底揍扁\\n為止都不會停下，不斷落下的鐵拳如同暴風。\\n\\n‧必殺技能夠對敵方全體依照其最大HP\\n\u3000造成物理比例傷害，\\n\u3000大幅度降低其物理防禦力，\\n\u3000與提升物理攻擊力。\\n‧對前方範圍內的敵方全體\\n\u3000造成大幅度的物理傷害，\\n\u3000並且降低其物理防禦力。\\n‧擊退敵方全體。之後的一定時間內，\\n\u3000在自己身上纏繞雷電，極大幅度提升自身的\\n\u3000物理防禦力與魔法防禦力。\\n\u3000鮫吉受到中毒、猛毒、詛咒、火傷等效果時，\\n\u3000自身的物理防禦力與魔法防禦力提升的時間\\n\u3000將會縮短。\\n‧當鮫吉自身的HP低於10%時，對敵方全體\\n\u3000依照角色的最大HP造成物理比例傷害，\\n\u3000施加一定時間內無法使用必殺技\\n\u3000的狀態，並降低其魔法攻擊力。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n\u3000並且攻擊將會變得更加激烈且凶暴。');
insert into unit_enemy_data values (311500, '失控的純潔之弓', 311500, 0, 16, 270, 3000, 2, 2.4, 0, 0, 0, '');
insert into unit_enemy_data values (311501, '失控的純潔之弓', 311500, 0, 16, 270, 3000, 2, 2.4, 0, 0, 0, '【魔法】因為過多的無邪願望而失控的聖弓。\\n若被其箭矢貫穿，將會化為無力的天使。\\n\\n‧必殺技能夠對敵方全體依照其最大HP\\n\u3000造成魔法的比例傷害，再對陷入天使\\n\u3000狀態的角色施加詛咒狀態。\\n\u3000此效果施加的詛咒狀態所造成的傷害\\n\u3000將不會恢復TP。\\n‧對HP最低的3名角色依照最大HP造成\\n\u3000魔法的比例傷害，再對HP低於60％的角色\\n\u3000於一定時間內施加天使狀態。\\n\u3000陷入天使狀態的角色，會變成只能\\n\u3000進行普通攻擊，並且會解除身上的\\n\u3000狀態增益效果。');
insert into unit_enemy_data values (311502, '失控的純潔之弓', 311500, 0, 16, 270, 3000, 2, 2.4, 0, 0, 0, '【魔法】因為過多的無邪願望而失控的聖弓。\\n若被其箭矢貫穿，將會化為無力的天使。\\n\\n‧必殺技能夠對敵方全體依照其最大HP\\n\u3000造成魔法的比例傷害，再對陷入天使\\n\u3000狀態的角色施加詛咒狀態。\\n\u3000此效果施加的詛咒狀態所造成的傷害\\n\u3000將不會恢復TP。\\n‧對HP最低的3名角色依照最大HP造成\\n\u3000魔法的比例傷害，再對HP低於60％的角色\\n\u3000於一定時間內施加天使狀態。\\n\u3000陷入天使狀態的角色，會變成只能\\n\u3000進行普通攻擊，並且會解除身上的\\n\u3000狀態增益效果。\\n‧對HP最高的2名角色造成中幅度的魔法傷害，\\n\u3000同時降低行動速度。\\n‧當純潔之弓自身的HP低於50％時，\\n\u3000它的魔法攻擊力將會提升，攻擊也會\\n\u3000變得更加兇暴。');
insert into unit_enemy_data values (311503, '失控的純潔之弓', 311500, 0, 16, 270, 3000, 2, 2.4, 0, 0, 0, '【魔法】因為過多的無邪願望而失控的聖弓。\\n若被其箭矢貫穿，將會化為無力的天使。\\n\\n‧必殺技能夠對敵方全體依照其最大HP\\n\u3000造成魔法的比例傷害，再對陷入天使\\n\u3000狀態的角色施加詛咒狀態。\\n\u3000此效果施加的詛咒狀態所造成的傷害\\n\u3000將不會恢復TP。\\n‧對HP最低的3名角色依照最大HP造成\\n\u3000魔法的比例傷害，再對HP低於60％的角色於\\n\u3000一定時間內施加天使狀態。\\n\u3000陷入天使狀態的角色，會變成只能\\n\u3000進行普通攻擊，並且會解除身上的\\n\u3000狀態增益效果。\\n‧對HP最高的2名角色造成中幅度的魔法傷害，\\n\u3000同時降低行動速度。\\n‧當純潔之弓自身的HP低於50％時，\\n\u3000它的魔法攻擊力與TP將會提升，攻擊也會\\n\u3000變得更加兇暴。');
insert into unit_enemy_data values (311504, '失控的純潔之弓', 311500, 0, 16, 270, 3000, 2, 2.4, 0, 0, 0, '【MODE1】扭曲的心願化成的結晶，令人們\\n陷入瘋狂。這顆結晶能夠封殺所有的進攻。\\n\\n‧在戰鬥開始時，將會召喚出心願扭曲的水晶。\\n‧心願扭曲的水晶在戰鬥中存在的時候，\\n\u3000大幅度提升純潔之弓的物理防禦力及\\n\u3000魔法防禦力。\\n‧心願扭曲的水晶遭到破壞時，\\n\u3000大幅度降低純潔之弓的物理防禦力及\\n\u3000魔法防禦力。\\n‧必殺技能夠對敵方全體依照其最大HP\\n\u3000造成魔法的比例傷害。\\n‧對HP最高的2名角色造成中幅度的魔法傷害，\\n\u3000降低行動速度，\\n\u3000同時降低魔法防禦力。');
insert into unit_enemy_data values (311505, '失控的純潔之弓', 311500, 0, 16, 270, 3000, 2, 2.4, 0, 0, 0, '【MODE2】召喚依里與茜里的闇影。\\n以自身負面姿態，對雙胞胎真正的羈絆進行試煉。\\n\\n‧對HP最低的3名角色依照最大HP造成\\n\u3000魔法的比例傷害，再對HP低於60％的\\n\u3000角色於一定時間內\u3000施加天使狀態。\\n\u3000陷入天使狀態的角色，會變成只能\\n\u3000進行普通攻擊，並且會解除身上的\\n\u3000狀態增益效果。');
insert into unit_enemy_data values (311506, '失控的純潔之弓', 311500, 0, 16, 270, 3000, 2, 2.4, 0, 0, 0, '【MODE3】受到無法實現願望所囚禁，將聖弓\\n的權能臻至極限。解放的力量能夠撼動天地，\\n滅卻一切邪念。\\n\\n‧必殺技能夠對敵方全體依照其最大HP\\n\u3000造成魔法的比例傷害，再對陷入天使\\n\u3000狀態的角色施加詛咒狀態。\\n\u3000此效果施加的詛咒狀態所造成的傷害\\n\u3000將不會恢復TP。\\n‧對HP最低的3名角色依照最大HP造成\\n\u3000魔法的比例傷害，再對HP低於60％的\\n\u3000角色於一定時間內\u3000施加天使狀態。\\n\u3000陷入天使狀態的角色，會變成只能\\n\u3000進行普通攻擊，並且會解除身上的\\n\u3000狀態增益效果。\\n‧對HP最高的2名角色造成中幅度的魔法傷害，\\n\u3000同時降低行動速度，\\n\u3000並且降低魔法防禦力。\\n‧當剩餘時間低於35秒時，提升魔法攻擊力\\n\u3000與TP，攻擊也會變得更加兇暴。');
insert into unit_enemy_data values (311600, '驚叫鬼魂教父', 311600, 0, 16, 270, 3000, 2, 4.0, 0, 0, 0, '【魔法】令人類戰慄不已的鬼怪首領。\\n它唆使手下們，秘密策劃著島嶼的擴大。\\n\\n‧必殺技能對全體敵人依照其初始最大HP\\n\u3000造成魔法比例傷害。\\n\u3000並使全體敵人的最大HP減少10％。\\n\u3000減少的HP直到戰鬥結束後才會恢復。');
insert into unit_enemy_data values (311601, '驚叫鬼魂教父', 311600, 0, 16, 270, 3000, 2, 4.0, 0, 0, 0, '【魔法】令人類戰慄不已的鬼怪首領。\\n它唆使手下們，秘密策劃著島嶼的擴大。\\n\\n‧必殺技能對全體敵人依照其初始最大HP\\n\u3000造成魔法比例傷害。\\n\u3000並使全體敵人的最大HP減少10％。\\n\u3000減少的HP直到戰鬥結束後才會恢復。');
insert into unit_enemy_data values (311602, '驚叫鬼魂教父', 311600, 0, 16, 270, 3000, 2, 4.0, 0, 0, 0, '【魔法】令人類戰慄不已的鬼怪首領。\\n它唆使手下們，秘密策劃著島嶼的擴大。\\n\\n‧必殺技能對敵方全體依照其初始最大HP\\n\u3000造成魔法比例傷害。\\n\u3000並使全體敵人的最大HP減少10％\\n\u3000減少的HP直到戰鬥結束後才會恢復。\\n‧當鬼魂教父的HP在40％ 以下時，\\n\u3000它的攻擊將會變得更加狂暴。');
insert into unit_enemy_data values (311603, '驚叫鬼魂教父', 311600, 0, 16, 270, 3000, 2, 4.0, 0, 0, 0, '【魔法】令人類戰慄不已的鬼怪首領。\\n它唆使手下們，秘密策劃著島嶼的擴大。\\n\\n‧必殺技能對敵方全體依照其初始最大HP\\n\u3000造成魔法比例傷害。\\n\u3000並使全體敵人的最大HP減少10％\\n\u3000減少的HP直到戰鬥結束後才會恢復。\\n‧當鬼魂教父的HP在40％ 以下時，\\n\u3000它的攻擊將會變得更加狂暴。');
insert into unit_enemy_data values (311604, '驚叫鬼魂教父', 311600, 0, 16, 270, 3000, 2, 4.0, 0, 0, 0, '【MODE1】為尋求美味的靈魂，\\n鬼怪們的首領再次現身。\\n它率領殘暴的家族大肆蹂躪人類，\\n街上充斥著極盡恐懼的悲鳴。\\n\\n‧戰鬥開始時，\\n\u3000召喚出 3 隻鬼魂手下。\\n‧每打倒 1 隻鬼魂手下，\\n\u3000便會減少剩餘的 1 隻鬼魂手下。\\n\u3000接著，鬼魂手下又會被再度召喚。\\n‧鬼魂手下會使面前的 1 名敵人\\n\u3000TP 下降，並恢復\\n\u3000鬼魂教父的 TP 。\\n‧必殺技會對全體敵人依照其初始\\n\u3000最大 HP 造成魔法比例傷害，\\n\u3000同時使全體敵人的\\n\u3000最大 HP 減少 10％ 。\\n\u3000減少的 HP 直到戰鬥結束後\\n\u3000才會恢復。');
insert into unit_enemy_data values (311605, '驚叫鬼魂教父', 311600, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, '【MODE2】肆虐島嶼，為萬物降下制裁。\\n一旦踏入了他的島嶼，\\n便會被蜂擁的魍魎腐蝕生命，\\n體會人間地獄。\\n\\n‧戰鬥開始時，\\n\u3000角色的最大HP減少35％。\\n\u3000減少的HP直到戰鬥結束後才會恢復。\\n‧必殺技會對敵方全體依照其初始\\n\u3000最大HP造成魔法比例傷害，\\n\u3000同時使全體敵人的\\n\u3000最大HP減少10％。\\n\u3000減少的HP直到戰鬥結束後才會恢復。');
insert into unit_enemy_data values (311606, '驚叫鬼魂教父', 311600, 0, 16, 270, 3000, 2, 4.0, 0, 0, 0, '【MODE3】將蓄積之力全部釋放，\\n解放真正的力量。\\n支配這個世界，極盡殘忍之能事，\\n使一切染上地獄般的色彩。\\n\\n‧必殺技會對敵方全體依照其\\n\u3000初始最大HP造成魔法比例傷害，\\n\u3000同時使敵方全體的最大HP減少10％。\\n\u3000減少的HP直到戰鬥結束後才會恢復。\\n‧對自己展開使物理/魔法無效化的護盾。\\n‧當鬼魂教父的HP在40％以下時，\\n\u3000它的攻擊將會變得更加狂暴。');
insert into unit_enemy_data values (311700, '鬼魂兄弟', 311700, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, '鬼魂教父的左右手。\\n將自身化為盾，保護首領免於一切攻擊。');
insert into unit_enemy_data values (311701, '鬼魂兄弟', 311700, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, '鬼魂教父的左右手。\\n以千錘百鍊的槍砲，向城鎮發動特攻。\\n血氣方剛地突襲四處逃竄的人們，將其逼至恐懼的深淵。\\n\\n‧鬼魂兄弟無法被視為攻擊對象。');
insert into unit_enemy_data values (311702, '鬼魂兄弟', 311700, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, '鬼魂教父的左右手。\\n將槍砲們蒐集而來的上等精氣獻給首領。\\n\\n‧鬼魂兄弟無法被視為攻擊對象。\\n‧能夠恢復鬼魂教父的 TP 。\\n\u3000在鬼魂教父陷入無法行動的狀態時，\\n\u3000則不會恢復 TP 。');
insert into unit_enemy_data values (311703, '鬼魂兄弟', 311700, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, '於最後一刻登場，來勢洶洶地到訪。\\n氣勢十足的最強之盾，擊潰敵對之人的心。');
insert into unit_enemy_data values (311800, '鬼魂兄弟', 311800, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, '鬼魂教父的左右手。\\n將提取而出的精氣交給首領，負責輔佐的工作。\\n\\n‧能夠恢復鬼魂教父的 TP 。');
insert into unit_enemy_data values (311801, '鬼魂兄弟', 311800, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, '鬼魂教父的左右手。\\n在首領的周邊護衛，不給敵人絲毫可趁之機。在暗地裡偷偷\\n把鎮上的人們逼入絕境。\\n\\n‧鬼魂兄弟無法被視為攻擊對象。');
insert into unit_enemy_data values (311802, '鬼魂兄弟', 311800, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, '鬼魂教父的左右手。\\n將部下們提取到的精氣獻給首領。\\n\\n‧鬼魂兄弟無法被視為攻擊對象。\\n‧能夠恢復鬼魂教父的 TP 。\\n\u3000在鬼魂教父陷入無法行動的狀態時，\\n\u3000則不會恢復 TP 。');
insert into unit_enemy_data values (311803, '鬼魂兄弟', 311800, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, '保護家族免於危機，\\n冷靜地看清戰況。到死那一刻為止，都作為首領忠實的左右手，\\n貫徹輔佐的使命。\\n\\n‧能夠恢復鬼魂教父的 TP 。');
insert into unit_enemy_data values (311900, '光明獨角獸', 311900, 0, 13, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】吞食雲霧，而自身的樣貌\\n也如雲霧般難以捉摸。討厭人類，\\n會無情地踐踏接近之人。\\n\\n‧對全體敵人造成大幅度的魔法傷害。\\n\u3000同時對陷入火傷狀態的敵人\\n\u3000增加傷害。\\n\\n‧以物理攻擊力最高的敵人為中心，\\n\u3000對範圍內的敵人造成中幅度的魔法傷害，\\n\u3000並且施加火傷狀態。');
insert into unit_enemy_data values (312000, '黑曜飛龍', 312000, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '【物理】寄宿著魔力的黑曜結晶龍。\\n據說其閃耀的美麗身軀是徬徨於冥府之魂的嘆息。\\n\\n‧必殺技能對全體敵人依照其\\n\u3000最大 HP 造成魔法比例傷害。\\n\u3000當角色的 HP 低於 60％ 時，\\n\u3000會造成 TP 大幅度下降。\\n‧使全體敵人的HP吸收特大幅度下降，同時\\n\u3000大幅度降低其物理防禦力。\\n‧對魔法攻擊力最高的 1 名角色\\n\u3000造成大幅度的物理傷害。\\n\u3000並以該角色為中心，\\n\u3000對範圍內的全體敵人造成中幅度的物理傷害，\\n\u3000再中幅度降低其 TP 。');
insert into unit_enemy_data values (312100, '反逆獸 de M', 312100, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】奪去人們夢想的一種負面魔法生物。\\n以陰鬱的黑霧籠罩希望，腐蝕人們的內心。');
insert into unit_enemy_data values (312101, '反逆獸 de M', 312100, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】奪去人們夢想的一種負面魔法生物。\\n以陰鬱的黑霧籠罩希望，腐蝕人們的內心。\\n\\n‧必殺技能解除敵方全體的護盾，\\n\u3000造成中幅度的魔法傷害，同時小幅度降低\\n\u3000其物理防禦力，中幅度降低其魔法防禦力，\\n\u3000並在一定時間內使HP恢復量下降70％。\\n‧對前方的2名角色造成中幅度的物理傷害。');
insert into unit_enemy_data values (312102, '反逆獸 de M', 312100, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】奪去人們夢想的一種負面魔法生物。\\n以陰鬱的黑霧籠罩希望，腐蝕人們的內心。\\n\\n‧必殺技能解除敵方全體的護盾，\\n\u3000造成中幅度的魔法傷害，同時小幅度降低\\n\u3000其物理防禦力，中幅度降低其魔法防禦力，\\n\u3000並在一定時間內使HP恢復量下降70％。\\n‧對前方的2名角色造成中幅度的物理傷害。');
insert into unit_enemy_data values (312103, '反逆獸 de M', 312100, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】奪去人們夢想的一種負面魔法生物。\\n以陰鬱的黑霧籠罩希望，腐蝕人們的內心。\\n\\n‧必殺技能解除敵方全體的護盾，\\n\u3000造成中幅度的魔法傷害，同時中幅度降低其\\n\u3000物理防禦力與魔法防禦力，\\n\u3000並在一定時間內使HP恢復量下降 70％ 。\\n‧對前方的2名角色造成大幅度的物理傷害。\\n‧當反逆獸 de M的HP在15％以下時，\\n\u3000會中幅度提升自身TP，\\n\u3000攻擊也會變得更加狂暴。');
insert into unit_enemy_data values (312104, '反逆獸 de M', 312100, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【MODE1】在鎮上吸收愛與希望的\\n反逆獸。它企圖擊敗魔法少女們，\\n將鎮上所有的光輝之力收歸己用。\\n\\n‧必殺技能解除敵方全體的護盾，\\n\u3000造成大幅度的魔法傷害，同時大幅度降低其\\n\u3000物理防禦力與魔法防禦力，\\n\u3000並在一定時間內使HP恢復量下降70％。\\n‧對最後方的1名敵方角色依照其最大HP\\n\u3000造成物理比例傷害，使其陷入束縛狀態，\\n\u3000並特大幅度降低其TP，\\n\u3000再中幅度提升反逆獸 de M自身的TP。');
insert into unit_enemy_data values (312105, '反逆獸 de M', 312100, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【MODE2】渴望吸收魔法少女們的猛烈攻擊，\\n使自身更加強大的反逆獸。連守護人們的勇氣\\n也將快被它腐蝕殆盡。\\n\\n‧必殺技能解除全體敵人的護盾，\\n\u3000給予大幅度的魔法傷害，同時大幅度降低其\\n\u3000物理防禦力與魔法防禦力，\\n\u3000在一定時間內使ＨＰ恢復量下降 70％\\n‧解除全體敵人的護盾，對全體敵人\\n\u3000依照其最大ＨＰ造成魔法比例傷害，\\n\u3000並使其陷入中毒狀態。');
insert into unit_enemy_data values (312106, '反逆獸 de M', 312100, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【MODE3】反逆獸的負面情感達到最高潮，\\n它扭曲的渴望籠罩了周遭一帶，\\n重挫魔法少女們的信念，企圖使失去守護者的城鎮成為自己的囊中物。\\n\\n‧必殺技能解除敵方全體的護盾，\\n\u3000造成大幅度的魔法傷害，同時大幅度降低其\\n\u3000物理防禦力與魔法防禦力，\\n\u3000並在一定時間內使HP恢復量下降70％。\\n‧對前方2名角色造成大幅度的物理傷害。\\n‧當反逆獸 de M的HP在12％以下時，\\n\u3000攻擊將會變得更加狂暴。');
insert into unit_enemy_data values (312200, '被操控的雪人', 312200, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】肥嘟嘟且眼神銳利的最恐怖雪人。\\n它全身纏繞著狂氣，在聖夜的大街上不停徘徊，\\n使一年一度的特別夜晚變成了黑色聖誕節。');
insert into unit_enemy_data values (312201, '被操控的雪人', 312200, 0, 16, 270, 3000, 1, 4.0, 0, 0, 0, '【物理】肥嘟嘟且眼神銳利的最恐怖雪人。\\n它全身纏繞著狂氣，在聖夜的大街上不停徘徊，\\n使一年一度的特別夜晚變成了黑色聖誕節。\\n\\n‧必殺技能對敵方全體依照其角色最大HP\\n\u3000造成物理比例傷害，並且大距離向後擊飛。\\n\u3000同時，當自己的目標沒有被破壞時，\\n\u3000中幅度提升物理防禦力、\\n\u3000小幅度提升魔法防禦力。\\n‧對敵方全體依照其角色最大HP\\n\u3000造成物理比例傷害。當自己的目標\\n\u3000沒有被破壞時，額外使其陷入暈眩狀態。\\n‧當剩餘時間不到20秒時，\\n\u3000它將會丟出禮物型炸彈，在一定時間過後，\\n\u3000對敵方全體依照其角色最大HP\\n\u3000造成物理比例傷害。\\n\u3000並且，被操控的雪人自己也會依照自身剩餘HP\\n\u3000受到物理比例傷害及特大幅度的TP下降。\\n‧當頭部被破壞時，將會小幅度降低\\n\u3000物理防禦力與魔法防禦力。\\n‧當軀體被破壞時，將會小幅度降低\\n\u3000物理防禦力與魔法防禦力。\\n');
insert into unit_enemy_data values (312202, '被操控的雪人', 312200, 0, 16, 270, 3000, 1, 3.6, 0, 0, 0, '【物理】肥嘟嘟且眼神銳利的最恐怖雪人。\\n它全身纏繞著狂氣，在聖夜的大街上不停徘徊，\\n使一年一度的特別夜晚變成了黑色聖誕節。\\n\\n‧必殺技能對敵方全體依照其角色最大HP\\n\u3000造成物理比例傷害，並且大距離向後擊飛。\\n\u3000同時，當自己的目標沒有被破壞時，\\n\u3000中幅度提升物理防禦力、\\n\u3000小幅度提升魔法防禦力。\\n‧對敵方全體依照其角色最大HP\\n\u3000造成物理比例傷害。當自己的目標\\n\u3000沒有被破壞時，額外使其陷入暈眩狀態。\\n‧當剩餘時間不到20秒時，\\n\u3000它將會丟出禮物型炸彈，在一定時間過後，\\n\u3000對敵方全體依照其角色最大HP\\n\u3000造成物理比例傷害。\\n\u3000並且，被操控的雪人自己也會依照自身剩餘HP\\n\u3000受到物理比例傷害及特大幅度的TP下降。\\n‧當頭部被破壞時，將會小幅度降低\\n\u3000物理防禦力與魔法防禦力。\\n‧當軀體被破壞時，將會小幅度降低\\n\u3000物理防禦力與魔法防禦力。\\n');
insert into unit_enemy_data values (312203, '被操控的雪人', 312200, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】肥嘟嘟且眼神銳利的最恐怖雪人。\\n它全身纏繞著狂氣，在聖夜的大街上不停徘徊，\\n使一年一度的特別夜晚變成了黑色聖誕節。\\n\\n‧必殺技能對敵方全體依照其角色最大HP\\n\u3000造成物理比例傷害，並且大距離向後擊飛。\\n\u3000同時，當自己的目標沒有被破壞時，\\n\u3000中幅度提升物理防禦力、\\n\u3000小幅度提升魔法防禦力。\\n‧對敵方全體依照其角色最大HP\\n\u3000造成物理比例傷害。當自己的目標\\n\u3000沒有被破壞時，額外使其陷入暈眩狀態。\\n‧當剩餘時間不到30秒時，\\n\u3000它的攻擊將會變得更加狂暴。\\n‧當剩餘時間不到20秒時，\\n\u3000它將會丟出禮物型炸彈，在一定時間過後，\\n\u3000對敵方全體依照其角色最大HP\\n\u3000造成物理比例傷害。\\n\u3000並且，被操控的雪人自己也會依照自身剩餘HP\\n\u3000受到物理比例傷害及特大幅度的TP下降。\\n‧當頭部被破壞時，將會小幅度降低\\n\u3000物理防禦力與魔法防禦力。\\n‧當軀體被破壞時，將會小幅度降低\\n\u3000物理防禦力與魔法防禦力。\\n');
insert into unit_enemy_data values (312204, '被操控的雪人', 312200, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【MODE1】讓派對會場陷入大混亂的巨大雪人。\\n原本是備受人們喜愛且心地善良的吉祥物。\\n眾人的聲援是攻略它的關鍵。\\n\\n‧必殺技能對敵方全體依照其角色最大HP\\n\u3000造成物理比例傷害，並且大距離向後擊飛。\\n\u3000同時，當自己的目標沒有被破壞時，\\n\u3000中幅度提升物理防禦力、\\n\u3000小幅度提升魔法防禦力。\\n‧對敵方全體造成大幅度的魔法傷害，\\n\u3000並使其陷入凍結狀態。\\n\u3000同時使行動速度與物理防禦力大幅度降低。\\n‧當頭部被破壞時，將會小幅度降低\\n\u3000物理防禦力與魔法防禦力。\\n‧當軀體被破壞時，將會小幅度降低\\n\u3000物理防禦力與魔法防禦力。\\n‧在戰鬥中，被操控的雪人\\n\u3000被附加的狀態異常效果\\n\u3000或能力下降數量越多，\\n\u3000能對其造成的傷害量就會上升越多。\\n');
insert into unit_enemy_data values (312205, '被操控的雪人', 312200, 0, 16, 270, 3000, 1, 20.0, 0, 0, 0, '【MODE2】召喚沉醉於聖夜中的三人娘的闇影。\\n那是由巨大雪人做出的虛像。\\n為了挽回名譽，現在正是少女們起身奮戰的時候！\\n\\n‧必殺技能對敵方全體依照其角色最大HP\\n\u3000造成物理比例傷害，並且大距離向後擊飛。\\n\u3000同時，當自己的目標沒有被破壞時，\\n\u3000中幅度提升物理防禦力、\\n\u3000小幅度提升魔法防禦力。\\n‧對敵方全體依照其角色最大HP\\n\u3000造成物理比例傷害。當自己的目標\\n\u3000沒有被破壞時，額外使其陷入暈眩狀態。\\n‧當頭部被破壞時，將會小幅度降低\\n\u3000物理防禦力與魔法防禦力。\\n‧當軀體被破壞時，將會小幅度降低\\n\u3000物理防禦力與魔法防禦力。');
insert into unit_enemy_data values (312206, '被操控的雪人', 312200, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【MODE3】誓要輾殺所有意念而\\n不斷滾動的巨大雪人。向所有孤獨之人，\\n溫柔地獻上爆炎的禮物for you♪\\n\\n‧必殺技能對敵方全體依照其角色最大HP\\n\u3000造成物理比例傷害，並且大距離向後擊飛。\\n\u3000同時，當自己的目標沒有被破壞時，\\n\u3000中幅度提升物理防禦力、\\n\u3000小幅度提升魔法防禦力。\\n‧對敵方全體依照其角色最大HP\\n\u3000造成物理比例傷害。當自己的目標\\n\u3000沒有被破壞時，額外使其陷入暈眩狀態。\\n‧當剩餘時間不到30秒時，\\n\u3000它的攻擊將會變得更加狂暴。\\n‧當剩餘時間不到20秒時，\\n\u3000它將會丟出禮物型炸彈，在一定時間過後，\\n\u3000對敵方全體依照其角色最大HP\\n\u3000造成物理比例傷害。\\n\u3000並且，被操控的雪人自己也會依照自身剩餘HP\\n\u3000受到物理比例傷害及特大幅度的TP下降。\\n‧當頭部被破壞時，將會小幅度降低\\n\u3000物理防禦力與魔法防禦力。\\n‧當軀體被破壞時，將會小幅度降低\\n\u3000物理防禦力與魔法防禦力。\\n');
insert into unit_enemy_data values (312300, '究極金槍鮪', 312300, 0, 16, 270, 3000, 1, 1.1, 0, 0, 0, '');
insert into unit_enemy_data values (312301, '究極金槍鮪', 312300, 0, 16, 270, 3000, 1, 4.0, 0, 0, 0, '【物理】大間的漁夫自古流傳的夢幻巨魚。\\n牠會用巨大身驅高速衝撞，使所有船隻葬身海底，\\n但據說牠的肉是世間僅有的極致美味。\\n\\n‧必殺技能對敵方全體依照其角色最大HP\\n\u3000造成物理比例傷害。\\n\u3000並將其擊退。');
insert into unit_enemy_data values (312302, '究極金槍鮪', 312302, 0, 16, 270, 3000, 1, 3.3, 0, 0, 0, '【物理】大間的漁夫自古流傳的夢幻巨魚。\\n牠會用巨大身驅高速衝撞，使所有船隻葬身海底，\\n但據說牠的肉是世間僅有的極致美味。\\n\\n‧必殺技能對敵方全體依照其角色最大HP\\n\u3000造成物理比例傷害。\\n\u3000並且將其擊退。\\n‧當剩餘時間不到35秒時，\\n\u3000牠的攻擊將會變得更加狂暴。');
insert into unit_enemy_data values (312303, '究極金槍鮪', 312302, 0, 16, 270, 3000, 1, 1.1, 0, 0, 0, '【物理】大間的漁夫自古流傳的夢幻巨魚。\\n牠會用巨大身驅高速衝撞，使所有船隻葬身海底，\\n但據說牠的肉是世間僅有的極致美味。\\n\\n‧必殺技能對敵方全體依照其角色最大HP\\n\u3000造成物理比例傷害。\\n\u3000並且將其擊退。\\n‧當剩餘時間不到35秒時，\\n\u3000牠的攻擊將會變得更加狂暴。');
insert into unit_enemy_data values (312304, '究極金槍鮪', 312302, 0, 16, 270, 3000, 1, 0.0, 0, 0, 0, '【MODE1】讓眾多漁夫葬身海底的海中之王。\\n閃著金光的魚鰭連大型漁船的龍骨也能輕易折斷，\\n那幅景象簡直是海面上的解體秀。\\n\\n‧必殺技能對敵方全體依照其角色最大HP\\n\u3000造成物理比例傷害。\\n\u3000並且將其擊退。\\n‧對前方範圍內所有敵人造成大幅度的物理傷害，\\n\u3000再對後方的2名角色造成中幅度的\\n\u3000物理傷害。另外再提升自身的物理攻擊力。');
insert into unit_enemy_data values (312305, '究極金槍鮪', 312305, 0, 16, 270, 3000, 1, 1.0, 0, 0, 0, '【MODE2】馳騁大海的怪魚變得更加強大。\\n輕輕一游就像在激勵自己似地掀起巨大漩渦，\\n化身將大海一分為二的巨大砲彈衝撞敵人。\\n\\n‧必殺技能對前方的3名角色\\n\u3000造成特大幅度的物理傷害，\\n\u3000並且將其擊退。\\n‧提升自身的物理攻擊力與行動速度、TP。');
insert into unit_enemy_data values (312306, '究極金槍鮪', 312302, 0, 16, 270, 3000, 1, 1.0, 0, 0, 0, '【MODE3】不論黝黑的巨大身驅被魚叉射中幾次，\\n也無法阻止這條傳說巨魚的衝刺。\\n與海上男兒們長久的戰鬥即將分出勝負。\\n\\n‧必殺技能對敵方全體依照其角色最大HP\\n\u3000造成物理比例傷害。\\n\u3000並且將其擊退。\\n‧提升自身的物理攻擊力與行動速度、TP。\\n‧當剩餘時間不到35秒時，\\n\u3000牠的攻擊將會變得更加狂暴。');
insert into unit_enemy_data values (312400, '寒冰格里芬', 312400, 0, 11, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】張開冰翼\\n威嚇冒險者的大鷲。\\n對於闖入地盤之人，\\n會毫不留情地將其冰凍住，\\n並餵予雛鳥。\\n\\n‧必殺技能對前方小範圍內\\n\u3000造成大幅度物理傷害，\\n\u3000並大幅度向後擊飛，\\n\u3000使其陷入凍結狀態。');
insert into unit_enemy_data values (312401, '寒冰格里芬', 312400, 0, 11, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】張開冰翼\\n威嚇冒險者的大鷲。\\n對於闖入地盤之人，\\n會毫不留情地將其冰凍住，\\n並餵予雛鳥。\\n\\n‧必殺技能對前方小範圍內\\n\u3000造成大幅度物理傷害，\\n\u3000並大幅度向後擊飛，\\n\u3000使其陷入凍結狀態。');
insert into unit_enemy_data values (312500, '厄勒克特拉夫人', 312500, 0, 6, 270, 1000, 2, 1.6, 0, 0, 0, '【魔法】積蓄塔之魔力來放出電擊的怪鳥。\\n會與雷雲一同現身，以如天災般的雷擊葬送敵人。\\n\\n‧對敵方全體造成大幅度魔法傷害，\\n\u3000同時小幅度提升\\n\u3000自身的魔法攻擊力與行動速度。\\n\u3000對進行物理攻擊的敵人造成追加傷害。\\n‧對前方範圍內所有敵人造成中幅度的魔法傷害，\\n\u3000並且中幅度降低物理防禦力與魔法防禦力。\\n‧對物理攻擊力最高的1名敵方角色造成大幅度的\\n\u3000魔法傷害，並使其陷入長時間的麻痺狀態。\\n\u3000自身的HP低於85%時，也會對魔法攻擊力\\n\u3000最高的敵人發動此攻擊。');
insert into unit_enemy_data values (312600, '角鹿將軍', 312600, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '');
insert into unit_enemy_data values (312601, '角鹿將軍', 312600, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】擁有巨大麋鹿角的大型魔物。\\n牠會以連大岩石都能輕易粉碎的大角，\\n一次掃蕩所有冒險者。\\n\\n‧普通攻擊會以前方1名角色為中心，對範圍內的\\n\u3000角色造成小幅度的物理傷害。\\n‧必殺技會對敵方全體依照其角色最大HP\\n\u3000造成魔法比例傷害。\\n\u3000同時中幅度降低自身的物理與\\n\u3000魔法防禦力。\\n‧對前方範圍內敵人造成中幅度的物理傷害，\\n\u3000並使其暈眩。同時大幅度降低\\n\u3000自身的物理與魔法防禦力。');
insert into unit_enemy_data values (312602, '角鹿將軍', 312600, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】擁有巨大麋鹿角的大型魔物。\\n牠會以連大岩石都能輕易粉碎的大角，\\n一次掃蕩所有冒險者。\\n\\n‧普通攻擊會以前方1名角色為中心，對範圍內的\\n\u3000角色造成小幅度的物理傷害。\\n‧必殺技會對敵方全體依照其角色最大HP\\n\u3000造成魔法比例傷害。\\n\u3000同時中幅度降低自身的物理與\\n\u3000魔法防禦力。\\n‧對前方範圍內敵人造成中幅度的物理傷害，\\n\u3000並使其暈眩。同時大幅度降低\\n\u3000自身的物理與魔法防禦力。\\n‧當剩餘時間不到25秒時，牠的攻擊\\n\u3000將會變得更加兇暴。');
insert into unit_enemy_data values (312603, '角鹿將軍', 312600, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】擁有巨大麋鹿角的大型魔物。\\n牠會以連大岩石都能輕易粉碎的大角，\\n一次掃蕩所有冒險者。\\n\\n‧普通攻擊會以前方1名角色為中心，對範圍內的\\n\u3000角色造成小幅度的物理傷害。\\n‧必殺技會對敵方全體依照其角色最大HP\\n\u3000造成魔法比例傷害。\\n\u3000同時中幅度降低自身的物理與\\n\u3000魔法防禦力。\\n‧對前方範圍內敵人造成中幅度的物理傷害，\\n\u3000並使其暈眩。同時大幅度降低\\n\u3000自身的物理與魔法防禦力。\\n‧當剩餘時間不到25秒時，牠的攻擊\\n\u3000將會變得更加兇暴。');
insert into unit_enemy_data values (312604, '角鹿將軍', 312600, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【MODE1】聽到首領吼叫聲，手下的雄鹿\\n成群結隊地蜂擁而至。抵擋得住捨身的\\n突進嗎？\\n\\n‧戰鬥開始時，召喚3隻狂野角鹿，\\n\u3000並使其擊退。\\n‧每打倒1隻狂野角鹿，剩餘的\\n\u3000狂野角鹿數量減少1。\\n\u3000之後，將會再次召喚狂野角鹿，\\n\u3000並使其擊退。\\n‧普通攻擊會以前方1名角色為中心，對範圍內的\\n\u3000角色造成小幅度的物理傷害。\\n‧必殺技會對敵方全體依照其角色最大HP\\n\u3000造成魔法比例傷害。\\n\u3000同時中幅度降低自身的物理與\\n\u3000魔法防禦力。');
insert into unit_enemy_data values (312605, '角鹿將軍', 312600, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【MODE2】操縱朽木魔物，將冒險者逼入\\n絕境。若是失去共生的朽木，其身也將\\n邁向毀滅。擊敗朽木將成為攻略的關鍵。\\n\\n‧戰鬥開始時，召喚2隻多倫多獸\\n\u3000並使其擊退。\\n‧前方的多倫多獸HP變成0時，小幅度\\n\u3000降低角鹿將軍的物理與魔法\\n\u3000防禦力。\\n‧後方的多倫多獸HP變成0時，極大幅度\\n\u3000降低角鹿將軍的物理與\\n\u3000魔法防禦力。\\n‧普通攻擊會以前方1名角色為中心，對範圍內的\\n\u3000角色造成小幅度的物理傷害。\\n‧必殺技會對敵方全體依照其角色最大HP\\n\u3000造成魔法比例傷害。\\n\u3000同時中幅度降低自身的物理與\\n\u3000魔法防禦力。\\n‧對前方範圍內敵人造成中幅度的物理傷害，\\n\u3000並使其陷入暈眩。同時大幅度降低\\n\u3000自身的物理與魔法防禦力。');
insert into unit_enemy_data values (312606, '角鹿將軍', 312600, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【MODE3】身負重傷的角獸傾盡全力抗戰。\\n賭上性命的突進使身驅化為紫電，以如光一閃\\n瓦解身經百戰的冒險者一行人。\\n\\n‧普通攻擊會以前方1名角色為中心，對範圍內的\\n\u3000角色造成小幅度的物理傷害。\\n‧必殺技會對敵方全體依照其角色最大HP\\n\u3000造成魔法比例傷害。\\n\u3000同時中幅度降低自身的物理與魔法\\n\u3000防禦力。\\n‧對前方範圍內敵人造成中幅度的物理傷害，\\n\u3000並使其陷入暈眩。同時大幅度降低\\n\u3000自身的物理與魔法防禦力。\\n\u3000當剩餘時間不到25秒時，牠的攻擊\\n\u3000將會變得更加兇暴。');
insert into unit_enemy_data values (312700, '黑風之精靈', 312700, 0, 16, 270, 3000, 2, 2.7, 0, 0, 0, '');
insert into unit_enemy_data values (312701, '黑風之精靈', 312700, 0, 16, 270, 3000, 2, 2.7, 0, 0, 0, '【魔法】試探操控者真正實力的漆黑風之精靈。\\n那裡不含有惡意，純粹只為測試懷藏於自己內心的\\n想法與羈絆。\\n\\n‧必殺技會對敵方全體依照其角色最大HP\\n\u3000造成魔法比例傷害。並賦予\\n\u3000剩餘HP最低的1名角色倒數計時\\n\u3000效果，5秒後造成該角色HP80%的\\n\u3000魔法比例傷害。');
insert into unit_enemy_data values (312702, '黑風之精靈', 312700, 0, 16, 270, 3000, 2, 2.7, 0, 0, 0, '【魔法】試探操控者真正實力的漆黑風之精靈。\\n那裡不含有惡意，純粹只為測試懷藏於自己內心的\\n想法與羈絆。\\n\\n‧必殺技會對敵方全體依照其角色最大HP\\n\u3000造成魔法比例傷害。並賦予\\n\u3000剩餘HP最低的1名角色倒數計時\\n\u3000效果，5秒後造成該角色HP80%的\\n\u3000魔法比例傷害。\\n‧使敵方全體陷入猛毒狀態，並大幅度降低物理與\\n\u3000魔法攻擊力。\\n當剩餘時間不到25秒時，牠的攻擊將會變得\\n\u3000更加兇暴。');
insert into unit_enemy_data values (312703, '黑風之精靈', 312700, 0, 16, 270, 3000, 2, 2.7, 0, 0, 0, '【魔法】試探操控者真正實力的漆黑風之精靈。\\n那裡不含有惡意，純粹只為測試懷藏於自己內心的\\n想法與羈絆。\\n\\n‧必殺技會對敵方全體依照其角色最大HP\\n\u3000造成魔法比例傷害。並賦予\\n\u3000剩餘HP最低的1名角色倒數計時\\n\u3000效果，5秒後造成該角色HP80%的\\n\u3000魔法比例傷害。\\n‧使敵方全體陷入猛毒狀態，並大幅度降低物理與\\n\u3000魔法攻擊力。\\n當剩餘時間不到25秒時，牠的攻擊將會變得\\n\u3000更加兇暴。');
insert into unit_enemy_data values (312704, '黑風之精靈', 312700, 0, 16, 270, 3000, 2, 2.7, 0, 0, 0, '【MODE1】第一道試煉。若是無法看穿漆黑風之精靈\\n暴風的接合之處，將無法主動開拓自己\\n應前往之路。\\n\\n‧對敵方全體造成物理傷害並使其陷入暈眩，\\n\u3000同時將其擊退。\\n\u3000黑風之精靈睡著的期間，會大幅度降低自身的\\n\u3000物理防禦力，若在期間內對其造成100000\\n\u3000以上的傷害，將延長防禦力降低時間，\\n\u3000並降低行動速度。');
insert into unit_enemy_data values (312705, '黑風之精靈', 312705, 0, 16, 270, 3000, 2, 2.7, 0, 0, 0, '【MODE2】第二道試煉。與自己軟弱的心對峙\\n吧。答案隨時在自己心中。現在\\n相信夥伴的力量並挺身對抗吧。\\n\\n‧對前方2名角色造成小幅度的物理傷害，\\n\u3000同時將其擊退，並使其陷入暈眩。');
insert into unit_enemy_data values (312706, '黑風之精靈', 312700, 0, 16, 270, 3000, 2, 2.7, 0, 0, 0, '【MODE3】第三道試煉。最終的試煉為賭上\\n自己的全部向漆黑風之精靈展現真正的想法與\\n羈絆，確認自己的想法吧。\\n\\n‧必殺技會對敵方全體依照其角色最大HP\\n\u3000造成魔法比例傷害。並賦予\\n\u3000剩餘HP最低的1名角色倒數計時\\n\u3000效果，5秒後造成該角色HP80%的\\n\u3000魔法比例傷害。\\n‧使敵方全體陷入猛毒狀態，並大幅度降低物理與\\n\u3000魔法攻擊力。\\n當剩餘時間不到25秒時，牠的攻擊將會變得\\n\u3000更加兇暴。');
insert into unit_enemy_data values (312800, '魔物的公主', 312800, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '');
insert into unit_enemy_data values (312801, '魔物的公主', 312800, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】坐鎮於邊境之城，孤高的魔物的公主。\\n懷著悲哀的愛慕，粉碎挑戰自己的人。\\n\\n‧必殺技能夠對前方的2名角色依照其最大HP\\n\u3000造成物理比例傷害。\\n\u3000當成功累積力量時，會提升\\n\u3000傷害，使敵方全體陷入畏懼狀態。\\n\u3000陷入畏懼狀態的角色，在一定時間之內進行\\n\u3000攻擊與HP恢復的必殺技與技能，其效果都將\\n\u3000降低。\\n‧大幅度降低物理防禦力與魔法防禦力後，\\n\u3000在一定時間內，會累積力量。\\n\u3000累積力量後，特大幅度恢復TP。\\n\u3000在累積力量時，當魔物的公主受到7000\\n\u3000以上的傷害時，累積力量會失敗，\\n\u3000大幅度降低TP。 \\n‧對面前的1名敵方角色造成物理傷害。\\n\u3000此攻擊容易受到物理攻擊力提升、降低\\n\u3000的效果影響。\\n‧對前方的3名角色依照其最大HP造成\\n\u3000物理比例傷害。\\n\u3000此攻擊容易受到物理攻擊力提升、降低\\n\u3000的效果影響。');
insert into unit_enemy_data values (312802, '魔物的公主', 312800, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】坐鎮於邊境之城，孤高的魔物的公主。\\n懷著悲哀的愛慕，粉碎挑戰自己的人。\\n\\n‧必殺技能夠對前方的2名角色依照其最大HP\\n\u3000造成物理比例傷害。\\n\u3000當成功累積力量時，會提升\\n\u3000傷害，使敵方全體陷入畏懼狀態。\\n\u3000陷入畏懼狀態的角色，在一定時間之內進行\\n\u3000攻擊與HP恢復的必殺技與技能，其效果都將\\n\u3000降低。\\n‧大幅度降低物理防禦力與魔法防禦力後，\\n\u3000在一定時間內，會累積力量。\\n\u3000累積力量後，特大幅度恢復TP。\\n\u3000在累積力量時，當魔物的公主受到21000\\n\u3000以上的傷害時，累積力量會失敗，\\n\u3000大幅度降低TP。 \\n‧對面前的1名敵方角色造成物理傷害。\\n\u3000此攻擊容易受到物理攻擊力提升、降低\\n\u3000的效果影響。\\n‧對前方的3名角色依照其最大HP造成\\n\u3000物理比例傷害。\\n\u3000此攻擊容易受到物理攻擊力提升、降低\\n\u3000的效果影響。');
insert into unit_enemy_data values (312803, '魔物的公主', 312800, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】坐鎮於邊境之城，孤高的魔物的公主。\\n懷著悲哀的愛慕，粉碎挑戰自己的人。\\n\\n‧必殺技能夠對前方的2名角色依照其最大HP\\n\u3000造成物理比例傷害。\\n\u3000當成功累積力量時，會提升\\n\u3000傷害，使敵方全體陷入畏懼狀態。\\n\u3000陷入畏懼狀態的角色，在一定時間之內進行\\n\u3000攻擊與HP恢復的必殺技與技能，其效果都將\\n\u3000降低。\\n‧大幅度降低物理防禦力與魔法防禦力後，\\n\u3000在一定時間內，會累積力量。\\n\u3000累積力量後，特大幅度恢復TP。\\n\u3000在累積力量時，當魔物的公主受到了\\n\u3000260000以上的傷害時，累積力量會\\n\u3000失敗，大幅度降低TP。 \\n‧對面前的1名敵人造成物理傷害。\\n\u3000此攻擊容易受到物理攻擊力提升、降低\\n\u3000的效果影響。\\n‧對前方的3名角色依照其最大HP造成\\n\u3000物理比例傷害。\\n\u3000此攻擊容易受到物理攻擊力提升、降低\\n\u3000的效果影響。\\n‧當魔物的公主自身的HP不到25％之時，\\n\u3000牠的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (312804, '魔物的公主', 312800, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【MODE1】清高的公主派出隨從拒絕\\n對敵。彷彿在掩飾內心的悲嘆。\\n\\n‧必殺技能夠對前方的2名角色依照其最大HP\\n\u3000造成物理比例傷害。\\n‧對面前的1名敵人造成物理傷害。\\n\u3000此攻擊容易受到物理攻擊力提升、降低\\n\u3000的效果影響。\\n‧對前方的3名角色依照其最大HP造成\\n\u3000物理比例傷害。\\n\u3000此攻擊容易受到物理攻擊力提升、降低\\n\u3000的效果影響。');
insert into unit_enemy_data values (312805, '魔物的公主', 312800, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【MODE2】公主解放更多力量。\\n以扭曲的強烈愛慕，阻擋一切並殲滅。\\n\\n‧對敵人攻擊造成的麻痺、暈眩、束縛、凍結、\\n\u3000時間停止、行動速度降低等效果沒有\\n\u3000抗性。\\n‧必殺技能夠對前方的2名角色依照其最大HP\\n\u3000造成物理比例傷害。\\n‧對面前的1名敵人造成物理傷害。\\n\u3000此攻擊容易受到物理攻擊力提升、降低\\n\u3000的效果影響。\\n‧對前方的3名角色依照其最大HP造成\\n\u3000物理比例傷害。\\n\u3000此攻擊容易受到物理攻擊力提升、降低\\n\u3000的效果影響。\\n‧短時間成為無敵狀態，解除敵方全體的能力\\n\u3000提升效果後，在一定時間內\\n\u3000展開戰鬥場地。\\n\\n【戰鬥場地效果】\\n‧降低敵方全體100%的物理攻擊力與\\n\u3000魔法攻擊力後，特大幅度提升物理攻擊力與\\n\u3000魔法攻擊力。\\n‧特大幅度提升魔物的公主的物理攻擊力。');
insert into unit_enemy_data values (312806, '魔物的公主', 312800, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【MODE3】呼應巨大的悲傷，公主的\\n進攻極為激烈。懷著少女的熱情，其\\n悲傷得不到救贖。\\n\\n‧必殺技能夠對前方的2名角色依照其最大HP\\n\u3000造成物理比例傷害。\\n\u3000當成功累積力量時，會提升\\n\u3000傷害，使敵方全體陷入畏懼狀態。\\n\u3000陷入畏懼狀態的角色，在一定時間之內進行\\n\u3000攻擊與HP恢復的必殺技與技能，其效果都將\\n\u3000降低。\\n‧大幅度降低物理防禦力與魔法防禦力後，\\n\u3000在一定時間內，會累積力量。\\n\u3000累積力量後，特大幅度恢復TP。\\n\u3000在累積力量時，當魔物的公主受到了\\n\u30001500000以上的傷害時，累積力量會\\n\u3000失敗，大幅度降低TP。 \\n‧對面前的1名敵人造成物理傷害。\\n\u3000此攻擊容易受到物理攻擊力提升、降低\\n\u3000的效果影響。\\n‧對前方的3名角色依照其最大HP造成\\n\u3000物理比例傷害。\\n\u3000此攻擊容易受到物理攻擊力提升、降低\\n\u3000的效果影響。\\n‧當魔物的公主自身的HP低於25％之時，\\n\u3000牠的攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (312900, '黑月守護像', 312900, 0, 16, 270, 3000, 1, 2.5, 0, 0, 0, '【物理】受黑月祝福的雕像，守護天上的聖域。\\n將踏入聖域的冒險者埋葬於常世的黑暗中。\\n\\n‧必殺技能夠對敵方全體依照其角色最大\\n\u3000HP造成物理比例傷害。\\n‧對敵方全體造成大幅度的物理傷害，並解除\\n\u3000能力提升效果。此技能的效果，\\n\u3000即使傷害無效也會施加。\\n‧大幅度提升自身的物理攻擊力與魔法\\n\u3000攻擊力。當白陽守護像被討伐時，\\n\u3000會使用此技能。\\n‧當黑月守護像的HP不到50%時，將會大幅度\\n\u3000提升物理攻擊力，中幅度提升物理\\n\u3000防禦力。\\n‧當黑月守護像的目標部位被\\n\u3000破壞時，將會小幅度降低物理防禦力與魔法\\n\u3000防禦力。\\n‧當白陽守護像已被討伐時，當戰鬥\\n\u3000開始時或黑月守護像進行普通攻擊\\n\u3000時，會改變黑月守護像的攻擊\\n\u3000行動。');
insert into unit_enemy_data values (313000, '白陽守護像', 313000, 0, 16, 270, 3000, 2, 2.5, 0, 0, 0, '【魔法】受白陽祝福的雕像，守護天上的聖域。\\n用淨化一切的白雷，對冒險者降下審判。\\n\\n‧必殺技能夠對敵方全體依照其角色最大\\n\u3000HP造成魔法比例傷害。\\n‧對敵方全體造成大幅度的魔法傷害，並解除\\n\u3000能力提升效果。同時大幅度提升白陽守護像的\\n\u3000魔法攻擊力。此技能的效果，\\n\u3000即使傷害無效也會施加。當黑月\\n\u3000守護像被討伐時，會使用\\n\u3000此技能。\\n‧中幅度提升我方全體的物理防禦力與魔法\\n\u3000防禦力。\\n‧當白陽守護像的HP不到50%時，將會特大\\n\u3000幅度提升魔法攻擊力，小幅度提升\\n\u3000魔法防禦力。\\n‧當白陽守護像的目標部位被\\n\u3000破壞時，將會小幅度降低物理防禦力與\\n\u3000魔法防禦力。\\n‧當黑月守護像已被討伐時，當戰鬥\\n\u3000開始時或白陽守護像進行普通攻擊\\n\u3000時，會改變白陽守護像的攻擊\\n\u3000行動。');
insert into unit_enemy_data values (313100, '爆裂‧時間儀', 313100, 0, 16, 270, 3000, 2, 1.4, 0, 0, 0, '');
insert into unit_enemy_data values (313101, '爆裂‧時間儀', 313100, 0, 16, 270, 3000, 2, 1.4, 0, 0, 0, '【魔法】帆稀收藏的魔導具超越界限失控\\n的模樣。忘卻原本的職責，變成將冒險者\\n導向混沌的領航員。\\n\\n‧必殺技能夠對敵方全體造成大幅度的\\n\u3000魔法傷害，同時中幅度降低其行動速度，\\n\u3000中幅度降低其魔法防禦力。\\n\u3000此技能所造成的狀態異常，\\n\u3000即使傷害無效也會施加。\\n‧中幅度提升自身的魔法攻擊力，\\n\u3000大幅度提升行動速度。\\n‧當左側的目標被破壞時，\\n\u3000將會中幅度降低物理與魔法防禦力。\\n‧當中央下方的目標被破壞時，\\n\u3000將會大幅度降低物理與魔法防禦力。\\n‧當中央上方的目標被破壞時，\\n\u3000將會大幅度降低物理與魔法防禦力。\\n‧當右側的目標被破壞時，\\n\u3000將會特大幅度降低物理與魔法防禦力。');
insert into unit_enemy_data values (313102, '爆裂‧時間儀', 313100, 0, 16, 270, 3000, 2, 1.4, 0, 0, 0, '【魔法】帆稀收藏的魔導具超越界限失控\\n的模樣。忘卻原本的職責，變成將冒險者\\n導向混沌的領航員。\\n\\n‧必殺技能夠對敵方全體造成大幅度的\\n\u3000魔法傷害，同時中幅度降低其行動速度，\\n\u3000中幅度降低其魔法防禦力。\\n\u3000此技能所造成的狀態異常，\\n\u3000即使傷害無效也會施加。\\n‧中幅度提升自身的魔法攻擊力，\\n\u3000大幅度提升行動速度。\\n‧當左側的目標被破壞時，\\n\u3000將會中幅度降低物理與魔法防禦力。\\n‧當中央下方的目標被破壞時，\\n\u3000將會大幅度降低物理與魔法防禦力。\\n‧當中央上方的目標被破壞時，\\n\u3000將會大幅度降低物理與魔法防禦力。\\n‧當右側的目標被破壞時，\\n\u3000將會特大幅度降低物理與魔法防禦力。');
insert into unit_enemy_data values (313103, '爆裂‧時間儀', 313100, 0, 16, 270, 3000, 2, 1.4, 0, 0, 0, '【魔法】帆稀收藏的魔導具超越界限失控\\n的模樣。忘卻原本的職責，變成將冒險者\\n導向混沌的領航員。\\n\\n‧必殺技能夠對敵方全體造成大幅度的\\n\u3000魔法傷害，同時中幅度降低其行動速度，\\n\u3000中幅度降低其魔法防禦力。\\n\u3000此技能所造成的狀態異常，\\n\u3000即使傷害無效也會施加。\\n‧中幅度提升自身的魔法攻擊力，\\n\u3000大幅度提升行動速度。\\n‧當剩餘時間不到25秒時，\\n\u3000將會大幅度提升自身的TP，\\n\u3000其攻擊將會變得更加兇暴。\\n‧當左側的目標被破壞時，\\n\u3000將會中幅度降低物理與魔法防禦力。\\n‧當中央下方的目標被破壞時，\\n\u3000將會大幅度降低物理與魔法防禦力。\\n‧當中央上方的目標被破壞時，\\n\u3000將會大幅度降低物理與魔法防禦力。\\n‧當右側的目標被破壞時，\\n\u3000將會特大幅度降低物理與魔法防禦力。');
insert into unit_enemy_data values (313104, '爆裂‧時間儀', 313104, 0, 16, 270, 3000, 2, 1.4, 0, 0, 0, '【MODE1】失控的魔導具想將所有東西\\n都留在自身的領域中。不論有多少障礙\\n也不屈服，相信自己並開拓未來。\\n\\n‧使此戰鬥中全部目標的破壞\\n\u3000無效。\\n‧展開護盾，使其不會受到敵人造成的任何攻擊。\\n\u3000護盾受到攻擊時會漸漸降低\\n\u3000耐久，受到一定數量時護盾\\n\u3000就會被破壞。\\n‧必殺技能夠對敵方全體造成大幅度的\\n\u3000魔法傷害，同時中幅度降低其行動速度，\\n\u3000中幅度降低其魔法防禦力。\\n\u3000此技能所造成的狀態異常，\\n\u3000即使傷害無效也會施加。\\n‧中幅度提升自身的魔法攻擊力，\\n\u3000並大幅度提升行動速度。');
insert into unit_enemy_data values (313105, '爆裂‧時間儀', 313100, 0, 16, 270, 3000, 2, 1.4, 0, 0, 0, '【MODE2】召喚祈梨與嘉夜的闇影。\\n兩人會在自身的「如果」的姿態中看到什麼。\\n是時候打破虛構並證明自己的道路正確。\\n\\n‧使此戰鬥中全部目標的破壞無效。\\n‧中幅度提升自身的魔法攻擊力，\\n\u3000並大幅度提升行動速度。');
insert into unit_enemy_data values (313106, '爆裂‧時間儀', 313100, 0, 16, 270, 3000, 2, 0.8, 0, 0, 0, '【MODE3】失去了主人的魔導具\\n持續失控。如果在絕望降臨中不斷\\n反抗，就會開啟一條希望之光的道路。\\n\\n‧必殺技能夠對敵方全體造成大幅度的\\n\u3000魔法傷害，同時中幅度降低其行動速度，\\n\u3000中幅度降低其魔法防禦力。\\n\u3000此技能所造成的狀態異常，\\n\u3000即使傷害無效也會施加。\\n‧中幅度提升自身的魔法攻擊力，\\n\u3000大幅度提升行動速度。\\n‧當剩餘時間不到25秒時，\\n\u3000將會大幅度提升自身的TP，\\n\u3000其攻擊將會變得更加兇暴。\\n‧當左側的目標被破壞時，\\n\u3000將會中幅度降低物理與魔法防禦力。\\n‧當中央下方的目標被破壞時，\\n\u3000將會大幅度降低物理與魔法防禦力。\\n‧當中央上方的目標被破壞時，\\n\u3000將會大幅度降低物理與魔法防禦力。\\n‧當右側的目標被破壞時，\\n\u3000將會特大幅度降低物理與魔法防禦力。');
insert into unit_enemy_data values (313200, '無名的藝術', 313200, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '');
insert into unit_enemy_data values (313201, '無名的藝術', 313200, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '【物理】奇形怪狀藝術作品的魔物，表現出了\\n製造者的深淵？其風貌完全無法以一般人的標準\\n理解，製造者說懂的人就懂。\\n\\n‧必殺技能夠對敵方全體依照其角色最大\\n\u3000HP造成魔法比例傷害。\\n\u3000而當該角色的HP低於50%時，使其陷入\\n\u3000火傷狀態。\\n\u3000此技能施加的火傷狀態所造成的傷害\\n\u3000將不會恢復TP。\\n‧以前方第3名角色為中心，\\n\u3000對範圍內依照其角色\\n\u3000最大HP造成物理比例傷害。\\n\u3000並且對陷入火傷狀態的角色\\n\u3000依照其最大HP造成追加物理比例傷害。');
insert into unit_enemy_data values (313202, '無名的藝術', 313200, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '【物理】奇形怪狀藝術作品的魔物，表現出了\\n製造者的深淵？其風貌完全無法以一般人的標準\\n理解，製造者說懂的人就懂。\\n\\n‧必殺技能夠對敵方全體依照其角色最大\\n\u3000HP造成魔法比例傷害。\\n\u3000而當該角色的HP低於50%時，使其陷入\\n\u3000火傷狀態。\\n\u3000此技能施加的火傷狀態所造成的傷害\\n\u3000將不會恢復TP。\\n‧以前方第3名角色為中心，\\n\u3000對範圍內依照其角色\\n\u3000最大HP造成物理比例傷害。\\n\u3000並且對陷入火傷狀態的角色\\n\u3000依照其最大HP造成追加物理比例傷害。');
insert into unit_enemy_data values (313203, '無名的藝術', 313200, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '【物理】奇形怪狀藝術作品的魔物，表現出了\\n製造者的深淵？其風貌完全無法以一般人的標準\\n理解，製造者說懂的人就懂。\\n\\n‧必殺技能夠對敵方全體依照其角色最大\\n\u3000HP造成魔法比例傷害。\\n\u3000而當該角色的HP低於50%時，使其陷入\\n\u3000火傷狀態。\\n\u3000此技能施加的火傷狀態所造成的傷害\\n\u3000將不會提升TP。\\n‧以前方第3名角色為中心，對範圍內依照其角色\\n\u3000最大HP造成物理比例傷害。\\n\u3000並且對陷入火傷狀態的角色依照其最大\\n\u3000HP造成追加物理比例傷害。\\n‧當剩餘時間不到30秒時，將會小幅度提升自身\\n\u3000的TP，其攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (313204, '無名的藝術', 313200, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '【MODE1】寄宿著生命的黏土人偶不會停止。\\n內部發出奇形怪狀的魔力，少女們和已抵抗的校舍\\n能承受接連射出的光線嗎？\\n\\n‧必殺技能夠對敵方全體依照其角色最大\\n\u3000HP造成魔法比例傷害。\\n\u3000並且當該角色的HP低於50%時，使其陷入\\n\u3000火傷狀態。\\n\u3000此技能施加的火傷狀態所造成的傷害\\n\u3000將不會提升TP。\\n‧解除前方範圍內的敵人的護盾，\\n\u3000並依照其角色最大HP\\n\u3000造成魔法比例傷害。\\n\u3000並且使其陷入束縛狀態。\\n\u3000但是，當無名的藝術受到\\n\u3000下毒、猛毒、詛咒、火傷\\n\u3000等效果時，不會被施加束縛。\\n‧當自身受到下毒、猛毒、詛咒、火傷時，\\n\u3000特大幅度降低自身的物理、魔法防禦力。');
insert into unit_enemy_data values (313205, '無名的藝術', 313200, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '【MODE2】黏土人偶所畫的獨特\\n設計的魔法陣。不要被視覺\\n迷惑，趁其鬆懈時一眨眼將它打扁。\\n\\n‧必殺技能夠對敵方全體依照其角色最大\\n\u3000HP造成魔法比例傷害。\\n\u3000而當該角色的HP低於50%時，使其陷入\\n\u3000火傷狀態。\\n\u3000此技能施加的火傷狀態所造成的傷害\\n\u3000將不會提升TP。\\n‧普通攻擊會對前方1名角色造成中幅度的\\n\u3000物理傷害。\\n\u3000無名的藝術所持有的【美感】的數量\\n\u3000越多，傷害也越高。\\n‧以前方第3名角色為中心，對範圍內角色造成\\n\u3000中幅度物理傷害。\\n\u3000無名的藝術所持有的【美感】的數量\\n\u3000越多，傷害也越高。\\n‧戰鬥開始時，會展開魔法陣。\\n\\n【魔法陣效果】\\n‧無名的藝術每秒追加【美感】5個。\\n‧每當無名的藝術受到傷害時，\\n\u3000無名的藝術的【美感】會減少1個。');
insert into unit_enemy_data values (313206, '無名的藝術', 313200, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '【MODE3】竭盡殘存的力量，放肆展現最後的\\n瘋狂的黏土人偶。能守護住她們燦爛的學生\\n生活嗎？挺身面對吧，好朋友社！\\n\\n‧必殺技能夠對敵方全體依照其角色最大\\n\u3000HP造成魔法比例傷害。\\n\u3000而當該角色的HP低於50%時，使其陷入\\n\u3000火傷狀態。\\n\u3000此技能施加的火傷狀態所造成的傷害\\n\u3000將不會提升TP。\\n‧以前方第3名角色為中心，對範圍內依照其角色\\n\u3000最大HP造成物理比例傷害。\\n\u3000並且對陷入火傷狀態的角色依照其最大\\n\u3000HP造成追加物理比例傷害。\\n‧當剩餘時間不到30秒時，將會大幅度提升自身\\n\u3000的TP，其攻擊將會變得更加兇暴。');
insert into unit_enemy_data values (313300, '究極機械玩具王', 313300, 0, 16, 270, 3000, 1, 3.0, 0, 0, 0, '');
insert into unit_enemy_data values (313301, '究極機械玩具王', 313300, 0, 16, 270, 3000, 1, 3.0, 0, 0, 0, '【物理】因被遺忘而失控的悲慘的玩具之王。\\n三度被孩子們遺忘，使它陷在恐懼與悲傷中難以自拔。\\n來吧！現在正是BB團的奮起之時！\\n\\n‧必殺技為對敵方全體依照其最大HP\\n\u3000造成物理比例傷害，\\n\u3000並特大幅度降低面前 1 名敵人的\\n\u3000物理攻擊力與魔法攻擊力。\\n\u3000此技能的效果，即使傷害無效\\n\u3000也會施加。\\n‧對面前的 1 名敵人依照其最大HP\\n\u3000造成物理比例傷害。\\n‧對物理攻擊力或魔法攻擊力其中一者\\n\u3000最高的 2 名角色依照其最大HP\\n\u3000造成物理比例傷害。');
insert into unit_enemy_data values (313302, '究極機械玩具王', 313300, 0, 16, 270, 3000, 1, 3.0, 0, 0, 0, '【物理】因被遺忘而失控的悲慘的玩具之王。\\n三度被孩子們遺忘，使它陷在恐懼與悲傷中難以自拔。\\n來吧！現在正是BB團的奮起之時！\\n\\n‧必殺技為對敵方全體依照其最大HP\\n\u3000造成物理比例傷害，\\n\u3000並特大幅度降低面前 1 名敵人的\\n\u3000物理攻擊力與魔法攻擊力。\\n\u3000此技能的效果，即使傷害無效\\n\u3000也會施加。\\n‧對面前的 1 名敵人依照其最大HP\\n\u3000造成物理比例傷害。\\n‧對物理攻擊力或魔法攻擊力其中一者\\n\u3000最高的 2 名角色依照其最大HP\\n\u3000造成物理比例傷害。');
insert into unit_enemy_data values (313303, '究極機械玩具王', 313300, 0, 16, 270, 3000, 1, 3.0, 0, 0, 0, '【物理】因被遺忘而失控的悲慘的玩具之王。\\n三度被孩子們遺忘，使它陷在恐懼與悲傷中難以自拔。\\n來吧！現在正是BB團的奮起之時！\\n\\n‧當究極機械玩具王自身的 HP 低於40%時，\\n\u3000它的兩臂會綻放光芒，\\n\u3000攻擊也將變得更加兇暴。\\n‧必殺技為對敵方全體依照其最大 HP\\n\u3000造成物理比例傷害，\\n\u3000並特大幅度降低面前 1 名敵人的\\n\u3000物理攻擊力與魔法攻擊力。\\n\u3000此技能的效果，即使傷害無效\\n\u3000也會施加。\\n\u3000在它的兩臂發光時，造成的傷害會增加，\\n\u3000並且對面前的 1 名敵人造成\\n\u3000大幅度的物理傷害。\\n‧對面前的 1 名敵人依照其最大 HP\\n\u3000造成物理比例傷害。\\n\u3000在它的兩臂發光時，造成的傷害會增加，\\n\u3000且此技能所造成的傷害\\n\u3000將不會恢復 TP。\\n‧對物理攻擊力或魔法攻擊力其中一者\\n\u3000最高的 2 名角色依照其最大 HP\\n\u3000造成物理比例傷害。\\n\u3000在它的兩臂發光時，此技能所造成的傷害\\n\u3000將不會恢復 TP。');
insert into unit_enemy_data values (313304, '究極機械玩具王', 313300, 0, 16, 270, 3000, 1, 3.0, 0, 0, 0, '【MODE1】小小的英雄阻擋在\\n失控的好友身前。究竟能否將它從悲傷之中解救出來呢？\\n與好朋友號一同挺身戰鬥吧，BB團！\\n\\n‧必殺技為對敵方全體依照其最大HP\\n\u3000造成物理比例傷害，\\n\u3000並特大幅度降低面前 1 名敵人的\\n\u3000物理攻擊力與魔法攻擊力。\\n\u3000此技能的效果，即使傷害無效\\n\u3000也會施加。\\n‧對面前的 1 名敵人依照其最大 HP\\n\u3000造成物理比例傷害。\\n‧對物理攻擊力或魔法攻擊力其中一者\\n\u3000最高的 2 名角色依照其最大 HP\\n\u3000造成物理比例傷害。\\n‧在一定時間內，\\n\u3000好朋友號會作為角色的夥伴現身，這時究極機械玩具王\\n\u3000會陷入無法行動的狀態。\\n\u3000並且，會以好朋友號為中心，\\n\u3000展開使範圍內角色\\n\u3000物理攻擊力、物理暴擊率及 TP 上升率都\\n\u3000特大幅度提升的領域。');
insert into unit_enemy_data values (313305, '究極機械玩具王', 313305, 0, 16, 270, 3000, 1, 3.0, 0, 0, 0, '【MODE2】悲傷的玩具王創造出的虛像。\\n「誰都會害怕正視自己。你並不孤單！」\\n胸懷如此強烈的情感，別認輸了啊，BB團！\\n\\n‧召喚出碧、美冬、珠希的闇影。\\n‧對面前的 1 名敵人依照其最大 HP\\n\u3000造成物理比例傷害。');
insert into unit_enemy_data values (313306, '究極機械玩具王', 313300, 0, 16, 270, 3000, 1, 3.0, 0, 0, 0, '【MODE3】悲傷的玩具王的最後抵抗。\\n受被遺忘的寂寞支配的它有著毀滅性的強大力量。\\n將對朋友的心意化作力量，拯救它吧，BB團！\\n\\n‧當究極機械玩具王自身的 HP 低於20%時，\\n\u3000它的兩臂會綻放光芒，且物理防禦力及魔法防禦力\\n\u3000會特大幅度降低，\\n\u3000攻擊也將變得更加兇暴。\\n‧必殺技為對敵方全體依照其最大 HP\\n\u3000造成物理比例傷害，\\n\u3000並特大幅度降低面前 1 名敵人的\\n\u3000物理攻擊力與魔法攻擊力。\\n\u3000此技能的效果，即使傷害無效\\n\u3000也會施加。\\n\u3000在它的兩臂發光時，造成的傷害會增加，\\n\u3000並且對面前的 1 名敵人造成\\n\u3000大幅度的物理傷害。\\n‧對面前的 1 名敵人依照其最大 HP\\n\u3000造成物理比例傷害。\\n\u3000在它的兩臂發光時，造成的傷害會增加，\\n\u3000且此技能所造成的傷害\\n\u3000將不會恢復 TP。\\n‧對物理攻擊力或魔法攻擊力其中一者\\n\u3000最高的 2 名角色依照其最大 HP\\n\u3000造成物理比例傷害。\\n\u3000在它的兩臂發光時，此技能所造成的傷害\\n\u3000將不會恢復 TP。');
insert into unit_enemy_data values (313400, '劍蛇', 313400, 0, 16, 270, 3000, 1, 3.0, 0, 0, 0, '【物理】尾巴藏有紅色邪劍的凶暴大毒蛇。\\n以有毒的氣息使獵物衰弱，\\n再以可一擊斃命的劍送葬敵人。\\n\\n‧必殺技會對魔法攻擊力最高的1名\\n\u3000敵人造成大幅度的物理傷害。\\n\u3000當角色處於猛毒狀態時再追加傷害。\\n\u3000之後特大幅度降低敵方全體的HP吸收。\\n‧對敵方全體造成小幅度的魔法傷害，\\n\u3000施加中毒狀態。\\n\u3000對已處於中毒狀態的敵方施加猛毒狀態。\\n‧對從前方數來第1名敵人\\n\u3000造成中幅度的物理傷害，\\n\u3000施加中毒狀態。\\n‧劍蛇施加的中毒及猛毒所造成的傷害，\\n\u3000不會恢復角色的TP。');
insert into unit_enemy_data values (313500, '卡里莎', 313500, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '隨心所欲操縱魔物，獲得強化的辣鞭的少年。\\n操使紅藍黃三色的史萊姆發動敏捷的猛攻。\\n\\n‧必殺技會依照卡里莎的物理攻擊力\\n\u3000對前方範圍內的敵方\\n\u3000造成物理比例傷害。\\n‧大幅度提升卡里莎的物理攻擊力。\\n‧依照卡里莎的物理攻擊力\\n\u3000對從前方數來第1名角色\\n\u3000造成物理比例傷害。');
insert into unit_enemy_data values (313501, '卡里莎', 313501, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '隨心所欲操縱魔物，獲得強化的辣鞭的少年。\\n操使紅藍黃三色的史萊姆發動敏捷的猛攻。\\n\\n‧必殺技會依照卡里莎的物理攻擊力\\n\u3000對前方範圍內的敵方\\n\u3000造成物理比例傷害。\\n‧大幅度提升卡里莎的物理攻擊力。\\n‧依照卡里莎的物理攻擊力\\n\u3000對從前方數來第1名角色\\n\u3000造成物理比例傷害。');
insert into unit_enemy_data values (313600, '蘭法', 313600, 0, 16, 270, 3001, 2, 3.0, 0, 0, 0, '對於天賦異稟的才華與異常的感受力感到懊惱，深沉平靜的歌姬。\\n雖不好鬥爭，但會為了願望及夥伴而奮戰。\\n\\n‧必殺技會對前方範圍內的敵方造成中幅度的\\n\u3000魔法傷害，並使其陷入結晶化狀態。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n\u3000處於結晶化狀態會無法行動，\\n\u3000並受到持續傷害。\\n\u3000完全恢復HP或經過一定時間後，\\n\u3000結晶化狀態就會解除。\\n‧對前方範圍內的敵方施加猛毒狀態。\\n\u3000對處於結晶化狀態的敵方造成大幅度的\\n\u3000魔法追加傷害。\\n‧對從前方數來第1名角色造成小幅度的魔法傷害。');
insert into unit_enemy_data values (313601, '蘭法', 313601, 0, 16, 270, 3001, 2, 3.0, 0, 0, 0, '對於天賦異稟的才華與異常的感受力感到懊惱，深沉平靜的歌姬。\\n雖不好鬥爭，但會為了願望及夥伴而奮戰。\\n\\n‧必殺技會對前方範圍內的敵方造成中幅度的\\n\u3000魔法傷害，並使其陷入結晶化狀態。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n\u3000處於結晶化狀態會無法行動，\\n\u3000並受到持續傷害。\\n\u3000完全恢復HP或經過一定時間後，\\n\u3000結晶化狀態就會解除。\\n‧對前方範圍內的敵方施加猛毒狀態。\\n\u3000對處於結晶化狀態的敵方造成大幅度的\\n\u3000魔法追加傷害。\\n‧對從前方數來第1名角色造成小幅度的魔法傷害。');
insert into unit_enemy_data values (313700, '美空', 313700, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '總是樂觀開朗，和任何人都能當朋友的活潑少女。\\n喜歡使用轉輪機槍，隻身對敵人施展飽和攻擊。\\n\\n‧戰鬥開始時，召喚怪奇怪靈。\\n\u3000召喚時擊退前方範圍內的\\n\u3000敵方全體。\\n\u3000怪奇怪靈會對從前方數來2名角色造成大幅度的\\n\u3000物理傷害。\\n‧必殺技會對敵方全體\\n\u3000造成物理比例傷害。\\n\u3000並且大幅度提升怪奇怪靈的物理攻擊力\\n\u3000與行動速度。\\n‧恢復怪奇怪靈的HP。\\n‧對從前方數來第1名角色造成\\n\u3000小幅度的物理傷害。');
insert into unit_enemy_data values (313701, '美空', 313701, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '總是樂觀開朗，和任何人都能當朋友的活潑少女。\\n喜歡使用轉輪機槍，隻身對敵人施展飽和攻擊。\\n\\n‧戰鬥開始時，召喚怪奇怪靈。\\n\u3000召喚時擊退前方範圍內的\\n\u3000敵方全體。\\n\u3000怪奇怪靈會對從前方數來2名角色造成大幅度的\\n\u3000物理傷害。\\n‧必殺技會對敵方全體\\n\u3000造成物理比例傷害。\\n\u3000並且大幅度提升怪奇怪靈的物理攻擊力\\n\u3000與行動速度。\\n\u3000此技能造成的傷害會減少\\n\u3000TP恢復量。\\n‧恢復怪奇怪靈的HP。\\n‧對從前方數來第1名角色造成\\n\u3000小幅度的物理傷害。');
insert into unit_enemy_data values (313800, '阿澤爾德', 313800, 0, 16, 270, 3000, 1, 1.5, 0, 0, 0, '總是暗藏好幾招殺手鐧的大胃王紳士。\\n操縱萬能人偶並運用謀略將敵人逼至絕境。\\n\\n‧必殺技會依照阿澤爾德的物理攻擊力\\n\u3000對敵方全體造成物理比例傷害。\\n\u3000並且大幅度降低阿澤爾德的物理防禦力\\n\u3000與魔法防禦力。\\n‧召喚萬能人偶並擊退敵方全體。\\n\u3000萬能人偶會對從前方數來第1名角色造成\\n\u3000小幅度的物理傷害。\\n\u3000萬能人偶的HP低於一定數值時，\\n\u3000大幅度降低阿澤爾德的物理防禦力\\n\u3000與魔法防禦力。\\n‧對從前方數來第1名角色造成小幅度的物理傷害。');
insert into unit_enemy_data values (313801, '阿澤爾德', 313801, 0, 16, 270, 3000, 1, 1.5, 0, 0, 0, '總是暗藏好幾招殺手鐧的大胃王紳士。\\n操縱萬能人偶並運用謀略將敵人逼至絕境。\\n\\n‧必殺技會依照阿澤爾德的物理攻擊力\\n\u3000對敵方全體造成物理比例傷害。\\n\u3000並且大幅度降低阿澤爾德的物理防禦力\\n\u3000與魔法防禦力。\\n‧召喚萬能人偶並擊退敵方全體。\\n\u3000萬能人偶會對從前方數來第1名角色造成\\n\u3000小幅度的物理傷害。\\n\u3000萬能人偶的HP低於一定數值時，\\n\u3000大幅度降低阿澤爾德的物理防禦力\\n\u3000與魔法防禦力。\\n‧對從前方數來第1名角色造成小幅度的物理傷害。');
insert into unit_enemy_data values (313900, '贊恩', 313900, 0, 16, 270, 3000, 1, 1.0, 313900, 313900, 0, '橫掃千軍、萬夫莫敵，沉默寡言的劍士。\\n一經覺醒，龍將飛升至更高的境界。\\n\\n‧必殺技會依照贊恩的\\n\u3000物理攻擊力與剩餘HP造成\\n\u3000物理比例傷害。\\n\u3000此技能造成的傷害\\n\u3000會減少TP恢復量。\\n‧對敵方全體造成中幅度的物理傷害，\\n\u3000並使其暈眩。\\n‧大幅度提升贊恩的TP上升、行動速度、\\n\u3000物理攻擊力。\\n\u3000每次發動，此技能的效果\\n\u3000都會提升。\\n\u3000第3次發動時再提升TP1000。\\n‧對從前方數來第1名角色造成\\n\u3000中幅度的物理傷害，並小幅度擊飛。');
insert into unit_enemy_data values (313901, '贊恩', 313901, 0, 16, 270, 3000, 1, 1.0, 313900, 313900, 0, '');
insert into unit_enemy_data values (314000, '作業', 314000, 0, 16, 270, 3000, 1, 1.0, 0, 0, 0, '');
insert into unit_enemy_data values (314001, '擅長的作業', 314001, 0, 16, 270, 3000, 1, 1.0, 0, 0, 0, '一開始先來做完比較擅長的作業吧。\\n不能在這裡一蹶不振。\\n暑假作業還有很多很多喔！！\\n\\n‧在戰鬥開始後，大量的作業會從天而降，\\n\u3000對敵方全體造成傷害。\\n‧在戰鬥中，每當經過一定時間，\\n\u3000怪物會蜂擁而來。');
insert into unit_enemy_data values (314002, '有些棘手的作業', 314002, 0, 16, 270, 3000, 1, 1.0, 0, 0, 0, '不擅長的科目的作業，任何人都會遇到。\\n往往在不知不覺間一直拖延，結果累積了一大堆沒寫，真是吃足苦頭了。\\n不可以停在這裡止步不前！\\n\\n‧在戰鬥開始後，大量的作業會從天而降，\\n\u3000對敵方全體造成傷害。\\n‧在戰鬥中，每當經過一定時間，\\n\u3000怪物會蜂擁而來。');
insert into unit_enemy_data values (314003, '非常棘手的作業', 314003, 0, 16, 270, 3000, 1, 1.0, 0, 0, 0, '討人厭的作業，光看就讓人頭昏。\\n強忍住丟下手中的筆衝到外頭去的沖動，\\n踏實地向前邁進就是獲勝的關鍵！\\n\\n‧在戰鬥開始後，大量的作業會從天而降，\\n\u3000對敵方全體造成傷害。\\n‧在戰鬥中，每當經過一定時間，\\n\u3000怪物會蜂擁而來。');
insert into unit_enemy_data values (314004, '留到暑假最後一天的作業', 314004, 0, 16, 270, 3000, 1, 1.0, 0, 0, 0, 'SP MODE1');
insert into unit_enemy_data values (314005, '留到暑假最後一天的作業', 314005, 0, 16, 270, 3000, 1, 1.0, 0, 0, 0, 'SP MODE2');
insert into unit_enemy_data values (314006, '留到暑假最後一天的作業', 314006, 0, 16, 270, 3000, 1, 1.0, 0, 0, 0, '暑假期間一直裝作沒看見的最後的作業。\\n居然堆到現在都沒管它，後悔的心情一口氣湧上了心頭。\\n究竟能不能全部搞定、帶著笑容去上學呢！？\\n\\n‧在戰鬥開始後，大量的作業會從天而降，\\n\u3000對敵方全體造成傷害。\\n‧在戰鬥中，每當經過一定時間，\\n\u3000怪物會蜂擁而來。');
insert into unit_enemy_data values (314100, '女王歌唱水母', 314100, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '');
insert into unit_enemy_data values (314101, '女王歌唱水母', 314100, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】在大海上像花一般搖盪，唱出悠揚歌聲的\\n歌唱水母女王。外表裝飾得美麗動人，\\n裡頭卻隱藏著帶有猛毒的體液。\\n\\n‧必殺技會依照角色的HP對敵方全體造成\\n\u3000魔法比例傷害。\\n\u3000對處於猛毒狀態的敵方傷害會提升。\\n\u3000並且對敵方施加中毒狀態，\\n\u3000對已處於中毒或猛毒狀態的敵方\\n\u3000施加猛毒狀態。\\n‧對面前的 1 名敵方造成大幅度的魔法傷害。\\n‧對敵方全體造成小幅度的魔法傷害，\\n\u3000並施加中毒狀態。\\n\u3000敵方處於猛毒狀態時使其暈眩。\\n‧女王歌唱水母施加的中毒及猛毒\\n\u3000所造成的傷害不會恢復角色的TP。');
insert into unit_enemy_data values (314102, '女王歌唱水母', 314100, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】在大海上像花一般搖盪，唱出悠揚歌聲的\\n歌唱水母女王。外表裝飾得美麗動人，\\n裡頭卻隱藏著帶有猛毒的體液。\\n\\n‧必殺技會依照角色的HP對敵方全體造成\\n\u3000魔法比例傷害。\\n\u3000對處於猛毒狀態的敵方傷害會提升。\\n\u3000並且對敵方施加中毒狀態，\\n\u3000對已處於中毒或猛毒狀態的敵方\\n\u3000施加猛毒狀態。\\n‧對面前的 1 名敵方造成大幅度的魔法傷害。\\n‧對敵方全體造成小幅度的魔法傷害，\\n\u3000並施加中毒狀態。\\n\u3000敵方處於猛毒狀態時使其暈眩。\\n‧女王歌唱水母施加的中毒及猛毒\\n\u3000所造成的傷害不會恢復角色的TP。');
insert into unit_enemy_data values (314103, '女王歌唱水母', 314100, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】在大海上像花一般搖盪，唱出悠揚歌聲的\\n歌唱水母女王。外表裝飾得美麗動人，\\n裡頭卻隱藏著帶有猛毒的體液。\\n\\n‧必殺技會依照角色的HP對敵方全體造成\\n\u3000魔法比例傷害。\\n\u3000對處於猛毒狀態的敵方傷害會提升。\\n\u3000並且對敵方施加中毒狀態，\\n\u3000對已處於中毒或猛毒狀態的敵方\\n\u3000施加猛毒狀態。\\n‧對面前的 1 名敵方造成大幅度的魔法傷害。\\n‧對敵方全體造成小幅度的魔法傷害，\\n\u3000並施加中毒狀態。\\n\u3000敵方處於猛毒狀態時使其暈眩。\\n‧女王歌唱水母施加的中毒及猛毒\\n\u3000所造成的傷害不會恢復角色的TP。\\n‧當剩餘時間不到25秒時，攻擊將會變得\\n\u3000更加兇暴。');
insert into unit_enemy_data values (314104, '女王歌唱水母', 314104, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE1】襲擊而來的無數魔物。\\n其歌聲轟然迴響，危害著舞台。為了守護\\n粉絲的笑容，少女們唱歌跳舞並勇敢奮戰。\\n\\n‧在戰鬥開始時，召喚3隻歌唱水母。\\n‧每打倒1隻歌唱水母，剩餘的歌唱水母\\n\u3000數量會減少1。\\n\u3000之後會再次召喚歌唱水母，\\n\u3000擊退隊伍全體角色。\\n‧歌唱水母會對剩餘HP最高的1名敵方角色\\n\u3000造成中幅度的魔法傷害，並施加中毒狀態。\\n‧必殺技會依照角色的HP\\n\u3000對敵方全體造成魔法比例傷害。\\n\u3000對處於猛毒狀態的敵方傷害會提升。\\n\u3000並且對敵方施加中毒狀態，\\n\u3000對已處於中毒或猛毒狀態的敵方\\n\u3000施加猛毒狀態。\\n‧對面前的1名敵方角色造成大幅度的魔法傷害。\\n‧女王歌唱水母與歌唱水母施加的中毒及猛毒\\n\u3000所造成的傷害不會恢復\\n\u3000角色的TP。');
insert into unit_enemy_data values (314105, '女王歌唱水母', 314105, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE2】出現在眼前的是\\n過去的自己。成長後的結果，少女們超越了過去，\\n將那每一瞬間的光芒都化成了歌聲。\\n\\n‧召喚慈樂之音的闇影。\\n‧對面前的1名敵方角色造成大幅度的魔法傷害。');
insert into unit_enemy_data values (314106, '女王歌唱水母', 314104, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE3】優雅的花紛飛，解放\\n內在的魔性。將劇毒的雨聲化成旋律，\\n歌姬就此演唱最後的一首歌。\\n\\n‧必殺技會依照角色的HP\\n\u3000對敵方全體造成魔法比例傷害。\\n\u3000對處於猛毒狀態的敵方傷害會提升。\\n\u3000並且對敵方施加中毒狀態，\\n\u3000對已處於中毒或猛毒狀態的敵方\\n\u3000施加猛毒狀態。\\n‧對面前的1名敵方角色造成大幅度的魔法傷害。\\n‧對敵方全體造成小幅度的魔法傷害，\\n\u3000並施加中毒狀態。\\n\u3000敵方處於猛毒狀態時使其暈眩。\\n‧女王歌唱水母施加的中毒及猛毒\\n\u3000所造成的傷害不會恢復角色的TP。\\n‧當剩餘時間不到25秒時，攻擊將會變得\\n\u3000更加兇暴。');
insert into unit_enemy_data values (314200, '基古魯博士', 314200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '');
insert into unit_enemy_data values (314201, '基古魯博士', 314200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】露出劣根性的大江戶怪醫。\\n打算靠著在研究中所獲得的究極肉體，\\n向世界進行報復。\\n\\n‧必殺技會依照基古魯博士的物理攻擊力，\\n\u3000對敵方全體造成物理比例傷害，\\n\u3000並使其陷入中毒狀態。\\n‧召喚惡魔燒瓶並擊退\\n\u3000敵方全體。\\n‧惡魔燒瓶每當經過一定的時間，\\n\u3000將中幅度提升基古魯博士的物理攻擊力，\\n\u3000並且在特大幅度恢復TP後，當場消失。\\n\u3000但是當惡魔燒瓶的HP低於\\n\u3000一定數值時，將特大幅度提升隊伍全體的\\n\u3000物理攻擊力與魔法攻擊力，並且在\\n\u3000特大幅度恢復TP後，當場消失。\\n\u3000同時基古魯博士下次所召喚出的\\n\u3000惡魔燒瓶將強化1個階段。\\n‧對物理攻擊力或魔法攻擊力其中一者最高的\\n\u30001名角色造成大幅度的物理傷害，\\n\u3000同時降低行動速度。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。');
insert into unit_enemy_data values (314202, '基古魯博士', 314200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】露出劣根性的大江戶怪醫。\\n打算靠著在研究中所獲得的究極肉體，\\n向世界進行報復。\\n\\n‧必殺技會依照基古魯博士的物理攻擊力，\\n\u3000對敵方全體造成物理比例傷害，\\n\u3000並使其陷入中毒狀態。\\n‧召喚惡魔燒瓶並擊退\\n\u3000敵方全體。\\n‧惡魔燒瓶每當經過一定的時間，\\n\u3000將中幅度提升基古魯博士的物理攻擊力，\\n\u3000並且在特大幅度恢復TP後，當場消失。\\n\u3000但是當惡魔燒瓶的HP低於\\n\u3000一定數值時，將特大幅度提升隊伍全體的\\n\u3000物理攻擊力與魔法攻擊力，並且在\\n\u3000特大幅度恢復TP後，當場消失。\\n\u3000同時基古魯博士下次所召喚出的\\n\u3000惡魔燒瓶將強化1個階段。\\n‧對物理攻擊力或魔法攻擊力其中一者最高的\\n\u30001名角色造成大幅度的物理傷害，\\n\u3000同時降低行動速度。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。');
insert into unit_enemy_data values (314203, '基古魯博士', 314200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】露出劣根性的大江戶怪醫。\\n打算靠著在研究中所獲得的究極肉體，\\n向世界進行報復。\\n\\n‧必殺技會依照基古魯博士的物理攻擊力，\\n\u3000對敵方全體造成物理比例傷害，\\n\u3000並使其陷入中毒狀態。\\n‧召喚惡魔燒瓶並擊退\\n\u3000敵方全體。\\n‧惡魔燒瓶每當經過一定的時間，\\n\u3000將中幅度提升基古魯博士的物理攻擊力，\\n\u3000並且在特大幅度恢復TP後，當場消失。\\n\u3000但是惡魔燒瓶的HP低於\\n\u3000一定數值時，將在特大幅度提升隊伍全體的\\n\u3000物理攻擊力與魔法攻擊力，並且在\\n\u3000特大幅度恢復TP後，當場消失。\\n\u3000同時基古魯博士下次所召喚出的\\n\u3000惡魔燒瓶將強化1個階段。\\n‧對物理攻擊力或魔法攻擊力其中一者最高的\\n\u30001名角色造成大幅度的物理傷害，\\n\u3000同時降低行動速度。\\n\u3000此技能所造成的狀態異常，即使傷害無效\\n\u3000也會施加。\\n‧當基古魯博士自身的HP低於30％時，\\n\u3000攻擊將會變得更加激烈且凶暴。');
insert into unit_enemy_data values (314204, '基古魯博士', 314204, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE1】藉著迷幻藥所看到的自我虛像。\\n秉持著真誠的醫道，擊碎阻擋在眼前的\\n實體化邪魔歪道。\\n\\n‧召喚深月、雪的闇影及魔物。\\n‧對面前的1名角色造成中幅度的物理傷害。');
insert into unit_enemy_data values (314205, '基古魯博士', 314205, 0, 16, 270, 3000, 1, 0.0, 0, 0, 0, '【MODE2】從魔手釋放出的妖光在地上疾馳。\\n被其魔性所吞噬的實驗品們，\\n忘我地瘋狂咆哮。\\n\\n‧召喚魔物，擊退敵方全體。\\n‧每打倒1隻被召喚出來的魔物，\\n\u3000剩餘的目標數量就會減少1個。\\n\u3000之後再次召喚魔物出來，\\n\u3000將擊退敵方全體。\\n‧特大幅度提升基古魯博士以外我方全體的\\n\u3000物理防禦力與魔法防禦力。\\n\u3000基古魯博士的HP在戰鬥開始後，\\n\u3000當減少5000以上及10000以上時，\\n\u3000其外貌就會改變，此技能效果\\n\u3000將降低。');
insert into unit_enemy_data values (314206, '基古魯博士', 314200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE3】肉體的進化提升到極限。\\n進化的最後，野心的最後，打算以這隻魔手\\n掌握世界的怪醫憤而怒吼。\\n\\n‧必殺技會依照基古魯博士的物理攻擊力\\n\u3000對敵方全體造成物理比例傷害，\\n\u3000並使其陷入中毒狀態。\\n‧召喚惡魔燒瓶並擊退敵方全體。\\n‧惡魔燒瓶每當經過一定的時間，\\n\u3000將中幅度提升基古魯博士的\\n\u3000物理攻擊力、物理防禦力與魔法防禦力，\\n\u3000並在特大幅度恢復TP後，\\n\u3000當場消失。\\n\u3000但是當惡魔燒瓶的HP低於\\n\u3000一定數值時，將中幅度提升隊伍全體的\\n\u3000物理攻擊力與魔法攻擊力，直到戰鬥結束，\\n\u3000並且在特大幅度恢復TP後，當場消失。\\n\u3000同時基古魯博士下次所召喚出的\\n\u3000惡魔燒瓶將強化1個階段。\\n‧對物理攻擊力或魔法攻擊力其中一者最高的\\n\u30001名角色造成大幅度的物理傷害，\\n\u3000同時降低行動速度。\\n\u3000此技能所造成的狀態異常，\\n\u3000即使傷害無效也會施加。\\n‧當基古魯博士自身的HP低於30％時，\\n\u3000攻擊將會變得更加激烈且凶暴。');
insert into unit_enemy_data values (314300, '哀暴小棉花糖', 314300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '');
insert into unit_enemy_data values (314301, '哀暴小棉花糖', 314301, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】在孤單不安之中，成為有錢人的道具，\\n悲傷情緒失控，解放出真正力量的魔犬。\\n除非毀滅一切，否則牠的失控絕不會停止。\\n\\n‧必殺技會解除敵方全體的護盾，\\n\u3000造成大幅度的物理傷害。\\n\u3000同時小幅度提升自己的物理攻擊力。\\n‧對面前的1名敵人造成物理傷害。\\n‧大幅度降低前方3名角色的\\n\u3000物理/魔法攻擊力，並大幅度降低\\n\u3000物理防禦力直到戰鬥結束。\\n‧小幅度提升自身的物理攻擊力。');
insert into unit_enemy_data values (314302, '哀暴小棉花糖', 314301, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】在孤單不安之中，成為有錢人的道具，\\n悲傷情緒失控，解放出真正力量的魔犬。\\n除非毀滅一切，否則牠的失控絕不會停止。\\n\\n‧必殺技會解除敵方全體的護盾，\\n\u3000造成大幅度的物理傷害。\\n\u3000同時小幅度提升自己的物理攻擊力。\\n‧對面前的1名敵人造成物理傷害。\\n‧大幅度降低前方3名角色的\\n\u3000物理/魔法攻擊力，並大幅度降低\\n\u3000物理防禦力直到戰鬥結束。\\n‧小幅度提升自身的物理攻擊力。');
insert into unit_enemy_data values (314303, '哀暴小棉花糖', 314300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】在孤單不安之中，成為有錢人的道具，\\n悲傷情緒失控，解放出真正力量的魔犬。\\n除非毀滅一切，否則牠的失控絕不會停止。\\n\\n‧必殺技會解除敵方全體的護盾，\\n\u3000造成大幅度的物理傷害。\\n\u3000同時小幅度提升自己的物理攻擊力。\\n\u3000此攻擊容易受到\\n\u3000物理攻擊力提升、降低的效果影響。\\n‧對面前的1名敵人造成物理傷害。\\n\u3000此攻擊容易受到\\n\u3000物理攻擊力提升、降低的效果影響。\\n‧大幅度降低前方3名角色的\\n\u3000物理/魔法攻擊力，並大幅度降低物理防禦力\\n\u3000直到戰鬥結束。\\n‧大幅度提升自身的物理攻擊力。\\n‧當剩餘時間不到30秒時，大幅度降低\\n\u3000敵方全體的物理防禦力，\\n\u3000大幅度提升自身的物理/魔法防禦力，\\n\u3000同時攻擊將會變得更加激烈且凶暴。');
insert into unit_enemy_data values (314304, '哀暴小棉花糖', 314304, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE1】從異界誤闖進來的幽靈，\\n像照鏡子般地幻化成所有人並阻擋在前方。\\n萬聖節拯救隊能否順利取勝，拯救世界？\\n\\n‧必殺技會解除敵方全體的護盾，\\n\u3000造成大幅度的物理傷害。\\n\u3000同時小幅度提升自身的物理攻擊力。\\n\u3000此攻擊容易受到\\n\u3000物理攻擊力提升、降低的效果影響。\\n‧對面前的1名角色造成物理傷害。');
insert into unit_enemy_data values (314305, '哀暴小棉花糖', 314305, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE2】失控後轉眼間如球體般縮成一團，\\n擋下各種攻擊。即便是使出全力的一擊，\\n在其這般姿態面前也宛如輕撫一般。\\n\\n‧戰鬥開始時，大幅度提升\\n\u3000自己的物理/魔法防禦力。\\n在戰鬥中，哀暴小棉花糖不會行動。');
insert into unit_enemy_data values (314306, '哀暴小棉花糖', 314300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE3】完全解放身為超特級妖魔的\\n靈力，以足以摧毀世界平衡的氣勢打鬧的\\n小棉花糖。你能夠擁抱牠全部的愛嗎？\\n\\n‧必殺技會解除敵方全體的護盾，\\n\u3000造成大幅度的物理傷害。\\n\u3000同時小幅度提升自身的物理攻擊力。\\n\u3000此攻擊容易受到\\n\u3000物理攻擊力提升、降低的效果影響。\\n‧對面前的1名敵人造成物理傷害。\\n\u3000此攻擊容易受到\\n\u3000物理攻擊力提升、降低的效果影響。\\n‧大幅度降低前方3名角色的物理/魔法攻擊力，\\n\u3000並大幅度降低物理防禦力\\n\u3000直到戰鬥結束。\\n‧大幅度提升自身的物理攻擊力。\\n‧當剩餘時間不到30秒時，大幅度降低\\n\u3000敵方全體的物理防禦力，\\n\u3000大幅度提升自身的物理/魔法防禦力，\\n\u3000同時攻擊將會變得更加激烈且凶暴。');
insert into unit_enemy_data values (314400, '反逆獸‧三重', 314400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '');
insert into unit_enemy_data values (314401, '反逆獸‧三重', 314400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】吸收魔法少女們的力量進化成\\n反逆獸。蘭德索爾是否就會這樣落入\\n魔之手！？可別輸了，黑暗三人組！\\n\\n‧必殺技會使前方3名角色之中，\\n\u3000HP在80％以下的角色陷入誘惑狀態。\\n\u3000之後，對前方的3名角色依照其最大HP\\n\u3000造成魔法比例傷害。\\n‧召喚反逆獸的屬下，\\n\u3000擊退敵方全體。\\n\u3000反逆獸的屬下每當經過一定的時間，\\n\u3000在使面前的1名敵人陷入誘惑狀態後，\\n\u3000當場消失。\\n\u3000但是當反逆獸屬下的HP\\n\u3000低於一定數值時，在特大幅度提升\\n\u3000隊伍整體的物理攻擊力與魔法攻擊力後，\\n\u3000當場消失。\\n‧對前方2名角色造成中幅度的魔法傷害。\\n\u3000同時對自己展開物理無效的護盾。\\n‧對前方的2名角色依照其最大HP\\n\u3000造成魔法比例傷害。');
insert into unit_enemy_data values (314402, '反逆獸‧三重', 314400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】吸收魔法少女們的力量進化成\\n反逆獸。蘭德索爾是否就會這樣落入\\n魔之手！？可別輸了，黑暗三人組！\\n\\n‧必殺技會使前方3名角色之中，\\n\u3000HP在80％以下的角色陷入誘惑狀態。\\n\u3000之後，對前方的3名角色依照其最大HP\\n\u3000造成魔法比例傷害。\\n‧召喚反逆獸的屬下，\\n\u3000擊退敵方全體。\\n\u3000反逆獸的屬下每當經過一定的時間，\\n\u3000在使面前的1名敵人陷入誘惑狀態後，\\n\u3000當場消失。\\n\u3000但是當反逆獸屬下的HP\\n\u3000低於一定數值時，在特大幅度提升\\n\u3000隊伍整體的物理攻擊力與魔法攻擊力後，\\n\u3000當場消失。\\n‧對前方2名角色造成中幅度的魔法傷害。\\n\u3000同時對自己展開物理無效的護盾。\\n‧對前方的2名角色依照其最大HP\\n\u3000造成魔法比例傷害。');
insert into unit_enemy_data values (314403, '反逆獸‧三重', 314400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】吸收魔法少女們的力量進化成\\n反逆獸。蘭德索爾是否就會這樣落入\\n魔之手！？可別輸了，黑暗三人組！\\n\\n‧必殺技會使前方3名角色之中，\\n\u3000HP在80％以下的角色陷入誘惑狀態。\\n\u3000之後，對前方的3名角色依照其最大HP\\n\u3000造成魔法比例傷害。\\n‧召喚反逆獸的屬下，\\n\u3000擊退敵方全體。\\n\u3000反逆獸的屬下每當經過一定的時間，\\n\u3000在使面前的1名敵人陷入誘惑狀態後，\\n\u3000當場消失。\\n\u3000但是當反逆獸的屬下的HP\\n\u3000低於一定數值時，在特大幅度提升\\n\u3000隊伍整體的物理攻擊力與魔法攻擊力後，\\n\u3000當場消失。\\n‧對前方2名角色造成中幅度的魔法傷害。\\n\u3000同時對自己展開物理無效的護盾。\\n‧對前方的2名角色依照其最大HP\\n\u3000造成魔法比例傷害。\\n‧反逆獸‧三重自身的HP\\n\u3000低於30％時，其攻擊將會變得更加\\n\u3000激烈且凶暴。');
insert into unit_enemy_data values (314404, '反逆獸‧三重', 314405, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE1】被囚禁在黑暗漩渦中，眼看就要失去希望的\\n魔法少女們──當時耳邊所聽到的，是來自\\n重要之人的聲援。振作起來吧，魔法少女！\\n\\n‧必殺技會使前方的3名角色之中，\\n\u3000HP在75％以下的角色陷入誘惑狀態。\\n\u3000之後，對前方的3名角色依照其最大HP\\n\u3000造成魔法比例傷害。\\n‧戰鬥開始時，使敵方全體陷入詛咒狀態。\\n\u3000此技能施加的詛咒所造成的傷害\\n\u3000不會恢復TP。\\n\u3000同時，不論是打算以任何效果進行HP的恢復，\\n\u3000都將降低原本恢復量的\\n\u300060％。\\n‧對前方的2名角色依照其最大HP\\n\u3000造成魔法比例傷害。');
insert into unit_enemy_data values (314405, '反逆獸‧三重', 314405, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE2】再次儲備黑暗力量的仇敵。\\n然而，開始失控的不單只是敵人而已──！？\\n已經沒有人能夠阻止這3個人了！\\n\\n‧展開護盾，使其不會受到敵人造成的任何攻擊。\\n\u3000此護盾與傷害量無關，而是每當受到攻擊時，\\n\u3000便會漸漸的降低其耐久度。\\n\u3000當受到490次的攻擊後，\\n\u3000護盾將會被破壞。\\n‧對前方的2名角色造成中幅度的魔法傷害。');
insert into unit_enemy_data values (314406, '反逆獸‧三重', 314400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE3】戰鬥終於進入最高潮。\\n為了親愛的學生、弟弟和虐待狂先生，\\n抱著愛、希望及黑暗，勇往向前吧，黑暗三人組！\\n\\n‧必殺技會使前方的3名角色之中，\\n\u3000HP在80％以下的角色陷入誘惑狀態。\\n\u3000之後，對前方的3名角色依照其最大HP\\n\u3000造成魔法比例傷害。\\n‧召喚反逆獸的屬下，擊退\\n\u3000敵方全體。\\n\u3000反逆獸的屬下每當經過一定的時間，\\n\u3000在使面前的1名敵人陷入誘惑狀態後，\\n\u3000當場消失。\\n\u3000但是當反逆獸的屬下的HP\\n\u3000低於一定數值時，在特大幅度提升\\n\u3000隊伍整體的物理攻擊力與魔法攻擊力後，\\n\u3000當場消失。\\n‧對前方的2名角色造成中幅度的魔法傷害。\\n\u3000同時對自己展開物理無效的護盾。\\n‧對前方的2名角色依照其最大HP\\n\u3000造成魔法比例傷害。\\n‧反逆獸‧三重自身的HP\\n\u3000低於30％時，其攻擊將會變得更加\\n\u3000激烈且凶暴。');
